function safeCurrentWorkingDirectory() {
  try {
    return process.cwd();
  } catch {
    return os.homedir();
  }
}

function resolveAppRoot() {
  const candidates = [
    process.env.JAVIS_REPO_ROOT,
    process.env.JAVIS_APP_ROOT,
    typeof app?.getAppPath === 'function' ? app.getAppPath() : '',
    safeCurrentWorkingDirectory(),
    path.resolve(__dirname, '..'),
  ]
    .filter(Boolean)
    .map((candidate) => path.resolve(candidate));
  for (const candidate of candidates) {
    if (
      fs.existsSync(path.join(candidate, 'package.json')) &&
      fs.existsSync(path.join(candidate, 'electron', 'main.cjs'))
    ) {
      return candidate;
    }
  }
  return candidates[0] || os.homedir();
}

const APP_ROOT = resolveAppRoot();
try {
  if (safeCurrentWorkingDirectory() !== APP_ROOT) {
    process.chdir(APP_ROOT);
  }
} catch (error) {
  console.error(`JAVIS failed to enter app root ${APP_ROOT}: ${error instanceof Error ? error.message : String(error)}`);
}

dotenv.config({ path: path.join(APP_ROOT, '.env') });

function appendStartupTrace(event, data = {}) {
  try {
    const file = path.join(APP_ROOT, 'logs', 'startup-trace.log');
    fs.mkdirSync(path.dirname(file), { recursive: true });
    fs.appendFileSync(file, `${JSON.stringify({
      at: new Date().toISOString(),
      event,
      pid: process.pid,
      cwd: safeCurrentWorkingDirectory(),
      appRoot: APP_ROOT,
      ...data,
    })}\n`);
  } catch {}
}

appendStartupTrace('module_loaded');

function parseJsonBodyLimit(limit = '1mb') {
  if (typeof limit === 'number') return Math.max(1, limit);
  const text = String(limit || '1mb').trim().toLowerCase();
  const match = text.match(/^(\d+(?:\.\d+)?)\s*(b|kb|mb)?$/);
  if (!match) return 1024 * 1024;
  const value = Number(match[1]);
  const unit = match[2] || 'b';
  const multiplier = unit === 'mb' ? 1024 * 1024 : unit === 'kb' ? 1024 : 1;
  return Math.max(1, Math.round(value * multiplier));
}

function localJsonBodyParser(options = {}) {
  const limitBytes = parseJsonBodyLimit(options.limit || '100kb');
  return (req, res, next) => {
    if (req.body !== undefined || req.method === 'GET' || req.method === 'HEAD') {
      next();
      return;
    }
    const contentType = String(req.headers['content-type'] || '').toLowerCase();
    const looksJson = contentType.includes('application/json') || contentType.includes('+json');
    if (!looksJson) {
      next();
      return;
    }
    const chunks = [];
    let size = 0;
    let completed = false;
    const fail = (status, message) => {
      if (completed) return;
      completed = true;
      res.status(status).json({ ok: false, error: message });
    };
    req.on('data', (chunk) => {
      size += chunk.length;
      if (size > limitBytes) {
        fail(413, 'JSON body is too large.');
        req.destroy();
        return;
      }
      chunks.push(chunk);
    });
    req.on('error', (error) => {
      fail(400, error instanceof Error ? error.message : String(error));
    });
    req.on('end', () => {
      if (completed) return;
      completed = true;
      const text = Buffer.concat(chunks).toString('utf8').trim();
      if (!text) {
        req.body = {};
        next();
        return;
      }
      try {
        req.body = JSON.parse(text);
        next();
      } catch {
        res.status(400).json({ ok: false, error: 'Invalid JSON request body.' });
      }
    });
  };
}

function localTextBodyParser(options = {}) {
  const limitBytes = parseJsonBodyLimit(options.limit || '100kb');
  const allowedTypes = Array.isArray(options.type)
    ? options.type.map((item) => String(item).toLowerCase())
    : [String(options.type || 'text/plain').toLowerCase()];
  return (req, res, next) => {
    if (req.body !== undefined || req.method === 'GET' || req.method === 'HEAD') {
      next();
      return;
    }
    const contentType = String(req.headers['content-type'] || '').split(';')[0].trim().toLowerCase();
    const shouldParse = allowedTypes.includes('*/*') || allowedTypes.includes(contentType);
    if (!shouldParse) {
      next();
      return;
    }
    const chunks = [];
    let size = 0;
    let completed = false;
    const fail = (status, message) => {
      if (completed) return;
      completed = true;
      res.status(status).send(message);
    };
    req.on('data', (chunk) => {
      size += chunk.length;
      if (size > limitBytes) {
        fail(413, 'Text body is too large.');
        req.destroy();
        return;
      }
      chunks.push(chunk);
    });
    req.on('error', (error) => {
      fail(400, error instanceof Error ? error.message : String(error));
    });
    req.on('end', () => {
      if (completed) return;
      completed = true;
      req.body = Buffer.concat(chunks).toString(options.defaultCharset || 'utf8');
      next();
    });
  };
}

express.json = localJsonBodyParser;
express.text = localTextBodyParser;

