function parseParkCorner(value) {
  const normalized = String(value || '').trim().toLowerCase();
  return ['notch', 'top-left', 'top-right', 'bottom-left', 'bottom-right'].includes(normalized)
    ? normalized
    : 'notch';
}

function windowBoundsSnapshot() {
  if (!mainWindow || mainWindow.isDestroyed()) return null;
  const bounds = mainWindow.getBounds();
  return {
    x: bounds.x,
    y: bounds.y,
    width: bounds.width,
    height: bounds.height,
  };
}

function windowTargetForMode(mode = currentWindowMode) {
  return windowModes[mode] || windowModes.pet;
}

function normalizeWindowMode(mode) {
  return Object.prototype.hasOwnProperty.call(windowModes, String(mode || ''))
    ? String(mode)
    : 'pet';
}

function clearComposeAutoParkTimer() {
  if (!composeAutoParkTimer) return;
  clearTimeout(composeAutoParkTimer);
  composeAutoParkTimer = null;
  composeAutoParkStartedAt = 0;
}

function scheduleComposeAutoPark(source = 'compose') {
  clearComposeAutoParkTimer();
  if (!WINDOW_COMPOSE_AUTO_PARK_MS) return;
  composeAutoParkStartedAt = Date.now();
  composeAutoParkTimer = setTimeout(() => {
    composeAutoParkTimer = null;
    if (currentWindowMode !== 'compose') return;
    const ageMs = Math.max(0, Date.now() - composeAutoParkStartedAt);
    composeAutoParkStartedAt = 0;
    appendAudit('window.compose_auto_parked', {
      source: compactRecordText(source, 80),
      ageMs,
      timeoutMs: WINDOW_COMPOSE_AUTO_PARK_MS,
    });
    applyWindowMode('pet', {
      source: 'compose_auto_park',
      focus: false,
      park: true,
      corner: currentParkCorner,
    });
  }, WINDOW_COMPOSE_AUTO_PARK_MS);
  if (typeof composeAutoParkTimer.unref === 'function') composeAutoParkTimer.unref();
}

function displayForWindow(displayMode = WINDOW_PARK_DISPLAY) {
  try {
    if (displayMode === 'primary') {
      return screen.getPrimaryDisplay();
    }
    if (mainWindow && !mainWindow.isDestroyed()) {
      return screen.getDisplayMatching(mainWindow.getBounds());
    }
    return screen.getPrimaryDisplay();
  } catch {
    return {
      bounds: { x: 0, y: 0, width: 1440, height: 900 },
      workArea: { x: 0, y: 0, width: 1440, height: 900 },
    };
  }
}

function displayWorkAreaForWindow(displayMode = WINDOW_PARK_DISPLAY) {
  return displayForWindow(displayMode).workArea;
}

function enforceWindowSize(mode = currentWindowMode) {
  if (!mainWindow || mainWindow.isDestroyed()) return null;
  const target = windowTargetForMode(mode);
  try {
    const bounds = mainWindow.getBounds();
    mainWindow.setResizable(true);
    mainWindow.setMinimumSize(1, 1);
    mainWindow.setMaximumSize(10000, 10000);
    mainWindow.setBounds(
      {
        ...bounds,
        width: target.width,
        height: target.height,
      },
      false,
    );
    mainWindow.setSize(target.width, target.height, false);
    mainWindow.setMinimumSize(target.width, target.height);
    mainWindow.setMaximumSize(target.width, target.height);
    mainWindow.setResizable(false);
  } catch (error) {
    appendAudit('window.size_enforce_failed', {
      mode,
      width: target.width,
      height: target.height,
      error: error instanceof Error ? error.message : String(error),
    });
  }
  return windowBoundsSnapshot();
}

function scheduleWindowSizeEnforcement(source = 'window') {
  for (const delay of [0, 160, 700, 1500]) {
    setTimeout(() => {
      if (!mainWindow || mainWindow.isDestroyed()) return;
      enforceWindowSize(currentWindowMode);
      parkWindow(source, { corner: currentParkCorner, display: WINDOW_PARK_DISPLAY, menu: false });
    }, delay);
  }
}

function parkedPosition(mode = currentWindowMode, corner = currentParkCorner, displayMode = WINDOW_PARK_DISPLAY) {
  const target = windowTargetForMode(mode);
  const display = displayForWindow(displayMode);
  const bounds = display.bounds || display.workArea || { x: 0, y: 0, width: 1440, height: 900 };
  const workArea = displayWorkAreaForWindow(displayMode);
  const safeCorner = parseParkCorner(corner);
  if (safeCorner === 'notch') {
    return {
      x: Math.round(bounds.x + ((bounds.width - target.width) / 2)),
      y: Math.round(bounds.y + WINDOW_NOTCH_TOP_OFFSET),
      corner: safeCorner,
      display: displayMode === 'current' ? 'current' : 'primary',
      margin: WINDOW_NOTCH_TOP_OFFSET,
    };
  }
  const x = safeCorner.endsWith('right')
    ? workArea.x + workArea.width - target.width - WINDOW_PARK_MARGIN
    : workArea.x + WINDOW_PARK_MARGIN;
  const y = safeCorner.startsWith('bottom')
    ? workArea.y + workArea.height - target.height - WINDOW_PARK_MARGIN
    : workArea.y + WINDOW_PARK_MARGIN;
  return {
    x: Math.round(x),
    y: Math.round(y),
    corner: safeCorner,
    display: displayMode === 'current' ? 'current' : 'primary',
    margin: WINDOW_PARK_MARGIN,
  };
}

function parkWindow(source = 'api', options = {}) {
  if (!mainWindow || mainWindow.isDestroyed()) return windowStateSnapshot();
  if (options.corner) currentParkCorner = parseParkCorner(options.corner);
  const displayMode = options.display === 'current' ? 'current' : options.display === 'primary' ? 'primary' : WINDOW_PARK_DISPLAY;
  enforceWindowSize(currentWindowMode);
  const position = parkedPosition(currentWindowMode, currentParkCorner, displayMode);
  const target = windowTargetForMode(currentWindowMode);
  mainWindow.setBounds({ x: position.x, y: position.y, width: target.width, height: target.height }, false);
  mainWindow.setPosition(position.x, position.y, false);
  appendAudit('window.park', {
    source,
    mode: currentWindowMode,
    corner: position.corner,
    display: position.display,
    margin: position.margin,
    x: position.x,
    y: position.y,
  });
  if (options.menu !== false) updateMenuBarMenu();
  return windowStateSnapshot();
}

function moveWindow(source = 'api', options = {}) {
  if (!mainWindow || mainWindow.isDestroyed()) return windowStateSnapshot();
  enforceWindowSize(currentWindowMode);
  const current = mainWindow.getBounds();
  const x = Number.isFinite(Number(options.x)) ? Math.round(Number(options.x)) : current.x;
  const y = Number.isFinite(Number(options.y)) ? Math.round(Number(options.y)) : current.y;
  const target = windowTargetForMode(currentWindowMode);
  mainWindow.setBounds({ x, y, width: target.width, height: target.height }, false);
  appendAudit('window.move', {
    source,
    mode: currentWindowMode,
    x,
    y,
  });
  updateMenuBarMenu();
  return windowStateSnapshot();
}

function tapToSummonSnapshot(options = {}) {
  const voiceHealth = options.voiceHealth || realtimeVoiceHealthSnapshot({ includeRecentAudit: true });
  const realtimeProviderReady = voiceHealth.status === 'ready';
  const zeroSpendLocked = openAiZeroSpendModeActive();
  const realtimeTapAllowed = Boolean(TAP_TO_REALTIME_ENABLED && realtimeProviderReady && !zeroSpendLocked);
  const fallbackReady = !realtimeProviderReady;
  const localInputDefault = !realtimeTapAllowed;
  const hotkey = SUMMON_HOTKEY;
  const currentAction = localInputDefault
    ? {
        id: 'open_compact_local_input',
        label: 'Open local input',
        mode: 'compose',
        endpoint: '/api/voice/command',
        startsMicrophone: false,
        usesRealtime: false,
      }
    : {
        id: 'wake_realtime_voice',
        label: 'Wake Realtime voice',
        mode: 'pet',
        endpoint: '/api/wake/status',
        startsMicrophone: true,
        usesRealtime: true,
      };
  return {
    version: 1,
    enabled: Boolean(hotkey),
    hotkey,
    registered: Boolean(summonHotkeyRegistered),
    endpoint: '/api/window/summon',
    label: 'Tap to summon',
    sourceEnv: 'JAVIS_SUMMON_HOTKEY or JAVIS_TAP_HOTKEY',
    parksAt: currentParkCorner,
    fallbackReady,
    localInputDefault,
    realtimeProviderReady,
    realtimeTapEnabled: TAP_TO_REALTIME_ENABLED,
    realtimeTapAllowed,
    zeroSpendLocked,
    currentAction,
    summary: hotkey
      ? localInputDefault
        ? `${hotkey} opens the compact local input at the notch without microphone, Realtime, Terminal, or provider spend.`
        : `${hotkey} wakes JAVIS through the renderer voice path because realtime tap is explicitly enabled and spend is unlocked.`
      : 'Tap-to-summon is disabled.',
    safety: {
      residentStartsMicrophone: false,
      residentUsesRealtime: false,
      opensTerminal: false,
      mutatesUserFiles: false,
      storesRawAudio: false,
      fallbackStartsMicrophone: false,
      fallbackUsesRealtime: false,
      fallbackCallsOpenAi: false,
      realtimeReadyMayStartRendererVoice: realtimeTapAllowed,
      realtimeTapRequiresExplicitEnv: true,
    },
  };
}

function compactTapToSummonSnapshot(tap = tapToSummonSnapshot()) {
  return {
    version: tap.version,
    enabled: Boolean(tap.enabled),
    registered: Boolean(tap.registered),
    endpoint: tap.endpoint || '/api/window/summon',
    localInputDefault: tap.localInputDefault !== false,
    realtimeTapAllowed: Boolean(tap.realtimeTapAllowed),
    currentAction: tap.currentAction
      ? {
          id: tap.currentAction.id || '',
          mode: tap.currentAction.mode || '',
          startsMicrophone: Boolean(tap.currentAction.startsMicrophone),
          usesRealtime: Boolean(tap.currentAction.usesRealtime),
        }
      : null,
    safety: {
      residentStartsMicrophone: Boolean(tap.safety?.residentStartsMicrophone),
      residentUsesRealtime: Boolean(tap.safety?.residentUsesRealtime),
      opensTerminal: Boolean(tap.safety?.opensTerminal),
      fallbackCallsOpenAi: Boolean(tap.safety?.fallbackCallsOpenAi),
      realtimeReadyMayStartRendererVoice: Boolean(tap.safety?.realtimeReadyMayStartRendererVoice),
      realtimeTapRequiresExplicitEnv: tap.safety?.realtimeTapRequiresExplicitEnv !== false,
    },
  };
}

