function notificationSupported() {
  try {
    return typeof Notification?.isSupported === 'function' ? Notification.isSupported() : false;
  } catch {
    return false;
  }
}

function normalizeAttentionNotificationHistoryRecord(record = {}, options = {}) {
  const createdAt = Number(record.createdAt || options.createdAt || Date.parse(options.ts || '') || 0);
  const payload = record.data || {};
  const delivered = record.delivered === true;
  const reason = compactRecordText(record.reason || (delivered ? 'sent' : 'unknown'), 80);
  return {
    id: crypto.createHash('sha1').update([
      createdAt,
      options.eventType || '',
      record.title || '',
      record.body || '',
      delivered ? 'sent' : reason,
    ].join('|')).digest('hex').slice(0, 16),
    eventType: compactRecordText(options.eventType || '', 80),
    source: compactRecordText(payload.source || record.source || options.source || 'resident', 80),
    title: compactRecordText(record.title || 'JAVIS attention', 100),
    body: compactRecordText(record.body || '', 240),
    delivered,
    suppressed: !delivered,
    reason,
    attentionReason: compactRecordText(record.attentionReason || payload.attentionReason || '', 80),
    attentionLevel: compactRecordText(record.attentionLevel || payload.attentionLevel || '', 40),
    cooldownRemainingMs: Math.max(0, Number(record.cooldownRemainingMs || 0)),
    createdAt,
    ageMs: createdAt ? Math.max(0, Date.now() - createdAt) : null,
    ageLabel: createdAt ? `${attentionDurationLabel(Date.now() - createdAt)} ago` : 'unknown',
  };
}

function attentionNotificationHistory(limit = 8, auditLimit = 160) {
  const max = Math.max(1, Math.min(25, Number(limit || 8)));
  const records = [];
  const seen = new Set();
  const add = (record, options = {}) => {
    if (!record) return;
    const normalized = normalizeAttentionNotificationHistoryRecord(record, options);
    if (!normalized.createdAt || seen.has(normalized.id)) return;
    seen.add(normalized.id);
    records.push(normalized);
  };

  add(notificationState.attention.last, { source: 'memory', eventType: 'notification.last' });
  try {
    for (const event of readRecentAudit(auditLimit)) {
      const data = event.data || {};
      const attentionEvent = event.type === 'notification.attention_suppressed' || data.attention === true;
      if (!attentionEvent) continue;
      add(data, { source: 'audit', eventType: event.type, ts: event.ts });
    }
  } catch {
    // History is operator evidence only; never let a damaged audit log break attention policy.
  }

  records.sort((a, b) => b.createdAt - a.createdAt);
  const recent = records.slice(0, max);
  const delivered = records.filter((record) => record.delivered).length;
  const suppressed = records.filter((record) => record.suppressed).length;
  const latest = recent[0] || null;
  const summary = latest
    ? `Latest attention notification ${latest.delivered ? 'sent' : `suppressed (${latest.reason || 'policy'})`} ${latest.ageLabel}.`
    : 'No attention notification history yet.';
  return {
    ok: true,
    operatorOnly: true,
    desktopPet: false,
    count: records.length,
    returned: recent.length,
    limit: max,
    delivered,
    suppressed,
    latest,
    summary,
    recent,
  };
}

function notificationSnapshot() {
  return {
    enabled: NOTIFICATIONS_ENABLED,
    supported: notificationSupported(),
    sent: notificationState.sent,
    skipped: notificationState.skipped,
    last: notificationState.last,
    attentionNotifications: {
      ...notificationState.attention,
      history: attentionNotificationHistory(8),
    },
    attention: attentionPolicySnapshot(),
  };
}

function latestAttentionNotificationAuditAt(limit = 120) {
  try {
    const events = readRecentAudit(limit);
    for (let index = events.length - 1; index >= 0; index -= 1) {
      const event = events[index] || {};
      if (event.type !== 'notification.sent') continue;
      const data = event.data || {};
      if (data.attention !== true) continue;
      return Number(data.createdAt || 0) || Date.parse(event.ts || '') || 0;
    }
  } catch {
    return 0;
  }
  return 0;
}

function lastAttentionNotificationAt() {
  const inMemory = Number(notificationState.attention.lastNotificationAt || 0);
  if (inMemory) return inMemory;
  const audited = latestAttentionNotificationAuditAt();
  if (audited) {
    notificationState.attention.lastNotificationAt = audited;
  }
  return audited;
}

function attentionDurationLabel(ms) {
  const value = Math.max(0, Number(ms || 0));
  if (!value) return 'now';
  const seconds = Math.ceil(value / 1000);
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.ceil(seconds / 60);
  if (minutes < 60) return `${minutes}m`;
  return `${Math.ceil(minutes / 60)}h`;
}

function attentionReason(id, severity, label, summary, options = {}) {
  return {
    id,
    severity,
    label: compactRecordText(label || id, 90),
    summary: compactRecordText(summary || '', 240),
    notify: options.notify !== false,
    source: compactRecordText(options.source || id, 80),
    count: Math.max(0, Number(options.count || 0)),
    action: compactRecordText(options.action || '', 160),
  };
}

function attentionSeverityRank(value) {
  return {
    critical: 4,
    high: 3,
    medium: 2,
    low: 1,
    info: 0,
  }[String(value || '').toLowerCase()] ?? 0;
}

function attentionPetState(level, reasons = []) {
  if (level === 'notify' || reasons.some((reason) => reason.severity === 'critical' || reason.severity === 'high')) return 'red';
  if (level === 'waiting' || reasons.some((reason) => reason.severity === 'medium')) return 'yellow';
  if (level === 'watching' || reasons.length) return 'green_yellow';
  return 'green';
}

function isQuietBrowserRecoveryAttentionRoute(route) {
  const status = String(route?.status || '');
  if (!['blocked', 'failed', 'needs_attention'].includes(status)) return false;
  return browserUnavailableRouteBlocker(route, route);
}

function readinessIsQuietZeroSpendFallback(readiness) {
  const issue = readiness?.primaryIssue || {};
  const recovery = issue.recovery || {};
  const counts = readiness?.counts || {};
  return Boolean(
    readiness?.overall === 'degraded' &&
      issue.id === 'realtime_voice_provider' &&
      issue.status === 'warning' &&
      recovery.spendLocked === true &&
      recovery.localFallback?.available === true &&
      Number(counts.blocked || 0) === 0 &&
      Number(counts.warning || 0) === 1 &&
      openAiZeroSpendModeActive()
  );
}

function attentionPolicySnapshot(options = {}) {
  const now = Date.now();
  const readiness = options.readiness || readinessSnapshot();
  const quietZeroSpendFallback = readinessIsQuietZeroSpendFallback(readiness);
  const conversation = options.conversation || conversationStateSnapshot();
  const pendingApprovals = options.pendingApprovals || pendingApprovalSnapshot(10);
  const activeJobs = options.activeJobs || jobSnapshot(30).filter((job) => job.status === 'queued' || job.status === 'running');
  const failedJobs = options.failedJobs || jobSnapshot(30).filter((job) => job.status === 'failed' && !job.recoveryForJobId && !isInternalJob(job));
  const activeRoutes = options.activeRoutes || activeRoutingSnapshot(10).map(routingLedgerEntry).filter(Boolean);
  const inbox = options.inbox || inboxCounts();
  const reasons = [];

  if (readiness?.overall === 'blocked') {
    reasons.push(attentionReason(
      'setup_blocked',
      'critical',
      'Setup blocked',
      readiness.primaryIssue?.summary || readiness.summary || 'A setup or permission issue blocks JAVIS.',
      { source: 'readiness', action: readiness.primaryIssue?.next || '' },
    ));
  } else if (readiness?.overall === 'degraded' && !quietZeroSpendFallback) {
    reasons.push(attentionReason(
      'setup_degraded',
      'medium',
      'Setup needs attention',
      readiness.primaryIssue?.summary || readiness.summary || 'A setup check needs attention.',
      { source: 'readiness', action: readiness.primaryIssue?.next || '', notify: false },
    ));
  }

  if (pendingApprovals.length) {
    reasons.push(attentionReason(
      'pending_approvals',
      'high',
      'Approval waiting',
      `${pendingApprovals.length} action approval(s) are waiting.`,
      { source: 'approvals', count: pendingApprovals.length, action: pendingApprovals[0]?.summary || '' },
    ));
  }

  if (conversation.status === 'error' && Number(conversation.ageMs || 0) < 300000) {
    reasons.push(attentionReason(
      'voice_error',
      'high',
      'Voice error',
      conversation.error || 'The last Realtime voice session failed.',
      { source: 'realtime' },
    ));
  } else if (conversation.status === 'connecting') {
    reasons.push(attentionReason(
      'voice_connecting',
      'medium',
      'Voice connecting',
      'Realtime voice is connecting.',
      { source: 'realtime', notify: false },
    ));
  } else if (conversation.status === 'live') {
    reasons.push(attentionReason(
      'voice_live',
      'low',
      'Voice live',
      `Realtime voice is live; ${conversation.microphone?.label || `mic mode ${conversation.micMode || 'open'}`}.`,
      { source: 'realtime', notify: false },
    ));
  }

  if (failedJobs.length) {
    reasons.push(attentionReason(
      'failed_jobs',
      'medium',
      'Worker recovery available',
      `${failedJobs.length} failed worker job(s) have recovery context.`,
      { source: 'jobs', count: failedJobs.length, action: failedJobs[0]?.title || '', notify: false },
    ));
  }

  const blockedRoutes = activeRoutes
    .filter((route) => ['blocked', 'failed', 'needs_attention'].includes(String(route.status || '')))
    .filter((route) => !isQuietBrowserRecoveryAttentionRoute(route));
  if (blockedRoutes.length) {
    reasons.push(attentionReason(
      'blocked_routes',
      'medium',
      'Routed work blocked',
      `${blockedRoutes.length} routed task(s) need attention.`,
      { source: 'routing', count: blockedRoutes.length, action: blockedRoutes[0]?.nextAction || blockedRoutes[0]?.taskTitle || '', notify: false },
    ));
  }

  if (activeJobs.length) {
    reasons.push(attentionReason(
      'active_jobs',
      'low',
      'Background work running',
      `${activeJobs.length} background job(s) are queued or running.`,
      { source: 'jobs', count: activeJobs.length, action: activeJobs[0]?.title || '', notify: false },
    ));
  }

  if (inbox.open) {
    reasons.push(attentionReason(
      'open_inbox',
      'low',
      'Inbox has captures',
      `${inbox.open} Inbox item(s) are open.`,
      { source: 'inbox', count: inbox.open, notify: false },
    ));
  }

  reasons.sort((a, b) => attentionSeverityRank(b.severity) - attentionSeverityRank(a.severity) || b.count - a.count || a.id.localeCompare(b.id));
  const top = reasons[0] || null;
  const lastNotificationAt = lastAttentionNotificationAt();
  const elapsed = lastNotificationAt ? now - lastNotificationAt : Infinity;
  const cooldownRemainingMs = Number.isFinite(elapsed)
    ? Math.max(0, ATTENTION_NOTIFICATION_COOLDOWN_MS - elapsed)
    : 0;
  const cooldownActive = cooldownRemainingMs > 0;
  const candidate = reasons.find((reason) => reason.notify && attentionSeverityRank(reason.severity) >= 3) || null;
  const canNotify = Boolean(NOTIFICATIONS_ENABLED && notificationSupported());
  const shouldNotify = Boolean(candidate && canNotify && !cooldownActive);
  const level = shouldNotify
    ? 'notify'
    : candidate
      ? 'waiting'
      : top
        ? 'watching'
        : 'quiet';
  const summary = top
    ? `${top.label}: ${top.summary}`
    : 'No attention needed. Keep the pet quiet and stay in passive watch mode.';
  const nextAction = shouldNotify
    ? `Notify user about ${candidate.label}.`
    : candidate && cooldownActive
      ? `Keep quiet for ${attentionDurationLabel(cooldownRemainingMs)} before notifying about ${candidate.label}.`
      : top
        ? `Expose ${top.label} in CUI/API without interrupting the user.`
        : 'Stay quiet until the user speaks, a permission blocks work, or a high-priority approval appears.';

  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    level,
    shouldNotify,
    canNotify,
    enabled: NOTIFICATIONS_ENABLED,
    supported: notificationSupported(),
    cooldownMs: ATTENTION_NOTIFICATION_COOLDOWN_MS,
    cooldown: {
      active: cooldownActive,
      remainingMs: cooldownRemainingMs,
      remainingLabel: attentionDurationLabel(cooldownRemainingMs),
      lastNotificationAt,
    },
    petState: attentionPetState(level, reasons),
    topReason: top,
    notifyCandidate: candidate,
    reasons,
    counts: {
      reasons: reasons.length,
      highPriority: reasons.filter((reason) => attentionSeverityRank(reason.severity) >= 3).length,
      pendingApprovals: pendingApprovals.length,
      activeJobs: activeJobs.length,
      failedJobs: failedJobs.length,
      openInbox: inbox.open || 0,
      activeRoutes: activeRoutes.length,
    },
    summary,
    nextAction,
  };
}

function attentionVoiceExplanationSnapshot(options = {}) {
  const limit = Math.max(1, Math.min(8, Number(options.limit || 4)));
  const policy = attentionPolicySnapshot();
  const history = attentionNotificationHistory(limit);
  const top = policy.topReason;
  const candidate = policy.notifyCandidate;
  const latest = history.latest;
  const statusLine = `现在是 ${policy.level}，宠物状态 ${policy.petState}。`;
  const reasonLine = top
    ? `主要原因是 ${top.label}：${top.summary}`
    : '现在没有需要打断你的事项。';
  const actionLine = policy.shouldNotify
    ? `应该提醒你：${candidate?.label || '有高优先级事项'}。`
    : candidate && policy.cooldown?.active
      ? `有高优先级事项，但还在 ${policy.cooldown.remainingLabel || 'cooldown'} 安静冷却中。`
      : '保持安静，等你叫它或出现高优先级审批、设置、语音错误再介入。';
  const historyLine = latest
    ? `最近一次 attention 通知是 ${latest.ageLabel} ${latest.delivered ? '发出' : `被压住(${latest.reason || 'policy'})`}：${latest.title}。`
    : '还没有 attention 通知历史。';
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    spokenSummary: compactRecordText(`${statusLine} ${reasonLine} ${actionLine} ${historyLine}`, 420),
    statusLine,
    reasonLine,
    actionLine,
    historyLine,
    policy,
    history,
    guidance: {
      answerStyle: 'short_spoken_chinese',
      desktopPetStillMinimal: true,
      readOnly: true,
    },
  };
}

function attentionNotificationDecision(options = {}) {
  const attention = options.attention || attentionPolicySnapshot();
  const candidate = attention.notifyCandidate || null;
  let reason = '';
  if (!candidate) {
    reason = 'no_candidate';
  } else if (!attention.enabled) {
    reason = 'disabled';
  } else if (!attention.supported) {
    reason = 'unsupported';
  } else if (attention.cooldown?.active) {
    reason = 'cooldown';
  } else if (!attention.shouldNotify) {
    reason = 'policy';
  }
  return {
    ok: true,
    shouldNotify: Boolean(attention.shouldNotify),
    wouldNotify: Boolean(attention.shouldNotify),
    reason,
    candidate,
    candidateId: candidate?.id || '',
    level: attention.level,
    petState: attention.petState,
    cooldown: attention.cooldown,
    attention,
  };
}

function recordSuppressedAttentionNotification(title, body, data, decision) {
  const record = {
    title: String(title || 'JAVIS').slice(0, 80),
    body: compactRecordText(body || '', 180),
    data,
    attention: true,
    attentionReason: decision.candidateId || '',
    attentionLevel: decision.level || 'quiet',
    cooldownRemainingMs: Number(decision.cooldown?.remainingMs || 0),
    createdAt: Date.now(),
    delivered: false,
    reason: decision.reason || 'attention_policy',
  };
  notificationState.skipped += 1;
  notificationState.last = record;
  notificationState.attention.skipped += 1;
  notificationState.attention.last = record;
  appendAudit('notification.attention_suppressed', record);
  return record;
}

function notifyResident(title, body, data = {}, options = {}) {
  const cleanTitle = String(title || 'JAVIS').slice(0, 80);
  const cleanBody = compactRecordText(body || '', 180);
  const isAttention = options.attention === true;
  const record = {
    title: cleanTitle,
    body: cleanBody,
    data,
    attention: isAttention,
    attentionReason: options.attentionReason || options.attentionPolicy?.notifyCandidate?.id || '',
    attentionLevel: options.attentionPolicy?.level || '',
    createdAt: Date.now(),
  };

  if (!NOTIFICATIONS_ENABLED || !notificationSupported()) {
    notificationState.skipped += 1;
    notificationState.last = { ...record, delivered: false, reason: NOTIFICATIONS_ENABLED ? 'unsupported' : 'disabled' };
    if (isAttention) {
      notificationState.attention.skipped += 1;
      notificationState.attention.last = notificationState.last;
    }
    appendAudit('notification.skipped', notificationState.last);
    return false;
  }

  try {
    const notification = new Notification({
      title: cleanTitle,
      body: cleanBody,
      silent: true,
    });
    notification.on('click', () => {
      openConfigCui('notification');
    });
    notification.show();
    notificationState.sent += 1;
    notificationState.last = { ...record, delivered: true };
    if (isAttention) {
      notificationState.attention.sent += 1;
      notificationState.attention.last = notificationState.last;
      notificationState.attention.lastNotificationAt = record.createdAt;
    }
    appendAudit('notification.sent', notificationState.last);
    return true;
  } catch (error) {
    notificationState.skipped += 1;
    notificationState.last = {
      ...record,
      delivered: false,
      reason: error instanceof Error ? error.message : String(error),
    };
    if (isAttention) {
      notificationState.attention.skipped += 1;
      notificationState.attention.last = notificationState.last;
    }
    appendAudit('notification.failed', notificationState.last);
    return false;
  }
}

function notifyCurrentAttention(source = 'attention', options = {}) {
  const decision = attentionNotificationDecision(options);
  const candidate = decision.candidate || null;
  const title = compactRecordText(options.title || (candidate ? `JAVIS ${candidate.label}` : 'JAVIS attention check'), 80);
  const body = compactRecordText(options.body || candidate?.summary || 'No high-priority attention item is waiting.', 180);
  const data = {
    type: 'attention',
    source: compactRecordText(source, 80),
    ...(options.data || {}),
    attentionReason: decision.candidateId,
    attentionLevel: decision.level,
  };
  if (options.dryRun === true) {
    return {
      ok: true,
      dryRun: true,
      delivered: false,
      suppressed: !decision.shouldNotify,
      reason: decision.reason,
      decision,
      notifications: notificationSnapshot(),
    };
  }
  if (!decision.shouldNotify) {
    const record = options.recordSuppressed === false && decision.reason === 'no_candidate'
      ? null
      : recordSuppressedAttentionNotification(title, body, data, decision);
    return {
      ok: true,
      delivered: false,
      suppressed: true,
      reason: decision.reason,
      decision,
      record,
      notifications: notificationSnapshot(),
    };
  }
  const delivered = notifyResident(title, body, data, {
    attention: true,
    attentionReason: decision.candidateId,
    attentionPolicy: decision.attention,
  });
  return {
    ok: delivered,
    delivered,
    suppressed: false,
    reason: delivered ? '' : 'notification_failed',
    decision,
    notifications: notificationSnapshot(),
  };
}

function applyWindowMode(mode, options = {}) {
  const nextMode = normalizeWindowMode(mode);
  currentWindowMode = nextMode;
  if (nextMode === 'compose') scheduleComposeAutoPark(options.source || 'api');
  else clearComposeAutoParkTimer();
  if (mainWindow && !mainWindow.isDestroyed()) {
    enforceWindowSize(nextMode);
    mainWindow.setAlwaysOnTop(true, 'floating');
    mainWindow.setVisibleOnAllWorkspaces(true, { visibleOnFullScreen: true });
    if (options.park !== false) {
      parkWindow(options.source || 'api', { corner: options.corner, display: options.display, menu: false });
    }
    if (options.focus) {
      mainWindow.show();
      mainWindow.focus();
    } else {
      mainWindow.showInactive();
    }
  }
  appendAudit('window.mode', { mode: nextMode, source: options.source || 'api' });
  updateMenuBarMenu();
  return windowStateSnapshot();
}

function toggleWindowMode(source = 'hotkey') {
  return applyWindowMode('pet', { source, focus: false });
}

function summonJavis(source = 'hotkey', options = {}) {
  const voiceHealth = realtimeVoiceHealthSnapshot({ includeRecentAudit: true });
  const tapToSummon = tapToSummonSnapshot({ voiceHealth });
  const opensLocalInput = tapToSummon.currentAction?.id === 'open_compact_local_input';
  const windowState = applyWindowMode(opensLocalInput ? 'compose' : 'pet', {
    source,
    focus: opensLocalInput,
    park: true,
    corner: currentParkCorner,
  });
  const wakeTriggered = options.wake !== false && !opensLocalInput;
  const wake = wakeTriggered
    ? triggerWake({
        source,
        phrase: source === 'hotkey' ? `hotkey:${SUMMON_HOTKEY}` : source,
      })
    : wakeStatusSnapshot();
  appendAudit('summon.triggered', {
    source,
    hotkey: SUMMON_HOTKEY,
    mode: windowState.mode,
    fallbackReady: tapToSummon.fallbackReady,
    localInputDefault: tapToSummon.localInputDefault,
    realtimeTapAllowed: tapToSummon.realtimeTapAllowed,
    currentAction: tapToSummon.currentAction?.id || '',
    wakeTriggered,
    wakeSuppressedReason: !wakeTriggered && opensLocalInput ? 'local_input_default' : '',
    wakePending: wake.pending,
    triggerCount: wake.triggerCount,
  });
  return {
    ok: true,
    output: opensLocalInput ? 'JAVIS local input opened.' : 'JAVIS summoned.',
    window: windowState,
    wake,
    hotkey: SUMMON_HOTKEY,
    tapToSummon,
    fallbackReady: tapToSummon.fallbackReady,
    localInputDefault: tapToSummon.localInputDefault,
    realtimeTapAllowed: tapToSummon.realtimeTapAllowed,
  };
}

function captureClipboardToInbox(source = 'hotkey') {
  const item = createInboxItem({ fromClipboard: true, source });
  lastInboxCapture = {
    id: item.id,
    title: item.title,
    source,
    createdAt: Date.now(),
  };
  appendAudit('inbox.clipboard_captured', {
    id: item.id,
    source,
    title: item.title,
    hotkey: source === 'hotkey' ? CAPTURE_HOTKEY : '',
  });
  notifyResident('JAVIS inbox captured', 'Clipboard text was saved to Inbox.', { type: 'inbox', id: item.id, source });
  updateMenuBarMenu();
  return item;
}

function registerGlobalHotkeys() {
  if (TOGGLE_HOTKEY && !toggleHotkeyRegistered) try {
    toggleHotkeyRegistered = globalShortcut.register(TOGGLE_HOTKEY, () => {
      toggleWindowMode('hotkey');
    });
    appendAudit('hotkey.register', { hotkey: TOGGLE_HOTKEY, registered: toggleHotkeyRegistered });
  } catch (error) {
    toggleHotkeyRegistered = false;
    appendAudit('hotkey.register_failed', {
      hotkey: TOGGLE_HOTKEY,
      error: error instanceof Error ? error.message : String(error),
    });
  }

  if (SUMMON_HOTKEY && !summonHotkeyRegistered) try {
    summonHotkeyRegistered = globalShortcut.register(SUMMON_HOTKEY, () => {
      summonJavis('hotkey');
    });
    appendAudit('hotkey.register', { hotkey: SUMMON_HOTKEY, purpose: 'summon', registered: summonHotkeyRegistered });
  } catch (error) {
    summonHotkeyRegistered = false;
    appendAudit('hotkey.register_failed', {
      hotkey: SUMMON_HOTKEY,
      purpose: 'summon',
      error: error instanceof Error ? error.message : String(error),
    });
  }

  if (CAPTURE_HOTKEY && !captureHotkeyRegistered) try {
    captureHotkeyRegistered = globalShortcut.register(CAPTURE_HOTKEY, () => {
      try {
        captureClipboardToInbox('hotkey');
      } catch (error) {
        appendAudit('hotkey.capture_failed', {
          hotkey: CAPTURE_HOTKEY,
          error: error instanceof Error ? error.message : String(error),
        });
        notifyResident('JAVIS inbox capture failed', error instanceof Error ? error.message : String(error), { type: 'inbox', source: 'hotkey' });
      }
    });
    appendAudit('hotkey.register', { hotkey: CAPTURE_HOTKEY, purpose: 'capture_inbox', registered: captureHotkeyRegistered });
  } catch (error) {
    captureHotkeyRegistered = false;
    appendAudit('hotkey.register_failed', {
      hotkey: CAPTURE_HOTKEY,
      purpose: 'capture_inbox',
      error: error instanceof Error ? error.message : String(error),
    });
  }

  return toggleHotkeyRegistered || summonHotkeyRegistered || captureHotkeyRegistered;
}

function createMenuBarImage() {
  const svg = [
    '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 18 18">',
    '<path fill="black" d="M9 1.4c4.2 0 7.6 3.4 7.6 7.6s-3.4 7.6-7.6 7.6S1.4 13.2 1.4 9 4.8 1.4 9 1.4Z"/>',
    '<path fill="white" d="M5.3 8.2h1.4v2c0 1 .5 1.5 1.4 1.5.9 0 1.4-.5 1.4-1.5V5.4h1.6v4.8c0 1.9-1.1 3-3 3s-2.8-1-2.8-3V8.2Z"/>',
    '<path fill="white" d="M11.9 5.4h1.6v7.5h-1.6z"/>',
    '</svg>',
  ].join('');
  const image = nativeImage.createFromDataURL(`data:image/svg+xml;base64,${Buffer.from(svg).toString('base64')}`);
  image.setTemplateImage(true);
  return image;
}

function runMenuBarSetupAction(action) {
  runSetupAction(action)
    .then((result) => {
      appendAudit('menubar.setup_action.completed', { action, ok: result.ok, output: result.output });
      updateMenuBarMenu();
    })
    .catch((error) => {
      appendAudit('menubar.setup_action.failed', {
        action,
        error: error instanceof Error ? error.message : String(error),
      });
      updateMenuBarMenu();
    });
}

function isLocalVoiceTerminalLoopCommand(command) {
  const text = String(command || '');
  return /\bnpm\s+run\s+voice:chat\b/.test(text)
    || /local-voice-command-dogfood\.mjs\b[\s\S]*\s--chat\b/.test(text);
}

function openTerminalCommand(command, options = {}) {
  if (isLocalVoiceTerminalLoopCommand(command)) {
    const sourceText = String(options.source || 'api').slice(0, 80);
    const action = openLocalVoiceInput(sourceText, { execute: true });
    appendAudit('terminal.voice_loop_blocked', {
      source: sourceText,
      reason: 'voice_terminal_loop_disabled_product_default',
      command: compactRecordText(options.auditCommand || command, 180),
    });
    return {
      ok: action.ok !== false,
      executed: Boolean(action.executed),
      redirectedToCompose: true,
      output: 'Blocked Terminal voice loop and opened JAVIS local input inside the desktop pet instead.',
      command: options.displayCommand || 'npm run voice:chat',
      window: action.window || null,
      safety: {
        startsMicrophone: false,
        usesRealtime: false,
        storesRawAudio: false,
        opensTerminal: false,
      },
    };
  }
  const escapedCommand = command.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
  const child = spawn('osascript', [
    '-e',
    `tell application "Terminal" to do script "${escapedCommand}"`,
    '-e',
    'tell application "Terminal" to activate',
  ], {
    detached: true,
    stdio: 'ignore',
    env: guardedChildProcessEnv({ source: options.source || 'terminal_open' }),
  });
  child.unref();
  appendAudit(options.auditType || 'terminal.opened', {
    source: String(options.source || 'api').slice(0, 80),
    command: compactRecordText(options.auditCommand || command, 180),
  });
  return {
    ok: true,
    output: options.output || 'Opened JAVIS terminal.',
    command: options.displayCommand || command,
  };
}

function openLocalVoiceInput(source = 'api', options = {}) {
  const sourceText = String(source || 'api').slice(0, 80);
  if (options.execute === false) {
    appendAudit('local_voice_input.previewed', { source: sourceText });
    return {
      ok: true,
      executed: false,
      output: 'Prepared JAVIS local input inside the desktop pet.',
      command: '',
      safety: {
        startsMicrophone: false,
        usesRealtime: false,
        storesRawAudio: false,
        opensTerminal: false,
      },
    };
  }
  const window = applyWindowMode('compose', { source: sourceText, focus: true });
  appendAudit('local_voice_input.opened', { source: sourceText, mode: window?.mode || 'compose' });
  return {
    ok: true,
    executed: true,
    output: 'Opened JAVIS local input inside the desktop pet.',
    command: '',
    window,
    safety: {
      startsMicrophone: false,
      usesRealtime: false,
      storesRawAudio: false,
      opensTerminal: false,
    },
  };
}

function openConfigCui(source = 'api') {
  return openTerminalCommand(`cd ${shQuote(process.cwd())} && npm run config:cui`, {
    source,
    auditType: 'config_cui.opened',
    auditCommand: 'npm run config:cui',
    output: 'Opened JAVIS terminal config.',
    displayCommand: 'npm run config:cui',
  });
}

function openLocalVoiceLoop(source = 'api', options = {}) {
  const sourceText = String(source || 'api').slice(0, 80);
  if (options.execute === false) {
    appendAudit('local_voice_loop.previewed', {
      source: sourceText,
      command: 'npm run voice:chat',
    });
    return {
      ok: true,
      executed: false,
      output: 'Prepared JAVIS local voice/text loop command.',
      command: 'npm run voice:chat',
      safety: {
        startsMicrophone: false,
        usesRealtime: false,
        storesRawAudio: false,
        opensTerminal: false,
      },
      terminalLoop: {
        available: true,
        command: 'npm run voice:chat',
        disabledByResident: true,
        manualOnly: true,
        opensTerminal: false,
        requiresExplicitConfirmation: true,
      },
    };
  }
  const requestedTerminal = options.allowTerminal === true || options.confirmTerminal === true;
  const action = openLocalVoiceInput(sourceText, { execute: true });
  appendAudit('local_voice_loop.redirected_to_compose', {
    source: sourceText,
    reason: 'terminal_loop_disabled_product_default',
    requestedTerminal,
    terminalLoopManualOnly: true,
  });
  return {
    ok: action.ok !== false,
    executed: Boolean(action.executed),
    redirectedToCompose: true,
    output: 'Opened JAVIS local input inside the desktop pet instead of launching a Terminal loop.',
    command: 'npm run voice:chat',
    window: action.window || null,
    safety: {
      startsMicrophone: false,
      usesRealtime: false,
      storesRawAudio: false,
      opensTerminal: false,
    },
    terminalLoop: {
      available: true,
      command: 'npm run voice:chat',
      disabledByResident: true,
      manualOnly: true,
      opensTerminal: false,
      requestedTerminal,
      requiresExplicitConfirmation: true,
    },
  };
}

function menuBarStatusLabel(readiness) {
  if (readiness.overall === 'ready') return 'Ready';
  if (readiness.overall === 'blocked') return `Blocked: ${readiness.primaryIssue?.label || 'Setup'}`;
  return `Needs attention: ${readiness.primaryIssue?.label || 'Setup'}`;
}

function updateMenuBarMenu() {
  if (!menuBarAvailable()) return;
  const readiness = readinessSnapshot({ includeRecentAudit: true });
  const briefing = workflowBriefing({ workflowLimit: 3, jobLimit: 3 });
  const firstAction = briefing.nextActions?.[0] || null;
  const inbox = inboxCounts();
  const nextInbox = inboxSnapshot(1, 'open')[0] || null;
  const activeSession = activeSessionSnapshot();
  const nextSummary = compactRecordText(firstAction?.summary || briefing.summary, 92);
  const menu = Menu.buildFromTemplate([
    { label: 'JAVIS', enabled: false },
    { label: menuBarStatusLabel(readiness), enabled: false },
    { label: activeSession ? `Session: ${compactRecordText(activeSession.title, 42)}` : 'Session: idle', enabled: false },
    { label: `${inbox.open} open inbox item(s)`, enabled: false },
    { type: 'separator' },
    {
      label: 'Park Pet',
      accelerator: TOGGLE_HOTKEY,
      click: () => applyWindowMode('pet', { source: 'menubar', focus: false }),
    },
    {
      label: `Park to ${WINDOW_PARK_CORNER === 'notch' ? 'Mac notch' : WINDOW_PARK_CORNER}`,
      click: () => parkWindow('menubar'),
    },
    {
      label: 'Open Config Terminal',
      click: () => openConfigCui('menubar'),
    },
    {
      label: 'Refresh Status',
      click: () => updateMenuBarMenu(),
    },
    {
      label: latestScreen ? 'Refresh Screen Frame' : 'Capture Screen Frame',
      click: () => {
        captureResidentScreen({ source: 'menubar' })
          .then((screenFrame) => {
            notifyResident('JAVIS screen captured', `${screenFrame.width}x${screenFrame.height} ${screenFrame.privacy?.label || screenFrame.privacy?.mode || 'screen'} frame ready.`, {
              type: 'screen',
              source: 'menubar',
            });
            updateMenuBarMenu();
          })
          .catch((error) => {
            notifyResident('JAVIS screen capture failed', error instanceof Error ? error.message : String(error), {
              type: 'screen',
              source: 'menubar',
            });
          });
      },
    },
    { type: 'separator' },
    { label: firstAction ? `Next: ${firstAction.label}` : 'Next: Ready', enabled: false },
    { label: nextSummary, enabled: false },
    nextInbox ? { label: `Inbox: ${compactRecordText(nextInbox.title, 56)}`, enabled: false } : { label: 'Inbox: empty', enabled: false },
    activeSession
      ? {
          label: 'End Current Session',
          click: () => {
            try {
              endWorkSession(activeSession.id, { source: 'menubar' });
            } catch (error) {
              notifyResident('JAVIS session end failed', error instanceof Error ? error.message : String(error), { type: 'session', source: 'menubar' });
            }
          },
        }
      : { label: 'End Current Session', enabled: false },
    { type: 'separator' },
    {
      label: 'Capture Clipboard to Inbox',
      accelerator: CAPTURE_HOTKEY || undefined,
      click: () => {
        try {
          captureClipboardToInbox('menubar');
        } catch (error) {
          notifyResident('JAVIS inbox capture failed', error instanceof Error ? error.message : String(error), { type: 'inbox', source: 'menubar' });
        }
      },
    },
    {
      label: 'Open .env',
      click: () => runMenuBarSetupAction('prepare_env_file'),
    },
    {
      label: 'Open Microphone Settings',
      click: () => runMenuBarSetupAction('open_microphone_settings'),
    },
    {
      label: 'Open Screen Recording Settings',
      click: () => runMenuBarSetupAction('open_screen_settings'),
    },
    {
      label: 'Open Accessibility Settings',
      click: () => runMenuBarSetupAction('open_accessibility_settings'),
    },
    {
      label: 'Open Runtime Folder',
      click: () => runMenuBarSetupAction('open_runtime_dir'),
    },
    {
      label: 'Send Test Notification',
      click: () => notifyResident('JAVIS test notification', 'Resident notifications are working.', { type: 'test', source: 'menubar' }),
    },
    { type: 'separator' },
    {
      label: 'Quit JAVIS',
      click: () => app.quit(),
    },
  ]);
  menuBarTray.setToolTip(`JAVIS - ${readiness.label}: ${compactRecordText(readiness.summary, 120)}`);
  menuBarTray.setContextMenu(menu);
  menuBarUpdatedAt = Date.now();
}

function createMenuBarTray() {
  if (menuBarAvailable()) return true;
  try {
    menuBarTray = new Tray(createMenuBarImage());
    menuBarTray.setTitle('');
    menuBarTray.on('click', () => {
      updateMenuBarMenu();
      menuBarTray.popUpContextMenu();
    });
    menuBarTray.on('right-click', () => updateMenuBarMenu());
    updateMenuBarMenu();
    appendAudit('menubar.ready', { available: true });
    return true;
  } catch (error) {
    menuBarTray = null;
    appendAudit('menubar.failed', { error: error instanceof Error ? error.message : String(error) });
    return false;
  }
}

function ensureRuntimeStorage() {
  fs.mkdirSync(DATA_DIR, { recursive: true });
  fs.mkdirSync(REALTIME_DOGFOOD_ARCHIVES_DIR, { recursive: true });
  const legacyJobsFile = path.join(APP_SUPPORT_DIR, 'jobs.json');
  const legacyAuditFile = path.join(APP_SUPPORT_DIR, 'audit.jsonl');
  if (!process.env.JAVIS_DATA_DIR && fs.existsSync(legacyJobsFile) && !fs.existsSync(JOBS_FILE)) {
    fs.copyFileSync(legacyJobsFile, JOBS_FILE);
  }
  if (!process.env.JAVIS_DATA_DIR && fs.existsSync(legacyAuditFile) && !fs.existsSync(AUDIT_FILE)) {
    fs.copyFileSync(legacyAuditFile, AUDIT_FILE);
  }
}

function loadOrCreateApiToken() {
  const envToken = String(process.env.JAVIS_API_TOKEN || '').trim();
  if (envToken) return envToken;
  try {
    if (fs.existsSync(API_TOKEN_FILE)) {
      const token = fs.readFileSync(API_TOKEN_FILE, 'utf8').trim();
      if (token.length >= 32) {
        try {
          fs.chmodSync(API_TOKEN_FILE, 0o600);
        } catch {}
        return token;
      }
    }
  } catch {}

  const token = crypto.randomBytes(32).toString('base64url');
  fs.writeFileSync(API_TOKEN_FILE, `${token}\n`, { encoding: 'utf8', mode: 0o600 });
  try {
    fs.chmodSync(API_TOKEN_FILE, 0o600);
  } catch {}
  return token;
}

function apiTokenMatches(value) {
  if (!API_AUTH_ENABLED) return true;
  const candidate = String(value || '').trim();
  if (!candidate || !apiToken) return false;
  const expected = Buffer.from(apiToken);
  const actual = Buffer.from(candidate);
  if (expected.length !== actual.length) return false;
  return crypto.timingSafeEqual(expected, actual);
}

function requestApiToken(req) {
  const explicit = req.get('x-javis-token') || req.get('x-javis-api-token');
  if (explicit) return explicit;
  const authorization = String(req.get('authorization') || '').trim();
  const match = authorization.match(/^Bearer\s+(.+)$/i);
  return match ? match[1] : '';
}

function trustedApiOrigins() {
  const origins = new Set([
    'null',
    'file://',
    'http://127.0.0.1:5173',
    'http://localhost:5173',
  ]);
  const rendererUrl = String(process.env.JAVIS_RENDERER_URL || '').trim();
  if (rendererUrl) {
    try {
      origins.add(new URL(rendererUrl).origin);
    } catch {}
  }
  return origins;
}

function isTrustedApiOrigin(origin) {
  if (!origin) return true;
  return trustedApiOrigins().has(String(origin));
}

function isPublicApiPath(pathname) {
  return pathname === '/api/health';
}

function apiAuthSnapshot() {
  return {
    enabled: API_AUTH_ENABLED,
    tokenFile: API_TOKEN_FILE,
    header: 'X-JAVIS-Token',
  };
}

function writeJsonAtomic(filePath, value) {
  const tempPath = `${filePath}.${process.pid}.tmp`;
  fs.writeFileSync(tempPath, `${JSON.stringify(value, null, 2)}\n`, 'utf8');
  fs.renameSync(tempPath, filePath);
}

class OpenAiSpendGuardBlocked extends Error {
  constructor(decision) {
    super(decision?.summary || 'OpenAI cloud call blocked by spend guard.');
    this.name = 'OpenAiSpendGuardBlocked';
    this.decision = decision;
  }
}

function normalizeOpenAiCloudMode(value) {
  const text = String(value || '').trim().toLowerCase();
  if (['off', 'disabled', 'none', '0', 'false'].includes(text)) return 'off';
  if (['auto', 'autopilot', 'unattended', 'background'].includes(text)) return 'auto';
  return 'manual';
}

function openAiSpendDayKey(time = Date.now()) {
  const date = new Date(time);
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function normalizeOpenAiSpendState(raw = {}) {
  const day = openAiSpendDayKey();
  const stateDay = raw.day === day ? raw.day : day;
  const reset = raw.day !== day;
  const counts = reset ? {} : (raw.counts || {});
  return {
    version: 1,
    day: stateDay,
    counts: {
      total: Math.max(0, Number(counts.total || 0)),
      manual: Math.max(0, Number(counts.manual || 0)),
      unattended: Math.max(0, Number(counts.unattended || 0)),
      blocked: Math.max(0, Number(counts.blocked || 0)),
    },
    events: reset ? [] : (Array.isArray(raw.events) ? raw.events.slice(-80) : []),
    updatedAt: Number(raw.updatedAt || 0),
  };
}

function readOpenAiSpendState() {
  try {
    if (!fs.existsSync(OPENAI_SPEND_GUARD_FILE)) return normalizeOpenAiSpendState();
    return normalizeOpenAiSpendState(JSON.parse(fs.readFileSync(OPENAI_SPEND_GUARD_FILE, 'utf8')));
  } catch {
    return normalizeOpenAiSpendState();
  }
}

function persistOpenAiSpendState(state) {
  try {
    fs.mkdirSync(path.dirname(OPENAI_SPEND_GUARD_FILE), { recursive: true });
    writeJsonAtomic(OPENAI_SPEND_GUARD_FILE, normalizeOpenAiSpendState(state));
  } catch (error) {
    appendAudit('openai.spend_guard_persist_failed', {
      error: error instanceof Error ? error.message : String(error),
    });
  }
}

function isManualOpenAiSource(source = '', options = {}) {
  if (options.userInitiated === true || options.confirmCloud === true) return true;
  const text = String(source || '').toLowerCase();
  if (/^(manual|user|cui|cui_cli|local_command|voice|api_voice|renderer_dogfood|dogfood_cli)\b/.test(text)) return true;
  if (options.kind === 'realtime_session' && text === 'renderer') return true;
  return false;
}

function openAiSpendGuardSnapshot() {
  const state = readOpenAiSpendState();
  return {
    version: 1,
    mode: OPENAI_CLOUD_MODE,
    hardSpendLock: OPENAI_HARD_SPEND_LOCK,
    egressGuardEnabled: OPENAI_EGRESS_GUARD_ENABLED,
    egressGuardMode: OPENAI_EGRESS_GUARD_ENABLED ? 'scoped_allow_only' : 'off',
    file: OPENAI_SPEND_GUARD_FILE,
    dailyRequestLimit: OPENAI_DAILY_REQUEST_LIMIT,
    unattendedDailyRequestLimit: OPENAI_UNATTENDED_DAILY_REQUEST_LIMIT,
    allowAutopilotCloud: OPENAI_ALLOW_AUTOPILOT,
    allowRendererStartupProbe: OPENAI_ALLOW_RENDERER_STARTUP_PROBE,
    requireSpendConfirmationPhrase: OPENAI_REQUIRE_SPEND_CONFIRMATION_PHRASE,
    spendConfirmationPhrase: OPENAI_REQUIRE_SPEND_CONFIRMATION_PHRASE ? 'configured' : 'not_required',
    requireSpendLease: OPENAI_REQUIRE_SPEND_LEASE,
    spendLeaseTtlMs: OPENAI_SPEND_LEASE_TTL_MS,
    spendLease: openAiSpendLeaseStateSnapshot(),
    runtimeKeyIsolation: openAiRuntimeKeyIsolationSnapshot(),
    childEnvGuard: openAiChildEnvGuardSnapshot(),
    autopilotRequiresExplicitEnv: true,
    autopilotEnabled: AUTOPILOT_ENABLED,
    day: state.day,
    counts: state.counts,
    remaining: {
      total: Math.max(0, OPENAI_DAILY_REQUEST_LIMIT - Number(state.counts.total || 0)),
      unattended: Math.max(0, OPENAI_UNATTENDED_DAILY_REQUEST_LIMIT - Number(state.counts.unattended || 0)),
    },
    recent: state.events.slice(-10).reverse(),
    safety: {
      unattendedCloudDefaultBlocked: OPENAI_UNATTENDED_DAILY_REQUEST_LIMIT === 0 && !OPENAI_ALLOW_AUTOPILOT,
      zeroBudgetDefault: OPENAI_DAILY_REQUEST_LIMIT === 0,
      manualOnlyByDefault: OPENAI_CLOUD_MODE === 'manual',
      hardSpendLockDefault: OPENAI_HARD_SPEND_LOCK,
      confirmationPhraseRequired: OPENAI_REQUIRE_SPEND_CONFIRMATION_PHRASE,
      oneRequestLeaseRequired: OPENAI_REQUIRE_SPEND_LEASE,
      off: OPENAI_CLOUD_MODE === 'off',
      unscopedOpenAiEgressBlocked: OPENAI_EGRESS_GUARD_ENABLED,
      childProcessOpenAiCredentialsBlocked: OPENAI_CHILD_ENV_GUARD_ENABLED,
      runtimeProcessEnvOpenAiCredentialsBlocked: OPENAI_RUNTIME_KEY_ISOLATION,
    },
  };
}

function openAiZeroSpendModeActive() {
  const guard = openAiSpendGuardSnapshot();
  return Boolean(
    guard.hardSpendLock ||
    guard.mode === 'off' ||
    guard.dailyRequestLimit <= 0 ||
    guard.remaining?.total <= 0 ||
    guard.safety?.zeroBudgetDefault ||
    guard.safety?.off
  );
}

function openAiSpendForensicsSnapshot(options = {}) {
  const guard = options.guard || openAiSpendGuardSnapshot();
  const egress = options.egress || openAiEgressGuardSnapshot();
  const events = Array.isArray(guard.recent) ? guard.recent : [];
  const allowed = events.filter((event) => event.allowed === true);
  const blocked = events.filter((event) => event.allowed !== true);
  const countBy = (items, key) => {
    const counts = new Map();
    for (const item of items) {
      const value = compactRecordText(item?.[key] || 'unknown', 100) || 'unknown';
      counts.set(value, (counts.get(value) || 0) + 1);
    }
    return Array.from(counts.entries())
      .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
      .slice(0, 8)
      .map(([value, count]) => ({ value, count }));
  };
  const latestAllowed = allowed[0] || null;
  const latestBlocked = blocked[0] || null;
  const zeroLocked = Boolean(
    guard.hardSpendLock === true &&
      guard.mode === 'off' &&
      Number(guard.dailyRequestLimit || 0) === 0 &&
      Number(guard.unattendedDailyRequestLimit || 0) === 0 &&
      guard.allowAutopilotCloud === false &&
      guard.allowRendererStartupProbe === false &&
      guard.requireSpendLease === true &&
      guard.egressGuardEnabled === true &&
      egress.safety?.blocksUnscopedOpenAiFetch === true
  );
  const localAllowedCount = Number(guard.counts?.total || 0);
  const localUnattendedAllowedCount = Number(guard.counts?.unattended || 0);
  const status = localAllowedCount > 0
    ? 'local_allowed_spend_recorded'
    : zeroLocked
      ? 'zero_spend_locked'
      : 'spend_guard_needs_review';
  const likelyBillableFromJavis = localAllowedCount > 0;
  const summary = likelyBillableFromJavis
    ? `JAVIS has ${localAllowedCount} local allowed OpenAI request record(s) today; inspect latest allowed event before leaving it unattended.`
    : zeroLocked
      ? 'JAVIS has no local allowed OpenAI spend records today; recent OpenAI events were blocked locally before confirmed spend.'
      : 'JAVIS has no local allowed OpenAI spend records today, but the guard is not fully zero-locked; review before unattended use.';
  return {
    version: 1,
    generatedAt: new Date().toISOString(),
    day: guard.day || openAiSpendDayKey(),
    status,
    summary,
    likelyBillableFromJavis,
    zeroLocked,
    counts: {
      allowed: localAllowedCount,
      manualAllowed: Number(guard.counts?.manual || 0),
      unattendedAllowed: localUnattendedAllowedCount,
      blocked: Number(guard.counts?.blocked || 0),
      recentAllowed: allowed.length,
      recentBlocked: blocked.length,
    },
    latestAllowed: latestAllowed
      ? {
          at: latestAllowed.at || '',
          kind: compactRecordText(latestAllowed.kind || '', 80),
          source: compactRecordText(latestAllowed.source || '', 80),
          model: compactRecordText(latestAllowed.model || '', 120),
          manual: Boolean(latestAllowed.manual),
          leaseId: compactRecordText(latestAllowed.leaseId || '', 120),
        }
      : null,
    latestBlocked: latestBlocked
      ? {
          at: latestBlocked.at || '',
          kind: compactRecordText(latestBlocked.kind || '', 80),
          source: compactRecordText(latestBlocked.source || '', 80),
          reasons: Array.isArray(latestBlocked.reasons)
            ? latestBlocked.reasons.map((reason) => compactRecordText(reason, 120)).filter(Boolean).slice(0, 8)
            : [],
        }
      : null,
    blockedBySource: countBy(blocked, 'source'),
    blockedByKind: countBy(blocked, 'kind'),
    allowedBySource: countBy(allowed, 'source'),
    allowedByKind: countBy(allowed, 'kind'),
    recommendations: [
      zeroLocked ? '' : 'Run npm run openai:lockdown before unattended use.',
      localAllowedCount > 0 ? 'Inspect the latest allowed event and OpenAI dashboard usage for billing reconciliation.' : '',
      localUnattendedAllowedCount > 0 ? 'Disable autopilot cloud and set JAVIS_OPENAI_UNATTENDED_DAILY_REQUEST_LIMIT=0 before leaving JAVIS running.' : '',
      !egress.safety?.blocksUnscopedOpenAiFetch ? 'Enable JAVIS_OPENAI_EGRESS_GUARD=true so direct OpenAI egress is scoped through the spend guard.' : '',
    ].filter(Boolean),
    safety: {
      readOnly: true,
      localGuardStateOnly: true,
      callsOpenAI: false,
      createsSpendLease: false,
      startsMicrophone: false,
      usesRealtime: false,
      startsWorkers: false,
      readsUserFiles: false,
      opensTerminal: false,
    },
  };
}

function openAiSpendAuditEventRelevant(event = {}) {
  const type = String(event.type || '');
  const data = event.data || {};
  const source = String(data.source || '');
  const kind = String(data.kind || '');
  return type.startsWith('openai.') ||
    type.includes('spend_guard') ||
    source.toLowerCase().includes('openai') ||
    kind.toLowerCase().includes('openai') ||
    kind.toLowerCase().includes('realtime') ||
    type === 'realtime.provider_probe.completed' ||
    type === 'realtime.provider_probe.failed' ||
    type === 'realtime.renderer_control_event';
}

function compactOpenAiSpendAuditEvent(event = {}) {
  const data = event.data || {};
  const timestampMs = auditEventTimestampMs(event);
  const reasons = Array.isArray(data.reasons)
    ? data.reasons.map((reason) => compactRecordText(reason, 120)).filter(Boolean).slice(0, 8)
    : [];
  const allowed = data.allowed === true ? true : data.allowed === false ? false : null;
  const source = compactRecordText(data.source || data.requestSource || data.auditSource || '', 100);
  const kind = compactRecordText(data.kind || data.type || '', 100);
  const detail = [
    allowed === true ? 'allowed' : allowed === false ? 'blocked' : '',
    kind ? `kind=${kind}` : '',
    source ? `source=${source}` : '',
    data.status ? `status=${compactRecordText(data.status, 80)}` : '',
    reasons.length ? `reasons=${reasons.slice(0, 3).join(',')}` : '',
  ].filter(Boolean).join(' · ');
  return {
    type: compactRecordText(event.type || 'unknown', 120),
    ts: event.ts || data.at || '',
    ageMs: timestampMs ? Math.max(0, Date.now() - timestampMs) : null,
    allowed,
    kind,
    source,
    reasons,
    summary: compactRecordText(detail || JSON.stringify(data || {}), 260),
  };
}

function openAiSpendIncidentConclusion(forensics = {}) {
  if (forensics.likelyBillableFromJavis) {
    return {
      id: 'local_javis_allowed_spend_recorded',
      severity: 'review',
      label: 'JAVIS has a local allowed OpenAI record',
      summary: `JAVIS recorded ${forensics.counts?.allowed || 0} allowed OpenAI request(s) today. Reconcile the latest allowed event with the OpenAI dashboard before leaving it unattended.`,
    };
  }
  if (forensics.zeroLocked) {
    return {
      id: 'no_local_javis_allowed_spend',
      severity: 'safe',
      label: 'No local JAVIS allowed spend today',
      summary: 'This running JAVIS instance has no local allowed OpenAI request records today; recent OpenAI-related events were blocked locally before a request could leave JAVIS.',
    };
  }
  return {
    id: 'local_guard_not_fully_locked',
    severity: 'attention',
    label: 'Spend guard needs review',
    summary: 'JAVIS has no local allowed spend record today, but the zero-spend guard is not fully locked; run openai:lockdown before unattended use.',
  };
}

function openAiSpendIncidentReportSnapshot(options = {}) {
  const guard = openAiSpendGuardSnapshot();
  const egress = openAiEgressGuardSnapshot();
  const forensics = openAiSpendForensicsSnapshot({ guard, egress });
  const childEnv = openAiChildEnvGuardSnapshot();
  const auditLimit = Math.max(20, Math.min(300, Number(options.auditLimit || 160)));
  const eventLimit = Math.max(1, Math.min(20, Number(options.limit || 8)));
  const audit = readRecentAudit(auditLimit);
  const auditEvents = audit
    .filter(openAiSpendAuditEventRelevant)
    .map(compactOpenAiSpendAuditEvent)
    .sort((a, b) => (b.ts || '').localeCompare(a.ts || ''))
    .slice(0, eventLimit);
  const conclusion = openAiSpendIncidentConclusion(forensics);
  const hypotheses = forensics.likelyBillableFromJavis
    ? [
        'A JAVIS cloud request was locally allowed; inspect latestAllowed and the matching OpenAI dashboard usage window.',
      ]
    : [
        'If the OpenAI dashboard still moved, the usage is likely from another app, CLI, browser test page, old process, or another machine using the same API key.',
        'OpenAI dashboard usage can also lag or aggregate requests from before the current local guard day.',
        'Blocked events in this report are local guard stops; they are not confirmed billable JAVIS requests.',
      ];
  const recommendations = [
    forensics.zeroLocked ? 'Keep zero-spend lockdown on for unattended work.' : 'Run npm run openai:lockdown before unattended work.',
    !forensics.likelyBillableFromJavis ? 'If external usage continues, rotate the OpenAI key or move JAVIS to a dedicated project-scoped key.' : '',
    'Compare OpenAI dashboard usage by project/key/time with this report; this endpoint only proves local JAVIS guard state.',
    childEnv.safety?.mcpConfiguredEnvCredentialsBlocked ? '' : 'Enable child env guard so MCP/worker child processes do not inherit OpenAI credentials.',
  ].filter(Boolean);
  return {
    ok: true,
    version: 1,
    generatedAt: new Date().toISOString(),
    query: compactRecordText(options.query || options.q || '', 240),
    conclusion,
    summary: conclusion.summary,
    spendGuard: guard,
    egressGuard: egress,
    forensics,
    childEnvGuard: childEnv,
    hypotheses,
    recommendations,
    audit: {
      file: AUDIT_FILE,
      scanned: audit.length,
      returned: auditEvents.length,
      events: auditEvents,
    },
    externalBoundary: {
      dashboardRequiredForBillingTruth: true,
      localRecordsOnly: true,
      canProveJavisAllowedSpend: forensics.likelyBillableFromJavis,
      cannotProveOtherAppsOrKeys: true,
    },
    safety: {
      readOnly: true,
      localGuardStateOnly: true,
      usesLocalAuditOnly: true,
      callsOpenAI: false,
      createsSpendLease: false,
      startsMicrophone: false,
      usesRealtime: false,
      startsWorkers: false,
      capturesScreen: false,
      readsClipboardText: false,
      opensTerminal: false,
      executesActions: false,
    },
  };
}

function evaluateOpenAiSpendGuard(options = {}) {
  const kind = compactRecordText(options.kind || 'openai', 80);
  const source = compactRecordText(options.source || 'unspecified', 80);
  const model = compactRecordText(options.model || '', 120);
  const manual = isManualOpenAiSource(source, { ...options, kind });
  const confirmed = openAiSpendConfirmationIsValid(options);
  const state = readOpenAiSpendState();
  const reasons = [];

  if (OPENAI_HARD_SPEND_LOCK) reasons.push('hard_spend_lock_enabled');
  if (OPENAI_CLOUD_MODE === 'off') reasons.push('cloud_mode_off');
  if (OPENAI_REQUIRE_SPEND_CONFIRMATION_PHRASE && !confirmed) reasons.push('explicit_spend_confirmation_required');
  if (!manual && OPENAI_CLOUD_MODE !== 'auto') reasons.push('manual_mode_blocks_unattended');
  if (!manual && !OPENAI_ALLOW_AUTOPILOT) reasons.push('autopilot_cloud_disabled');
  if (kind === 'realtime_provider_probe' && /^renderer(_|$)|renderer_startup/.test(source.toLowerCase()) && !OPENAI_ALLOW_RENDERER_STARTUP_PROBE) {
    reasons.push('renderer_startup_probe_disabled');
  }
  if (OPENAI_DAILY_REQUEST_LIMIT <= 0 || Number(state.counts.total || 0) >= OPENAI_DAILY_REQUEST_LIMIT) {
    reasons.push('daily_request_limit_reached');
  }
  if (!manual && (OPENAI_UNATTENDED_DAILY_REQUEST_LIMIT <= 0 || Number(state.counts.unattended || 0) >= OPENAI_UNATTENDED_DAILY_REQUEST_LIMIT)) {
    reasons.push('unattended_request_limit_reached');
  }
  const leaseDecision = options.reserve === true || options.requireSpendLease === true
    ? evaluateOpenAiSpendLease({ ...options, kind, source, model })
    : { ok: true, required: OPENAI_REQUIRE_SPEND_LEASE, reason: '', lease: null };
  if (!leaseDecision.ok && leaseDecision.reason) reasons.push(leaseDecision.reason);
  for (const reason of Array.isArray(options.forceBlockedReasons) ? options.forceBlockedReasons : []) {
    const text = compactRecordText(reason, 120);
    if (text && !reasons.includes(text)) reasons.push(text);
  }

  const allowed = reasons.length === 0;
  const now = Date.now();
  const event = {
    id: crypto.randomUUID(),
    at: new Date(now).toISOString(),
    allowed,
    kind,
    source,
    model,
    manual,
    confirmed,
    hardSpendLock: OPENAI_HARD_SPEND_LOCK,
    confirmationPhraseRequired: OPENAI_REQUIRE_SPEND_CONFIRMATION_PHRASE,
    leaseRequired: OPENAI_REQUIRE_SPEND_LEASE,
    leaseId: leaseDecision.lease?.id || openAiSpendLeaseIdFromOptions(options) || '',
    leaseStatus: leaseDecision.ok ? (leaseDecision.required ? 'valid' : 'not_required') : leaseDecision.reason,
    mode: OPENAI_CLOUD_MODE,
    reasons,
  };

  if (options.reserve === true || (!allowed && options.recordBlocked !== false)) {
    const next = normalizeOpenAiSpendState(state);
    if (allowed) {
      next.counts.total += 1;
      if (manual) next.counts.manual += 1;
      else next.counts.unattended += 1;
      consumeOpenAiSpendLease(leaseDecision.lease, event.id);
    } else {
      next.counts.blocked += 1;
    }
    next.events = [...next.events, event].slice(-80);
    next.updatedAt = now;
    persistOpenAiSpendState(next);
    appendAudit(allowed ? 'openai.spend_guard_allowed' : 'openai.spend_guard_blocked', event);
  }

  return {
    ...event,
    summary: allowed
      ? `OpenAI cloud call allowed (${manual ? 'manual' : 'unattended'}): ${kind}.`
      : `OpenAI cloud call blocked: ${reasons.join(', ') || 'spend_guard'}.`,
    state: openAiSpendGuardSnapshot(),
  };
}

function truthyRequestValue(value) {
  return value === true || ['true', '1', 'yes', 'y', 'confirm', 'confirmed'].includes(String(value || '').trim().toLowerCase());
}

function openAiSpendConfirmationPhraseFromOptions(options = {}) {
  return String(
    options.confirmOpenAiSpendPhrase ||
      options.openAiSpendPhrase ||
      options.spendConfirmationPhrase ||
      options.confirmationPhrase ||
      '',
  ).trim();
}

function openAiSpendConfirmationPhraseMatches(options = {}) {
  if (!OPENAI_REQUIRE_SPEND_CONFIRMATION_PHRASE) return true;
  const expected = OPENAI_SPEND_CONFIRMATION_PHRASE;
  if (!expected) return false;
  return openAiSpendConfirmationPhraseFromOptions(options) === expected;
}

function openAiSpendConfirmationIsValid(options = {}) {
  const requested = truthyRequestValue(options.confirmOpenAiSpend || options.confirmCloud);
  if (!requested) return false;
  return openAiSpendConfirmationPhraseMatches(options);
}

function openAiSpendConfirmationSnapshot(options = {}) {
  const kind = compactRecordText(options.kind || 'openai', 80);
  const source = compactRecordText(options.source || 'unspecified', 80);
  const manual = isManualOpenAiSource(source, { ...options, kind });
  const requested = truthyRequestValue(options.confirmOpenAiSpend || options.confirmCloud);
  const phraseMatched = openAiSpendConfirmationPhraseMatches(options);
  const confirmed = requested && phraseMatched;
  return {
    version: 1,
    required: Boolean(options.required ?? kind === 'realtime_provider_probe'),
    requested,
    confirmed,
    hardSpendLock: OPENAI_HARD_SPEND_LOCK,
    phraseRequired: OPENAI_REQUIRE_SPEND_CONFIRMATION_PHRASE,
    phraseMatched,
    leaseRequired: OPENAI_REQUIRE_SPEND_LEASE,
    leaseTtlMs: OPENAI_SPEND_LEASE_TTL_MS,
    lease: evaluateOpenAiSpendLease({ ...options, kind, source }),
    manual,
    kind,
    source,
    prompt: OPENAI_HARD_SPEND_LOCK
      ? 'OpenAI spending is hard-locked. To spend, set JAVIS_OPENAI_HARD_SPEND_LOCK=false, set a positive daily limit, restart JAVIS, then confirm the one request with the configured spend phrase.'
      : 'This OpenAI call can consume API quota. Create a one-request spend lease with the exact phrase, then execute before the lease expires.',
  };
}

function assertOpenAiSpendAllowed(options = {}) {
  const decision = evaluateOpenAiSpendGuard({ ...options, reserve: true });
  if (!decision.allowed) throw new OpenAiSpendGuardBlocked(decision);
  return decision;
}

function openAiCredentialEnvKeys(env = process.env) {
  return OPENAI_CHILD_ENV_CREDENTIAL_KEYS.filter((key) => {
    if (!Object.prototype.hasOwnProperty.call(env, key)) return false;
    return String(env[key] || '').trim() !== '';
  });
}

function openAiRuntimeCredentialEnvKeys(env = process.env) {
  return OPENAI_RUNTIME_ENV_CREDENTIAL_KEYS.filter((key) => {
    if (!Object.prototype.hasOwnProperty.call(env, key)) return false;
    return String(env[key] || '').trim() !== '';
  });
}

function openAiRuntimeKeyIsolationSnapshot() {
  const processEnvOpenAiKeys = openAiRuntimeCredentialEnvKeys(process.env);
  return {
    version: 1,
    enabled: OPENAI_RUNTIME_KEY_ISOLATION,
    protectedKeys: OPENAI_RUNTIME_ENV_CREDENTIAL_KEYS,
    isolatedKeys: OPENAI_RUNTIME_ENV_ISOLATED_KEYS,
    openAiApiKeyInProcessEnv: Object.prototype.hasOwnProperty.call(process.env, 'OPENAI_API_KEY') &&
      String(process.env.OPENAI_API_KEY || '').trim() !== '',
    openAiCredentialKeyCount: processEnvOpenAiKeys.length,
    processEnvOpenAiCredentialKeys: processEnvOpenAiKeys,
    preservedForGuardedCalls: Boolean(OPENAI_API_KEY),
    safety: {
      defaultRuntimeProcessEnvOpenAiCredentialsBlocked: OPENAI_RUNTIME_KEY_ISOLATION,
      childProcessesCannotInheritRuntimeOpenAiCredentials: OPENAI_RUNTIME_KEY_ISOLATION && processEnvOpenAiKeys.length === 0,
      preservesEnvFile: true,
      callsOpenAi: false,
      createsSpendLease: false,
      startsProcess: false,
      exposesSecretValues: false,
    },
  };
}

function openAiCredentialEnvPattern() {
  const escaped = OPENAI_CHILD_ENV_CREDENTIAL_KEYS.map((key) => key.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|');
  return new RegExp(`(?:^|[\\s;&|()])(?:export\\s+)?(?:${escaped})\\s*=`, 'i');
}

function commandContainsOpenAiCredentialEnv(command = '') {
  return openAiCredentialEnvPattern().test(String(command || ''));
}

function openAiChildEnvGuardSnapshot() {
  const presentCredentialKeys = openAiCredentialEnvKeys(process.env);
  const runtimeKeyIsolation = openAiRuntimeKeyIsolationSnapshot();
  return {
    version: 1,
    enabled: OPENAI_CHILD_ENV_GUARD_ENABLED,
    protectedKeys: OPENAI_CHILD_ENV_CREDENTIAL_KEYS,
    presentCredentialKeyCount: presentCredentialKeys.length,
    presentCredentialKeys,
    runtimeKeyIsolation,
    defaultChildReceivesOpenAiCredentials: !OPENAI_CHILD_ENV_GUARD_ENABLED,
    blocksInlineCredentialEnv: OPENAI_CHILD_ENV_GUARD_ENABLED,
    defaultChildProcessEnv: OPENAI_CHILD_ENV_GUARD_ENABLED ? 'openai_credentials_redacted' : 'inherits_parent_env',
    coversKnownChildEntrypoints: [
      'background_jobs',
      'worker_fallbacks',
      'mcp_stdio_servers',
      'wake_engine',
      'browser_control_helpers',
      'mac_setup_helpers',
      'local_speech',
    ],
    bypassEnv: 'JAVIS_OPENAI_CHILD_ENV_GUARD=false',
    safety: {
      stripsOpenAiApiKeyFromWorkers: OPENAI_CHILD_ENV_GUARD_ENABLED,
      blocksInlineOpenAiApiKeyAssignments: OPENAI_CHILD_ENV_GUARD_ENABLED,
      mcpConfiguredEnvCredentialsBlocked: OPENAI_CHILD_ENV_GUARD_ENABLED,
      knownChildEntrypointsUseSanitizedEnv: OPENAI_CHILD_ENV_GUARD_ENABLED,
      runtimeProcessEnvOpenAiCredentialsBlocked: OPENAI_RUNTIME_KEY_ISOLATION && runtimeKeyIsolation.openAiCredentialKeyCount === 0,
      preservesParentEnvFile: true,
      callsOpenAi: false,
      startsProcess: false,
      exposesSecretValues: false,
    },
  };
}

function sanitizeChildProcessEnv(options = {}) {
  const env = { ...process.env };
  const allowOpenAiCredentialEnv = options.allowOpenAiCredentialEnv === true || OPENAI_CHILD_ENV_GUARD_ENABLED === false;
  const redactedKeys = [];
  if (!allowOpenAiCredentialEnv) {
    for (const key of OPENAI_CHILD_ENV_CREDENTIAL_KEYS) {
      if (Object.prototype.hasOwnProperty.call(env, key)) {
        delete env[key];
        redactedKeys.push(key);
      }
    }
  }
  env.JAVIS_OPENAI_CHILD_ENV_GUARD = OPENAI_CHILD_ENV_GUARD_ENABLED ? 'true' : 'false';
  env.JAVIS_OPENAI_CHILD_ENV_REDACTED_KEYS = redactedKeys.join(',');
  return env;
}

function guardedChildProcessEnv(options = {}) {
  return sanitizeChildProcessEnv(options);
}

function guardedChildProcessOptions(options = {}, envOptions = {}) {
  return {
    ...options,
    env: options.env || guardedChildProcessEnv(envOptions),
  };
}

function assertOpenAiChildEnvCommandAllowed(command = '', options = {}) {
  if (!OPENAI_CHILD_ENV_GUARD_ENABLED) return true;
  if (!commandContainsOpenAiCredentialEnv(command)) return true;
  const source = compactRecordText(options.source || 'child_process', 80);
  const commandName = compactRecordText(shellCommandName(command) || options.commandName || '', 80);
  const decision = {
    id: crypto.randomUUID(),
    at: new Date().toISOString(),
    allowed: false,
    kind: 'child_env_guard',
    source,
    commandName,
    reasons: ['inline_openai_credential_env_blocked'],
    summary: 'OpenAI credential environment injection is blocked by JAVIS child env guard.',
  };
  appendAudit('openai.child_env_guard_blocked', {
    ...decision,
    command: redactCommandForLog(command),
  });
  throw new OpenAiSpendGuardBlocked(decision);
}

function openAiChildEnvGuardProbe(options = {}) {
  const command = String(options.command || 'OPENAI_API_KEY=sk-test echo should-block').slice(0, 500);
  let inlineInjectionBlocked = false;
  let inlineInjectionReason = '';
  try {
    assertOpenAiChildEnvCommandAllowed(command, { source: options.source || 'child_env_guard_probe' });
  } catch (error) {
    if (error instanceof OpenAiSpendGuardBlocked) {
      inlineInjectionBlocked = true;
      inlineInjectionReason = error.decision?.reasons?.[0] || 'child_env_guard_blocked';
    } else {
      throw error;
    }
  }
  const sanitized = sanitizeChildProcessEnv({ source: options.source || 'child_env_guard_probe' });
  const sanitizedCredentialKeys = openAiCredentialEnvKeys(sanitized);
  const mcpSanitized = mcpServerEnvForSpawn({
    server: {
      env: {
        OPENAI_API_KEY: 'sk-probe-should-be-redacted',
        JAVIS_API_TOKEN: 'probe-token-should-be-redacted',
        JAVIS_CHILD_ENV_PROBE_ALLOWED: 'kept',
      },
    },
    normalized: {
      name: 'child_env_guard_probe',
      sourceId: 'probe',
      command: 'probe',
    },
  });
  const mcpSanitizedCredentialKeys = openAiCredentialEnvKeys(mcpSanitized);
  return {
    version: 1,
    ok: OPENAI_CHILD_ENV_GUARD_ENABLED
      ? sanitizedCredentialKeys.length === 0 &&
        inlineInjectionBlocked &&
        mcpSanitizedCredentialKeys.length === 0 &&
        mcpSanitized.JAVIS_CHILD_ENV_PROBE_ALLOWED === 'kept'
      : true,
    guard: openAiChildEnvGuardSnapshot(),
    parentHasOpenAiCredentials: openAiCredentialEnvKeys(process.env).length > 0,
    sanitizedHasOpenAiCredentials: sanitizedCredentialKeys.length > 0,
    sanitizedCredentialKeys,
    redactedKeys: String(sanitized.JAVIS_OPENAI_CHILD_ENV_REDACTED_KEYS || '').split(',').filter(Boolean),
    mcpSanitizedHasOpenAiCredentials: mcpSanitizedCredentialKeys.length > 0,
    mcpSanitizedCredentialKeys,
    mcpRedactedKeys: String(mcpSanitized.JAVIS_OPENAI_CHILD_ENV_MCP_REDACTED_KEYS || '').split(',').filter(Boolean),
    mcpAllowedEnvPreserved: mcpSanitized.JAVIS_CHILD_ENV_PROBE_ALLOWED === 'kept',
    inlineInjectionBlocked,
    inlineInjectionReason,
    commandPreview: redactCommandForLog(command),
    safety: {
      readOnly: true,
      startsProcess: false,
      callsOpenAi: false,
      usesRealtime: false,
      startsMicrophone: false,
      exposesApiKey: false,
    },
  };
}

const ORIGINAL_GLOBAL_FETCH = typeof globalThis.fetch === 'function' ? globalThis.fetch.bind(globalThis) : null;
const ORIGINAL_HTTP_REQUEST = http.request.bind(http);
const ORIGINAL_HTTP_GET = http.get.bind(http);
const ORIGINAL_HTTPS_REQUEST = https.request.bind(https);
const ORIGINAL_HTTPS_GET = https.get.bind(https);
let openAiEgressGuardInstalled = false;
let openAiEgressAllowDepth = 0;
const openAiEgressSourceStack = [];
const openAiSpendLeases = new Map();

function openAiSpendLeaseIdFromOptions(options = {}) {
  return String(
    options.openAiSpendLeaseId ||
      options.spendLeaseId ||
      options.leaseId ||
      options.openAiLeaseId ||
      '',
  ).trim();
}

function pruneOpenAiSpendLeases(now = Date.now()) {
  for (const [id, lease] of openAiSpendLeases.entries()) {
    if (!lease || lease.expiresAt <= now || lease.usedAt) {
      openAiSpendLeases.delete(id);
    }
  }
}

function openAiSpendLeaseSnapshot(lease = null, now = Date.now()) {
  if (!lease) return null;
  return {
    id: lease.id,
    kind: lease.kind,
    source: lease.source,
    model: lease.model,
    createdAt: lease.createdAt,
    expiresAt: lease.expiresAt,
    expiresInMs: Math.max(0, lease.expiresAt - now),
    usedAt: lease.usedAt || 0,
    usedByEventId: lease.usedByEventId || '',
  };
}

function openAiSpendLeaseStateSnapshot() {
  const now = Date.now();
  pruneOpenAiSpendLeases(now);
  const leases = Array.from(openAiSpendLeases.values())
    .sort((a, b) => b.createdAt - a.createdAt)
    .slice(0, 8)
    .map((lease) => openAiSpendLeaseSnapshot(lease, now));
  return {
    required: OPENAI_REQUIRE_SPEND_LEASE,
    ttlMs: OPENAI_SPEND_LEASE_TTL_MS,
    activeCount: leases.length,
    active: leases,
    oneRequestOnly: true,
  };
}

function evaluateOpenAiSpendLease(options = {}) {
  if (!OPENAI_REQUIRE_SPEND_LEASE) {
    return { ok: true, required: false, reason: '', lease: null };
  }
  const now = Date.now();
  pruneOpenAiSpendLeases(now);
  const leaseId = openAiSpendLeaseIdFromOptions(options);
  if (!leaseId) return { ok: false, required: true, reason: 'spend_lease_required', lease: null };
  const lease = openAiSpendLeases.get(leaseId);
  if (!lease) return { ok: false, required: true, reason: 'spend_lease_missing', lease: null };
  if (lease.usedAt) return { ok: false, required: true, reason: 'spend_lease_already_used', lease };
  if (lease.expiresAt <= now) {
    openAiSpendLeases.delete(leaseId);
    return { ok: false, required: true, reason: 'spend_lease_expired', lease };
  }
  const kind = compactRecordText(options.kind || 'openai', 80);
  if (lease.kind && kind && lease.kind !== kind) {
    return { ok: false, required: true, reason: 'spend_lease_kind_mismatch', lease };
  }
  return { ok: true, required: true, reason: '', lease };
}

function consumeOpenAiSpendLease(lease, eventId) {
  if (!lease || lease.usedAt) return null;
  lease.usedAt = Date.now();
  lease.usedByEventId = String(eventId || '');
  openAiSpendLeases.delete(lease.id);
  appendAudit('openai.spend_lease_consumed', {
    leaseId: lease.id,
    kind: lease.kind,
    source: lease.source,
    model: lease.model,
    usedByEventId: lease.usedByEventId,
  });
  return lease;
}

function createOpenAiSpendLease(options = {}) {
  const kind = compactRecordText(options.kind || 'openai', 80);
  const source = compactRecordText(options.source || 'manual_spend_lease', 80);
  const model = compactRecordText(options.model || '', 120);
  const decision = evaluateOpenAiSpendGuard({
    ...options,
    kind,
    source,
    model,
    reserve: false,
    recordBlocked: false,
  });
  if (!decision.allowed) {
    appendAudit('openai.spend_lease_blocked', {
      kind,
      source,
      model,
      reasons: decision.reasons,
    });
    return {
      ok: false,
      status: 403,
      decision,
      lease: null,
      spendGuard: openAiSpendGuardSnapshot(),
      output: `OpenAI spend lease not created: ${decision.reasons.join(', ') || 'spend_guard'}.`,
    };
  }
  const now = Date.now();
  const lease = {
    id: crypto.randomUUID(),
    kind,
    source,
    model,
    createdAt: now,
    expiresAt: now + OPENAI_SPEND_LEASE_TTL_MS,
    usedAt: 0,
    usedByEventId: '',
  };
  pruneOpenAiSpendLeases(now);
  openAiSpendLeases.set(lease.id, lease);
  appendAudit('openai.spend_lease_created', {
    leaseId: lease.id,
    kind,
    source,
    model,
    ttlMs: OPENAI_SPEND_LEASE_TTL_MS,
    expiresAt: new Date(lease.expiresAt).toISOString(),
  });
  return {
    ok: true,
    status: 200,
    decision,
    lease: openAiSpendLeaseSnapshot(lease, now),
    spendGuard: openAiSpendGuardSnapshot(),
    output: 'OpenAI spend lease created for one request.',
  };
}

function openAiEgressHostIsGuarded(hostname = '') {
  const host = String(hostname || '').trim().toLowerCase().replace(/\.$/, '');
  return (
    host === 'api.openai.com' ||
    host.endsWith('.api.openai.com') ||
    host === 'realtime.openai.com' ||
    host.endsWith('.realtime.openai.com')
  );
}

function urlFromFetchInput(input) {
  try {
    if (!input) return null;
    if (typeof input === 'string') return new URL(input);
    if (input instanceof URL) return input;
    if (typeof Request !== 'undefined' && input instanceof Request) return new URL(input.url);
    if (typeof input.url === 'string') return new URL(input.url);
  } catch {
    return null;
  }
  return null;
}

function urlFromRequestArgs(args = [], fallbackProtocol = 'https:') {
  const [target, options] = args;
  try {
    if (typeof target === 'string' || target instanceof URL) {
      const base = new URL(target);
      const extra = options && typeof options === 'object' && !(options instanceof Function) ? options : {};
      const protocol = extra.protocol || base.protocol || fallbackProtocol;
      const hostname = extra.hostname || extra.host || base.hostname;
      if (!hostname) return base;
      const pathname = extra.path || extra.pathname || `${base.pathname || '/'}${base.search || ''}`;
      const port = extra.port || base.port;
      return new URL(`${protocol}//${hostname}${port ? `:${port}` : ''}${String(pathname || '/').startsWith('/') ? pathname : `/${pathname}`}`);
    }
    if (target && typeof target === 'object') {
      if (typeof target.href === 'string') return new URL(target.href);
      const protocol = target.protocol || fallbackProtocol;
      const hostname = target.hostname || target.host;
      if (!hostname) return null;
      const pathname = target.path || target.pathname || '/';
      const port = target.port || '';
      return new URL(`${protocol}//${hostname}${port ? `:${port}` : ''}${String(pathname).startsWith('/') ? pathname : `/${pathname}`}`);
    }
  } catch {
    return null;
  }
  return null;
}

function makeOpenAiEgressBlockedDecision(kind, url, source = 'network_egress_guard') {
  const decision = evaluateOpenAiSpendGuard({
    kind,
    source,
    model: 'direct_openai_egress',
    recordBlocked: true,
    forceBlockedReasons: ['unscoped_openai_egress_blocked'],
    targetHost: url?.hostname || '',
  });
  appendAudit('openai.egress_guard_blocked', {
    kind,
    source,
    host: compactRecordText(url?.hostname || '', 120),
    pathname: compactRecordText(url?.pathname || '', 160),
    decisionId: decision.id,
    reasons: decision.reasons,
  });
  return decision;
}

function assertOpenAiEgressAllowed(kind, url, source) {
  if (!OPENAI_EGRESS_GUARD_ENABLED || !url || !openAiEgressHostIsGuarded(url.hostname)) return;
  if (openAiEgressAllowDepth > 0) return;
  throw new OpenAiSpendGuardBlocked(makeOpenAiEgressBlockedDecision(kind, url, source));
}

async function withOpenAiEgressAllowed(decision, fn) {
  if (!decision?.allowed) {
    throw new OpenAiSpendGuardBlocked(decision || makeOpenAiEgressBlockedDecision('egress_scope', null, 'missing_spend_reservation'));
  }
  openAiEgressAllowDepth += 1;
  try {
    return await fn();
  } finally {
    openAiEgressAllowDepth = Math.max(0, openAiEgressAllowDepth - 1);
  }
}

async function withOpenAiEgressSource(source, fn) {
  openAiEgressSourceStack.push(compactRecordText(source || 'openai_egress', 80));
  try {
    return await fn();
  } finally {
    openAiEgressSourceStack.pop();
  }
}

function currentOpenAiEgressSource(fallback = 'network_egress_guard') {
  return openAiEgressSourceStack[openAiEgressSourceStack.length - 1] || fallback;
}

function installOpenAiEgressGuard() {
  if (!OPENAI_EGRESS_GUARD_ENABLED || openAiEgressGuardInstalled) return false;
  openAiEgressGuardInstalled = true;
  if (ORIGINAL_GLOBAL_FETCH) {
    globalThis.fetch = async function javisGuardedFetch(input, init) {
      assertOpenAiEgressAllowed('egress_fetch', urlFromFetchInput(input), currentOpenAiEgressSource('global_fetch'));
      return ORIGINAL_GLOBAL_FETCH(input, init);
    };
  }
  http.request = function javisGuardedHttpRequest(...args) {
    assertOpenAiEgressAllowed('egress_http', urlFromRequestArgs(args, 'http:'), currentOpenAiEgressSource('http_request'));
    return ORIGINAL_HTTP_REQUEST(...args);
  };
  http.get = function javisGuardedHttpGet(...args) {
    assertOpenAiEgressAllowed('egress_http_get', urlFromRequestArgs(args, 'http:'), currentOpenAiEgressSource('http_get'));
    return ORIGINAL_HTTP_GET(...args);
  };
  https.request = function javisGuardedHttpsRequest(...args) {
    assertOpenAiEgressAllowed('egress_https', urlFromRequestArgs(args, 'https:'), currentOpenAiEgressSource('https_request'));
    return ORIGINAL_HTTPS_REQUEST(...args);
  };
  https.get = function javisGuardedHttpsGet(...args) {
    assertOpenAiEgressAllowed('egress_https_get', urlFromRequestArgs(args, 'https:'), currentOpenAiEgressSource('https_get'));
    return ORIGINAL_HTTPS_GET(...args);
  };
  appendAudit('openai.egress_guard_installed', {
    fetch: Boolean(ORIGINAL_GLOBAL_FETCH),
    http: true,
    https: true,
    mode: 'scoped_allow_only',
  });
  return true;
}

function openAiEgressGuardSnapshot() {
  return {
    version: 1,
    enabled: OPENAI_EGRESS_GUARD_ENABLED,
    installed: openAiEgressGuardInstalled,
    mode: OPENAI_EGRESS_GUARD_ENABLED ? 'scoped_allow_only' : 'off',
    guardedHosts: ['api.openai.com', '*.api.openai.com', 'realtime.openai.com', '*.realtime.openai.com'],
    guardedApis: {
      fetch: Boolean(ORIGINAL_GLOBAL_FETCH),
      httpRequest: true,
      httpGet: true,
      httpsRequest: true,
      httpsGet: true,
    },
    safety: {
      blocksUnscopedOpenAiFetch: OPENAI_EGRESS_GUARD_ENABLED && openAiEgressGuardInstalled,
      requiresSpendReservationScope: true,
      callsOpenAiDuringProbe: false,
      exposesApiToken: false,
    },
  };
}

function xmlEscape(value) {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

function shQuote(value) {
  return `'${String(value).replace(/'/g, `'\\''`)}'`;
}

function uniqueStringList(value, fallback) {
  const list = Array.isArray(value) ? value : fallback;
  return Array.from(new Set(list.map((item) => String(item).trim()).filter(Boolean)));
}

function stringListWithDefaultAdditions(value, fallback) {
  const current = uniqueStringList(value, fallback);
  return Array.from(new Set([...current, ...fallback]));
}

function browserAllowedActionsList(value) {
  const current = uniqueStringList(value, DEFAULT_ACTION_POLICY.allow.browser_control.allowedActions);
  return Array.from(new Set([...current, ...DEFAULT_ACTION_POLICY.allow.browser_control.allowedActions]));
}

function isProjectOnlyRootList(roots) {
  if (!Array.isArray(roots) || roots.length !== 1) return false;
  try {
    return path.resolve(resolvePath(roots[0])) === path.resolve(process.cwd());
  } catch {
    return false;
  }
}

function mutationAllowedRoots(value, fallback) {
  const roots = uniqueStringList(value, fallback);
  if (TRUSTED_LOCAL_MODE && isProjectOnlyRootList(roots)) {
    return DEFAULT_WRITE_ROOTS;
  }
  return roots;
}

function normalizeActionPolicy(value) {
  const raw = value && typeof value === 'object' ? value : {};
  return {
    version: 1,
    dryRun: typeof raw.dryRun === 'boolean' ? raw.dryRun : DEFAULT_ACTION_POLICY.dryRun,
    maxAutoRiskLevel: Math.max(0, Math.min(4, Number(raw.maxAutoRiskLevel ?? DEFAULT_ACTION_POLICY.maxAutoRiskLevel))),
    requireApprovalAtRiskLevel: Math.max(
      0,
      Math.min(4, Number(raw.requireApprovalAtRiskLevel ?? DEFAULT_ACTION_POLICY.requireApprovalAtRiskLevel)),
    ),
    allow: {
      open_url: {
        enabled: raw.allow?.open_url?.enabled !== false,
        allowedHosts: uniqueStringList(raw.allow?.open_url?.allowedHosts, DEFAULT_ACTION_POLICY.allow.open_url.allowedHosts),
      },
      open_app: {
        enabled: raw.allow?.open_app?.enabled !== false,
        allowedApps: uniqueStringList(raw.allow?.open_app?.allowedApps, DEFAULT_ACTION_POLICY.allow.open_app.allowedApps),
      },
      type_text: {
        enabled: raw.allow?.type_text?.enabled !== false,
      },
      hotkey: {
        enabled: raw.allow?.hotkey?.enabled !== false,
        allowedKeys: uniqueStringList(raw.allow?.hotkey?.allowedKeys, DEFAULT_ACTION_POLICY.allow.hotkey.allowedKeys),
      },
      read_clipboard: {
        enabled: raw.allow?.read_clipboard?.enabled !== false,
        maxBytes: Math.max(1, Number(raw.allow?.read_clipboard?.maxBytes || DEFAULT_ACTION_POLICY.allow.read_clipboard.maxBytes)),
      },
      write_clipboard: {
        enabled: raw.allow?.write_clipboard?.enabled !== false,
        maxBytes: Math.max(1, Number(raw.allow?.write_clipboard?.maxBytes || DEFAULT_ACTION_POLICY.allow.write_clipboard.maxBytes)),
      },
      clear_clipboard: {
        enabled: raw.allow?.clear_clipboard?.enabled !== false,
      },
      read_accessibility_tree: {
        enabled: raw.allow?.read_accessibility_tree?.enabled !== false,
        maxNodes: Math.max(
          DEFAULT_ACTION_POLICY.allow.read_accessibility_tree.maxNodes,
          Math.min(500, Number(raw.allow?.read_accessibility_tree?.maxNodes || DEFAULT_ACTION_POLICY.allow.read_accessibility_tree.maxNodes)),
        ),
        maxDepth: Math.max(
          DEFAULT_ACTION_POLICY.allow.read_accessibility_tree.maxDepth,
          Math.min(12, Number(raw.allow?.read_accessibility_tree?.maxDepth || DEFAULT_ACTION_POLICY.allow.read_accessibility_tree.maxDepth)),
        ),
      },
      ax_press: {
        enabled: raw.allow?.ax_press?.enabled !== false,
        allowedRoles: uniqueStringList(raw.allow?.ax_press?.allowedRoles, DEFAULT_ACTION_POLICY.allow.ax_press.allowedRoles),
      },
      ax_set_value: {
        enabled: raw.allow?.ax_set_value?.enabled !== false,
        allowedRoles: stringListWithDefaultAdditions(raw.allow?.ax_set_value?.allowedRoles, DEFAULT_ACTION_POLICY.allow.ax_set_value.allowedRoles),
        editableEvidenceRequiredRoles: stringListWithDefaultAdditions(
          raw.allow?.ax_set_value?.editableEvidenceRequiredRoles,
          DEFAULT_ACTION_POLICY.allow.ax_set_value.editableEvidenceRequiredRoles,
        ),
        maxBytes: Math.max(1, Number(raw.allow?.ax_set_value?.maxBytes || DEFAULT_ACTION_POLICY.allow.ax_set_value.maxBytes)),
      },
      productivity_app: {
        enabled: raw.allow?.productivity_app?.enabled !== false,
        allowedApps: uniqueStringList(raw.allow?.productivity_app?.allowedApps, DEFAULT_ACTION_POLICY.allow.productivity_app.allowedApps),
      },
      browser_control: {
        enabled: raw.allow?.browser_control?.enabled !== false,
        allowedActions: browserAllowedActionsList(raw.allow?.browser_control?.allowedActions),
      },
      code_agent: {
        enabled: raw.allow?.code_agent?.enabled !== false,
        allowedCommands: uniqueStringList(raw.allow?.code_agent?.allowedCommands, DEFAULT_ACTION_POLICY.allow.code_agent.allowedCommands),
        maxTimeoutMs: Math.max(
          1000,
          Math.min(3600000, Number(raw.allow?.code_agent?.maxTimeoutMs || DEFAULT_ACTION_POLICY.allow.code_agent.maxTimeoutMs)),
        ),
      },
      cli_command: {
        enabled: raw.allow?.cli_command?.enabled !== false,
        allowedCommands: uniqueStringList(raw.allow?.cli_command?.allowedCommands, DEFAULT_ACTION_POLICY.allow.cli_command.allowedCommands),
        maxCommandLength: Math.max(
          80,
          Math.min(20000, Number(raw.allow?.cli_command?.maxCommandLength || DEFAULT_ACTION_POLICY.allow.cli_command.maxCommandLength)),
        ),
        maxTimeoutMs: Math.max(
          1000,
          Math.min(3600000, Number(raw.allow?.cli_command?.maxTimeoutMs || DEFAULT_ACTION_POLICY.allow.cli_command.maxTimeoutMs)),
        ),
      },
      read_browser_page: {
        enabled: raw.allow?.read_browser_page?.enabled !== false,
        maxChars: Math.max(1000, Math.min(120000, Number(raw.allow?.read_browser_page?.maxChars || DEFAULT_ACTION_POLICY.allow.read_browser_page.maxChars))),
      },
      list_directory: {
        enabled: raw.allow?.list_directory?.enabled !== false,
        allowedRoots: uniqueStringList(raw.allow?.list_directory?.allowedRoots, DEFAULT_ACTION_POLICY.allow.list_directory.allowedRoots),
      },
      read_file: {
        enabled: raw.allow?.read_file?.enabled !== false,
        allowedRoots: uniqueStringList(raw.allow?.read_file?.allowedRoots, DEFAULT_ACTION_POLICY.allow.read_file.allowedRoots),
        maxBytes: Math.max(1, Number(raw.allow?.read_file?.maxBytes || DEFAULT_ACTION_POLICY.allow.read_file.maxBytes)),
      },
      search_files: {
        enabled: raw.allow?.search_files?.enabled !== false,
        allowedRoots: uniqueStringList(raw.allow?.search_files?.allowedRoots, DEFAULT_ACTION_POLICY.allow.search_files.allowedRoots),
        maxResults: Math.max(1, Math.min(500, Number(raw.allow?.search_files?.maxResults || DEFAULT_ACTION_POLICY.allow.search_files.maxResults))),
      },
      write_file: {
        enabled: raw.allow?.write_file?.enabled !== false,
        allowedRoots: mutationAllowedRoots(raw.allow?.write_file?.allowedRoots, DEFAULT_ACTION_POLICY.allow.write_file.allowedRoots),
        maxBytes: Math.max(1, Number(raw.allow?.write_file?.maxBytes || DEFAULT_ACTION_POLICY.allow.write_file.maxBytes)),
      },
      create_directory: {
        enabled: raw.allow?.create_directory?.enabled !== false,
        allowedRoots: mutationAllowedRoots(raw.allow?.create_directory?.allowedRoots, DEFAULT_ACTION_POLICY.allow.create_directory.allowedRoots),
      },
      copy_file: {
        enabled: raw.allow?.copy_file?.enabled !== false,
        allowedRoots: mutationAllowedRoots(raw.allow?.copy_file?.allowedRoots, DEFAULT_ACTION_POLICY.allow.copy_file.allowedRoots),
        maxBytes: Math.max(1, Number(raw.allow?.copy_file?.maxBytes || DEFAULT_ACTION_POLICY.allow.copy_file.maxBytes)),
      },
      move_file: {
        enabled: raw.allow?.move_file?.enabled !== false,
        allowedRoots: mutationAllowedRoots(raw.allow?.move_file?.allowedRoots, DEFAULT_ACTION_POLICY.allow.move_file.allowedRoots),
      },
    },
  };
}

function loadActionPolicy() {
  if (!fs.existsSync(ACTION_POLICY_FILE)) {
    const policy = normalizeActionPolicy(DEFAULT_ACTION_POLICY);
    writeJsonAtomic(ACTION_POLICY_FILE, policy);
    return policy;
  }

  try {
    const policy = normalizeActionPolicy(JSON.parse(fs.readFileSync(ACTION_POLICY_FILE, 'utf8')));
    writeJsonAtomic(ACTION_POLICY_FILE, policy);
    return policy;
  } catch (error) {
    appendAudit('action_policy.load_failed', { message: error instanceof Error ? error.message : String(error) });
    return normalizeActionPolicy(DEFAULT_ACTION_POLICY);
  }
}

function persistActionPolicy() {
  writeJsonAtomic(ACTION_POLICY_FILE, actionPolicy);
}

function defaultControlModeId() {
  return LOCAL_EXEC_ENABLED && TRUSTED_LOCAL_MODE ? 'trusted_local' : 'ask_before_action';
}

function normalizeControlModeId(value) {
  const normalized = String(value || '').trim().toLowerCase().replace(/[-\s]+/g, '_');
  const aliased = CONTROL_MODE_ALIASES[normalized] || normalized;
  return CONTROL_MODE_DEFINITIONS[aliased] ? aliased : '';
}

function controlModeDefinition(value) {
  const id = normalizeControlModeId(value) || defaultControlModeId();
  return CONTROL_MODE_DEFINITIONS[id] || CONTROL_MODE_DEFINITIONS.ask_before_action;
}

function availableControlModes() {
  return Object.values(CONTROL_MODE_DEFINITIONS).map((mode) => ({ ...mode }));
}

function normalizeControlModeState(value = {}) {
  const mode = controlModeDefinition(value.mode || value.id || defaultControlModeId());
  return {
    version: 1,
    mode: mode.id,
    label: mode.label,
    description: mode.description,
    maxAutoRiskLevel: mode.maxAutoRiskLevel,
    requireApprovalAtRiskLevel: mode.requireApprovalAtRiskLevel,
    blocksActionsAtRiskLevel: mode.blocksActionsAtRiskLevel,
    source: compactRecordText(value.source || 'default', 80),
    updatedAt: Number(value.updatedAt || Date.now()),
  };
}

function loadControlMode() {
  if (!fs.existsSync(CONTROL_MODE_FILE)) {
    const state = normalizeControlModeState({ mode: defaultControlModeId(), source: 'default' });
    writeJsonAtomic(CONTROL_MODE_FILE, state);
    return state;
  }
  try {
    const state = normalizeControlModeState(JSON.parse(fs.readFileSync(CONTROL_MODE_FILE, 'utf8')));
    writeJsonAtomic(CONTROL_MODE_FILE, state);
    return state;
  } catch (error) {
    appendAudit('control_mode.load_failed', { message: error instanceof Error ? error.message : String(error) });
    return normalizeControlModeState({ mode: defaultControlModeId(), source: 'fallback' });
  }
}

function persistControlMode() {
  writeJsonAtomic(CONTROL_MODE_FILE, controlModeState);
}

function controlModeSnapshot(options = {}) {
  const snapshot = normalizeControlModeState(controlModeState || { mode: defaultControlModeId() });
  return {
    ...snapshot,
    effective: {
      maxAutoRiskLevel: Math.min(actionPolicy.maxAutoRiskLevel, snapshot.maxAutoRiskLevel),
      requireApprovalAtRiskLevel: Math.min(actionPolicy.requireApprovalAtRiskLevel, snapshot.requireApprovalAtRiskLevel),
    },
    policyMaxAutoRiskLevel: actionPolicy.maxAutoRiskLevel,
    policyRequireApprovalAtRiskLevel: actionPolicy.requireApprovalAtRiskLevel,
    localExecutionEnabled: LOCAL_EXEC_ENABLED,
    trustedLocalMode: TRUSTED_LOCAL_MODE,
    ...(options.includeAvailableModes ? { availableModes: availableControlModes() } : {}),
  };
}

function setControlMode(options = {}) {
  const modeId = normalizeControlModeId(options.mode || options.id);
  if (!modeId) {
    throw new Error(`Unsupported control mode: ${options.mode || options.id || ''}`);
  }
  controlModeState = normalizeControlModeState({
    mode: modeId,
    source: options.source || 'api',
    updatedAt: Date.now(),
  });
  persistControlMode();
  appendAudit('control_mode.updated', {
    mode: controlModeState.mode,
    source: controlModeState.source,
    effectiveMaxAutoRiskLevel: controlModeSnapshot().effective.maxAutoRiskLevel,
    effectiveRequireApprovalAtRiskLevel: controlModeSnapshot().effective.requireApprovalAtRiskLevel,
  });
  return {
    ok: true,
    controlMode: controlModeSnapshot({ includeAvailableModes: true }),
    effectivePolicy: effectiveActionPolicySnapshot(),
    controlModeFile: CONTROL_MODE_FILE,
  };
}

function effectiveActionPolicySnapshot() {
  const controlMode = controlModeSnapshot();
  return {
    version: actionPolicy.version,
    dryRun: actionPolicy.dryRun,
    maxAutoRiskLevel: controlMode.effective.maxAutoRiskLevel,
    requireApprovalAtRiskLevel: controlMode.effective.requireApprovalAtRiskLevel,
    policyMaxAutoRiskLevel: actionPolicy.maxAutoRiskLevel,
    policyRequireApprovalAtRiskLevel: actionPolicy.requireApprovalAtRiskLevel,
    allow: actionPolicy.allow,
    controlMode,
    localExecutionEnabled: LOCAL_EXEC_ENABLED,
    trustedLocalMode: TRUSTED_LOCAL_MODE,
  };
}

function evaluateControlModeRisk(plan, options = {}) {
  const effective = effectiveActionPolicySnapshot();
  const controlMode = effective.controlMode;
  const blockAt = Number(controlMode.blocksActionsAtRiskLevel || 0);
  if (blockAt > 0 && Number(plan.riskLevel || 0) >= blockAt) {
    return {
      dryRun: Boolean(actionPolicy.dryRun),
      needsApproval: false,
      blocked: true,
      reason: `control_mode_${controlMode.mode}_blocks_risk_level_${plan.riskLevel}`,
      controlMode,
      effectivePolicy: {
        maxAutoRiskLevel: effective.maxAutoRiskLevel,
        requireApprovalAtRiskLevel: effective.requireApprovalAtRiskLevel,
      },
    };
  }

  const needsApproval =
    !options.approved &&
    (plan.riskLevel >= effective.requireApprovalAtRiskLevel || plan.riskLevel > effective.maxAutoRiskLevel);
  return {
    dryRun: Boolean(actionPolicy.dryRun),
    needsApproval,
    blocked: false,
    reason: needsApproval ? `risk_level_${plan.riskLevel}_requires_approval` : '',
    controlMode,
    effectivePolicy: {
      maxAutoRiskLevel: effective.maxAutoRiskLevel,
      requireApprovalAtRiskLevel: effective.requireApprovalAtRiskLevel,
    },
  };
}

function normalizeScreenPrivacy(value = {}) {
  const mode = String(value.mode || DEFAULT_SCREEN_PRIVACY.mode) === 'clear' ? 'clear' : 'private';
  const privateMode = mode === 'private';
  const rules = normalizeScreenPrivacyRules(value.rules);
  const ruleCounts = screenPrivacyRuleCounts(rules);
  const regionMaskRuleCount = enabledScreenPrivacyRegionRules({ rules }).length;
  return {
    version: 1,
    mode,
    label: privateMode ? 'Private' : 'Clear',
    maxWidth: privateMode ? 640 : 1280,
    blurPx: privateMode ? 5 : 0,
    jpegQuality: privateMode ? 0.46 : 0.72,
    realtimeAllowed: true,
    rules,
    ruleCounts,
    rulesSummary: screenPrivacyRulesSummary(rules),
    enforcement: {
      globalTransform: privateMode ? 'downscale_blur' : 'clear_frame',
      appWindowContextFilter: true,
      browserHostContextFilter: true,
      regionRendererMask: regionMaskRuleCount > 0,
      regionRendererMaskStatus: regionMaskRuleCount ? 'resident_region_mask' : 'not_configured',
      residentRegionMask: regionMaskRuleCount > 0,
      residentRegionMaskStatus: regionMaskRuleCount ? 'enabled_before_storage' : 'not_configured',
      regionRuleCount: regionMaskRuleCount,
      regionMaskAppliesBeforeStorage: true,
    },
    updatedAt: Number(value.updatedAt || Date.now()),
  };
}

function screenPrivacyRuleCounts(rules = []) {
  return rules.reduce((counts, rule) => {
    counts.total += 1;
    if (rule.enabled) counts.enabled += 1;
    counts[rule.kind] = (counts[rule.kind] || 0) + 1;
    counts[rule.effect] = (counts[rule.effect] || 0) + 1;
    return counts;
  }, { total: 0, enabled: 0 });
}

function screenPrivacyRulesSummary(rules = []) {
  const enabled = rules.filter((rule) => rule.enabled);
  if (!enabled.length) return 'No app/window/browser/region privacy rules configured.';
  const counts = screenPrivacyRuleCounts(enabled);
  const parts = [
    counts.app ? `${counts.app} app` : '',
    counts.window ? `${counts.window} window` : '',
    counts.browser_host ? `${counts.browser_host} browser host` : '',
    counts.region ? `${counts.region} region` : '',
  ].filter(Boolean);
  return `${enabled.length} enabled privacy rule(s): ${parts.join(', ') || 'custom rules'}.`;
}

function normalizeScreenPrivacyMatch(value) {
  const normalized = String(value || '').trim().toLowerCase();
  if (['exact', 'prefix', 'suffix'].includes(normalized)) return normalized;
  return 'contains';
}

function normalizeScreenPrivacyEffect(value) {
  const normalized = String(value || '').trim().toLowerCase();
  if (['blur', 'mask'].includes(normalized)) return 'blur';
  return 'exclude';
}

function normalizeScreenPrivacyRuleKind(value) {
  const normalized = String(value || '').trim().toLowerCase().replace(/[-\s]+/g, '_');
  if (['app', 'window', 'browser_host', 'region'].includes(normalized)) return normalized;
  if (['host', 'site', 'domain', 'browser'].includes(normalized)) return 'browser_host';
  return 'app';
}

function normalizeScreenPrivacyRegion(value = {}) {
  const unit = String(value.unit || '').trim().toLowerCase() === 'px' ? 'px' : 'percent';
  const clamp = (raw, min, max) => {
    const parsed = Number(raw);
    if (!Number.isFinite(parsed)) return min;
    return Math.max(min, Math.min(max, parsed));
  };
  const max = unit === 'px' ? 100000 : 100;
  return {
    unit,
    x: clamp(value.x, 0, max),
    y: clamp(value.y, 0, max),
    width: clamp(value.width, 1, max),
    height: clamp(value.height, 1, max),
  };
}

function normalizeScreenPrivacyRules(value = []) {
  const rules = Array.isArray(value) ? value : [];
  const now = Date.now();
  const seen = new Set();
  return rules
    .map((item, index) => {
      if (!item || typeof item !== 'object') return null;
      const kind = normalizeScreenPrivacyRuleKind(item.kind || item.type);
      const label = compactRecordText(item.label || item.name || '', 120);
      const rawValue = kind === 'region' ? '' : compactRecordText(item.value || item.pattern || item.app || item.window || item.host || '', 180);
      const region = kind === 'region' ? normalizeScreenPrivacyRegion(item.region || item) : null;
      if (kind !== 'region' && !rawValue) return null;
      const idBase = compactRecordText(item.id || `${kind}_${rawValue || `${region.x}_${region.y}_${region.width}_${region.height}`}_${index}`, 120)
        .toLowerCase()
        .replace(/[^a-z0-9_-]+/g, '_')
        .replace(/^_+|_+$/g, '') || `rule_${index}`;
      let id = idBase;
      let suffix = 2;
      while (seen.has(id)) {
        id = `${idBase}_${suffix}`;
        suffix += 1;
      }
      seen.add(id);
      return {
        id,
        presetId: compactRecordText(item.presetId || '', 80),
        presetLabel: compactRecordText(item.presetLabel || '', 120),
        enabled: item.enabled !== false,
        kind,
        effect: normalizeScreenPrivacyEffect(item.effect || item.action),
        match: kind === 'region' ? 'region' : normalizeScreenPrivacyMatch(item.match),
        value: rawValue,
        label: label || (kind === 'region' ? `Region ${index + 1}` : rawValue),
        region,
        appliesTo: Array.isArray(item.appliesTo) && item.appliesTo.length
          ? item.appliesTo.map((target) => compactRecordText(target, 40)).filter(Boolean).slice(0, 8)
          : kind === 'region'
            ? ['renderer_mask', 'screen_context']
            : ['model_context', 'realtime', 'vision', 'ambient'],
        createdAt: Number(item.createdAt || now),
        updatedAt: Number(item.updatedAt || item.createdAt || now),
      };
    })
    .filter(Boolean)
    .slice(0, 40);
}

function enabledScreenPrivacyRegionRules(privacy = {}) {
  return (Array.isArray(privacy.rules) ? privacy.rules : [])
    .filter((rule) => rule?.enabled && rule.kind === 'region' && rule.region);
}

function screenPrivacyRegionRect(rule, width, height) {
  const region = rule?.region || {};
  const unit = region.unit === 'px' ? 'px' : 'percent';
  const leftRaw = unit === 'px' ? Number(region.x) : (Number(region.x) / 100) * width;
  const topRaw = unit === 'px' ? Number(region.y) : (Number(region.y) / 100) * height;
  const widthRaw = unit === 'px' ? Number(region.width) : (Number(region.width) / 100) * width;
  const heightRaw = unit === 'px' ? Number(region.height) : (Number(region.height) / 100) * height;
  if (![leftRaw, topRaw, widthRaw, heightRaw].every(Number.isFinite)) return null;
  const left = Math.max(0, Math.min(width, Math.floor(leftRaw)));
  const top = Math.max(0, Math.min(height, Math.floor(topRaw)));
  const right = Math.max(left, Math.min(width, Math.ceil(leftRaw + widthRaw)));
  const bottom = Math.max(top, Math.min(height, Math.ceil(topRaw + heightRaw)));
  const rectWidth = right - left;
  const rectHeight = bottom - top;
  if (rectWidth <= 0 || rectHeight <= 0) return null;
  return { x: left, y: top, width: rectWidth, height: rectHeight, right, bottom };
}

function screenPrivacyBitmapPixelOffset(width, x, y) {
  return ((y * width) + x) * 4;
}

function sampleScreenPrivacyBitmapPixel(image, x, y) {
  const size = image.getSize();
  if (!size.width || !size.height || image.isEmpty()) return null;
  const sampleX = Math.max(0, Math.min(size.width - 1, Math.round(Number(x) || 0)));
  const sampleY = Math.max(0, Math.min(size.height - 1, Math.round(Number(y) || 0)));
  const bitmap = image.toBitmap();
  const offset = screenPrivacyBitmapPixelOffset(size.width, sampleX, sampleY);
  if (!bitmap || bitmap.length < offset + 4) return null;
  return {
    x: sampleX,
    y: sampleY,
    channels: [bitmap[offset], bitmap[offset + 1], bitmap[offset + 2], bitmap[offset + 3]],
  };
}

function applyScreenPrivacyRegionMasks(image, privacy = {}) {
  const normalizedPrivacy = normalizeScreenPrivacy(privacy);
  const rules = enabledScreenPrivacyRegionRules(normalizedPrivacy);
  if (!rules.length) {
    return {
      image,
      applied: false,
      required: false,
      ruleCount: 0,
      maskedPixels: 0,
      regions: [],
      status: 'not_configured',
    };
  }

  const size = image.getSize();
  if (!size.width || !size.height || image.isEmpty()) {
    return {
      image,
      applied: false,
      required: true,
      ruleCount: rules.length,
      maskedPixels: 0,
      regions: [],
      status: 'failed_empty_image',
    };
  }

  const bitmap = image.toBitmap();
  const expectedBytes = size.width * size.height * 4;
  if (!bitmap || bitmap.length < expectedBytes) {
    return {
      image,
      applied: false,
      required: true,
      ruleCount: rules.length,
      maskedPixels: 0,
      regions: [],
      status: `failed_bitmap_bytes_${bitmap?.length || 0}`,
    };
  }

  const output = Buffer.from(bitmap);
  const regions = [];
  let maskedPixels = 0;
  for (const rule of rules) {
    const rect = screenPrivacyRegionRect(rule, size.width, size.height);
    if (!rect) continue;
    regions.push({ id: rule.id, label: rule.label, ...rect });
    for (let y = rect.y; y < rect.bottom; y += 1) {
      for (let x = rect.x; x < rect.right; x += 1) {
        const offset = screenPrivacyBitmapPixelOffset(size.width, x, y);
        output[offset] = 18;
        output[offset + 1] = 18;
        output[offset + 2] = 18;
        output[offset + 3] = 255;
        maskedPixels += 1;
      }
    }
  }

  if (!regions.length || maskedPixels <= 0) {
    return {
      image,
      applied: false,
      required: true,
      ruleCount: rules.length,
      maskedPixels: 0,
      regions,
      status: 'failed_no_pixels',
    };
  }

  const maskedImage = nativeImage.createFromBitmap(output, { width: size.width, height: size.height });
  if (maskedImage.isEmpty()) {
    return {
      image,
      applied: false,
      required: true,
      ruleCount: rules.length,
      maskedPixels,
      regions,
      status: 'failed_create_image',
    };
  }

  return {
    image: maskedImage,
    applied: true,
    required: true,
    ruleCount: rules.length,
    maskedPixels,
    regions,
    status: 'resident_region_mask',
  };
}

function screenPrivacyRegionMaskPreview(options = {}) {
  const width = Math.max(16, Math.min(320, Math.round(Number(options.width || 64))));
  const height = Math.max(16, Math.min(320, Math.round(Number(options.height || 64))));
  const rules = Array.isArray(options.rules) && options.rules.length
    ? options.rules
    : [{
        id: 'preview_screen_privacy_region',
        kind: 'region',
        effect: 'blur',
        label: 'Preview top-right region',
        region: { unit: 'percent', x: 75, y: 0, width: 25, height: 25 },
      }];
  const privacy = normalizeScreenPrivacy({
    ...(options.privacy || {}),
    mode: options.mode || options.privacy?.mode || screenPrivacy?.mode || 'private',
    rules,
  });
  const buffer = Buffer.alloc(width * height * 4);
  for (let offset = 0; offset < buffer.length; offset += 4) {
    buffer[offset] = 210;
    buffer[offset + 1] = 210;
    buffer[offset + 2] = 210;
    buffer[offset + 3] = 255;
  }
  const image = nativeImage.createFromBitmap(buffer, { width, height });
  if (image.isEmpty()) throw new Error('Synthetic preview image could not be created.');

  const mask = applyScreenPrivacyRegionMasks(image, privacy);
  const firstRegion = mask.regions[0] || screenPrivacyRegionRect(enabledScreenPrivacyRegionRules(privacy)[0], width, height);
  const inside = firstRegion
    ? sampleScreenPrivacyBitmapPixel(
        mask.image,
        Math.min(firstRegion.right - 1, firstRegion.x + Math.floor(firstRegion.width / 2)),
        Math.min(firstRegion.bottom - 1, firstRegion.y + Math.floor(firstRegion.height / 2)),
      )
    : null;
  const outside = sampleScreenPrivacyBitmapPixel(mask.image, 1, height - 2);
  const insideMasked = Boolean(inside && inside.channels.slice(0, 3).every((value) => value <= 40));
  const outsidePreserved = Boolean(outside && outside.channels.slice(0, 3).every((value) => value >= 180));
  return {
    ok: Boolean(mask.applied && insideMasked && outsidePreserved),
    preview: {
      width,
      height,
      mask: {
        applied: mask.applied,
        required: mask.required,
        ruleCount: mask.ruleCount,
        maskedPixels: mask.maskedPixels,
        regions: mask.regions,
        status: mask.status,
      },
      samples: {
        inside,
        outside,
        insideMasked,
        outsidePreserved,
      },
      privacy: {
        mode: privacy.mode,
        ruleCounts: privacy.ruleCounts,
        enforcement: privacy.enforcement,
      },
    },
  };
}

function screenPrivacyComparable(value) {
  return String(value || '').trim().toLowerCase();
}

function screenPrivacyValueMatches(actual, expected, match = 'contains') {
  const left = screenPrivacyComparable(actual);
  const right = screenPrivacyComparable(expected);
  if (!left || !right) return false;
  if (match === 'exact') return left === right;
  if (match === 'prefix') return left.startsWith(right);
  if (match === 'suffix') return left.endsWith(right);
  return left.includes(right);
}

function screenPrivacyContextFields(context = {}) {
  const frontmost = context.frontmost || context.mac?.frontmost || {};
  const browser = context.browser || context.mac?.browser || {};
  return {
    app: frontmost.app || context.app || '',
    window: frontmost.windowTitle || context.windowTitle || context.title || '',
    browserHost: browser.host || context.browserHost || '',
    browserTitle: browser.title || '',
    browserUrl: browser.url || '',
  };
}

function screenPrivacyMatchingRules(context = {}, rules = screenPrivacy?.rules || []) {
  const fields = screenPrivacyContextFields(context);
  return (Array.isArray(rules) ? rules : []).filter((rule) => {
    if (!rule.enabled) return false;
    if (rule.kind === 'region') return false;
    if (rule.kind === 'app') return screenPrivacyValueMatches(fields.app, rule.value, rule.match);
    if (rule.kind === 'window') return screenPrivacyValueMatches(fields.window, rule.value, rule.match);
    if (rule.kind === 'browser_host') {
      const host = fields.browserHost || (() => {
        try {
          return fields.browserUrl ? new URL(fields.browserUrl).hostname.replace(/^www\./i, '') : '';
        } catch {
          return '';
        }
      })();
      return screenPrivacyValueMatches(host, rule.value, rule.match)
        || screenPrivacyValueMatches(fields.browserTitle, rule.value, rule.match);
    }
    return false;
  });
}

function screenPrivacyContextPolicy(context = {}, rulesOverride = null) {
  const privacy = Array.isArray(rulesOverride)
    ? normalizeScreenPrivacy({ ...screenPrivacy, rules: rulesOverride })
    : screenPrivacySnapshot();
  const matchingRules = screenPrivacyMatchingRules(context, privacy.rules);
  const excluded = matchingRules.filter((rule) => rule.effect === 'exclude');
  const blurred = matchingRules.filter((rule) => rule.effect === 'blur');
  const regionRules = (privacy.rules || []).filter((rule) => rule.enabled && rule.kind === 'region');
  return {
    ok: true,
    allowed: excluded.length === 0,
    blocked: excluded.length > 0,
    reason: excluded.length
      ? `screen_context_excluded_by_${excluded.map((rule) => rule.id).join(',')}`
      : blurred.length
        ? `screen_context_blur_requested_by_${blurred.map((rule) => rule.id).join(',')}`
        : '',
    matchingRules: matchingRules.map((rule) => ({
      id: rule.id,
      kind: rule.kind,
      effect: rule.effect,
      label: rule.label,
      value: rule.value,
    })),
    regionRuleCount: regionRules.length,
    rendererRegionMask: privacy.enforcement?.regionRendererMask === true,
    rendererRegionMaskStatus: privacy.enforcement?.regionRendererMaskStatus || 'not_configured',
    summary: excluded.length
      ? `Screen model context blocked by ${excluded.length} privacy rule(s).`
      : blurred.length
        ? `Screen model context allowed, but ${blurred.length} blur/mask rule(s) need renderer enforcement.`
        : 'Screen model context allowed by configured privacy rules.',
  };
}

function loadScreenPrivacy() {
  if (!fs.existsSync(SCREEN_PRIVACY_FILE)) {
    const value = normalizeScreenPrivacy(DEFAULT_SCREEN_PRIVACY);
    writeJsonAtomic(SCREEN_PRIVACY_FILE, value);
    return value;
  }
  try {
    const value = normalizeScreenPrivacy(JSON.parse(fs.readFileSync(SCREEN_PRIVACY_FILE, 'utf8')));
    writeJsonAtomic(SCREEN_PRIVACY_FILE, value);
    return value;
  } catch (error) {
    appendAudit('screen_privacy.load_failed', { message: error instanceof Error ? error.message : String(error) });
    return normalizeScreenPrivacy(DEFAULT_SCREEN_PRIVACY);
  }
}

function persistScreenPrivacy() {
  writeJsonAtomic(SCREEN_PRIVACY_FILE, screenPrivacy);
}

function screenPrivacySnapshot() {
  return { ...screenPrivacy };
}

function updateScreenPrivacy(options = {}) {
  const nextInput = {
    ...screenPrivacy,
    mode: Object.prototype.hasOwnProperty.call(options, 'mode') ? options.mode : screenPrivacy.mode,
    rules: Object.prototype.hasOwnProperty.call(options, 'rules') ? options.rules : screenPrivacy.rules,
    updatedAt: Date.now(),
  };
  screenPrivacy = normalizeScreenPrivacy({
    ...nextInput,
    rules: options.clearRules === true ? [] : nextInput.rules,
  });
  persistScreenPrivacy();
  appendAudit('screen_privacy.updated', {
    mode: screenPrivacy.mode,
    rules: screenPrivacy.ruleCounts?.enabled || 0,
    source: String(options.source || 'api').slice(0, 80),
  });
  return screenPrivacySnapshot();
}

function addScreenPrivacyRule(rule = {}, options = {}) {
  const existing = Array.isArray(screenPrivacy.rules) ? screenPrivacy.rules : [];
  const normalized = normalizeScreenPrivacyRules([{
    ...rule,
    id: rule.id || `${rule.kind || rule.type || 'rule'}_${Date.now().toString(36)}`,
    createdAt: Date.now(),
    updatedAt: Date.now(),
  }])[0];
  if (!normalized) throw new Error('Invalid screen privacy rule.');
  screenPrivacy = normalizeScreenPrivacy({
    ...screenPrivacy,
    rules: [...existing.filter((item) => item.id !== normalized.id), normalized],
    updatedAt: Date.now(),
  });
  persistScreenPrivacy();
  appendAudit('screen_privacy.rule_added', {
    id: normalized.id,
    kind: normalized.kind,
    effect: normalized.effect,
    source: String(options.source || 'api').slice(0, 80),
  });
  return normalized;
}

function removeScreenPrivacyRule(id, options = {}) {
  const ruleId = String(id || '').trim();
  const existing = Array.isArray(screenPrivacy.rules) ? screenPrivacy.rules : [];
  const nextRules = existing.filter((rule) => rule.id !== ruleId);
  if (nextRules.length === existing.length) throw new Error('Screen privacy rule not found.');
  screenPrivacy = normalizeScreenPrivacy({
    ...screenPrivacy,
    rules: nextRules,
    updatedAt: Date.now(),
  });
  persistScreenPrivacy();
  appendAudit('screen_privacy.rule_removed', {
    id: ruleId,
    source: String(options.source || 'api').slice(0, 80),
  });
  return screenPrivacySnapshot();
}

function screenPrivacyRegionPresetById(id) {
  const presetId = String(id || '').trim();
  return SCREEN_PRIVACY_REGION_PRESETS.find((preset) => preset.id === presetId) || null;
}

function screenPrivacyRegionPresetRuleInput(preset, options = {}) {
  return {
    id: options.id || `region_preset_${preset.id}`,
    kind: 'region',
    effect: 'blur',
    label: options.label || preset.label,
    regionPresetId: preset.id,
    regionPresetLabel: preset.label,
    region: preset.region,
    enabled: options.enabled !== false,
    createdAt: Date.now(),
    updatedAt: Date.now(),
  };
}

function screenPrivacyRegionPresetRule(preset, options = {}) {
  return normalizeScreenPrivacyRules([screenPrivacyRegionPresetRuleInput(preset, options)])[0];
}

function screenPrivacyRegionPresetList(options = {}) {
  const currentIds = new Set((Array.isArray(screenPrivacy?.rules) ? screenPrivacy.rules : []).map((rule) => rule.id));
  const includeRules = options.includeRules === true || String(options.includeRules || '').toLowerCase() === 'true';
  const presets = SCREEN_PRIVACY_REGION_PRESETS.map((preset) => {
    const rule = screenPrivacyRegionPresetRule(preset);
    return {
      id: preset.id,
      label: preset.label,
      description: preset.description,
      applied: Boolean(rule && currentIds.has(rule.id)),
      ruleId: rule?.id || '',
      region: rule?.region || normalizeScreenPrivacyRegion(preset.region),
      rule: includeRules ? rule : undefined,
    };
  });
  return {
    ok: true,
    count: presets.length,
    presets,
  };
}

function screenPrivacyRegionPresetPreview(id, options = {}) {
  const preset = screenPrivacyRegionPresetById(id);
  if (!preset) throw new Error(`Unknown screen privacy region preset: ${id || 'missing'}.`);
  const rule = screenPrivacyRegionPresetRule(preset, options);
  if (!rule) throw new Error(`Invalid screen privacy region preset: ${id}.`);
  const existing = Array.isArray(screenPrivacy.rules) ? screenPrivacy.rules : [];
  const existingIds = new Set(existing.map((item) => item.id));
  const baseRules = existing.filter((item) => item.id !== rule.id);
  const privacy = normalizeScreenPrivacy({
    ...screenPrivacy,
    rules: [...baseRules, rule],
    updatedAt: Date.now(),
  });
  const maskPreview = screenPrivacyRegionMaskPreview({
    width: options.width || 96,
    height: options.height || 64,
    mode: privacy.mode,
    rules: [rule],
  });
  return {
    ok: true,
    dryRun: options.dryRun !== false,
    preset: {
      id: preset.id,
      label: preset.label,
      description: preset.description,
      region: rule.region,
      ruleId: rule.id,
    },
    counts: {
      existing: existing.length,
      wouldAdd: existingIds.has(rule.id) ? 0 : 1,
      wouldUpdate: existingIds.has(rule.id) ? 1 : 0,
      nextTotal: privacy.ruleCounts.total,
      nextEnabled: privacy.ruleCounts.enabled,
    },
    rule,
    privacy,
    maskPreview,
    output: `${preset.label}: mask ${rule.region.x},${rule.region.y} ${rule.region.width}x${rule.region.height} ${rule.region.unit}.`,
  };
}

function applyScreenPrivacyRegionPreset(id, options = {}) {
  const dryRun = options.dryRun === true || String(options.dryRun || '').toLowerCase() === 'true';
  const preview = screenPrivacyRegionPresetPreview(id, { ...(options || {}), dryRun });
  if (dryRun) return preview;
  screenPrivacy = normalizeScreenPrivacy(preview.privacy);
  persistScreenPrivacy();
  appendAudit('screen_privacy.region_preset_applied', {
    id: preview.preset.id,
    label: preview.preset.label,
    rule: preview.rule.id,
    source: String(options.source || 'api').slice(0, 80),
  });
  return {
    ...preview,
    dryRun: false,
    applied: true,
    privacy: screenPrivacySnapshot(),
    output: `Applied ${preview.preset.label} screen mask. ${screenPrivacy.rulesSummary}`,
  };
}

function screenPrivacyPresetById(id) {
  const presetId = String(id || '').trim();
  return SCREEN_PRIVACY_PRESETS.find((preset) => preset.id === presetId) || null;
}

function screenPrivacyPresetRuleInput(preset, options = {}) {
  const enabled = options.enabled !== false;
  return (preset.rules || []).map((rule) => ({
    ...rule,
    id: `preset_${preset.id}_${rule.id}`,
    presetId: preset.id,
    presetLabel: preset.label,
    enabled,
    createdAt: Date.now(),
    updatedAt: Date.now(),
  }));
}

function screenPrivacyPresetRules(preset, options = {}) {
  return normalizeScreenPrivacyRules(screenPrivacyPresetRuleInput(preset, options));
}

function screenPrivacyPresetList(options = {}) {
  const currentIds = new Set((Array.isArray(screenPrivacy?.rules) ? screenPrivacy.rules : []).map((rule) => rule.id));
  const includeRules = options.includeRules === true || String(options.includeRules || '').toLowerCase() === 'true';
  const presets = SCREEN_PRIVACY_PRESETS.map((preset) => {
    const rules = screenPrivacyPresetRules(preset);
    const appliedCount = rules.filter((rule) => currentIds.has(rule.id)).length;
    const counts = screenPrivacyRuleCounts(rules);
    return {
      id: preset.id,
      label: preset.label,
      description: preset.description,
      recommended: Boolean(preset.recommended),
      applied: appliedCount === rules.length && rules.length > 0,
      appliedCount,
      ruleCount: rules.length,
      counts,
      rulesSummary: screenPrivacyRulesSummary(rules),
      rules: includeRules ? rules : undefined,
    };
  });
  return {
    ok: true,
    count: presets.length,
    recommended: presets.find((preset) => preset.recommended)?.id || '',
    presets,
  };
}

function recommendedScreenPrivacyPresetStatus() {
  const list = screenPrivacyPresetList();
  const preset = list.presets.find((item) => item.id === list.recommended)
    || list.presets.find((item) => item.recommended)
    || null;
  return {
    ok: Boolean(preset),
    recommended: list.recommended,
    preset,
    applied: Boolean(preset?.applied),
  };
}

function screenPrivacyPresetPreview(id, options = {}) {
  const preset = screenPrivacyPresetById(id);
  if (!preset) throw new Error(`Unknown screen privacy preset: ${id || 'missing'}.`);
  const presetRules = screenPrivacyPresetRules(preset, options);
  const existing = Array.isArray(screenPrivacy.rules) ? screenPrivacy.rules : [];
  const presetRuleIds = new Set(presetRules.map((rule) => rule.id));
  const replacePreset = options.replacePreset !== false;
  const baseRules = replacePreset
    ? existing.filter((rule) => rule.presetId !== preset.id && !presetRuleIds.has(rule.id))
    : existing.filter((rule) => !presetRuleIds.has(rule.id));
  const existingIds = new Set(existing.map((rule) => rule.id));
  const wouldAdd = presetRules.filter((rule) => !existingIds.has(rule.id)).length;
  const wouldUpdate = presetRules.length - wouldAdd;
  const privacy = normalizeScreenPrivacy({
    ...screenPrivacy,
    mode: options.mode || screenPrivacy.mode,
    rules: [...baseRules, ...presetRules],
    updatedAt: Date.now(),
  });
  const samples = {
    appPasswordManager: screenPrivacyContextPolicy({
      frontmost: { app: 'Passwords', windowTitle: 'Passwords' },
    }, privacy.rules),
    windowPayment: screenPrivacyContextPolicy({
      frontmost: { app: 'Safari', windowTitle: 'Payment checkout' },
    }, privacy.rules),
    browserLogin: screenPrivacyContextPolicy({
      browser: { host: 'accounts.google.com', title: 'Sign in' },
    }, privacy.rules),
    safeFinder: screenPrivacyContextPolicy({
      frontmost: { app: 'Finder', windowTitle: 'Documents' },
    }, privacy.rules),
  };
  return {
    ok: true,
    dryRun: options.dryRun !== false,
    preset: {
      id: preset.id,
      label: preset.label,
      description: preset.description,
      recommended: Boolean(preset.recommended),
      ruleCount: presetRules.length,
      rulesSummary: screenPrivacyRulesSummary(presetRules),
    },
    counts: {
      existing: existing.length,
      presetRules: presetRules.length,
      wouldAdd,
      wouldUpdate,
      nextTotal: privacy.ruleCounts.total,
      nextEnabled: privacy.ruleCounts.enabled,
    },
    rules: presetRules,
    privacy,
    samples,
    output: [
      `${preset.label}: ${presetRules.length} rule(s).`,
      `Would add ${wouldAdd}, update ${wouldUpdate}.`,
      privacy.rulesSummary,
    ].join(' '),
  };
}

function applyScreenPrivacyPreset(id, options = {}) {
  const dryRun = options.dryRun === true || String(options.dryRun || '').toLowerCase() === 'true';
  const preview = screenPrivacyPresetPreview(id, { ...(options || {}), dryRun });
  if (dryRun) return preview;
  screenPrivacy = normalizeScreenPrivacy(preview.privacy);
  persistScreenPrivacy();
  appendAudit('screen_privacy.preset_applied', {
    id: preview.preset.id,
    label: preview.preset.label,
    rules: preview.preset.ruleCount,
    enabled: screenPrivacy.ruleCounts.enabled,
    source: String(options.source || 'api').slice(0, 80),
  });
  return {
    ...preview,
    dryRun: false,
    applied: true,
    privacy: screenPrivacySnapshot(),
    output: `Applied ${preview.preset.label}: ${preview.preset.ruleCount} rule(s). ${screenPrivacy.rulesSummary}`,
  };
}

function clearLatestScreen(source = 'api') {
  latestScreen = null;
  appendAudit('screen.frame_cleared', { source: String(source || 'api').slice(0, 80) });
  return null;
}

function latestScreenSnapshot(options = {}) {
  if (!latestScreen) return null;
  const snapshot = {
    width: latestScreen.width,
    height: latestScreen.height,
    updatedAt: latestScreen.updatedAt,
    privacy: latestScreen.privacy || screenPrivacySnapshot(),
    source: latestScreen.source || 'unknown',
    displayId: latestScreen.displayId || '',
    displayName: latestScreen.displayName || '',
  };
  if (latestScreen.regionMask) snapshot.regionMask = latestScreen.regionMask;
  if (options.includeImage) snapshot.imageDataUrl = latestScreen.imageDataUrl || '';
  return snapshot;
}

function latestScreenAgeMs() {
  if (!latestScreen?.updatedAt) return Infinity;
  return Math.max(0, Date.now() - Number(latestScreen.updatedAt));
}

function hasFreshLatestScreen(maxAgeMs) {
  return Number.isFinite(latestScreenAgeMs()) && latestScreenAgeMs() <= Math.max(0, Number(maxAgeMs || 0));
}

function transformScreenImageForPrivacy(image, privacy) {
  if (privacy.mode !== 'private') return image;
  const size = image.getSize();
  const factor = Math.max(3, Math.min(12, Number(privacy.blurPx || 5) + 2));
  const small = image.resize({
    width: Math.max(24, Math.round(size.width / factor)),
    height: Math.max(14, Math.round(size.height / factor)),
    quality: 'worst',
  });
  return small.resize({
    width: size.width,
    height: size.height,
    quality: 'worst',
  });
}

function resizeScreenImageForPrivacy(image, privacy) {
  const size = image.getSize();
  const maxWidth = privacy.mode === 'private'
    ? Math.max(320, Number(privacy.maxWidth || 640))
    : Math.max(640, Number(privacy.maxWidth || 1280));
  if (!size.width || size.width <= maxWidth) return image;
  return image.resize({
    width: maxWidth,
    height: Math.max(180, Math.round(size.height * (maxWidth / size.width))),
    quality: 'best',
  });
}

function prepareScreenImageForStorage(image, privacy, options = {}) {
  const normalizedPrivacy = normalizeScreenPrivacy(privacy);
  const transformed = transformScreenImageForPrivacy(resizeScreenImageForPrivacy(image, normalizedPrivacy), normalizedPrivacy);
  const mask = applyScreenPrivacyRegionMasks(transformed, normalizedPrivacy);
  if (mask.required && !mask.applied && options.requireRegionMask !== false) {
    throw new Error(`Screen privacy region mask failed: ${mask.status}`);
  }
  const result = {
    ...mask,
    image: mask.image || transformed,
  };
  return options.withEvidence ? result : result.image;
}

function nativeImageToDataUrl(image, privacy) {
  const buffer = image.toJPEG(Math.max(1, Math.min(100, Math.round((privacy.jpegQuality || 0.46) * 100))));
  return `data:image/jpeg;base64,${buffer.toString('base64')}`;
}

async function captureScreenWithScreencapture() {
  if (process.platform !== 'darwin') throw new Error('screencapture_fallback_unsupported');
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'javis-screen-'));
  const target = path.join(dir, 'screen.jpg');
  try {
    await execFileAsync('/usr/sbin/screencapture', ['-x', '-t', 'jpg', target], guardedChildProcessOptions(
      { timeout: 10000 },
      { source: 'screen_capture_fallback' },
    ));
    const image = nativeImage.createFromPath(target);
    if (image.isEmpty()) throw new Error('screencapture_thumbnail_empty');
    return image;
  } finally {
    try {
      fs.rmSync(dir, { recursive: true, force: true });
    } catch {
      // Temporary cleanup is best-effort.
    }
  }
}

async function captureResidentScreen(options = {}) {
  const privacy = screenPrivacySnapshot();
  const display = screen.getPrimaryDisplay();
  const scale = privacy.mode === 'private'
    ? Math.min(1, Math.max(320, privacy.maxWidth || 640) / Math.max(1, display.size.width))
    : Math.min(1, Math.max(640, privacy.maxWidth || 1280) / Math.max(1, display.size.width));
  const thumbnailSize = {
    width: Math.max(320, Math.round(display.size.width * scale)),
    height: Math.max(180, Math.round(display.size.height * scale)),
  };
  const sources = await desktopCapturer.getSources({
    types: ['screen'],
    thumbnailSize,
    fetchWindowIcons: false,
  });
  const preferredDisplayId = String(options.displayId || display.id || '');
  const source =
    sources.find((item) => String(item.display_id || '') === preferredDisplayId)
    || sources[0];
  let capturedImage = source && !source.thumbnail.isEmpty() ? source.thumbnail : null;
  let captureSource = 'desktopCapturer';
  if (!capturedImage) {
    capturedImage = await captureScreenWithScreencapture();
    captureSource = 'screencapture';
  }
  const prepared = prepareScreenImageForStorage(capturedImage, privacy, { withEvidence: true });
  const storedImage = prepared.image;
  const storedSize = storedImage.getSize();
  const regionMask = {
    applied: prepared.applied,
    required: prepared.required,
    ruleCount: prepared.ruleCount,
    maskedPixels: prepared.maskedPixels,
    regions: prepared.regions,
    status: prepared.status,
  };

  latestScreen = {
    imageDataUrl: nativeImageToDataUrl(storedImage, privacy),
    width: storedSize.width,
    height: storedSize.height,
    privacy,
    source: 'resident',
    displayId: String(source?.display_id || display.id || ''),
    displayName: source?.name || captureSource,
    regionMask,
    updatedAt: Date.now(),
  };
  appendAudit('screen.frame_captured', {
    source: String(options.source || 'resident').slice(0, 80),
    captureSource,
    width: latestScreen.width,
    height: latestScreen.height,
    privacy: privacy.mode,
    displayId: latestScreen.displayId,
    displayName: latestScreen.displayName,
    regionMaskApplied: regionMask.applied,
    regionMaskRules: regionMask.ruleCount,
    regionMaskPixels: regionMask.maskedPixels,
  });
  return latestScreenSnapshot({ includeImage: Boolean(options.includeImage) });
}

function appendAudit(type, data = {}) {
  const rotation = rotateAuditIfNeeded();
  const record = {
    ts: new Date().toISOString(),
    type,
    data,
  };
  try {
    if (rotation.rotated) {
      fs.appendFileSync(AUDIT_FILE, `${JSON.stringify({
        ts: new Date().toISOString(),
        type: 'audit.rotated',
        data: rotation,
      })}\n`, 'utf8');
    }
    fs.appendFileSync(AUDIT_FILE, `${JSON.stringify(record)}\n`, 'utf8');
  } catch (error) {
    fs.appendFileSync(
      path.join(process.cwd(), 'javis-error.log'),
      `${new Date().toISOString()} audit_write_failed ${error.stack || error}\n`,
    );
  }
}

function auditArchiveTimestamp(date = new Date()) {
  return date.toISOString().replace(/[:.]/g, '-');
}

function auditArchiveFiles() {
  try {
    return fs.readdirSync(DATA_DIR)
      .filter((name) => /^audit-\d{4}-\d{2}-\d{2}T.*\.jsonl$/.test(name))
      .map((name) => {
        const file = path.join(DATA_DIR, name);
        let stat = null;
        try {
          stat = fs.statSync(file);
        } catch {}
        return stat ? { name, file, size: stat.size, mtimeMs: stat.mtimeMs } : null;
      })
      .filter(Boolean)
      .sort((a, b) => b.mtimeMs - a.mtimeMs);
  } catch {
    return [];
  }
}

function readAuditTailFromFile(file, retainBytes = AUDIT_RETAIN_BYTES) {
  let fd = null;
  try {
    const stat = fs.statSync(file);
    if (!stat.size) return Buffer.alloc(0);
    const bytesToRead = Math.min(stat.size, Math.max(0, Number(retainBytes || 0)));
    const start = Math.max(0, stat.size - bytesToRead);
    const buffer = Buffer.allocUnsafe(bytesToRead);
    fd = fs.openSync(file, 'r');
    const bytesRead = fs.readSync(fd, buffer, 0, bytesToRead, start);
    let tail = buffer.subarray(0, bytesRead);
    if (start > 0) {
      const newline = tail.indexOf(10);
      tail = newline >= 0 ? tail.subarray(newline + 1) : Buffer.alloc(0);
    }
    return tail;
  } catch {
    return Buffer.alloc(0);
  } finally {
    if (fd !== null) {
      try {
        fs.closeSync(fd);
      } catch {}
    }
  }
}

function pruneAuditArchives(limit = AUDIT_ARCHIVE_LIMIT) {
  const archives = auditArchiveFiles();
  const keep = Math.max(0, Math.min(20, Number(limit || 0)));
  const removed = [];
  for (const archive of archives.slice(keep)) {
    try {
      fs.unlinkSync(archive.file);
      removed.push({ name: archive.name, size: archive.size });
    } catch {}
  }
  return { archives: archives.slice(0, keep), removed };
}

function auditStorageSnapshot() {
  let currentBytes = 0;
  let currentMtimeMs = 0;
  try {
    const stat = fs.statSync(AUDIT_FILE);
    currentBytes = stat.size;
    currentMtimeMs = stat.mtimeMs;
  } catch {}
  const archives = auditArchiveFiles();
  return {
    file: AUDIT_FILE,
    currentBytes,
    currentMtimeMs,
    maxBytes: AUDIT_MAX_BYTES,
    retainBytes: AUDIT_RETAIN_BYTES,
    archiveLimit: AUDIT_ARCHIVE_LIMIT,
    archiveCount: archives.length,
    archiveBytes: archives.reduce((total, archive) => total + Number(archive.size || 0), 0),
    archives: archives.slice(0, AUDIT_ARCHIVE_LIMIT).map((archive) => ({
      name: archive.name,
      size: archive.size,
      mtimeMs: archive.mtimeMs,
    })),
    bounded: currentBytes <= AUDIT_MAX_BYTES,
  };
}

function rotateAuditIfNeeded(options = {}) {
  const force = options.force === true;
  const now = Date.now();
  if (!force && now - auditLastRotationCheckAt < 15000) {
    return { checked: false, rotated: false };
  }
  auditLastRotationCheckAt = now;
  try {
    if (!fs.existsSync(AUDIT_FILE)) return { checked: true, rotated: false, size: 0, maxBytes: AUDIT_MAX_BYTES };
    const stat = fs.statSync(AUDIT_FILE);
    if (stat.size <= AUDIT_MAX_BYTES) {
      return { checked: true, rotated: false, size: stat.size, maxBytes: AUDIT_MAX_BYTES };
    }
    const archiveName = `audit-${auditArchiveTimestamp()}.jsonl`;
    const archiveFile = path.join(DATA_DIR, archiveName);
    fs.renameSync(AUDIT_FILE, archiveFile);
    const retainedTail = readAuditTailFromFile(archiveFile, AUDIT_RETAIN_BYTES);
    fs.writeFileSync(AUDIT_FILE, retainedTail.length ? retainedTail : '', 'utf8');
    const prune = pruneAuditArchives();
    const currentBytes = fs.existsSync(AUDIT_FILE) ? fs.statSync(AUDIT_FILE).size : 0;
    return {
      checked: true,
      rotated: true,
      archive: archiveName,
      previousBytes: stat.size,
      retainedBytes: currentBytes,
      maxBytes: AUDIT_MAX_BYTES,
      retainBytes: AUDIT_RETAIN_BYTES,
      prunedArchives: prune.removed.length,
    };
  } catch (error) {
    try {
      fs.appendFileSync(
        path.join(process.cwd(), 'javis-error.log'),
        `${new Date().toISOString()} audit_rotate_failed ${error.stack || error}\n`,
      );
    } catch {}
    return {
      checked: true,
      rotated: false,
      error: error instanceof Error ? error.message : String(error),
    };
  }
}

function normalizeJobAttempts(value) {
  const list = Array.isArray(value) ? value : [];
  return list
    .map((attempt) => (attempt && typeof attempt === 'object' ? {
      id: String(attempt.id || crypto.randomUUID()).slice(0, 120),
      tool: String(attempt.tool || attempt.mode || '').slice(0, 80),
      command: redactCommandForLog(attempt.command || ''),
      status: String(attempt.status || '').slice(0, 40),
      summary: compactRecordText(attempt.summary || attempt.error || '', 500),
      startedAt: Number(attempt.startedAt || 0),
      completedAt: Number(attempt.completedAt || 0),
    } : null))
    .filter(Boolean)
    .slice(-12);
}

function normalizeRecoveryPlan(plan) {
  if (!plan || typeof plan !== 'object') return null;
  const nextActions = Array.isArray(plan.nextActions) ? plan.nextActions : [];
  const diagnostics = plan.diagnostics && typeof plan.diagnostics === 'object' ? plan.diagnostics : null;
  return {
    failureKind: String(plan.failureKind || '').slice(0, 80),
    summary: compactRecordText(plan.summary || '', 800),
    attempted: Array.isArray(plan.attempted)
      ? plan.attempted.map((item) => compactRecordText(item, 240)).filter(Boolean).slice(0, 8)
      : [],
    nextActions: nextActions
      .map((action) => (action && typeof action === 'object' ? {
        label: compactRecordText(action.label || '', 120),
        type: String(action.type || 'manual').slice(0, 80),
        mode: String(action.mode || '').slice(0, 40),
        riskLevel: Math.max(0, Math.min(4, Number(action.riskLevel || 0))),
        autoEligible: Boolean(action.autoEligible),
        command: redactCommandForLog(action.command || ''),
        reason: compactRecordText(action.reason || '', 300),
      } : null))
      .filter(Boolean)
      .slice(0, 8),
    diagnostics: diagnostics ? {
      overall: String(diagnostics.overall || '').slice(0, 40),
      summary: compactRecordText(diagnostics.summary || '', 500),
      counts: {
        ready: Math.max(0, Number(diagnostics.counts?.ready || 0)),
        warning: Math.max(0, Number(diagnostics.counts?.warning || 0)),
        blocked: Math.max(0, Number(diagnostics.counts?.blocked || 0)),
        total: Math.max(0, Number(diagnostics.counts?.total || 0)),
      },
      primaryIssue: diagnostics.primaryIssue && typeof diagnostics.primaryIssue === 'object' ? {
        id: String(diagnostics.primaryIssue.id || '').slice(0, 80),
        label: compactRecordText(diagnostics.primaryIssue.label || '', 120),
        status: String(diagnostics.primaryIssue.status || '').slice(0, 40),
        summary: compactRecordText(diagnostics.primaryIssue.summary || '', 300),
        next: compactRecordText(diagnostics.primaryIssue.next || '', 300),
      } : null,
      runtime: diagnostics.runtime && typeof diagnostics.runtime === 'object' ? {
        localExecutionEnabled: Boolean(diagnostics.runtime.localExecutionEnabled),
        trustedLocalMode: Boolean(diagnostics.runtime.trustedLocalMode),
        dryRun: Boolean(diagnostics.runtime.dryRun),
        maxAutoRiskLevel: Math.max(0, Math.min(4, Number(diagnostics.runtime.maxAutoRiskLevel || 0))),
        requireApprovalAtRiskLevel: Math.max(0, Math.min(4, Number(diagnostics.runtime.requireApprovalAtRiskLevel || 0))),
      } : null,
      workers: diagnostics.workers && typeof diagnostics.workers === 'object' ? {
        codex: diagnostics.workers.codex && typeof diagnostics.workers.codex === 'object' ? {
          available: Boolean(diagnostics.workers.codex.available),
          command: redactCommandForLog(diagnostics.workers.codex.command || ''),
        } : null,
        claude: diagnostics.workers.claude && typeof diagnostics.workers.claude === 'object' ? {
          available: Boolean(diagnostics.workers.claude.available),
          command: redactCommandForLog(diagnostics.workers.claude.command || ''),
        } : null,
      } : null,
      policy: diagnostics.policy && typeof diagnostics.policy === 'object' ? {
        codeAgentEnabled: diagnostics.policy.codeAgentEnabled !== false,
        codeAgentAllowedCommands: uniqueStringList(diagnostics.policy.codeAgentAllowedCommands, []),
      } : null,
    } : null,
    generatedAt: Number(plan.generatedAt || Date.now()),
  };
}

function normalizePersistedJob(job) {
  if (!job || typeof job !== 'object' || !job.id) return null;
  const status = ['queued', 'running', 'done', 'failed', 'cancelled'].includes(job.status) ? job.status : 'failed';
  const interrupted = status === 'queued' || status === 'running';
  return {
    id: String(job.id),
    title: String(job.title || 'Untitled task').slice(0, 120),
    mode: ['background', 'codex', 'claude', 'cli'].includes(job.mode) ? job.mode : 'background',
    status: interrupted ? 'failed' : status,
    createdAt: Number(job.createdAt || Date.now()),
    updatedAt: interrupted ? Date.now() : Number(job.updatedAt || Date.now()),
    startedAt: interrupted ? Number(job.startedAt || 0) : Number(job.startedAt || 0),
    completedAt: interrupted ? Date.now() : Number(job.completedAt || 0),
    pid: interrupted ? null : job.pid || null,
    source: String(job.source || ''),
    workflowId: String(job.workflowId || ''),
    parentJobId: String(job.parentJobId || ''),
    recoveryForJobId: String(job.recoveryForJobId || ''),
    task: String(job.task || job.command || job.title || '').slice(0, 24000),
    command: String(job.command || '').slice(0, 4000),
    timeoutMs: Math.max(1000, Math.min(3600000, Number(job.timeoutMs || 180000))),
    cancelRequested: false,
    log: interrupted ? 'Interrupted by previous JAVIS shutdown.' : String(job.log || ''),
    result: interrupted ? 'This job was not completed before the previous process exited.' : String(job.result || ''),
    attempts: normalizeJobAttempts(job.attempts),
    failureKind: String(job.failureKind || '').slice(0, 80),
    recoveryPlan: normalizeRecoveryPlan(job.recoveryPlan),
    skillRecallPlan: normalizeSkillRecallPlan(job.skillRecallPlan),
  };
}

function redactUrlForStorage(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  try {
    const parsed = new URL(raw);
    if (parsed.protocol === 'http:' || parsed.protocol === 'https:') {
      return `${parsed.origin}${parsed.pathname}${parsed.search ? '?[redacted]' : ''}${parsed.hash ? '#[redacted]' : ''}`;
    }
    return raw;
  } catch {
    return raw.replace(/[?#].*$/, (suffix) => (suffix.startsWith('?') ? '?[redacted]' : '#[redacted]'));
  }
}

function normalizeWorkflowContinuationLink(link = {}, index = 0) {
  const href = normalizeBrowserHref(link?.href || link?.url);
  if (!href) return null;
  let host = '';
  try {
    host = new URL(href).hostname.replace(/^www\./i, '');
  } catch {
    return null;
  }
  const normalized = {
    index: Math.max(1, Math.min(999, Number(link.index || index + 1))),
    text: compactRecordText(link.text || link.title || link.label || href, 180) || href,
    href,
    host,
    sameHost: Boolean(link.sameHost),
  };
  if (link.sourceTitle) normalized.sourceTitle = compactRecordText(link.sourceTitle, 180);
  if (link.sourceUrl) normalized.sourceUrl = redactUrlForStorage(link.sourceUrl).slice(0, 2000);
  return normalized;
}

function normalizeWorkflowContinuationLinks(value, limit = 8) {
  return (Array.isArray(value) ? value : [])
    .map((link, index) => normalizeWorkflowContinuationLink(link, index))
    .filter(Boolean)
    .slice(0, Math.max(0, Math.min(12, Number(limit || 8))));
}

function normalizeWorkflowContinuationAction(action = {}, index = 0) {
  if (!action || typeof action !== 'object') return null;
  const rawArguments = action.arguments && typeof action.arguments === 'object' ? action.arguments : {};
  const urls = normalizeBrowserResearchUrls({ urls: rawArguments.urls }, 5);
  const query = compactRecordText(rawArguments.query || '', 240);
  const maxPages = Math.max(1, Math.min(5, Number(rawArguments.maxPages || urls.length || 3)));
  if (!urls.length && !query) return null;
  const args = {
    intent: 'research',
    mode: normalizeBrowserWorkflowMode(rawArguments.mode || action.mode || 'quick'),
    maxPages,
  };
  if (urls.length) args.urls = urls;
  if (query) args.query = query;
  const openWaitMs = Number(rawArguments.openWaitMs || rawArguments.waitMsAfterOpen || 0);
  if (Number.isFinite(openWaitMs) && openWaitMs > 0) {
    args.openWaitMs = Math.max(500, Math.min(8000, Math.floor(openWaitMs)));
  }
  return {
    type: compactRecordText(action.type || `action_${index + 1}`, 80),
    label: compactRecordText(action.label || 'Continue browser research', 180),
    reason: compactRecordText(action.reason || '', 360),
    arguments: args,
  };
}

function normalizeWorkflowContinuation(value = {}) {
  if (!value || typeof value !== 'object') return null;
  const selectedLinks = normalizeWorkflowContinuationLinks(value.selectedLinks, 12);
  const remainingSearchCandidates = normalizeWorkflowContinuationLinks(value.remainingSearchCandidates, 8);
  const failedLinks = normalizeWorkflowContinuationLinks(value.failedLinks, 8);
  const followUpLinks = normalizeWorkflowContinuationLinks(value.followUpLinks, 8);
  const nextActions = (Array.isArray(value.nextActions) ? value.nextActions : [])
    .map((action, index) => normalizeWorkflowContinuationAction(action, index))
    .filter(Boolean)
    .slice(0, 5);
  const status = compactRecordText(value.status || '', 80);
  const summary = compactRecordText(value.summary || '', 700);
  const normalized = {
    status,
    summary,
    reviewedCount: Math.max(0, Number(value.reviewedCount || 0)),
    failedCount: Math.max(0, Number(value.failedCount || 0)),
    selectedCount: Math.max(0, Number(value.selectedCount || selectedLinks.length || 0)),
    remainingCandidateCount: Math.max(0, Number(value.remainingCandidateCount || remainingSearchCandidates.length || 0)),
    followUpLinkCount: Math.max(0, Number(value.followUpLinkCount || followUpLinks.length || 0)),
    selectedLinks,
    remainingSearchCandidates,
    failedLinks,
    followUpLinks,
    nextActions,
  };
  const hasMeaningfulData = status || summary || selectedLinks.length || remainingSearchCandidates.length
    || failedLinks.length || followUpLinks.length || nextActions.length;
  return hasMeaningfulData ? normalized : null;
}

function normalizeBrowserFillDraftTarget(value = {}) {
  if (!value || typeof value !== 'object') return null;
  const steps = (Array.isArray(value.steps) ? value.steps : [])
    .map((step) => ({
      index: Math.max(0, Number(step?.index || 0)),
      field: compactRecordText(step?.field || step?.query || '', 120),
      action: compactRecordText(step?.action || '', 40),
      selector: compactRecordText(step?.selector || '', 220),
      valueBytes: Math.max(0, Number(step?.valueBytes || step?.expectedBytes || 0)),
      reason: compactRecordText(step?.reason || '', 220),
    }))
    .filter((step) => step.field || step.selector)
    .slice(0, 12);
  const blocked = (Array.isArray(value.blocked) ? value.blocked : [])
    .map((item) => ({
      field: compactRecordText(item?.field || item?.name || '', 120),
      reason: compactRecordText(item?.reason || '', 160),
      requiresUserPresence: item?.requiresUserPresence !== false,
      requiresSensitiveValue: item?.requiresSensitiveValue !== false,
      storesValue: false,
    }))
    .filter((item) => item.field || item.reason)
    .slice(0, 12);
  const version = Math.max(1, Number(value.version || 1));
  const safeStepCount = Math.max(0, Number(value.safeStepCount || value.plannedFieldCount || steps.length || 0));
  const blockedFieldCount = Math.max(0, Number(value.blockedFieldCount || blocked.length || 0));
  if (!steps.length && !blocked.length && !safeStepCount && !blockedFieldCount) return null;
  return {
    version,
    source: compactRecordText(value.source || 'browser_fill_draft', 80),
    status: compactRecordText(value.status || '', 80),
    summary: compactRecordText(value.summary || '', 500),
    safeStepCount,
    blockedFieldCount,
    verifiedFieldCount: Math.max(0, Number(value.verifiedFieldCount || 0)),
    verificationStatus: compactRecordText(value.verificationStatus || '', 80),
    recoveryStatus: compactRecordText(value.recoveryStatus || '', 80),
    fixture: Boolean(value.fixture),
    confirmed: Boolean(value.confirmed),
    confirmationRequired: Boolean(value.confirmationRequired),
    steps,
    blocked,
  };
}

function normalizePersistedWorkflow(workflow, fromDisk = false) {
  if (!workflow || typeof workflow !== 'object' || !workflow.id) return null;
  const status = ['queued', 'running', 'done', 'failed', 'cancelled', 'blocked'].includes(workflow.status)
    ? workflow.status
    : 'failed';
  const interrupted = fromDisk && (status === 'queued' || status === 'running');
  const target = workflow.target && typeof workflow.target === 'object' ? workflow.target : {};
  return {
    id: String(workflow.id),
    kind: String(workflow.kind || 'general').slice(0, 60),
    source: String(workflow.source || '').slice(0, 80),
    status: interrupted ? 'failed' : status,
    title: String(workflow.title || 'Untitled workflow').slice(0, 180),
    intent: String(workflow.intent || '').slice(0, 80),
    mode: String(workflow.mode || '').slice(0, 40),
    request: String(workflow.request || '').slice(0, 12000),
    result: interrupted ? 'Workflow was interrupted by previous JAVIS shutdown.' : String(workflow.result || '').slice(0, 100000),
    parentWorkflowId: String(workflow.parentWorkflowId || ''),
    target: {
      app: String(target.app || '').slice(0, 120),
      title: String(target.title || '').slice(0, 300),
      url: redactUrlForStorage(target.url).slice(0, 2000),
      path: String(target.path || '').slice(0, 2000),
      type: String(target.type || '').slice(0, 80),
      fallback: String(target.fallback || '').slice(0, 80),
      textLength: Number(target.textLength || 0),
      returnedLength: Number(target.returnedLength || 0),
      resultCount: Number(target.resultCount || 0),
      appId: String(target.appId || '').slice(0, 120),
      appDomain: String(target.appDomain || '').slice(0, 80),
      appInstalled: Boolean(target.appInstalled),
      appPath: String(target.appPath || '').slice(0, 2000),
      candidateCount: Number(target.candidateCount || 0),
      stageCount: Number(target.stageCount || 0),
      focusedStageId: String(target.focusedStageId || target.stageId || '').slice(0, 80),
      stageId: String(target.stageId || target.focusedStageId || '').slice(0, 80),
      actionId: String(target.actionId || '').slice(0, 120),
      actionCount: Number(target.actionCount || 0),
      riskLevel: Number(target.riskLevel || 0),
      safeToAutoRun: Boolean(target.safeToAutoRun),
      confirmationRequired: Boolean(target.confirmationRequired),
      fillDraft: normalizeBrowserFillDraftTarget(target.fillDraft),
    },
    jobId: String(workflow.jobId || ''),
    continuation: normalizeWorkflowContinuation(workflow.continuation),
    createdAt: Number(workflow.createdAt || Date.now()),
    updatedAt: interrupted ? Date.now() : Number(workflow.updatedAt || Date.now()),
    completedAt: interrupted ? Date.now() : Number(workflow.completedAt || 0),
  };
}

function normalizeRoutingStatus(value) {
  const status = String(value || '').trim();
  return ['preview', 'queued', 'running', 'done', 'failed', 'cancelled', 'blocked', 'approval_required'].includes(status)
    ? status
    : 'preview';
}

function normalizeRoutingLane(value) {
  const lane = String(value || '').trim().toLowerCase();
  return ['quick', 'background', 'codex', 'claude', 'local'].includes(lane) ? lane : 'quick';
}

function laneContractForLane(value) {
  const lane = String(value || '').trim().toLowerCase();
  if (!lane) return null;
  return LANE_CONTRACTS.find((contract) => (
    contract.id === lane ||
    (Array.isArray(contract.aliases) && contract.aliases.includes(lane))
  )) || null;
}

function laneContractIdForLane(value) {
  return laneContractForLane(value)?.id || '';
}

function laneContractReference(value) {
  const contract = laneContractForLane(value);
  if (!contract) return null;
  return {
    id: contract.id,
    label: contract.label,
    owner: contract.owner,
    riskBoundary: contract.riskBoundary,
    defaultHandoffLane: contract.handoff?.defaultLane || '',
  };
}

function ownerForRoutingLane(lane) {
  if (lane === 'background') return 'background';
  if (lane === 'codex') return 'codex';
  if (lane === 'claude') return 'claude';
  if (lane === 'local') return 'local';
  return 'realtime';
}

function normalizeRoutingOwnership(value) {
  const raw = value && typeof value === 'object' ? value : {};
  const access = ['read', 'write'].includes(String(raw.access || '').trim()) ? String(raw.access).trim() : 'read';
  const conflicts = Array.isArray(raw.conflicts)
    ? raw.conflicts.slice(0, 8).map((conflict) => ({
        index: Math.max(0, Number(conflict?.index || 0)),
        owner: String(conflict?.owner || '').slice(0, 80),
        key: compactRecordText(conflict?.key || '', 220),
        task: compactRecordText(conflict?.task || '', 180),
      }))
    : [];
  return {
    access,
    key: compactRecordText(raw.key || '', 220),
    parallelSafe: raw.parallelSafe !== false,
    serialized: Boolean(raw.serialized),
    reason: compactRecordText(raw.reason || '', 240),
    conflicts,
  };
}

function normalizeContextPlan(value) {
  const raw = value && typeof value === 'object' ? value : {};
  const rawNeeds = raw.needs && typeof raw.needs === 'object' ? raw.needs : {};
  const needs = {
    residentState: Boolean(rawNeeds.residentState),
    macContext: Boolean(rawNeeds.macContext),
    screen: Boolean(rawNeeds.screen),
    vision: Boolean(rawNeeds.vision),
    accessibility: Boolean(rawNeeds.accessibility),
    browserContext: Boolean(rawNeeds.browserContext),
    recentActivity: Boolean(rawNeeds.recentActivity),
    browserActivity: Boolean(rawNeeds.browserActivity),
    browserPage: Boolean(rawNeeds.browserPage),
    browserDom: Boolean(rawNeeds.browserDom),
    perceptionStatus: Boolean(rawNeeds.perceptionStatus),
    clipboard: Boolean(rawNeeds.clipboard),
    clipboardText: Boolean(rawNeeds.clipboardText),
    files: Boolean(rawNeeds.files),
    knowledge: Boolean(rawNeeds.knowledge),
    memory: Boolean(rawNeeds.memory),
    learning: Boolean(rawNeeds.learning),
    localSkills: Boolean(rawNeeds.localSkills),
    delegatedWorkerContext: Boolean(rawNeeds.delegatedWorkerContext),
    localExecution: Boolean(rawNeeds.localExecution),
  };
  const rawObserve = raw.observeOptions && typeof raw.observeOptions === 'object' ? raw.observeOptions : {};
  return {
    version: 1,
    mode: ['minimal', 'resident', 'screen', 'browser', 'file', 'knowledge', 'app', 'worker', 'full'].includes(String(raw.mode || ''))
      ? String(raw.mode)
      : 'minimal',
    summary: compactRecordText(raw.summary || '', 220),
    needs,
    reasons: Array.isArray(raw.reasons)
      ? raw.reasons.map((item) => compactRecordText(item, 160)).filter(Boolean).slice(0, 8)
      : [],
    recommendedTools: Array.isArray(raw.recommendedTools)
      ? Array.from(new Set(raw.recommendedTools.map((item) => String(item || '').trim()).filter(Boolean))).slice(0, 10)
      : [],
    observeOptions: {
      captureScreen: rawObserve.captureScreen === true,
      includeAccessibility: rawObserve.includeAccessibility === true,
      describeScreen: rawObserve.describeScreen === true,
      includeClipboardText: rawObserve.includeClipboardText === true,
      maxNodes: Math.max(10, Math.min(500, Number(rawObserve.maxNodes || 80))),
      maxDepth: Math.max(1, Math.min(12, Number(rawObserve.maxDepth || 5))),
    },
    browser: {
      maxChars: Math.max(1000, Math.min(30000, Number(raw.browser?.maxChars || 12000))),
      domLimit: Math.max(5, Math.min(100, Number(raw.browser?.domLimit || 40))),
    },
    privacy: {
      screenMode: String(raw.privacy?.screenMode || 'private').slice(0, 40),
      rationale: compactRecordText(raw.privacy?.rationale || '', 180),
    },
    skipped: Array.isArray(raw.skipped)
      ? raw.skipped.map((item) => String(item || '').trim()).filter(Boolean).slice(0, 12)
      : [],
    generatedAt: raw.generatedAt || new Date().toISOString(),
  };
}

function normalizeSkillPlanSkill(value = {}) {
  const raw = value && typeof value === 'object' ? value : {};
  return {
    name: compactRecordText(raw.name || '', 120),
    kind: ['demonstration', 'learning', 'user'].includes(String(raw.kind || '')) ? String(raw.kind) : 'user',
    path: String(raw.path || '').slice(0, 500),
    demonstrationId: String(raw.demonstrationId || '').slice(0, 120),
    score: Math.max(0, Number(raw.score || 0)),
    summary: compactRecordText(raw.summary || raw.description || raw.workflow || raw.replayPlan || '', 360),
  };
}

function normalizeSkillRecallPlan(value) {
  const raw = value && typeof value === 'object' ? value : {};
  const skills = Array.isArray(raw.skills)
    ? raw.skills.map(normalizeSkillPlanSkill).filter((skill) => skill.name).slice(0, 5)
    : [];
  const primarySkill = raw.primarySkill
    ? normalizeSkillPlanSkill(raw.primarySkill)
    : skills[0] || normalizeSkillPlanSkill({});
  const applied = Boolean(raw.applied || skills.length);
  const shortcut = raw.shortcutCandidate && typeof raw.shortcutCandidate === 'object' ? raw.shortcutCandidate : {};
  return {
    version: 1,
    applied,
    matched: Math.max(skills.length, Number(raw.matched || 0)),
    decisionEffect: compactRecordText(raw.decisionEffect || (applied ? 'attached_recalled_procedure_to_route_plan' : 'no_matching_local_skill'), 180),
    summary: compactRecordText(raw.summary || '', 360),
    primarySkill,
    skills,
    recommendedTools: Array.isArray(raw.recommendedTools)
      ? Array.from(new Set(raw.recommendedTools.map((item) => String(item || '').trim()).filter(Boolean))).slice(0, 12)
      : [],
    planSteps: Array.isArray(raw.planSteps)
      ? raw.planSteps.map((item) => compactRecordText(item, 260)).filter(Boolean).slice(0, 8)
      : [],
    confirmationRequired: applied ? raw.confirmationRequired !== false : Boolean(raw.confirmationRequired),
    confirmationGates: Array.isArray(raw.confirmationGates)
      ? raw.confirmationGates.map((item) => compactRecordText(item, 140)).filter(Boolean).slice(0, 8)
      : applied
        ? ['action_policy', 'control_mode', 'explicit_confirmation_for_replay_or_mutation']
        : [],
    shortcutCandidate: {
      eligible: Boolean(shortcut.eligible),
      reason: compactRecordText(shortcut.reason || '', 220),
      nextAction: compactRecordText(shortcut.nextAction || '', 220),
    },
    generatedAt: raw.generatedAt || new Date().toISOString(),
  };
}

function normalizeShortcutPhrase(value) {
  return String(value || '')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

function normalizeShortcutRecord(value = {}) {
  const raw = value && typeof value === 'object' ? value : {};
  const phrase = compactRecordText(raw.phrase || raw.trigger || raw.name || raw.title || '', 120);
  const normalizedPhrase = normalizeShortcutPhrase(phrase);
  const aliases = Array.isArray(raw.aliases)
    ? raw.aliases.map((item) => compactRecordText(item, 120)).filter(Boolean).slice(0, 12)
    : [];
  const skillRecallPlan = normalizeSkillRecallPlan(raw.skillRecallPlan || raw.plan);
  if (!normalizedPhrase || !skillRecallPlan.applied) return null;
  const now = Date.now();
  return {
    id: String(raw.id || crypto.randomUUID()).slice(0, 120),
    title: compactRecordText(raw.title || skillRecallPlan.primarySkill.name || phrase, 160),
    phrase,
    normalizedPhrase,
    aliases,
    normalizedAliases: aliases.map(normalizeShortcutPhrase).filter(Boolean),
    enabled: raw.enabled !== false,
    source: compactRecordText(raw.source || 'api', 80),
    createdAt: Number(raw.createdAt || now),
    updatedAt: Number(raw.updatedAt || now),
    lastUsedAt: Number(raw.lastUsedAt || 0),
    usedCount: Math.max(0, Number(raw.usedCount || 0)),
    routeId: String(raw.routeId || '').slice(0, 120),
    jobId: String(raw.jobId || '').slice(0, 120),
    evidence: {
      routeStatus: compactRecordText(raw.evidence?.routeStatus || raw.routeStatus || '', 40),
      jobStatus: compactRecordText(raw.evidence?.jobStatus || raw.jobStatus || '', 40),
      resultSummary: compactRecordText(raw.evidence?.resultSummary || raw.resultSummary || '', 500),
    },
    skillRecallPlan,
  };
}

function shortcutSnapshot(limit = 50) {
  const items = Array.from(shortcuts.values())
    .sort((a, b) => b.updatedAt - a.updatedAt)
    .slice(0, Math.max(1, Math.min(200, Number(limit || 50))));
  return {
    ok: true,
    file: SHORTCUTS_FILE,
    counts: {
      total: shortcuts.size,
      enabled: Array.from(shortcuts.values()).filter((item) => item.enabled).length,
      disabled: Array.from(shortcuts.values()).filter((item) => !item.enabled).length,
    },
    items,
  };
}

function shortcutMatchesText(shortcut, task) {
  if (!shortcut?.enabled) return false;
  const text = normalizeShortcutPhrase(task);
  if (!text) return false;
  const phrases = [shortcut.normalizedPhrase, ...(shortcut.normalizedAliases || [])].filter(Boolean);
  return phrases.some((phrase) => text === phrase || text.startsWith(`${phrase} `) || text.includes(` ${phrase} `));
}

function shortcutMatchForTask(task) {
  const matches = Array.from(shortcuts.values())
    .filter((shortcut) => shortcutMatchesText(shortcut, task))
    .sort((a, b) => b.normalizedPhrase.length - a.normalizedPhrase.length || b.updatedAt - a.updatedAt);
  return matches[0] || null;
}

function skillRecallPlanFromShortcut(shortcut) {
  const plan = normalizeSkillRecallPlan(shortcut?.skillRecallPlan);
  if (!shortcut || !plan.applied) return normalizeSkillRecallPlan();
  return normalizeSkillRecallPlan({
    ...plan,
    decisionEffect: 'shortcut_phrase_matched',
    summary: `Shortcut "${shortcut.phrase}" recalled ${plan.primarySkill.name}.`,
  });
}

function shortcutCandidateFromRouteRecord(record) {
  const route = record ? normalizePersistedRoutingRecord(record) : null;
  const skillRecallPlan = normalizeSkillRecallPlan(route?.skillRecallPlan);
  if (!route || !skillRecallPlan.applied || !skillRecallPlan.shortcutCandidate.eligible) return null;
  if (route.status !== 'done') return null;
  return {
    source: 'routing',
    routeId: route.id,
    jobId: route.jobId || '',
    title: skillRecallPlan.primarySkill.name || route.taskTitle,
    phrase: skillRecallPlan.primarySkill.name || route.taskTitle,
    taskTitle: route.taskTitle,
    status: route.status,
    eligible: true,
    resultSummary: route.resultSummary,
    skillRecallPlan,
    updatedAt: route.updatedAt,
  };
}

function shortcutCandidateFromJob(job) {
  const skillRecallPlan = normalizeSkillRecallPlan(job?.skillRecallPlan);
  if (!job || !skillRecallPlan.applied || !skillRecallPlan.shortcutCandidate.eligible) return null;
  if (job.status !== 'done') return null;
  return {
    source: 'job',
    jobId: job.id,
    routeId: routeForWorkerJob(job)?.id || '',
    title: skillRecallPlan.primarySkill.name || job.title,
    phrase: skillRecallPlan.primarySkill.name || job.title,
    taskTitle: job.title,
    status: job.status,
    eligible: true,
    resultSummary: job.result || job.log || '',
    skillRecallPlan,
    updatedAt: job.updatedAt,
  };
}

function shortcutPromotionCandidates(options = {}) {
  const limit = Math.max(1, Math.min(50, Number(options.limit || 10)));
  const routeCandidates = Array.from(routingRecords.values()).map(shortcutCandidateFromRouteRecord).filter(Boolean);
  const jobCandidates = Array.from(jobs.values()).map(shortcutCandidateFromJob).filter(Boolean);
  const seen = new Set();
  const items = [...routeCandidates, ...jobCandidates]
    .filter((candidate) => {
      const key = `${candidate.skillRecallPlan.primarySkill.name}:${candidate.routeId}:${candidate.jobId}`;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .sort((a, b) => b.updatedAt - a.updatedAt)
    .slice(0, limit)
    .map((candidate) => ({
      ...candidate,
      resultSummary: compactRecordText(candidate.resultSummary, 500),
    }));
  return {
    ok: true,
    count: items.length,
    items,
  };
}

function upsertShortcutFromPromotion(options = {}) {
  const confirmed = options.confirm === true || String(options.confirm || '').toLowerCase() === 'true';
  const route = options.routeId ? routingRecords.get(String(options.routeId)) || null : null;
  const job = options.jobId ? jobs.get(String(options.jobId)) || null : null;
  const routeCandidate = route ? shortcutCandidateFromRouteRecord(route) : null;
  const jobCandidate = job ? shortcutCandidateFromJob(job) : null;
  const explicitPlan = normalizeSkillRecallPlan(options.skillRecallPlan || options.plan);
  const skillRecallPlan = normalizeSkillRecallPlan(
    routeCandidate?.skillRecallPlan ||
    jobCandidate?.skillRecallPlan ||
    explicitPlan,
  );
  if (!skillRecallPlan.applied) throw new Error('Missing applied skillRecallPlan for shortcut promotion.');
  const phrase = compactRecordText(options.phrase || routeCandidate?.phrase || jobCandidate?.phrase || skillRecallPlan.primarySkill.name, 120);
  const candidate = {
    routeId: String(options.routeId || routeCandidate?.routeId || jobCandidate?.routeId || ''),
    jobId: String(options.jobId || routeCandidate?.jobId || jobCandidate?.jobId || ''),
    title: options.title || routeCandidate?.title || jobCandidate?.title || skillRecallPlan.primarySkill.name,
    phrase,
    aliases: options.aliases,
    source: options.source || 'api',
    skillRecallPlan,
    evidence: {
      routeStatus: route?.status || routeCandidate?.status || '',
      jobStatus: job?.status || jobCandidate?.status || '',
      resultSummary: route?.resultSummary || job?.result || job?.log || routeCandidate?.resultSummary || jobCandidate?.resultSummary || '',
    },
  };
  const shortcut = normalizeShortcutRecord(candidate);
  if (!shortcut) throw new Error('Shortcut phrase and applied skillRecallPlan are required.');
  if (!confirmed) {
    return {
      ok: false,
      status: 409,
      requiresConfirmation: true,
      shortcut,
      output: `Confirm before saving shortcut "${shortcut.phrase}".`,
    };
  }
  const existing = Array.from(shortcuts.values()).find((item) => item.normalizedPhrase === shortcut.normalizedPhrase) || null;
  const next = {
    ...shortcut,
    id: existing?.id || shortcut.id,
    createdAt: existing?.createdAt || shortcut.createdAt,
    usedCount: existing?.usedCount || 0,
    lastUsedAt: existing?.lastUsedAt || 0,
    updatedAt: Date.now(),
  };
  shortcuts.set(next.id, next);
  persistShortcuts();
  appendAudit('shortcut.promoted', {
    id: next.id,
    phrase: next.phrase,
    primarySkill: next.skillRecallPlan.primarySkill.name,
    routeId: next.routeId,
    jobId: next.jobId,
    source: next.source,
  });
  return {
    ok: true,
    shortcut: next,
    shortcuts: shortcutSnapshot(20),
    output: `Shortcut saved: "${next.phrase}" -> ${next.skillRecallPlan.primarySkill.name}.`,
  };
}

function removeShortcut(options = {}) {
  const id = String(options.id || options.shortcutId || '').trim();
  const phrase = normalizeShortcutPhrase(options.phrase || options.trigger || options.name);
  const existing = id
    ? shortcuts.get(id)
    : Array.from(shortcuts.values()).find((item) => item.normalizedPhrase === phrase) || null;
  if (!existing) {
    return {
      ok: false,
      status: 404,
      error: 'Shortcut not found',
      output: 'Shortcut not found.',
    };
  }
  shortcuts.delete(existing.id);
  persistShortcuts();
  appendAudit('shortcut.removed', {
    id: existing.id,
    phrase: existing.phrase,
    source: compactRecordText(options.source || 'api', 80),
  });
  return {
    ok: true,
    removed: existing,
    shortcuts: shortcutSnapshot(20),
    output: `Shortcut removed: "${existing.phrase}".`,
  };
}

function markShortcutUsed(shortcut, source = 'router') {
  if (!shortcut?.id || !shortcuts.has(shortcut.id)) return shortcut;
  const next = {
    ...shortcut,
    usedCount: Number(shortcut.usedCount || 0) + 1,
    lastUsedAt: Date.now(),
    updatedAt: Date.now(),
  };
  shortcuts.set(next.id, next);
  persistShortcuts();
  appendAudit('shortcut.used', {
    id: next.id,
    phrase: next.phrase,
    source: compactRecordText(source, 80),
    usedCount: next.usedCount,
  });
  return next;
}

function normalizePersistedRoutingRecord(record) {
  if (!record || typeof record !== 'object' || !record.id) return null;
  const lane = normalizeRoutingLane(record.lane);
  const status = normalizeRoutingStatus(record.status);
  const completedAt = ['done', 'failed', 'cancelled', 'blocked'].includes(status)
    ? Number(record.completedAt || Date.now())
    : Number(record.completedAt || 0);
  return {
    id: String(record.id),
    taskTitle: compactRecordText(record.taskTitle || record.title || 'Untitled routed task', 180),
    taskPrompt: compactRecordText(record.taskPrompt || record.task || record.taskTitle || record.title || 'Untitled routed task', 2000),
    lane,
    contractId: String(record.contractId || laneContractIdForLane(lane) || lane).slice(0, 80),
    label: String(record.label || (lane === 'background' ? 'Deep' : lane === 'local' ? 'Local' : lane)).slice(0, 80),
    owner: String(record.owner || ownerForRoutingLane(lane)).slice(0, 80),
    scope: compactRecordText(record.scope || '', 220),
    parallelGroup: String(record.parallelGroup || lane).slice(0, 120),
    approvalRequirement: String(record.approvalRequirement || 'none').slice(0, 120),
    status,
    source: String(record.source || 'router').slice(0, 80),
    execute: Boolean(record.execute),
    confidence: Number(record.confidence || 0),
    reason: compactRecordText(record.reason || '', 240),
    jobId: String(record.jobId || '').slice(0, 120),
    workflowId: String(record.workflowId || '').slice(0, 120),
    localCommand: String(record.localCommand || '').slice(0, 80),
    resultLink: String(record.resultLink || '').slice(0, 500),
    resultSummary: compactRecordText(record.resultSummary || '', 500),
    attempts: normalizeJobAttempts(record.attempts),
    failureKind: String(record.failureKind || '').slice(0, 80),
    recoveryPlan: normalizeRecoveryPlan(record.recoveryPlan),
    ownership: normalizeRoutingOwnership(record.ownership),
    memoryMatches: Math.max(0, Number(record.memoryMatches || 0)),
    learningEvidence: normalizeLearningEvidence(record.learningEvidence),
    contextPlan: normalizeContextPlan(record.contextPlan),
    skillRecallPlan: normalizeSkillRecallPlan(record.skillRecallPlan),
    createdAt: Number(record.createdAt || Date.now()),
    updatedAt: Number(record.updatedAt || Date.now()),
    completedAt,
  };
}

function cloneJsonObject(value, fallback = {}) {
  try {
    return JSON.parse(JSON.stringify(value || fallback));
  } catch {
    return fallback;
  }
}

function laneContractSnapshot(options = {}) {
  const requested = String(options.lane || options.id || '').trim().toLowerCase();
  const contracts = requested
    ? LANE_CONTRACTS.filter((contract) => contract.id === requested || contract.aliases?.includes(requested))
    : LANE_CONTRACTS;
  return {
    ok: contracts.length > 0,
    version: 1,
    generatedAt: new Date().toISOString(),
    summary: 'Lane contracts define owner, scope, non-goals, handoff path, tool posture, and risk boundary before model choice.',
    contracts: cloneJsonObject(contracts, []),
    aliases: Object.fromEntries(
      LANE_CONTRACTS.flatMap((contract) => [
        [contract.id, contract.id],
        ...(contract.aliases || []).map((alias) => [alias, contract.id]),
      ]),
    ),
  };
}

const LANE_CONTRACT_REQUIRED_IDS = ['realtime', 'background', 'codex', 'claude', 'local', 'browser', 'file', 'app'];
const LANE_CONTRACT_REQUIRED_FIELDS = ['id', 'label', 'owner', 'owns', 'nonGoals', 'handoff', 'toolPosture', 'riskBoundary'];

function laneContractValidationSnapshot() {
  const contracts = laneContractSnapshot().contracts;
  const ids = contracts.map((contract) => contract.id);
  const missingIds = LANE_CONTRACT_REQUIRED_IDS.filter((id) => !ids.includes(id));
  const incomplete = contracts
    .map((contract) => {
      const missingFields = LANE_CONTRACT_REQUIRED_FIELDS.filter((field) => {
        const value = contract[field];
        if (Array.isArray(value)) return value.length === 0;
        if (value && typeof value === 'object') return Object.keys(value).length === 0;
        return !String(value || '').trim();
      });
      const handoffMissing = !contract.handoff?.defaultLane || !Array.isArray(contract.handoff?.tools) || contract.handoff.tools.length === 0;
      return {
        id: contract.id,
        missingFields: handoffMissing ? Array.from(new Set([...missingFields, 'handoff.tools'])) : missingFields,
      };
    })
    .filter((item) => item.missingFields.length);
  const aliases = {
    quick: laneContractIdForLane('quick'),
    cli: laneContractIdForLane('cli'),
    dom: laneContractIdForLane('dom'),
    accessibility: laneContractIdForLane('accessibility'),
  };
  const aliasReady =
    aliases.quick === 'realtime' &&
    aliases.cli === 'local' &&
    aliases.dom === 'browser' &&
    aliases.accessibility === 'app';
  return {
    ok: missingIds.length === 0 && incomplete.length === 0 && aliasReady,
    count: contracts.length,
    ids,
    missingIds,
    incomplete,
    aliases,
  };
}

