function loadPersistedShortcuts() {
  if (!fs.existsSync(SHORTCUTS_FILE)) return;
  try {
    const parsed = JSON.parse(fs.readFileSync(SHORTCUTS_FILE, 'utf8'));
    const list = Array.isArray(parsed?.shortcuts) ? parsed.shortcuts : [];
    shortcuts.clear();
    for (const rawShortcut of list) {
      const shortcut = normalizeShortcutRecord(rawShortcut);
      if (shortcut) shortcuts.set(shortcut.id, shortcut);
    }
    persistShortcuts();
    appendAudit('shortcuts.loaded', { count: shortcuts.size });
  } catch (error) {
    appendAudit('shortcuts.load_failed', { message: error instanceof Error ? error.message : String(error) });
  }
}

function loadPersistedRealtimeDogfoodOperatorSessions() {
  if (!fs.existsSync(REALTIME_DOGFOOD_SESSIONS_FILE)) return;
  try {
    const parsed = JSON.parse(fs.readFileSync(REALTIME_DOGFOOD_SESSIONS_FILE, 'utf8'));
    const list = Array.isArray(parsed?.sessions) ? parsed.sessions : [];
    realtimeDogfoodOperatorSessions.clear();
    for (const rawSession of list) {
      const session = normalizeRealtimeDogfoodOperatorSession(rawSession);
      if (session) realtimeDogfoodOperatorSessions.set(session.id, session);
    }
    persistRealtimeDogfoodOperatorSessions();
    appendAudit('realtime.dogfood_operator_sessions_loaded', { count: realtimeDogfoodOperatorSessions.size });
  } catch (error) {
    appendAudit('realtime.dogfood_operator_sessions_load_failed', { message: error instanceof Error ? error.message : String(error) });
  }
}

function loadPersistedAmbient() {
  if (!fs.existsSync(AMBIENT_FILE)) return;
  try {
    const parsed = JSON.parse(fs.readFileSync(AMBIENT_FILE, 'utf8'));
    const list = Array.isArray(parsed?.events) ? parsed.events : [];
    ambientEvents.splice(0, ambientEvents.length);
    for (const rawEvent of list) {
      const event = normalizeAmbientEvent(rawEvent);
      if (event) ambientEvents.push(event);
    }
    persistAmbient();
    appendAudit('ambient.loaded', { count: ambientEvents.length });
  } catch (error) {
    appendAudit('ambient.load_failed', { message: error instanceof Error ? error.message : String(error) });
  }
}

function loadPersistedLearning() {
  if (!fs.existsSync(LEARNING_FILE)) {
    learnedProfile = normalizeLearnedProfile();
    return;
  }
  try {
    const parsed = JSON.parse(fs.readFileSync(LEARNING_FILE, 'utf8'));
    learnedProfile = normalizeLearnedProfile(parsed?.profile || parsed);
    appendAudit('learning.loaded', { sourceEventCount: learnedProfile.sourceEventCount });
  } catch (error) {
    learnedProfile = normalizeLearnedProfile();
    appendAudit('learning.load_failed', { message: error instanceof Error ? error.message : String(error) });
  }
}

