function productivityWorkflowIntentFromInstruction(instruction) {
  const text = String(instruction || '');
  if (!text.trim()) return '';
  const explicitApp = PRODUCTIVITY_APP_CATALOG.find((item) => creativeAppMatchesText(item, text));
  if (explicitApp?.domain === 'notes') return 'note_capture';
  if (explicitApp?.domain === 'reminders') return 'reminder_create';
  if (explicitApp?.domain === 'calendar') return 'calendar_event';
  if (explicitApp?.domain === 'mail') return 'email_draft';
  if (/邮件|邮箱|email|e-mail|mail|draft|回复|回信|写信/i.test(text)) return 'email_draft';
  if (/日历|会议|行程|预约|约会|calendar|meeting|event|schedule/i.test(text)) return 'calendar_event';
  if (/提醒|待办|todo|to-do|reminder|提醒事项/i.test(text)) return 'reminder_create';
  if (/备忘录|笔记|note|notes|记下|记录/i.test(text)) return 'note_capture';
  return '';
}

function normalizeProductivityWorkflowIntent(value, instruction = '') {
  const raw = String(value || '').trim().toLowerCase();
  if (['note', 'notes', 'note_capture', 'capture_note'].includes(raw)) return 'note_capture';
  if (['reminder', 'reminders', 'todo', 'to_do', 'reminder_create'].includes(raw)) return 'reminder_create';
  if (['calendar', 'event', 'meeting', 'calendar_event'].includes(raw)) return 'calendar_event';
  if (['mail', 'email', 'email_draft', 'draft_email'].includes(raw)) return 'email_draft';
  return productivityWorkflowIntentFromInstruction(instruction) || 'productivity_app';
}

function productivityWorkflowDomain(intent) {
  if (intent === 'note_capture') return 'notes';
  if (intent === 'reminder_create') return 'reminders';
  if (intent === 'calendar_event') return 'calendar';
  if (intent === 'email_draft') return 'mail';
  return '';
}

function productivityAppByName(value) {
  const text = String(value || '').trim();
  if (!text) return null;
  return PRODUCTIVITY_APP_CATALOG.find((item) => creativeAppMatchesText(item, text)) || {
    id: `custom_productivity_${crypto.createHash('sha1').update(text).digest('hex').slice(0, 10)}`,
    name: text,
    domain: '',
    aliases: [text],
    bundleNames: [`${text}.app`],
    custom: true,
  };
}

function publicProductivityAppRecord(appInfo, flags = {}) {
  const appPath = findApplicationBundlePath(appInfo);
  return {
    id: appInfo.id,
    name: appInfo.name,
    domain: appInfo.domain || '',
    installed: Boolean(appPath),
    appPath,
    explicit: Boolean(flags.explicit),
    requested: Boolean(flags.requested),
    custom: Boolean(appInfo.custom),
  };
}

function productivityAppCandidates(instruction, intent, requestedAppName = '') {
  const requestedApp = productivityAppByName(requestedAppName);
  const explicitHits = PRODUCTIVITY_APP_CATALOG.filter((item) => creativeAppMatchesText(item, instruction));
  const domain = productivityWorkflowDomain(intent);
  const domainHits = domain
    ? PRODUCTIVITY_APP_CATALOG.filter((item) => item.domain === domain)
    : PRODUCTIVITY_APP_CATALOG;
  const seen = new Set();
  return [requestedApp, ...explicitHits, ...domainHits, ...PRODUCTIVITY_APP_CATALOG]
    .filter(Boolean)
    .filter((item) => {
      if (seen.has(item.id)) return false;
      seen.add(item.id);
      return true;
    })
    .map((item) => publicProductivityAppRecord(item, {
      explicit: explicitHits.some((hit) => hit.id === item.id),
      requested: requestedApp?.id === item.id,
    }))
    .sort((a, b) => {
      if (a.requested !== b.requested) return a.requested ? -1 : 1;
      if (a.explicit !== b.explicit) return a.explicit ? -1 : 1;
      if (a.installed !== b.installed) return a.installed ? -1 : 1;
      return 0;
    });
}

function productivityWorkflowStages(intent) {
  if (intent === 'reminder_create') {
    return [
      { id: 'capture', label: '确认提醒内容', summary: '确认事项、时间、列表、优先级和是否重复。' },
      { id: 'create', label: '创建提醒', summary: '打开 Reminders 并只创建一条明确的待办。' },
      { id: 'verify', label: '复查提醒', summary: '观察列表，确认提醒内容和时间正确。' },
    ];
  }
  if (intent === 'calendar_event') {
    return [
      { id: 'capture', label: '确认日程信息', summary: '确认标题、日期、开始/结束时间、地点、日历和参与人。' },
      { id: 'create', label: '创建日历事件', summary: '打开 Calendar 并创建可复查的事件草稿。' },
      { id: 'invite', label: '邀请/通知确认', summary: '邀请、通知、发送更新都需要明确确认。' },
      { id: 'verify', label: '复查日程', summary: '观察日历事件，确认时间和参与人。' },
    ];
  }
  if (intent === 'email_draft') {
    return [
      { id: 'capture', label: '确认邮件 brief', summary: '确认收件人、主题、正文要点和语气。' },
      { id: 'draft', label: '创建邮件草稿', summary: '只创建或填写草稿，不发送。' },
      { id: 'review', label: '复查草稿', summary: '复查收件人、主题、正文和附件；发送必须人工确认。' },
    ];
  }
  return [
    { id: 'capture', label: '确认记录内容', summary: '确认标题、正文、标签/文件夹和后续用途。' },
    { id: 'create', label: '创建笔记', summary: '打开 Notes 并创建可复查的笔记。' },
    { id: 'organize', label: '整理归档', summary: '移动文件夹、添加标签或链接前先确认目标。' },
    { id: 'verify', label: '复查笔记', summary: '观察笔记内容和所在位置。' },
  ];
}

function productivityStageIdFromInstruction(instruction, intent) {
  const text = String(instruction || '');
  const signals = [
    ['verify', /复查|确认是否|检查|verify|review/i],
    ['invite', /邀请|参与人|attendee|invite|send update|通知/i],
    ['draft', /草稿|draft|write email|写邮件|回信|回复/i],
    ['organize', /整理|归档|文件夹|标签|tag|folder|organize/i],
    ['create', /创建|新建|添加|加入|create|add|new/i],
    ['capture', /确认|记录|记下|brief|capture|收集/i],
  ];
  const match = signals.find(([stage, pattern]) => {
    if (stage === 'draft' && intent !== 'email_draft') return false;
    if (stage === 'invite' && intent !== 'calendar_event') return false;
    if (stage === 'organize' && intent !== 'note_capture') return false;
    return pattern.test(text);
  });
  return match?.[0] || '';
}

function normalizeProductivityStageId(value, intent, instruction = '') {
  const raw = String(value || '').trim().toLowerCase();
  const aliases = {
    note: 'capture',
    notes: 'capture',
    brief: 'capture',
    collect: 'capture',
    schedule: intent === 'calendar_event' ? 'create' : 'capture',
    compose: intent === 'email_draft' ? 'draft' : 'create',
    write: intent === 'email_draft' ? 'draft' : 'create',
    email: 'draft',
    reminder: 'create',
    event: 'create',
    check: 'verify',
  };
  const stageIds = new Set(productivityWorkflowStages(intent).map((stage) => stage.id));
  const aliased = aliases[raw] || raw;
  if (stageIds.has(aliased)) return aliased;
  const inferred = productivityStageIdFromInstruction(instruction, intent);
  if (inferred && stageIds.has(inferred)) return inferred;
  return productivityWorkflowStages(intent)[0]?.id || 'capture';
}

function productivityStageDefinition(intent, stageId) {
  return productivityWorkflowStages(intent).find((stage) => stage.id === stageId) || productivityWorkflowStages(intent)[0] || null;
}

function productivityAction(id, type, label, options = {}) {
  return {
    id,
    type,
    label,
    summary: options.summary || '',
    tool: options.tool || '',
    riskLevel: Math.max(1, Math.min(4, Number(options.riskLevel || 2))),
    safeToAutoRun: Boolean(options.safeToAutoRun),
    requires: Array.isArray(options.requires) ? options.requires : [],
    confirmationRequired: Boolean(options.confirmationRequired),
    instruction: options.instruction || '',
    args: options.args || {},
    steps: options.steps || undefined,
    forbidden: Boolean(options.forbidden),
    nativeAutomation: Boolean(options.nativeAutomation),
    nativeKind: options.nativeKind || '',
  };
}

function productivityStageActionPack({ intent, stageId, selectedApp, instruction }) {
  const stage = productivityStageDefinition(intent, stageId);
  const appName = selectedApp?.name || 'productivity app';
  const actions = [
    productivityAction('open_app', 'app_workflow', `打开/聚焦 ${appName}`, {
      tool: 'run_app_workflow',
      riskLevel: 2,
      safeToAutoRun: true,
      summary: '低风险：只打开或聚焦目标生产力应用。',
      steps: [
        { type: 'open_app', app: appName, label: `Open ${appName}` },
        { type: 'wait', ms: 900, label: 'Wait for productivity app' },
      ],
    }),
    productivityAction('observe_app', 'observe', '观察当前应用窗口', {
      tool: 'observe_now',
      riskLevel: 1,
      safeToAutoRun: true,
      summary: '读取当前 App、屏幕和 Accessibility 树，确认下一步目标。',
      args: { captureScreen: 'auto', includeAccessibility: true, maxNodes: 160, maxDepth: 8 },
    }),
  ];

  if (intent === 'reminder_create') {
    actions.push(
      productivityAction('collect_reminder', 'prompt', '补齐提醒信息', {
        riskLevel: 1,
        summary: '确认提醒标题、截止时间、列表、优先级和重复规则。',
        requires: ['title', 'dueAt'],
      }),
      productivityAction('create_reminder', 'native_productivity', '创建一条提醒', {
        tool: 'run_productivity_action',
        riskLevel: 3,
        confirmationRequired: true,
        requires: ['title', 'dueAt'],
        summary: '只创建一条明确提醒；不会批量改动列表。',
        instruction: `在 ${appName} 中创建一条提醒，先复查标题和时间，不删除、不完成任何现有提醒。`,
        nativeAutomation: true,
        nativeKind: 'reminder',
      }),
    );
  } else if (intent === 'calendar_event') {
    actions.push(
      productivityAction('collect_event', 'prompt', '补齐日程信息', {
        riskLevel: 1,
        summary: '确认标题、日期、开始/结束时间、地点、日历和参与人。',
        requires: ['title', 'startAt', 'endAt'],
      }),
      productivityAction('create_event', 'native_productivity', '创建日历事件草稿', {
        tool: 'run_productivity_action',
        riskLevel: 3,
        confirmationRequired: true,
        requires: ['title', 'startAt', 'endAt'],
        summary: '创建或填写一个可复查事件；邀请/通知另行确认。',
        instruction: `在 ${appName} 中创建一个日历事件草稿，先复查标题、时间和日历，不发送邀请或更新通知。`,
        nativeAutomation: true,
        nativeKind: 'calendar_event',
      }),
      productivityAction('send_invite_gate', 'blocked', '邀请或发送更新需要人工确认', {
        riskLevel: 4,
        confirmationRequired: true,
        forbidden: true,
        summary: 'JAVIS 不自动发送日历邀请或更新；必须由用户明确确认并复查。',
      }),
    );
  } else if (intent === 'email_draft') {
    actions.push(
      productivityAction('collect_email', 'prompt', '补齐邮件 brief', {
        riskLevel: 1,
        summary: '确认收件人、主题、正文要点、语气和附件。',
        requires: ['recipient', 'subject', 'body'],
      }),
      productivityAction('draft_email', 'native_productivity', '创建邮件草稿', {
        tool: 'run_productivity_action',
        riskLevel: 3,
        confirmationRequired: true,
        requires: ['recipient', 'subject', 'body'],
        summary: '只创建草稿，不发送邮件。',
        instruction: `在 ${appName} 中创建一封邮件草稿，填写收件人、主题和正文后停在复查状态，不发送。`,
        nativeAutomation: true,
        nativeKind: 'email_draft',
      }),
      productivityAction('send_email_blocked', 'blocked', '发送邮件保持阻断', {
        riskLevel: 4,
        confirmationRequired: true,
        forbidden: true,
        summary: '发送邮件是高影响动作；JAVIS 只能准备草稿，不能自动发送。',
      }),
    );
  } else {
    actions.push(
      productivityAction('collect_note', 'prompt', '补齐笔记内容', {
        riskLevel: 1,
        summary: '确认标题、正文、文件夹/标签和是否需要后续任务。',
        requires: ['title', 'body'],
      }),
      productivityAction('create_note', 'native_productivity', '创建笔记', {
        tool: 'run_productivity_action',
        riskLevel: 3,
        confirmationRequired: true,
        requires: ['title', 'body'],
        summary: '创建一条可复查笔记；不移动或删除现有笔记。',
        instruction: `在 ${appName} 中创建一条新笔记，填写标题和正文后停下复查，不移动或删除现有笔记。`,
        nativeAutomation: true,
        nativeKind: 'note',
      }),
      productivityAction('capture_note_inbox', 'inbox', '先保存到本地 Inbox', {
        tool: 'capture_inbox_item',
        riskLevel: 1,
        safeToAutoRun: true,
        requires: ['body'],
        summary: '当暂时不想操作 Notes 时，把内容保存到本地 Inbox。',
      }),
    );
  }

  return {
    id: stageId,
    label: stage?.label || stageId,
    summary: stage?.summary || '',
    intent,
    app: selectedApp?.name || '',
    riskLevel: Math.max(...actions.map((action) => action.riskLevel), 1),
    actions,
    safeAutoActionIds: actions.filter((action) => action.safeToAutoRun).map((action) => action.id),
    confirmationActionIds: actions.filter((action) => action.confirmationRequired).map((action) => action.id),
    forbiddenActionIds: actions.filter((action) => action.forbidden).map((action) => action.id),
  };
}

function formatProductivityWorkflowOutput(result) {
  const appLabel = result.selectedApp?.name || '未选择';
  const installedLabel = result.selectedApp?.installed
    ? `已检测到 ${result.selectedApp.appPath}`
    : '未在常见位置检测到；仍可尝试用 macOS 打开应用名。';
  const stageLines = result.stages.map((stage, index) => `${index + 1}. ${stage.label}: ${stage.summary}`);
  const actionLines = result.actionPack?.actions?.length
    ? result.actionPack.actions
      .slice(0, 6)
      .map((action, index) => `${index + 1}. L${action.riskLevel} ${action.label}${action.tool ? ` -> ${action.tool}` : ''}${action.safeToAutoRun ? ' (可自动)' : action.confirmationRequired ? ' (需确认)' : ''}${action.forbidden ? ' (阻断)' : ''}`)
      .join('\n')
    : '';
  return [
    `生产力工作流: ${result.intent} · ${appLabel}`,
    `软件: ${installedLabel}`,
    `阶段:\n${stageLines.join('\n')}`,
    result.focusedStage ? `焦点阶段: ${result.focusedStage.label}` : '',
    actionLines ? `动作包:\n${actionLines}` : '',
    result.appRun?.output ? `本地操作:\n${result.appRun.output}` : '',
    result.observation?.output ? `观察:\n${result.observation.output}` : '',
    `下一步: ${result.nextActions[0] || '确认目标应用、内容和是否允许创建草稿。'}`,
  ].filter(Boolean).join('\n');
}

async function planProductivityWorkflow(options = {}) {
  const instruction = String(options.instruction || options.goal || options.task || '').trim();
  if (!instruction) throw new Error('Productivity workflow requires instruction.');
  const intent = normalizeProductivityWorkflowIntent(options.intent, instruction);
  const candidates = productivityAppCandidates(instruction, intent, options.app || options.application || '');
  const selectedApp =
    candidates.find((item) => item.requested) ||
    candidates.find((item) => item.explicit && item.installed) ||
    candidates.find((item) => item.explicit) ||
    candidates.find((item) => item.installed) ||
    candidates[0] ||
    null;
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  const stages = productivityWorkflowStages(intent);
  const focusedStageId = normalizeProductivityStageId(options.stage || options.phase || options.step, intent, instruction);
  const focusedStage = productivityStageDefinition(intent, focusedStageId);
  const actionPacks = stages.map((stage) => productivityStageActionPack({
    intent,
    stageId: stage.id,
    selectedApp,
    instruction,
  }));
  const actionPack = actionPacks.find((pack) => pack.id === focusedStageId) || actionPacks[0] || null;
  const nextActions = [
    selectedApp
      ? `${focusedStage?.label || '下一阶段'}: ${actionPack?.actions?.[0]?.label || `打开/聚焦 ${selectedApp.name}`}，然后观察窗口。`
      : '先指定要使用的生产力应用。',
    '补齐标题、时间、正文、收件人等缺失信息。',
    '创建笔记、提醒、日程或邮件草稿前先预览；发送、邀请、删除、批量修改保持确认门。',
  ];
  let appRun = null;
  let observation = null;

  if (execute && selectedApp?.name) {
    appRun = await runAppWorkflow({
      title: `Open productivity app · ${selectedApp.name}`,
      instruction,
      execute: true,
      source: 'productivity_workflow',
      recordWorkflow: false,
      steps: [
        { type: 'open_app', app: selectedApp.name, label: `Open ${selectedApp.name}` },
        { type: 'wait', ms: Math.max(500, Math.min(5000, Number(options.waitMs || 900))), label: 'Wait for productivity app' },
      ],
      continueOnError: false,
    });
    if (appRun.ok && options.observeAfterOpen !== false) {
      const observed = await observeNow({
        source: 'productivity_workflow',
        captureScreen: 'auto',
        includeAccessibility: true,
        screenMaxAgeMs: 8000,
        accessibilityMaxAgeMs: 4000,
        maxNodes: 160,
        maxDepth: 8,
      });
      observation = {
        ok: observed.ok,
        output: formatObservationForLocalCommand(observed),
        mac: observed.mac,
        screen: observed.screen,
        accessibility: observed.accessibility,
        errors: observed.errors,
      };
    }
  }

  const draft = {
    ok: Boolean(selectedApp) && (!execute || Boolean(appRun?.ok)),
    executed: execute,
    intent,
    selectedApp,
    candidates,
    stages,
    focusedStage,
    actionPacks,
    actionPack,
    nextActions,
    appRun,
    observation,
  };
  const output = formatProductivityWorkflowOutput(draft);
  const workflowDraft = {
    kind: 'productivity',
    source: options.source || 'productivity_workflow',
    status: execute && appRun && !appRun.ok ? 'blocked' : 'done',
    title: `Productivity workflow · ${selectedApp?.name || intent}`.slice(0, 180),
    intent,
    mode: execute ? 'local' : 'preview',
    request: instruction,
    result: output,
    target: {
      app: selectedApp?.name || '',
      appId: selectedApp?.id || '',
      appDomain: selectedApp?.domain || productivityWorkflowDomain(intent),
      appInstalled: Boolean(selectedApp?.installed),
      appPath: selectedApp?.appPath || '',
      candidateCount: candidates.length,
      stageCount: stages.length,
      focusedStageId,
      actionCount: actionPack?.actions?.length || 0,
      appWorkflowId: appRun?.workflow?.id || '',
    },
  };
  const workflow = options.recordWorkflow === false
    ? {
        id: '',
        ...workflowDraft,
        createdAt: Date.now(),
        updatedAt: Date.now(),
        completedAt: Date.now(),
      }
    : createWorkflowRecord(workflowDraft);
  const routing = options.recordRouting === false || !workflow.id
    ? null
    : createRoutingRecordForWorkflow({
        workflow,
        mode: 'local',
        source: options.source || 'productivity_workflow',
        owner: 'app',
        scope: `productivity:${intent}`,
        parallelGroup: options.parallelGroup || options.group || `productivity:${selectedApp?.domain || intent}`,
        resultSummary: output,
      });

  return {
    ...draft,
    workflow,
    routing,
    output,
  };
}

function productivityActionIdFromOptions(options = {}, actionPack = null) {
  const requested = String(options.actionId || options.action || options.actionName || options.id || '').trim();
  if (requested) return requested;
  if (options.execute === true || String(options.execute || '').toLowerCase() === 'true') {
    return actionPack?.safeAutoActionIds?.[0] || actionPack?.actions?.[0]?.id || '';
  }
  return actionPack?.actions?.[0]?.id || '';
}

function productivityActionRequiresConfirmation(action) {
  if (!action) return false;
  if (action.confirmationRequired) return true;
  return Number(action.riskLevel || 0) >= 4;
}

function productivityActionConfirmationSatisfied(options = {}) {
  return options.confirm === true || options.confirmed === true || String(options.confirm || options.confirmed || '').toLowerCase() === 'true';
}

function productivityRequirementValue(requirement, options = {}) {
  const aliases = {
    title: ['title', 'name', 'reminderTitle', 'eventTitle', 'noteTitle'],
    body: ['body', 'text', 'content', 'message', 'noteBody'],
    dueAt: ['dueAt', 'due', 'date', 'time', 'deadline'],
    startAt: ['startAt', 'start', 'date', 'time'],
    endAt: ['endAt', 'end', 'until'],
    recipient: ['recipient', 'to', 'email', 'mailto'],
    subject: ['subject', 'title'],
  }[requirement] || [requirement];
  for (const key of aliases) {
    const value = options[key];
    if (value !== undefined && value !== null && String(value).trim()) return String(value).trim();
  }
  return '';
}

function missingProductivityRequirements(action, options = {}) {
  return (action?.requires || []).filter((requirement) => !productivityRequirementValue(requirement, options));
}

function formatProductivityActionExecutionOutput(result) {
  const action = result.action || {};
  const recoveryHints = result.recoveryHints || [];
  return [
    `生产力动作: ${action.id || 'unknown'} · ${action.label || ''}`,
    `状态: ${result.status}${result.executed ? ' · executed' : ' · preview'}`,
    result.requiresConfirmation ? '需要确认: 是' : '',
    result.missingRequirements?.length ? `缺少信息: ${result.missingRequirements.join(', ')}` : '',
    recoveryHints.length ? `补救:\n${recoveryHints.map((hint, index) => `${index + 1}. ${hint}`).join('\n')}` : '',
    result.result?.output ? `结果:\n${compactRecordText(result.result.output, 900)}` : '',
    result.output && !result.result?.output ? result.output : '',
  ].filter(Boolean).join('\n');
}

function productivityActionRecoveryHints(action, execution, plan) {
  const hints = [];
  const add = (hint) => {
    const text = String(hint || '').trim();
    if (text && !hints.includes(text)) hints.push(text);
  };
  if (execution?.requiresConfirmation) add(`确认目标和内容无误后，重新运行 actionId:${action?.id || ''} 并传入 confirm:true。`);
  if (execution?.approval) add('本机动作策略仍要求审批；在 approvals 队列确认后继续执行。');
  for (const requirement of execution?.missingRequirements || []) add(`补充缺少的信息: ${requirement}。`);
  if (action?.type === 'blocked' || action?.forbidden) add('发送、邀请、删除或批量修改必须由用户在应用里明确复查确认。');
  if (['current_app_control', 'app_workflow', 'native_productivity'].includes(action?.type) && !execution?.ok) add(`确认 ${plan?.selectedApp?.name || '目标应用'} 可用并已授予 Automation/Accessibility 权限。`);
  if (!hints.length && execution?.status === 'preview') add('预览通过后，补齐信息并确认具体动作再执行。');
  return hints.slice(0, 6);
}

function productivityNativeText(value, maxLength = 20000) {
  const text = String(value ?? '').trim();
  if (text.length > maxLength) throw new Error(`Text exceeds max length ${maxLength}.`);
  return text;
}

function productivityNativeDateParts(value) {
  const text = String(value || '').trim();
  if (!text) return null;
  const date = new Date(text);
  if (!Number.isFinite(date.getTime())) return null;
  return [
    String(date.getFullYear()),
    String(date.getMonth() + 1),
    String(date.getDate()),
    String(date.getHours()),
    String(date.getMinutes()),
    String(date.getSeconds()),
  ];
}

function productivityNativeDateHandlerScript() {
  return [
    'on javisDateFromParts(y, m, d, h, n, s)',
    '  set dt to current date',
    '  set year of dt to (y as integer)',
    '  set month of dt to (m as integer)',
    '  set day of dt to (d as integer)',
    '  set hours of dt to (h as integer)',
    '  set minutes of dt to (n as integer)',
    '  set seconds of dt to (s as integer)',
    '  return dt',
    'end javisDateFromParts',
  ].join('\n');
}

function productivityNativeBlocked(output, missingRequirements = []) {
  return {
    blocked: true,
    ok: false,
    executed: false,
    status: 'blocked',
    missingRequirements,
    output,
  };
}

function productivityNativeActionSpec(action, options = {}, plan = {}) {
  const actionId = String(action?.id || '');
  if (!['create_note', 'create_reminder', 'create_event', 'draft_email'].includes(actionId)) return null;
  try {
    if (actionId === 'create_note') {
      const title = productivityNativeText(productivityRequirementValue('title', options), 240);
      const body = productivityNativeText(productivityRequirementValue('body', options), 50000);
      return {
        id: actionId,
        app: 'Notes',
        kind: 'note',
        summary: `Create note "${compactRecordText(title, 80)}" in Notes`,
        args: [title, body],
        script: [
          'on run argv',
          '  set titleText to item 1 of argv',
          '  set bodyText to item 2 of argv',
          '  tell application "Notes"',
          '    activate',
          '    try',
          '      set targetFolder to folder "Notes" of default account',
          '      make new note at targetFolder with properties {name:titleText, body:bodyText}',
          '    on error',
          '      make new note with properties {name:titleText, body:bodyText}',
          '    end try',
          '  end tell',
          '  return "Created Notes note: " & titleText',
          'end run',
        ].join('\n'),
      };
    }

    if (actionId === 'create_reminder') {
      const title = productivityNativeText(productivityRequirementValue('title', options), 240);
      const body = productivityNativeText(productivityRequirementValue('body', options), 8000);
      const dueParts = productivityNativeDateParts(productivityRequirementValue('dueAt', options));
      if (!dueParts) return productivityNativeBlocked('dueAt must be an explicit machine-readable date/time, for example 2026-06-20T17:00:00.', ['dueAt']);
      return {
        id: actionId,
        app: 'Reminders',
        kind: 'reminder',
        summary: `Create reminder "${compactRecordText(title, 80)}" in Reminders`,
        args: [title, body, ...dueParts],
        script: [
          productivityNativeDateHandlerScript(),
          'on run argv',
          '  set titleText to item 1 of argv',
          '  set bodyText to item 2 of argv',
          '  set dueDate to javisDateFromParts(item 3 of argv, item 4 of argv, item 5 of argv, item 6 of argv, item 7 of argv, item 8 of argv)',
          '  tell application "Reminders"',
          '    activate',
          '    set targetList to default list',
          '    set newReminder to make new reminder at end of reminders of targetList with properties {name:titleText, due date:dueDate}',
          '    if bodyText is not "" then',
          '      try',
          '        set body of newReminder to bodyText',
          '      end try',
          '    end if',
          '  end tell',
          '  return "Created Reminders item: " & titleText',
          'end run',
        ].join('\n'),
      };
    }

    if (actionId === 'create_event') {
      const title = productivityNativeText(productivityRequirementValue('title', options), 240);
      const locationText = productivityNativeText(options.location || options.place || '', 8000);
      const notesText = productivityNativeText(options.body || options.notes || options.description || '', 20000);
      const startParts = productivityNativeDateParts(productivityRequirementValue('startAt', options));
      const endParts = productivityNativeDateParts(productivityRequirementValue('endAt', options));
      if (!startParts) return productivityNativeBlocked('startAt must be an explicit machine-readable date/time, for example 2026-06-20T17:00:00.', ['startAt']);
      if (!endParts) return productivityNativeBlocked('endAt must be an explicit machine-readable date/time, for example 2026-06-20T17:30:00.', ['endAt']);
      const startDate = new Date(productivityRequirementValue('startAt', options));
      const endDate = new Date(productivityRequirementValue('endAt', options));
      if (Number.isFinite(startDate.getTime()) && Number.isFinite(endDate.getTime()) && endDate <= startDate) {
        return productivityNativeBlocked('endAt must be later than startAt.', ['endAt']);
      }
      return {
        id: actionId,
        app: 'Calendar',
        kind: 'calendar_event',
        summary: `Create calendar event "${compactRecordText(title, 80)}" in Calendar`,
        args: [title, locationText, notesText, ...startParts, ...endParts],
        script: [
          productivityNativeDateHandlerScript(),
          'on run argv',
          '  set titleText to item 1 of argv',
          '  set locationText to item 2 of argv',
          '  set notesText to item 3 of argv',
          '  set startDate to javisDateFromParts(item 4 of argv, item 5 of argv, item 6 of argv, item 7 of argv, item 8 of argv, item 9 of argv)',
          '  set endDate to javisDateFromParts(item 10 of argv, item 11 of argv, item 12 of argv, item 13 of argv, item 14 of argv, item 15 of argv)',
          '  tell application "Calendar"',
          '    activate',
          '    set targetCalendar to first calendar',
          '    set newEvent to make new event at end of events of targetCalendar with properties {summary:titleText, start date:startDate, end date:endDate}',
          '    if locationText is not "" then set location of newEvent to locationText',
          '    if notesText is not "" then set description of newEvent to notesText',
          '  end tell',
          '  return "Created Calendar event: " & titleText',
          'end run',
        ].join('\n'),
      };
    }

    if (actionId === 'draft_email') {
      const recipientText = productivityNativeText(productivityRequirementValue('recipient', options), 2000);
      const subject = productivityNativeText(productivityRequirementValue('subject', options), 240);
      const body = productivityNativeText(productivityRequirementValue('body', options), 50000);
      const recipients = recipientText
        .split(/[;,]/)
        .map((item) => item.trim())
        .filter(Boolean);
      if (!recipients.length || recipients.some((item) => !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(item))) {
        return productivityNativeBlocked('recipient must contain one or more email addresses separated by comma or semicolon.', ['recipient']);
      }
      return {
        id: actionId,
        app: 'Mail',
        kind: 'email_draft',
        summary: `Create Mail draft "${compactRecordText(subject, 80)}"`,
        args: [subject, body, ...recipients],
        script: [
          'on run argv',
          '  set subjectText to item 1 of argv',
          '  set bodyText to item 2 of argv',
          '  tell application "Mail"',
          '    activate',
          '    set newMessage to make new outgoing message with properties {subject:subjectText, content:bodyText & return, visible:true}',
          '    tell newMessage',
          '      repeat with i from 3 to count of argv',
          '        make new to recipient at end of to recipients with properties {address:(item i of argv)}',
          '      end repeat',
          '    end tell',
          '  end tell',
          '  return "Created Mail draft: " & subjectText',
          'end run',
        ].join('\n'),
      };
    }
  } catch (error) {
    return productivityNativeBlocked(error instanceof Error ? error.message : String(error));
  }
  return null;
}

function productivityNativePolicyPlan(spec, action) {
  return {
    action: 'productivity_app',
    riskLevel: Math.max(3, Number(action?.riskLevel || 3)),
    summary: spec.summary,
    target: spec.app,
    args: {
      action: 'productivity_app',
      nativeAction: spec.id,
      app: spec.app,
    },
    metadata: {
      nativeAction: spec.id,
      nativeKind: spec.kind,
      app: spec.app,
    },
  };
}

async function executeNativeProductivityAction(action, options = {}, plan = {}) {
  const spec = productivityNativeActionSpec(action, options, plan);
  if (!spec) return null;
  if (spec.blocked) return spec;

  const policyPlan = productivityNativePolicyPlan(spec, action);
  let evaluation;
  try {
    evaluation = evaluateMacActionPlan(policyPlan, {
      approved: options.approved === true || options.policyApproved === true || productivityActionConfirmationSatisfied(options),
      approvalContext: {
        workflowId: options.workflowId || '',
        title: `productivity native action · ${action.label}`,
        instruction: options.instruction || action.instruction || action.label,
        source: 'productivity_native_action',
      },
    });
  } catch (error) {
    if (error instanceof ActionApprovalRequired) {
      return {
        ok: false,
        executed: false,
        status: 'approval_required',
        approval: error.approval,
        output: `Approval required before I can ${spec.summary}.`,
      };
    }
    return {
      ok: false,
      executed: false,
      status: 'blocked',
      output: error instanceof Error ? error.message : String(error),
    };
  }

  if (evaluation.dryRun) {
    appendAudit('productivity_native_action.dry_run', {
      app: spec.app,
      actionId: spec.id,
      riskLevel: policyPlan.riskLevel,
      summary: spec.summary,
    });
    return {
      ok: true,
      executed: true,
      status: 'done',
      result: {
        native: true,
        dryRun: true,
        app: spec.app,
        actionId: spec.id,
        policy: evaluation,
        output: `[dry-run] ${spec.summary}`,
      },
      output: `[dry-run] ${spec.summary}`,
    };
  }

  try {
    const startedAt = Date.now();
    const { stdout, stderr } = await execFileAsync('osascript', ['-e', spec.script, ...spec.args], {
      timeout: Math.max(5000, Math.min(60000, Number(options.timeoutMs || 20000))),
      maxBuffer: 1024 * 1024,
      env: guardedChildProcessEnv({ source: 'productivity_native_action' }),
    });
    const nativeOutput = compactRecordText(String(stdout || stderr || spec.summary).trim(), 1200);
    let observation = null;
    if (options.observeAfterAction !== false) {
      await waitMs(Math.max(250, Math.min(3000, Number(options.waitMs || 900))));
      const observed = await observeNow({
        source: 'productivity_native_action',
        captureScreen: 'auto',
        includeAccessibility: true,
        screenMaxAgeMs: 8000,
        accessibilityMaxAgeMs: 4000,
        maxNodes: options.maxNodes || 160,
        maxDepth: options.maxDepth || 8,
      });
      observation = {
        ok: observed.ok,
        output: formatObservationForLocalCommand(observed),
        mac: observed.mac,
        screen: observed.screen,
        accessibility: observed.accessibility,
        errors: observed.errors,
      };
    }
    appendAudit('productivity_native_action.completed', {
      app: spec.app,
      actionId: spec.id,
      durationMs: Date.now() - startedAt,
      observed: Boolean(observation),
    });
    return {
      ok: true,
      executed: true,
      status: 'done',
      result: {
        native: true,
        dryRun: false,
        app: spec.app,
        actionId: spec.id,
        policy: evaluation,
        output: nativeOutput,
        observation,
      },
      output: observation?.output
        ? `${nativeOutput}\nPost-action observation:\n${compactRecordText(observation.output, 1200)}`
        : nativeOutput,
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    appendAudit('productivity_native_action.failed', {
      app: spec.app,
      actionId: spec.id,
      message,
    });
    return {
      ok: false,
      executed: false,
      status: 'blocked',
      output: message,
    };
  }
}

async function executeProductivityAction(action, options = {}, plan = {}) {
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  if (!execute) {
    return {
      ok: true,
      executed: false,
      status: 'preview',
      output: `${action.label}: ${action.summary || 'Prepared productivity action preview.'}`,
    };
  }

  const missingRequirements = missingProductivityRequirements(action, options);
  if (missingRequirements.length) {
    return {
      ok: false,
      executed: false,
      status: 'blocked',
      missingRequirements,
      output: `需要补充信息后才能执行: ${missingRequirements.join(', ')}`,
    };
  }

  if (action.type === 'blocked' || action.forbidden) {
    return {
      ok: false,
      executed: false,
      status: 'blocked',
      requiresConfirmation: true,
      output: action.summary || `${action.label} 被安全策略阻断。`,
    };
  }

  if (action.type === 'native_productivity' || action.nativeAutomation) {
    const nativeResult = await executeNativeProductivityAction(action, options, plan);
    if (nativeResult) return nativeResult;
  }

  if (action.type === 'app_workflow') {
    const result = await runAppWorkflow({
      title: `productivity action · ${action.label}`,
      instruction: options.instruction || action.summary || action.label,
      execute: true,
      source: 'productivity_action',
      recordWorkflow: false,
      steps: action.steps || [],
      continueOnError: false,
    });
    return {
      ok: result.ok,
      executed: true,
      status: result.ok ? 'done' : 'blocked',
      result,
      output: result.output,
    };
  }

  if (action.type === 'observe') {
    const observed = await observeNow({
      ...(action.args || {}),
      source: 'productivity_action',
      captureScreen: action.args?.captureScreen ?? 'auto',
      includeAccessibility: action.args?.includeAccessibility ?? true,
      screenMaxAgeMs: 8000,
      accessibilityMaxAgeMs: 4000,
      maxNodes: action.args?.maxNodes || options.maxNodes || 160,
      maxDepth: action.args?.maxDepth || options.maxDepth || 8,
    });
    const output = formatObservationForLocalCommand(observed);
    return {
      ok: observed.ok,
      executed: true,
      status: observed.ok ? 'done' : 'blocked',
      result: {
        ok: observed.ok,
        output,
        mac: observed.mac,
        screen: observed.screen,
        accessibility: observed.accessibility,
        errors: observed.errors,
      },
      output,
    };
  }

  if (action.type === 'current_app_control') {
    const result = await controlCurrentApp({
      instruction: String(options.actionInstruction || action.instruction || action.summary || action.label),
      content: options.content ?? options.value,
      execute: true,
      recordWorkflow: false,
      maxNodes: options.maxNodes || 160,
      maxDepth: options.maxDepth || 8,
      approvalContext: {
        workflowId: options.workflowId || '',
        title: `productivity action · ${action.label}`,
        instruction: options.instruction || action.instruction || action.label,
        source: 'productivity_action',
      },
    });
    return {
      ok: result.ok,
      executed: Boolean(result.executed),
      status: result.ok ? 'done' : result.approval ? 'approval_required' : 'blocked',
      approval: result.approval,
      result,
      output: result.output,
    };
  }

  if (action.type === 'inbox') {
    const body = productivityRequirementValue('body', options);
    if (!body) {
      return {
        ok: false,
        executed: false,
        status: 'blocked',
        missingRequirements: ['body'],
        output: '需要正文后才能保存到 Inbox。',
      };
    }
    const item = createInboxItem({
      title: options.title || action.label,
      body,
      source: 'productivity_action',
      priority: options.priority || 2,
      tags: ['productivity', plan.intent || 'productivity'].filter(Boolean),
    });
    return {
      ok: true,
      executed: true,
      status: 'done',
      result: { item, counts: inboxCounts() },
      output: `已保存到 Inbox: ${item.title}`,
    };
  }

  return {
    ok: false,
    executed: false,
    status: 'blocked',
    output: `${action.type} 动作需要用户补充信息或暂不支持自动执行。`,
  };
}

async function runProductivityWorkflowAction(options = {}) {
  const instruction = String(options.instruction || options.goal || options.task || '').trim();
  if (!instruction) throw new Error('Productivity action requires instruction.');
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  const plan = await planProductivityWorkflow({
    instruction,
    intent: options.intent,
    stage: options.stage || options.phase || options.step,
    app: options.app || options.application,
    execute: false,
    recordWorkflow: false,
    recordRouting: false,
    source: options.source || 'productivity_action',
  });
  const actionId = productivityActionIdFromOptions(options, plan.actionPack);
  const action = (plan.actionPack?.actions || []).find((item) => item.id === actionId);
  if (!action) throw new Error(`Productivity action not found: ${actionId || 'missing actionId'}.`);

  const confirmed = productivityActionConfirmationSatisfied(options);
  const requiresConfirmation = productivityActionRequiresConfirmation(action);
  let execution;
  if (requiresConfirmation && execute && !confirmed) {
    execution = {
      ok: false,
      executed: false,
      status: 'blocked',
      requiresConfirmation: true,
      output: `需要明确确认后才能执行: ${action.label}`,
    };
  } else {
    execution = await executeProductivityAction(action, {
      ...options,
      execute,
      intent: plan.intent,
    }, plan);
  }

  const outputDraft = {
    ok: execution.ok,
    executed: Boolean(execution.executed),
    status: execution.status || (execution.ok ? 'done' : 'blocked'),
    requiresConfirmation: Boolean(requiresConfirmation && execute && !confirmed) || Boolean(execution.requiresConfirmation),
    missingRequirements: execution.missingRequirements || [],
    plan,
    action,
    result: execution.result,
    approval: execution.approval,
    recoveryHints: productivityActionRecoveryHints(action, execution, plan),
    output: execution.output,
  };
  const output = formatProductivityActionExecutionOutput(outputDraft);
  const workflowStatus = outputDraft.status === 'preview'
    ? 'done'
    : ['queued', 'running', 'done', 'failed', 'cancelled', 'blocked'].includes(outputDraft.status)
      ? outputDraft.status
      : 'blocked';
  const workflowDraft = {
    kind: 'productivity_action',
    source: options.source || 'productivity_action',
    status: workflowStatus,
    title: `Productivity action · ${action.label}`.slice(0, 180),
    intent: action.id,
    mode: execute ? 'local' : 'preview',
    request: instruction,
    result: output,
    target: {
      app: plan.selectedApp?.name || '',
      appId: plan.selectedApp?.id || '',
      appDomain: plan.selectedApp?.domain || productivityWorkflowDomain(plan.intent),
      appInstalled: Boolean(plan.selectedApp?.installed),
      appPath: plan.selectedApp?.appPath || '',
      stageId: plan.focusedStage?.id || '',
      actionId: action.id,
      actionCount: plan.actionPack?.actions?.length || 0,
      riskLevel: action.riskLevel,
      safeToAutoRun: action.safeToAutoRun,
      confirmationRequired: requiresConfirmation,
      missingRequirements: outputDraft.missingRequirements,
      type: action.type,
    },
  };
  const workflow = options.recordWorkflow === false
    ? {
        id: '',
        ...workflowDraft,
        createdAt: Date.now(),
        updatedAt: Date.now(),
        completedAt: Date.now(),
      }
    : createWorkflowRecord(workflowDraft);
  const routing = options.recordRouting === false || !workflow.id
    ? null
    : createRoutingRecordForWorkflow({
        workflow,
        mode: 'local',
        source: options.source || 'productivity_action',
        owner: 'app',
        scope: `productivity:${plan.intent}:${plan.focusedStage?.id || 'stage'}:${action.id}`,
        parallelGroup: options.parallelGroup || options.group || `productivity:${plan.selectedApp?.domain || plan.intent}`,
        resultSummary: output,
      });

  return {
    ...outputDraft,
    workflow,
    routing,
    output,
  };
}

function productivityDogfoodFutureIso(minutesFromNow) {
  return new Date(Date.now() + Number(minutesFromNow || 0) * 60 * 1000).toISOString();
}

function productivityDogfoodSuitePayloads(options = {}) {
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  const confirm = options.confirm === true || options.confirmed === true || String(options.confirm || options.confirmed || '').toLowerCase() === 'true';
  const shouldRecord = options.record === true || options.recordWorkflow === true || (execute && confirm && options.recordWorkflow !== false);
  const title = String(options.title || 'JAVIS productivity dogfood').trim();
  const body = String(options.body || options.text || 'Created by JAVIS productivity dogfood preview.').trim();
  const dueAt = String(options.dueAt || productivityDogfoodFutureIso(24 * 60));
  const startAt = String(options.startAt || productivityDogfoodFutureIso(25 * 60));
  const endAt = String(options.endAt || productivityDogfoodFutureIso(26 * 60));
  const recipient = String(options.recipient || options.to || 'javis-dogfood@example.invalid').trim();
  const source = String(options.source || 'productivity_dogfood_archive').slice(0, 80);
  const common = {
    execute,
    confirm,
    recordWorkflow: shouldRecord,
    recordRouting: shouldRecord,
    source,
  };
  return [
    {
      id: 'notes_note_capture',
      instruction: 'Dogfood Notes note capture',
      intent: 'note_capture',
      stage: 'create',
      app: 'Notes',
      actionId: 'create_note',
      title: `${title} Notes`,
      body,
      ...common,
    },
    {
      id: 'reminders_create',
      instruction: 'Dogfood Reminders reminder creation',
      intent: 'reminder_create',
      stage: 'create',
      app: 'Reminders',
      actionId: 'create_reminder',
      title: `${title} Reminder`,
      body,
      dueAt,
      ...common,
    },
    {
      id: 'calendar_create_event',
      instruction: 'Dogfood Calendar event creation',
      intent: 'calendar_event',
      stage: 'create',
      app: 'Calendar',
      actionId: 'create_event',
      title: `${title} Calendar`,
      body,
      startAt,
      endAt,
      location: String(options.location || 'JAVIS local dogfood'),
      ...common,
    },
    {
      id: 'mail_draft',
      instruction: 'Dogfood Mail visible draft creation',
      intent: 'email_draft',
      stage: 'draft',
      app: 'Mail',
      actionId: 'draft_email',
      title: `${title} Mail`,
      body,
      recipient,
      subject: String(options.subject || `${title} Mail draft`),
      ...common,
    },
  ];
}

function productivityDogfoodCaseFromResult(payload = {}, result = {}, httpStatus = 200) {
  const action = result.action || {};
  const workflow = result.workflow || {};
  const ok = result.ok !== false;
  return {
    id: payload.id || `${payload.app || 'productivity'}_${payload.actionId || 'action'}`,
    app: payload.app || result.plan?.selectedApp?.name || '',
    intent: payload.intent || result.plan?.intent || '',
    actionId: payload.actionId || action.id || '',
    stage: payload.stage || result.plan?.focusedStage?.id || '',
    ok,
    httpStatus,
    status: result.status || (ok ? 'done' : 'blocked'),
    executed: Boolean(result.executed),
    requiresConfirmation: Boolean(result.requiresConfirmation),
    nativeAutomation: Boolean(action.nativeAutomation),
    nativeKind: action.nativeKind || '',
    workflowId: workflow.id || '',
    approvalId: result.approval?.id || '',
    missingRequirements: Array.isArray(result.missingRequirements) ? result.missingRequirements : [],
    recoveryHints: Array.isArray(result.recoveryHints) ? result.recoveryHints.slice(0, 8) : [],
    selectedApp: result.plan?.selectedApp?.name || payload.app || '',
    output: compactRecordText(result.output || '', 700),
  };
}

function productivityDogfoodArchiveFilename(generatedAt, id) {
  const timestamp = String(generatedAt || new Date().toISOString())
    .replace(/[:.]/g, '-')
    .replace(/[^0-9A-Za-zTZ_-]/g, '-');
  const suffix = String(id || crypto.randomUUID()).replace(/[^0-9A-Za-z_-]/g, '').slice(0, 8) || 'archive';
  return `${timestamp}-${suffix}.json`;
}

function productivityDogfoodArchiveSummary(archive = {}) {
  const counts = archive.counts || {};
  const safety = archive.safety || {};
  return [
    `Productivity dogfood archive ${counts.pass || 0}/${counts.total || 0} case(s) passed.`,
    safety.previewOnly ? 'Preview-only: no apps started, no messages sent, no user files mutated.' : '',
    counts.executed ? `${counts.executed} action(s) executed through policy gates.` : '',
  ].filter(Boolean).join(' ');
}

function productivityDogfoodArchiveMetadata(archive = {}, filePath = '') {
  const counts = archive.counts || {};
  const safety = archive.safety || {};
  return {
    id: archive.id || '',
    generatedAt: archive.generatedAt || archive.savedAt || '',
    savedAt: archive.savedAt || '',
    source: archive.source || '',
    ok: Boolean(archive.ok),
    suite: archive.suite !== false,
    saved: Boolean(archive.saved),
    execute: Boolean(archive.execute),
    confirm: Boolean(archive.confirm),
    summary: archive.archiveSummary || archive.summary || productivityDogfoodArchiveSummary(archive),
    file: filePath || archive.file?.path || archive.archiveFile || '',
    filename: filePath ? path.basename(filePath) : archive.file?.filename || '',
    counts: {
      total: Number(counts.total || 0),
      pass: Number(counts.pass || 0),
      fail: Number(counts.fail || 0),
      executed: Number(counts.executed || 0),
      preview: Number(counts.preview || 0),
      nativeAutomation: Number(counts.nativeAutomation || 0),
      workflows: Number(counts.workflows || 0),
    },
    safety: {
      previewOnly: Boolean(safety.previewOnly),
      startsApps: Boolean(safety.startsApps),
      executesProductivityActions: Boolean(safety.executesProductivityActions),
      sendsMessages: Boolean(safety.sendsMessages),
      mutatesUserFiles: Boolean(safety.mutatesUserFiles),
      mutatesUserRecords: Boolean(safety.mutatesUserRecords),
      storesRawAudio: Boolean(safety.storesRawAudio),
      storesScreenshots: Boolean(safety.storesScreenshots),
      recordsWorkflowHistory: Boolean(safety.recordsWorkflowHistory),
    },
  };
}

function productivityDogfoodArchiveList(options = {}) {
  fs.mkdirSync(PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR, { recursive: true });
  const limit = Math.max(1, Math.min(100, Number(options.limit || 10)));
  const files = fs.readdirSync(PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR)
    .filter((name) => name.endsWith('.json'))
    .map((name) => {
      const filePath = path.join(PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR, name);
      const stat = fs.statSync(filePath);
      return { name, filePath, mtimeMs: stat.mtimeMs, bytes: stat.size };
    })
    .sort((a, b) => b.mtimeMs - a.mtimeMs)
    .slice(0, limit);
  const items = files.map((file) => {
    try {
      const archive = JSON.parse(fs.readFileSync(file.filePath, 'utf8'));
      return {
        ...productivityDogfoodArchiveMetadata(archive, file.filePath),
        bytes: file.bytes,
      };
    } catch (error) {
      return {
        id: '',
        generatedAt: '',
        savedAt: '',
        source: '',
        ok: false,
        suite: true,
        saved: true,
        execute: false,
        confirm: false,
        status: 'unreadable',
        summary: error instanceof Error ? error.message : String(error),
        file: file.filePath,
        filename: file.name,
        counts: {},
        safety: {},
        bytes: file.bytes,
      };
    }
  });
  return {
    ok: true,
    archiveDir: PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR,
    maxArchives: MAX_PRODUCTIVITY_DOGFOOD_ARCHIVES,
    count: items.length,
    items,
  };
}

function pruneProductivityDogfoodArchives() {
  fs.mkdirSync(PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR, { recursive: true });
  const files = fs.readdirSync(PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR)
    .filter((name) => name.endsWith('.json'))
    .map((name) => {
      const filePath = path.join(PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR, name);
      const stat = fs.statSync(filePath);
      return { filePath, mtimeMs: stat.mtimeMs };
    })
    .sort((a, b) => b.mtimeMs - a.mtimeMs);
  const stale = files.slice(MAX_PRODUCTIVITY_DOGFOOD_ARCHIVES);
  for (const file of stale) {
    try {
      fs.unlinkSync(file.filePath);
    } catch {}
  }
  return stale.length;
}

function latestProductivityDogfoodArchive() {
  const list = productivityDogfoodArchiveList({ limit: 1 });
  return list.items[0] || null;
}

function productivityDogfoodArchiveFreshness(maxAgeMs = PRODUCTIVITY_DOGFOOD_FRESH_MS) {
  const latest = latestProductivityDogfoodArchive();
  const cooldownMs = Math.max(60000, Number(maxAgeMs || PRODUCTIVITY_DOGFOOD_FRESH_MS));
  if (!latest?.savedAt && !latest?.generatedAt) {
    return {
      fresh: false,
      cooldownMs,
      ageMs: null,
      waitMs: 0,
      ageLabel: '',
      waitLabel: '',
      latest: null,
    };
  }
  const timestamp = Date.parse(latest.savedAt || latest.generatedAt);
  if (!Number.isFinite(timestamp)) {
    return {
      fresh: false,
      cooldownMs,
      ageMs: null,
      waitMs: 0,
      ageLabel: '',
      waitLabel: '',
      latest: null,
    };
  }
  const ageMs = Math.max(0, Date.now() - timestamp);
  const waitMs = Math.max(0, cooldownMs - ageMs);
  return {
    fresh: waitMs > 0,
    cooldownMs,
    ageMs,
    waitMs,
    ageLabel: autopilotWaitDurationLabel(ageMs),
    waitLabel: autopilotWaitDurationLabel(waitMs),
    latest: {
      id: compactRecordText(latest.id || '', 120),
      at: new Date(timestamp).toISOString(),
      source: compactRecordText(latest.source || '', 80),
      file: compactRecordText(latest.file || '', 300),
      summary: compactRecordText(latest.summary || '', 240),
      counts: latest.counts || {},
      safety: latest.safety || {},
    },
  };
}

function compactProductivityDogfoodFreshness(freshness = null) {
  if (!freshness || typeof freshness !== 'object') return null;
  return {
    fresh: Boolean(freshness.fresh),
    cooldownMs: Math.max(0, Number(freshness.cooldownMs || 0)),
    ageMs: freshness.ageMs === null || freshness.ageMs === undefined ? null : Math.max(0, Number(freshness.ageMs || 0)),
    waitMs: Math.max(0, Number(freshness.waitMs || 0)),
    ageLabel: compactRecordText(freshness.ageLabel || '', 40),
    waitLabel: compactRecordText(freshness.waitLabel || '', 40),
    latest: freshness.latest
      ? {
        id: compactRecordText(freshness.latest.id || '', 120),
        at: compactRecordText(freshness.latest.at || '', 80),
        source: compactRecordText(freshness.latest.source || '', 80),
        file: compactRecordText(freshness.latest.file || '', 220),
        summary: compactRecordText(freshness.latest.summary || '', 180),
        pass: Number(freshness.latest.counts?.pass || 0),
        total: Number(freshness.latest.counts?.total || 0),
        previewOnly: freshness.latest.safety?.previewOnly === true,
      }
      : null,
  };
}

function productivityDogfoodArchiveWorkNextAction(options = {}) {
  const force = options.force === true || String(options.force || '').toLowerCase() === 'true';
  const freshness = productivityDogfoodArchiveFreshness(options.maxAgeMs || PRODUCTIVITY_DOGFOOD_FRESH_MS);
  if (!force && freshness.fresh) return null;
  return {
    id: 'productivity_dogfood:save_archive',
    priority: Math.max(3.02, Math.min(8, Number(options.priority || 3.08))),
    label: 'Save productivity dogfood archive',
    summary: 'Save a four-app Notes/Reminders/Calendar/Mail preview archive without launching apps, sending messages, or mutating user data.',
    source: 'productivity',
    type: 'productivity_dogfood_archive',
    productivityPreparation: 'dogfood_archive',
    freshness: compactProductivityDogfoodFreshness(freshness),
    executable: true,
    autoEligible: true,
    autopilotEligible: true,
    manualOnly: false,
    requiresUserPresence: false,
    startsMicrophone: false,
    requiresMicConfirmation: false,
    startsRecording: false,
    startsWorkers: false,
    startsApps: false,
    executesTask: false,
    executesProductivityActions: false,
    sendsMessages: false,
    mutatesUserFiles: false,
    mutatesUserRecords: false,
    riskLevel: 0,
    safety: {
      previewOnly: true,
      startsApps: false,
      executesProductivityActions: false,
      sendsMessages: false,
      mutatesUserFiles: false,
      mutatesUserRecords: false,
      storesRawAudio: false,
      storesScreenshots: false,
      recordsWorkflowHistory: false,
      actionPolicyBypassed: false,
    },
  };
}

async function productivityDogfoodArchiveSnapshot(options = {}) {
  const generatedAt = new Date().toISOString();
  const id = String(options.id || crypto.randomUUID());
  const payloads = productivityDogfoodSuitePayloads({
    ...(options || {}),
    source: options.source || 'api_productivity_dogfood_archive',
  });
  const cases = [];
  for (const payload of payloads) {
    try {
      const result = await runProductivityWorkflowAction({
        ...payload,
        recordWorkflow: payload.recordWorkflow,
        recordRouting: payload.recordRouting,
      });
      cases.push(productivityDogfoodCaseFromResult(payload, result, result.ok ? 200 : result.approval ? 202 : 409));
    } catch (error) {
      cases.push({
        id: payload.id,
        app: payload.app,
        intent: payload.intent,
        actionId: payload.actionId,
        stage: payload.stage,
        ok: false,
        httpStatus: 500,
        status: 'blocked',
        executed: false,
        requiresConfirmation: false,
        nativeAutomation: false,
        nativeKind: '',
        workflowId: '',
        approvalId: '',
        missingRequirements: [],
        recoveryHints: [error instanceof Error ? error.message : String(error)],
        selectedApp: payload.app,
        output: error instanceof Error ? error.message : String(error),
      });
    }
  }
  const executeRequested = payloads.some((item) => item.execute === true);
  const executed = cases.filter((item) => item.executed).length;
  const total = cases.length;
  const pass = cases.filter((item) => item.ok).length;
  const filename = productivityDogfoodArchiveFilename(generatedAt, id);
  const archive = {
    ok: pass === total,
    version: 1,
    kind: 'productivity_dogfood_archive',
    id,
    generatedAt,
    source: String(options.source || 'api').slice(0, 80),
    suite: true,
    execute: executeRequested,
    confirm: payloads.some((item) => item.confirm === true),
    saved: false,
    archiveFile: '',
    summary: `${pass}/${total} productivity dogfood cases passed`,
    archiveSummary: '',
    counts: {
      total,
      pass,
      fail: total - pass,
      executed,
      preview: total - executed,
      nativeAutomation: cases.filter((item) => item.nativeAutomation).length,
      workflows: cases.filter((item) => item.workflowId).length,
    },
    safety: {
      previewOnly: !executeRequested,
      startsApps: executed > 0,
      executesProductivityActions: executed > 0,
      sendsMessages: false,
      mutatesUserFiles: false,
      mutatesUserRecords: executed > 0,
      storesRawAudio: false,
      storesScreenshots: false,
      recordsWorkflowHistory: cases.some((item) => item.workflowId),
      mailDraftOnly: cases.some((item) => item.actionId === 'draft_email') && !cases.some((item) => /send_email|send_mail/i.test(item.actionId || '')),
      actionPolicyBypassed: false,
    },
    cases,
    file: {
      archiveDir: PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR,
      filename,
      path: path.join(PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR, filename),
    },
  };
  archive.archiveSummary = productivityDogfoodArchiveSummary(archive);
  archive.output = [
    archive.archiveSummary,
    `File: ${archive.file.path}`,
    archive.safety.previewOnly
      ? 'This preview does not start apps, send messages, mutate user files, or record workflow history.'
      : 'Executed actions still passed through local execution, control mode, action policy, and app permissions.',
  ].join('\n');
  return archive;
}

async function saveProductivityDogfoodArchive(options = {}) {
  fs.mkdirSync(PRODUCTIVITY_DOGFOOD_ARCHIVES_DIR, { recursive: true });
  const archive = await productivityDogfoodArchiveSnapshot({
    ...(options || {}),
    source: options.source || 'api_productivity_dogfood_archive',
  });
  const savedAt = new Date().toISOString();
  const filePath = archive.file.path;
  const nextArchive = {
    ...archive,
    saved: true,
    savedAt,
    archiveFile: filePath,
    file: {
      ...archive.file,
      path: filePath,
    },
  };
  writeJsonAtomic(filePath, nextArchive);
  const pruned = pruneProductivityDogfoodArchives();
  appendAudit('productivity.dogfood_archive_saved', {
    id: nextArchive.id,
    source: nextArchive.source,
    ok: nextArchive.ok,
    total: nextArchive.counts.total,
    pass: nextArchive.counts.pass,
    fail: nextArchive.counts.fail,
    executed: nextArchive.counts.executed,
    previewOnly: nextArchive.safety.previewOnly,
    file: filePath,
    pruned,
    sendsMessages: false,
  });
  return {
    ok: nextArchive.ok,
    saved: true,
    archive: nextArchive,
    metadata: productivityDogfoodArchiveMetadata(nextArchive, filePath),
    archives: productivityDogfoodArchiveList({ limit: options.limit || 5 }),
    output: [
      `Saved productivity dogfood archive: ${filePath}`,
      nextArchive.archiveSummary,
      'It did not send messages, bypass action policy, or store raw audio/screen images.',
    ].join('\n'),
  };
}

function productivityBenchmarkCaseResult({ id, label, intent, ok, result, assertions = {} }) {
  const workflow = result?.workflow || {};
  const routing = result?.routing || {};
  const selectedApp = result?.selectedApp || result?.plan?.selectedApp || {};
  const focusedStage = result?.focusedStage || result?.plan?.focusedStage || {};
  const actionPack = result?.actionPack || result?.plan?.actionPack || {};
  const action = result?.action || {};
  return {
    id,
    label,
    intent,
    ok: Boolean(ok),
    status: ok ? 'pass' : 'fail',
    previewOnly: result?.executed === false || result?.status === 'preview' || result?.status === 'blocked',
    executed: Boolean(result?.executed),
    blocked: String(result?.status || '').includes('blocked'),
    confirmationRequired: Boolean(result?.requiresConfirmation || action.confirmationRequired),
    modelCall: false,
    productivityAction: false,
    workflowId: workflow.id || '',
    workflowStatus: workflow.status || '',
    routingId: routing.id || '',
    routingStatus: routing.status || '',
    app: selectedApp.name || '',
    appId: selectedApp.id || '',
    stageId: focusedStage.id || actionPack.id || '',
    actionId: action.id || '',
    assertions,
    summary: compactRecordText(result?.output || actionPack.summary || action.summary || '', 260),
  };
}

