function appNameFromInstruction(instruction) {
  const text = String(instruction || '').trim();
  const explicit = text.match(/(?:open|launch|打开|启动)\s+([A-Za-z][A-Za-z0-9 ._-]{1,40})/i);
  if (explicit) return explicit[1].trim();
  const knownApps = [
    ['Calculator', ['calculator', '计算器']],
    ['Finder', ['finder', '访达']],
    ['Safari', ['safari']],
    ['Google Chrome', ['chrome', 'google chrome', '谷歌浏览器']],
    ['Notes', ['notes', '备忘录']],
    ['TextEdit', ['textedit', 'text edit', '文本编辑']],
    ['Obsidian', ['obsidian']],
    ['System Settings', ['system settings', '系统设置']],
    ...PRODUCTIVITY_APP_CATALOG.map((item) => [item.name, item.aliases]),
    ...CREATIVE_APP_CATALOG.map((item) => [item.name, item.aliases]),
  ];
  const lower = text.toLowerCase();
  const hit = knownApps.find(([_app, aliases]) => aliases.some((alias) => lower.includes(alias.toLowerCase())));
  return hit?.[0] || '';
}

function typedTextFromInstruction(instruction) {
  const text = String(instruction || '').trim();
  const match = text.match(/(?:type|输入|打字|写下|写入|记下)\s*[:：]?\s*([\s\S]+)$/i);
  if (!match?.[1]) return '';
  const content = match[1]
    .trim()
    .replace(/^[“"‘']+/, '')
    .replace(/[”"’']+$/, '')
    .trim();
  if (!content) return '';
  if (/(?:然后|接着|and then|then).*(?:close|quit|send|submit|delete|关闭|退出|发送|提交|删除)/i.test(content)) return '';
  if (content.length > 500) return '';
  return content;
}

function deterministicAppWorkflowPlan(options = {}, context = {}) {
  const instruction = String(options.instruction || options.goal || '').trim();
  const lower = instruction.toLowerCase();
  const steps = [];
  const appName = appNameFromInstruction(instruction);
  if (appName && /open|launch|打开|启动/.test(lower)) {
    steps.push({ type: 'open_app', app: appName, label: `Open ${appName}` });
    steps.push({ type: 'wait', ms: Number(options.waitMs || 900), label: 'Wait for app' });
  }

  const typedText = appName ? typedTextFromInstruction(instruction) : '';
  if (typedText) {
    steps.push({
      type: 'type_text',
      text: typedText,
      label: `Type ${typedText.length} chars`,
    });
  }

  const wantsClose =
    /close|quit|关闭|关掉|退出/.test(lower) &&
    !/delete|remove|trash|删除|移除|扔进废纸篓/.test(lower);
  if (wantsClose) {
    steps.push({
      type: 'hotkey',
      keys: 'cmd+w',
      label: 'Close window',
    });
  }

  const buttonMatch = instruction.match(/(?:press|click|tap|按|点击|点一下)\s*([^，。,.]+?)(?=\s*(?:按钮|button|tab|menu|菜单|链接|link)?(?:[，。,.]|$))/i);
  if (!wantsClose && buttonMatch) {
    const target = buttonMatch[1].trim().replace(/\s*(?:按钮|button|tab|menu|菜单|链接|link)\s*$/i, '').trim();
    if (target) {
      steps.push({
        type: 'control_current_app',
        instruction: /按钮|button/i.test(target) ? `按${target}` : `按${target}按钮`,
        maxNodes: options.maxNodes || 160,
        maxDepth: options.maxDepth || 8,
        label: `Press ${target}`,
      });
    }
  }

  if (!steps.length) return null;
  return {
    ok: true,
    source: 'deterministic',
    title: String(options.title || instruction || `Plan for ${context.frontmost?.app || 'current app'}`).slice(0, 180),
    instruction,
    confidence: steps.length >= 2 || wantsClose ? 0.82 : 0.66,
    needsClarification: false,
    reason: 'Matched a small local app workflow pattern.',
    steps,
  };
}

function safeLocalAppWorkflowPlan(instruction) {
  const text = String(instruction || '').trim();
  if (!text) return null;
  const unsafePattern =
    /\b(delete|remove|trash|erase|destroy|format|send|submit|buy|purchase|pay|payment|checkout|order|post|publish|share|upload|install|uninstall|login|log in|logout|log out|sign in|sign out|password|secret|token|api key)\b|删除|移除|废纸篓|抹掉|格式化|发送|提交|购买|付款|支付|下单|结账|发布|分享|上传|安装|卸载|登录|登入|退出登录|注销|密码|密钥/i;
  if (unsafePattern.test(text)) return null;

  const plan = deterministicAppWorkflowPlan({
    instruction: text,
    maxNodes: 160,
    maxDepth: 8,
    useModel: false,
  });
  if (!plan?.ok || !Array.isArray(plan.steps) || plan.steps.length < 2) return null;

  const hasAppOpen = plan.steps.some((step) => step.type === 'open_app' && step.app);
  const openedApp = plan.steps.find((step) => step.type === 'open_app')?.app || '';
  const hasTypeText = plan.steps.some((step) => step.type === 'type_text');
  const hasSafeAction = plan.steps.some((step) => step.type === 'control_current_app' || step.type === 'type_text' || (step.type === 'hotkey' && normalizeHotkey(step.keys) === 'cmd+w'));
  const onlySafeStepTypes = plan.steps.every((step) => ['open_app', 'wait', 'control_current_app', 'hotkey', 'type_text'].includes(step.type));
  const onlySafeHotkeys = plan.steps.every((step) => step.type !== 'hotkey' || normalizeHotkey(step.keys) === 'cmd+w');
  if (!hasAppOpen || !hasSafeAction || !onlySafeStepTypes || !onlySafeHotkeys) return null;
  if (hasTypeText) {
    const typingApps = new Set(['Notes', 'TextEdit', 'Obsidian']);
    const hasClose = plan.steps.some((step) => step.type === 'hotkey' && normalizeHotkey(step.keys) === 'cmd+w');
    if (!typingApps.has(openedApp) || hasClose) return null;
  }

  const riskyUiPattern = /删除|移除|发送|提交|购买|付款|支付|登录|允许|同意|确认|确定|\b(delete|remove|send|submit|buy|purchase|pay|login|allow|accept|confirm|ok)\b/i;
  if (plan.steps.some((step) => step.type === 'control_current_app' && riskyUiPattern.test(step.instruction || step.label || ''))) {
    return null;
  }

  return plan;
}

function sanitizePlannedAppWorkflow(rawPlan = {}, fallbackTitle = 'Planned app workflow') {
  const steps = normalizeAppWorkflowSteps(rawPlan.steps || []);
  return {
    ok: steps.length > 0,
    source: rawPlan.source || 'model',
    title: String(rawPlan.title || fallbackTitle).slice(0, 180),
    instruction: String(rawPlan.instruction || ''),
    confidence: Math.max(0, Math.min(1, Number(rawPlan.confidence || 0))),
    needsClarification: Boolean(rawPlan.needsClarification),
    reason: String(rawPlan.reason || ''),
    steps,
  };
}

function appWorkflowPlanningPrompt({ instruction, macContext, tree }) {
  return [
    'Plan a short local Mac app workflow as strict JSON only.',
    'Allowed step types: open_app, open_url, wait, control_current_app, browser_dom, hotkey, type_text, mac_action, file_action.',
    'Prefer control_current_app for visible UI targets and keep max 5 steps.',
    'Prefer browser_dom only for explicit webpage element click/fill/select tasks, and do not plan submits, purchases, sends, deletes, logins, or account changes.',
    'Do not plan sends, purchases, deletes, account changes, or irreversible external actions.',
    'If ambiguous, return needsClarification true and an empty steps array.',
    '',
    'JSON shape:',
    '{"title":"...","confidence":0.0,"needsClarification":false,"reason":"...","steps":[{"type":"open_app","app":"Calculator"},{"type":"wait","ms":900},{"type":"control_current_app","instruction":"按关闭按钮"}]}',
    '',
    `User instruction: ${instruction}`,
    '',
    `Frontmost app: ${macContext.frontmost?.app || ''}`,
    `Frontmost window: ${macContext.frontmost?.windowTitle || ''}`,
    `Browser title: ${macContext.browser?.title || ''}`,
    `Browser URL: ${macContext.browser?.url || ''}`,
    '',
    'Accessibility outline:',
    tree.outline || tree.error || '',
  ].join('\n');
}

async function modelAppWorkflowPlan(options = {}, context = {}) {
  if (!OPENAI_API_KEY) return null;
  const instruction = String(options.instruction || options.goal || '').trim();
  const output = await callOpenAIResponses({
    model: models.fast,
    instructions:
      'You are the JAVIS local app workflow planner. Return strict JSON only. Prefer safe previewable local steps. Never include prose outside JSON.',
    input: appWorkflowPlanningPrompt({
      instruction,
      macContext: context.macContext || {},
      tree: context.tree || {},
    }),
    maxOutputTokens: 700,
    source: options.source || 'app_workflow_planner',
  });
  const parsed = extractJsonObject(output);
  return sanitizePlannedAppWorkflow({
    ...parsed,
    source: 'model',
    instruction,
  }, instruction || 'Planned app workflow');
}

async function planAppWorkflow(options = {}) {
  const instruction = String(options.instruction || options.goal || '').trim();
  if (!instruction) throw new Error('App workflow planning requires instruction.');
  const maxNodes = options.maxNodes || 120;
  const maxDepth = options.maxDepth || 6;
  const [macContext, tree] = await Promise.all([
    macContextSnapshot({ includeClipboardText: false }),
    accessibilityTreeSnapshot({ maxNodes, maxDepth }),
  ]);
  const context = {
    macContext,
    tree,
    screen: latestScreenSnapshot(),
  };

  let plan = deterministicAppWorkflowPlan({ ...options, instruction, maxNodes, maxDepth }, {
    frontmost: macContext.frontmost || {},
  });
  if (!plan && options.useModel !== false) {
    try {
      plan = await modelAppWorkflowPlan({ ...options, instruction }, { macContext, tree });
    } catch (error) {
      plan = {
        ok: false,
        source: 'model',
        title: String(options.title || instruction).slice(0, 180),
        instruction,
        confidence: 0,
        needsClarification: true,
        reason: error instanceof Error ? error.message : String(error),
        steps: [],
      };
    }
  }

  if (!plan) {
    plan = {
      ok: false,
      source: 'none',
      title: String(options.title || instruction).slice(0, 180),
      instruction,
      confidence: 0,
      needsClarification: true,
      reason: 'No safe app workflow plan matched the instruction.',
      steps: [],
    };
  }

  const sanitized = sanitizePlannedAppWorkflow(plan, instruction);
  sanitized.ok = sanitized.ok && !sanitized.needsClarification;
  const output = sanitized.steps.length
    ? sanitized.steps.map((step, index) => `${index + 1}. ${step.type}: ${step.label || step.instruction || step.app || step.url || ''}`).join('\n')
    : sanitized.reason || 'No plan available.';

  appendAudit('app_workflow.plan', {
    source: sanitized.source,
    ok: sanitized.ok,
    confidence: sanitized.confidence,
    steps: sanitized.steps.length,
    instruction: compactRecordText(instruction, 180),
  });

  return {
    ...sanitized,
    context,
    output,
  };
}

async function planAndMaybeRunAppWorkflow(options = {}) {
  const plan = await planAppWorkflow(options);
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  if (!execute || !plan.ok) {
    return {
      ok: plan.ok,
      executed: false,
      plan,
      output: plan.output,
    };
  }
  const run = await runAppWorkflow({
    title: options.title || plan.title,
    instruction: plan.instruction,
    execute: true,
    steps: plan.steps,
    continueOnError: options.continueOnError,
  });
  return {
    ok: run.ok,
    executed: true,
    plan,
    run,
    workflow: run.workflow,
    output: run.output,
  };
}

function appWorkflowPlanOutput(steps = []) {
  return steps.length
    ? steps.map((step, index) => `${index + 1}. ${step.type}: ${step.label || step.instruction || step.app || step.url || ''}`).join('\n')
    : 'No plan available.';
}

function appWorkflowPlanFromLocalCommand(command = {}) {
  const embedded = command.args?.plan || null;
  if (!embedded || !Array.isArray(embedded.steps) || !embedded.steps.length) return null;
  const plan = sanitizePlannedAppWorkflow({
    source: embedded.source || 'deterministic',
    title: embedded.title || command.args?.instruction || command.label || 'App workflow',
    instruction: command.args?.instruction || '',
    confidence: embedded.confidence || 0.8,
    needsClarification: false,
    reason: 'Matched a small local app workflow pattern.',
    steps: embedded.steps,
  }, command.args?.instruction || command.label || 'App workflow');
  plan.ok = plan.ok && !plan.needsClarification;
  plan.output = appWorkflowPlanOutput(plan.steps);
  return plan.ok ? plan : null;
}

async function runAppWorkflow(options = {}) {
  const steps = normalizeAppWorkflowSteps(options.steps || []);
  if (!steps.length) throw new Error('App workflow requires at least one step.');

  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  const recordWorkflow = options.recordWorkflow !== false;
  const stopOnError = options.continueOnError !== true;
  const instruction = String(options.instruction || options.goal || '').trim();
  const title = String(options.title || instruction || `app workflow · ${steps.length} step(s)`).slice(0, 180);
  const workflowDraft = {
    kind: 'app',
    source: options.source || 'app_workflow',
    status: 'running',
    title,
    intent: 'run_app_workflow',
    mode: execute ? 'local' : 'preview',
    request: instruction || JSON.stringify(steps.map((step) => ({ type: step.type, label: step.label }))),
    target: {
      stepCount: steps.length,
      execute,
    },
  };
  const workflow = recordWorkflow
    ? createWorkflowRecord(workflowDraft)
    : {
        id: '',
        ...workflowDraft,
        createdAt: Date.now(),
        updatedAt: Date.now(),
      };

  appendAudit('app_workflow.requested', {
    workflowId: workflow.id || '',
    execute,
    steps: steps.length,
    title,
  });

  const results = [];
  const stepContext = {
    workflowId: workflow.id,
    title,
    instruction,
    steps,
    source: options.source || 'app_workflow',
  };
  for (const step of steps) {
    try {
      const result = await runAppWorkflowStep(step, execute, stepContext);
      results.push({ index: step.index, ...result });
      if (stopOnError && ['blocked', 'approval_required'].includes(result.status)) break;
    } catch (error) {
      results.push({
        index: step.index,
        status: 'blocked',
        type: step.type,
        label: step.label,
        summary: step.label,
        output: error instanceof Error ? error.message : String(error),
      });
      if (stopOnError) break;
    }
  }

  const counts = results.reduce(
    (memo, result) => {
      memo.total += 1;
      memo[result.status] = (memo[result.status] || 0) + 1;
      return memo;
    },
    { total: 0, previewed: 0, executed: 0, approval_required: 0, blocked: 0 },
  );
  const output = formatAppWorkflowResults(results);
  const status = counts.blocked || counts.approval_required ? 'blocked' : 'done';
  const finalTarget = {
    stepCount: steps.length,
    execute,
    counts,
    completedSteps: results.length,
  };
  const finalWorkflow = recordWorkflow
    ? setWorkflow(workflow.id, {
        status,
        result: output,
        completedAt: Date.now(),
        target: finalTarget,
      })
    : {
        ...workflow,
        status,
        result: output,
        target: finalTarget,
        completedAt: Date.now(),
        updatedAt: Date.now(),
      };

  appendAudit('app_workflow.completed', {
    workflowId: workflow.id || '',
    status,
    execute,
    counts,
  });

  return {
    ok: status === 'done',
    executed: execute,
    workflow: finalWorkflow,
    counts,
    results,
    output,
  };
}

function appWorkflowBenchmarkCaseResult({ id, label, intent, ok, result = null, assertions = {} }) {
  const finalOk = Boolean(ok);
  const workflow = result?.workflow || {};
  const plan = result?.plan || (Array.isArray(result?.steps) ? result : {});
  const steps = Array.isArray(plan?.steps) ? plan.steps : [];
  return {
    id,
    label,
    intent,
    ok: finalOk,
    status: finalOk ? 'pass' : 'fail',
    previewOnly: result?.executed === false || result?.previewOnly === true || !result,
    executed: Boolean(result?.executed),
    blocked: String(result?.status || workflow.status || '').includes('blocked'),
    modelCall: false,
    workflowId: workflow.id || '',
    workflowStatus: workflow.status || '',
    source: plan?.source || result?.source || '',
    stepCount: steps.length || Number(result?.counts?.total || 0),
    stepTypes: steps.map((step) => step.type).filter(Boolean),
    assertions,
    summary: compactRecordText(result?.output || plan?.reason || '', 260),
  };
}

async function appWorkflowBenchmarkSnapshot(options = {}) {
  const source = String(options.source || 'app_benchmark').slice(0, 80);
  const sourcePrefix = source.startsWith('eval_') ? source : `${source}`;
  const cases = [];

  const calculatorClose = await planAppWorkflow({
    instruction: '打开 Calculator 然后关闭窗口',
    useModel: false,
    maxNodes: 40,
    maxDepth: 3,
    source: `${sourcePrefix}_calculator_close`,
  });
  cases.push(appWorkflowBenchmarkCaseResult({
    id: 'calculator_close_plan',
    label: 'Calculator open and close plan',
    intent: 'open_close',
    result: { plan: calculatorClose, executed: false, output: calculatorClose.output },
    assertions: {
      source: calculatorClose.source || '',
      hasOpenApp: calculatorClose.steps?.some((step) => step.type === 'open_app' && step.app === 'Calculator') === true,
      hasWait: calculatorClose.steps?.some((step) => step.type === 'wait') === true,
      hasCloseHotkey: calculatorClose.steps?.some((step) => step.type === 'hotkey' && normalizeHotkey(step.keys) === 'cmd+w') === true,
    },
    ok: calculatorClose.ok === true &&
      calculatorClose.source === 'deterministic' &&
      calculatorClose.steps?.some((step) => step.type === 'open_app' && step.app === 'Calculator') &&
      calculatorClose.steps?.some((step) => step.type === 'wait') &&
      calculatorClose.steps?.some((step) => step.type === 'hotkey' && normalizeHotkey(step.keys) === 'cmd+w'),
  }));

  const textEditTyping = await planAppWorkflow({
    instruction: '打开 TextEdit 输入 benchmark note',
    useModel: false,
    maxNodes: 40,
    maxDepth: 3,
    source: `${sourcePrefix}_textedit_type`,
  });
  cases.push(appWorkflowBenchmarkCaseResult({
    id: 'textedit_type_plan',
    label: 'TextEdit type-text plan',
    intent: 'type_text',
    result: { plan: textEditTyping, executed: false, output: textEditTyping.output },
    assertions: {
      source: textEditTyping.source || '',
      hasOpenApp: textEditTyping.steps?.some((step) => step.type === 'open_app' && step.app === 'TextEdit') === true,
      hasTypeText: textEditTyping.steps?.some((step) => step.type === 'type_text' && step.text === 'benchmark note') === true,
      hasUnsafeCloseWhileTyping: textEditTyping.steps?.some((step) => step.type === 'hotkey') === true,
    },
    ok: textEditTyping.ok === true &&
      textEditTyping.source === 'deterministic' &&
      textEditTyping.steps?.some((step) => step.type === 'open_app' && step.app === 'TextEdit') &&
      textEditTyping.steps?.some((step) => step.type === 'type_text' && step.text === 'benchmark note') &&
      !textEditTyping.steps?.some((step) => step.type === 'hotkey'),
  }));

  const systemSettingsPlan = await planAppWorkflow({
    instruction: '打开 System Settings 点击 General 按钮',
    useModel: false,
    maxNodes: 40,
    maxDepth: 3,
    source: `${sourcePrefix}_settings_button`,
  });
  cases.push(appWorkflowBenchmarkCaseResult({
    id: 'current_app_control_plan',
    label: 'Current-app control planning',
    intent: 'control_current_app',
    result: { plan: systemSettingsPlan, executed: false, output: systemSettingsPlan.output },
    assertions: {
      source: systemSettingsPlan.source || '',
      hasOpenApp: systemSettingsPlan.steps?.some((step) => step.type === 'open_app' && step.app === 'System Settings') === true,
      hasControlStep: systemSettingsPlan.steps?.some((step) => step.type === 'control_current_app') === true,
      targetIncludesGeneral: systemSettingsPlan.steps?.some((step) => step.type === 'control_current_app' && /General/i.test(step.instruction || step.label || '')) === true,
    },
    ok: systemSettingsPlan.ok === true &&
      systemSettingsPlan.source === 'deterministic' &&
      systemSettingsPlan.steps?.some((step) => step.type === 'open_app' && step.app === 'System Settings') &&
      systemSettingsPlan.steps?.some((step) => step.type === 'control_current_app' && /General/i.test(step.instruction || step.label || '')),
  }));

  const explicitPreview = await runAppWorkflow({
    title: 'App benchmark explicit preview',
    instruction: 'Preview a Finder focus workflow.',
    execute: false,
    recordWorkflow: false,
    source: `${sourcePrefix}_explicit_preview`,
    steps: [
      { type: 'open_app', app: 'Finder', label: 'Open Finder' },
      { type: 'wait', ms: 250, label: 'Wait for Finder' },
      { type: 'hotkey', keys: 'cmd+w', label: 'Close window' },
    ],
  });
  cases.push(appWorkflowBenchmarkCaseResult({
    id: 'explicit_workflow_preview',
    label: 'Explicit multi-step workflow preview',
    intent: 'preview_sequence',
    result: explicitPreview,
    assertions: {
      status: explicitPreview.workflow?.status || '',
      previewed: Number(explicitPreview.counts?.previewed || 0),
      workflowId: explicitPreview.workflow?.id || '',
      noHistoryRecord: !explicitPreview.workflow?.id,
    },
    ok: explicitPreview.ok === true &&
      explicitPreview.executed === false &&
      explicitPreview.workflow?.status === 'done' &&
      Number(explicitPreview.counts?.previewed || 0) === 3 &&
      !explicitPreview.workflow?.id,
  }));

  const unsafeDeletePlan = safeLocalAppWorkflowPlan('打开 Finder 删除 Downloads 里的文件');
  cases.push(appWorkflowBenchmarkCaseResult({
    id: 'unsafe_delete_rejected',
    label: 'Unsafe delete instruction rejected',
    intent: 'safety_gate',
    result: { previewOnly: true, executed: false, output: 'Unsafe delete instruction was rejected.' },
    assertions: {
      rejected: unsafeDeletePlan === null,
    },
    ok: unsafeDeletePlan === null,
  }));

  const counts = {
    total: cases.length,
    pass: cases.filter((item) => item.ok).length,
    fail: cases.filter((item) => !item.ok).length,
    previewOnly: cases.filter((item) => item.previewOnly).length,
    executed: cases.filter((item) => item.executed).length,
    planned: cases.filter((item) => Number(item.stepCount || 0) > 0).length,
    blocked: cases.filter((item) => item.blocked).length,
  };
  const snapshot = {
    ok: counts.fail === 0,
    generatedAt: new Date().toISOString(),
    source,
    manualOnly: true,
    previewOnly: true,
    startsApps: false,
    executesAppActions: false,
    modelCalls: false,
    mutatesUserFiles: false,
    recordsWorkflowHistory: false,
    summary: `${counts.pass}/${counts.total} app workflow benchmark case(s) passed.`,
    counts,
    cases,
    nextAction: counts.fail
      ? 'Fix failing app workflow benchmark cases before broadening live Mac app automation.'
      : 'Use these preview-only app workflow benchmarks before running live Mac app dogfood.',
    safety: {
      planOnly: true,
      noAppLaunch: true,
      noUiActions: true,
      noModelCalls: true,
      noUserFileMutation: true,
      noWorkflowHistory: cases.every((item) => !item.workflowId),
      unsafeDeleteRejected: cases.find((item) => item.id === 'unsafe_delete_rejected')?.assertions?.rejected === true,
      coversOpenClose: cases.find((item) => item.id === 'calculator_close_plan')?.ok === true,
      coversTypeText: cases.find((item) => item.id === 'textedit_type_plan')?.ok === true,
      coversCurrentAppControl: cases.find((item) => item.id === 'current_app_control_plan')?.ok === true,
      coversExplicitPreview: cases.find((item) => item.id === 'explicit_workflow_preview')?.ok === true,
    },
  };
  appendAudit('app_benchmark.completed', {
    source,
    ok: snapshot.ok,
    total: counts.total,
    pass: counts.pass,
    fail: counts.fail,
    noAppLaunch: true,
    noUiActions: true,
    noModelCalls: true,
  });
  return snapshot;
}

function assertValidAccessibilityNodeId(value) {
  const nodeId = String(value || '').trim();
  if (!/^[1-9]\d{0,4}$/.test(nodeId)) throw new Error('Missing or invalid accessibility node id.');
  return nodeId;
}

async function runAccessibilityNodeAction(plan) {
  if (process.platform !== 'darwin') throw new Error('Accessibility actions are macOS-only.');
  const accessibilityTrusted =
    typeof systemPreferences?.isTrustedAccessibilityClient === 'function'
      ? systemPreferences.isTrustedAccessibilityClient(false)
      : null;
  if (accessibilityTrusted === false) throw new Error('accessibility_permission_not_granted');

  const actionConfig = actionPolicy.allow?.[plan.action] || {};
  const maxNodes = Math.max(10, Math.min(actionPolicy.allow?.read_accessibility_tree?.maxNodes || 120, Number(plan.metadata?.maxNodes || 120)));
  const maxDepth = Math.max(1, Math.min(actionPolicy.allow?.read_accessibility_tree?.maxDepth || 6, Number(plan.metadata?.maxDepth || 6)));
  const targetApp = String(plan.args?.app || plan.metadata?.app || '').trim().slice(0, 120);
  const script = `
const nodeId = ${JSON.stringify(String(plan.args.nodeId))};
const action = ${JSON.stringify(plan.action)};
const content = ${JSON.stringify(String(plan.args.content || ''))};
const expectedLabel = ${JSON.stringify(String(plan.args.expectedLabel || ''))};
const expectedRole = ${JSON.stringify(String(plan.args.expectedRole || ''))};
const allowedRoles = ${JSON.stringify(actionConfig.allowedRoles || [])};
const maxNodes = ${JSON.stringify(maxNodes)};
const maxDepth = ${JSON.stringify(maxDepth)};
const targetApp = ${JSON.stringify(targetApp)};
const systemEvents = Application('System Events');

function readProp(element, name) {
  try {
    const value = element[name]();
    if (value === null || value === undefined) return '';
    return String(value).replace(/[\\t\\r\\n]+/g, ' ').replace(/\\s{2,}/g, ' ').trim();
  } catch (_) {
    return '';
  }
}

function readAttribute(element, name) {
  try {
    const value = element.attributes.byName(name).value();
    if (value === null || value === undefined) return '';
    if (Array.isArray(value)) return value.map((item) => String(item)).join(' ');
    return String(value).replace(/[\\t\\r\\n]+/g, ' ').replace(/\\s{2,}/g, ' ').trim();
  } catch (_) {
    return '';
  }
}

function writeAttribute(element, name, value) {
  try {
    const attribute = element.attributes.byName(name);
    if (attribute.value && attribute.value.set) {
      attribute.value.set(value);
      return true;
    }
    attribute.value = value;
    return true;
  } catch (_) {
    return false;
  }
}

function childrenOf(element) {
  try {
    return element.uiElements();
  } catch (_) {
    return [];
  }
}

function isChromiumApp(name) {
  return /Google Chrome|Chrome Canary|Chromium|Brave Browser|Microsoft Edge|Arc|Comet/i.test(String(name || ''));
}

function targetProcesses() {
  const processes = systemEvents.applicationProcesses();
  if (targetApp) {
    const wanted = targetApp.toLowerCase();
    return processes.filter((process) => readProp(process, 'name').toLowerCase() === wanted);
  }
  return processes.filter((process) => {
    try {
      return process.frontmost();
    } catch (_) {
      return false;
    }
  });
}

function labelOf(element) {
  return [
    readProp(element, 'name'),
    readProp(element, 'description'),
    readProp(element, 'value'),
    readAttribute(element, 'AXPlaceholderValue'),
    readAttribute(element, 'AXTitle'),
    readAttribute(element, 'AXDOMIdentifier'),
    readAttribute(element, 'AXDOMRole'),
].filter(Boolean)[0] || '';
}

function editableTextOf(element, role) {
  return [
    role,
    readProp(element, 'subrole'),
    readProp(element, 'roleDescription'),
    readAttribute(element, 'AXPlaceholderValue'),
    readAttribute(element, 'AXTitle'),
    readAttribute(element, 'AXDOMIdentifier'),
    readAttribute(element, 'AXDOMClassList'),
    readAttribute(element, 'AXDOMRole'),
    readAttribute(element, 'AXEditable'),
  ].join(' ').toLowerCase();
}

function targetIsSettable(element, role) {
  if (['AXComboBox', 'AXSearchField', 'AXTextArea', 'AXTextField'].includes(role)) return true;
  if (!['AXGroup', 'AXStaticText', 'AXWebArea'].includes(role)) return false;
  return /(^|[^a-z])true([^a-z]|$)|editable|contenteditable|rich.?textarea|textbox|searchbox|text area|text field|composer|compose|input/.test(editableTextOf(element, role));
}

const processes = targetProcesses();
if (!processes.length) throw new Error(targetApp ? 'accessibility_app_not_running:' + targetApp : 'no_frontmost_app');
const process = processes[0];
const appName = readProp(process, 'name');
if (isChromiumApp(appName)) {
  writeAttribute(process, 'AXManualAccessibility', true)
    || writeAttribute(process, 'AXEnhancedUserInterface', true);
}
const windows = process.windows();
let root = null;
for (const window of windows) {
  const children = childrenOf(window);
  if (readProp(window, 'subrole') === 'AXStandardWindow' && children.length) {
    root = window;
    break;
  }
}
if (!root) root = windows.find((window) => childrenOf(window).length) || windows[0] || process;

const elements = [];
const queue = [{ element: root, depth: 0 }];
while (queue.length && elements.length < maxNodes) {
  const item = queue.shift();
  elements.push(item.element);
  if (item.depth < maxDepth) {
    for (const child of childrenOf(item.element)) {
      queue.push({ element: child, depth: item.depth + 1 });
    }
  }
}

const index = Number(nodeId) - 1;
const target = elements[index];
if (!target) throw new Error('accessibility_node_not_found');
const role = readProp(target, 'role');
const label = labelOf(target);
if (allowedRoles.length && !allowedRoles.includes(role)) throw new Error('accessibility_role_not_allowed:' + role);
if (expectedRole && expectedRole !== role) throw new Error('accessibility_role_changed:' + role);
if (expectedLabel && expectedLabel !== label) throw new Error('accessibility_label_changed:' + label);

var resultExtra = { method: action };
if (action === 'ax_press') {
  const actionNames = target.actions().map((item) => readProp(item, 'name'));
  if (!actionNames.includes('AXPress')) throw new Error('accessibility_press_not_available');
  target.actions.byName('AXPress').perform();
} else if (action === 'ax_set_value') {
  if (!content) throw new Error('missing_accessibility_value');
  if (!targetIsSettable(target, role)) throw new Error('accessibility_target_not_settable:' + role);

  // Fix E: focus the resolved target first, so the keystroke fallback below can
  // never type into the wrong field.
  if (readAttribute(target, 'AXFocused') !== 'true') writeAttribute(target, 'AXFocused', true);
  var focused = readAttribute(target, 'AXFocused') === 'true';

  // Primary path: direct AX setValue (works for AXTextField/AXTextArea/etc.).
  var setError = '';
  try {
    target.value = content;
  } catch (_) {
    try {
      target.value.set(content);
    } catch (error) {
      setError = String(error && error.message ? error.message : error);
    }
  }
  var valueAfter = readProp(target, 'value');
  var verified = valueAfter === content;

  // Fix C (write half): contenteditable / rich web editors (e.g. the Gemini
  // composer) reject AX setValue. Recover with a keystroke fallback, but ONLY
  // when focus is confirmed on the target — never blind-type into whatever is
  // focused. (Note: content with newlines may submit a chat composer.)
  if (!verified) {
    if (!focused) {
      throw new Error(setError ? 'accessibility_set_value_failed:' + setError : 'accessibility_set_value_unverified_no_focus:' + role);
    }
    systemEvents.keystroke('a', { using: 'command down' });
    $.NSThread.sleepForTimeInterval(0.05);
    systemEvents.keystroke(content);
    $.NSThread.sleepForTimeInterval(0.05);
    resultExtra.method = 'keystroke';
    valueAfter = readProp(target, 'value');
    // contenteditable often keeps AXValue empty; confirmed focus + keystroke is best-effort success.
    verified = valueAfter === content || (valueAfter === '' && focused);
  }

  resultExtra.focused = focused;
  resultExtra.verified = verified;
  resultExtra.valueAfter = String(valueAfter || '').slice(0, 200);
} else {
  throw new Error('unsupported_accessibility_action:' + action);
}

JSON.stringify({
  ok: true,
  app: readProp(process, 'name'),
  windowTitle: readProp(root, 'name'),
  nodeId,
  role,
  label,
  action,
  method: resultExtra.method,
  focused: resultExtra.focused,
  verified: resultExtra.verified,
  valueAfter: resultExtra.valueAfter,
});
`;

  const { stdout } = await execFileAsync('osascript', ['-l', 'JavaScript', '-e', script], guardedChildProcessOptions(
    { timeout: AX_ACTION_TIMEOUT_MS, maxBuffer: 1_000_000 },
    { source: 'accessibility_action' },
  ));
  const result = JSON.parse(String(stdout || '{}'));
  appendAudit('accessibility_action.executed', {
    action: plan.action,
    nodeId: plan.args.nodeId,
    role: result.role,
    label: result.label,
    app: result.app,
    method: result.method,
    verified: result.verified,
  });
  const verifyNote = result.method === 'keystroke' ? ' via keystroke' : '';
  const verifiedNote = result.verified === false
    ? ' (unverified — re-read did not confirm)'
    : result.verified === true ? ' (verified)' : '';
  return `${result.action} executed on ${result.role}${result.label ? ` "${result.label}"` : ''}${verifyNote}${verifiedNote}.`;
}

function normalizeBrowserMaxChars(value) {
  const policyMax = actionPolicy.allow?.read_browser_page?.maxChars || 30000;
  return Math.max(1000, Math.min(policyMax, Number(value || policyMax)));
}

function decodeHtmlEntities(value) {
  return String(value || '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&#(\d+);/g, (_match, code) => String.fromCharCode(Number(code)))
    .replace(/&#x([0-9a-f]+);/gi, (_match, code) => String.fromCharCode(parseInt(code, 16)));
}

function htmlAttributeValue(tag, name) {
  const match = tag.match(new RegExp(`${name}\\s*=\\s*["']([^"']*)["']`, 'i'));
  return match ? decodeHtmlEntities(match[1]) : '';
}

function normalizeBrowserHref(rawHref, baseUrl = '') {
  const raw = String(rawHref || '').trim();
  if (!raw || /^(?:javascript|mailto|tel|sms|data|blob):/i.test(raw)) return '';
  try {
    const url = new URL(raw, baseUrl || undefined);
    if (!['http:', 'https:'].includes(url.protocol)) return '';
    const googleTarget = (url.hostname === 'www.google.com' || url.hostname === 'google.com')
      && (url.pathname === '/url' || url.pathname === '/interstitial')
      ? url.searchParams.get('q') || url.searchParams.get('url')
      : '';
    if (googleTarget && /^https?:\/\//i.test(googleTarget)) return new URL(googleTarget).href;
    return url.href;
  } catch {
    return '';
  }
}

function normalizeBrowserLinks(rawLinks = [], pageUrl = '', maxLinks = MAX_BROWSER_PAGE_LINKS) {
  const pageHost = (() => {
    try {
      return pageUrl ? new URL(pageUrl).hostname.replace(/^www\./i, '') : '';
    } catch {
      return '';
    }
  })();
  const seen = new Set();
  const links = [];
  for (const item of Array.isArray(rawLinks) ? rawLinks : []) {
    const href = normalizeBrowserHref(item?.href || item?.url, pageUrl);
    if (!href) continue;
    const key = href.replace(/#.*$/, '');
    if (seen.has(key)) continue;
    let host = '';
    try {
      host = new URL(href).hostname.replace(/^www\./i, '');
    } catch {
      continue;
    }
    const text = compactRecordText(
      String(item?.text || item?.label || item?.title || item?.ariaLabel || host)
        .replace(/\s+/g, ' ')
        .trim(),
      180,
    ) || host;
    seen.add(key);
    links.push({
      index: links.length + 1,
      text,
      href,
      host,
      sameHost: Boolean(pageHost && host === pageHost),
    });
    if (links.length >= maxLinks) break;
  }
  return links;
}

function extractHtmlLinks(html, pageUrl = '') {
  const rawLinks = [];
  const source = String(html || '');
  for (const match of source.matchAll(/<a\b([^>]*)>([\s\S]*?)<\/a>/gi)) {
    const href = htmlAttributeValue(match[1] || '', 'href');
    if (!href) continue;
    const text = decodeHtmlEntities(String(match[2] || '').replace(/<[^>]+>/g, ' '))
      .replace(/\s+/g, ' ')
      .trim();
    rawLinks.push({ href, text });
    if (rawLinks.length >= MAX_BROWSER_PAGE_LINKS * 4) break;
  }
  return normalizeBrowserLinks(rawLinks, pageUrl);
}

function browserSearchResultLinks(page = {}, maxLinks = 10) {
  const links = Array.isArray(page.links) ? page.links : [];
  const pageHost = (() => {
    try {
      return page.url ? new URL(page.url).hostname.replace(/^www\./i, '') : '';
    } catch {
      return '';
    }
  })();
  const isSearchUtilityHost = (host = '') => {
    const normalized = String(host || '').replace(/^www\./i, '');
    return /^google\.[a-z.]+$/i.test(normalized)
      || ['accounts.google.com', 'policies.google.com', 'support.google.com', 'maps.google.com', 'news.google.com', 'translate.google.com', 'webcache.googleusercontent.com'].includes(normalized)
      || /^bing\.[a-z.]+$/i.test(normalized)
      || /^duckduckgo\.[a-z.]+$/i.test(normalized)
      || normalized === 'search.yahoo.com';
  };
  const searchUtilityHosts = new Set([
    'google.com',
    'accounts.google.com',
    'policies.google.com',
    'support.google.com',
    'maps.google.com',
    'news.google.com',
    'webcache.googleusercontent.com',
    'bing.com',
    'duckduckgo.com',
    'search.yahoo.com',
  ]);
  return links
    .filter((link) => {
      if (!link?.href || !link.host) return false;
      if (pageHost && link.host === pageHost) return false;
      if (searchUtilityHosts.has(link.host) || isSearchUtilityHost(link.host)) return false;
      if (/^(Images|Videos|News|Shopping|Maps|Books|Tools|Settings|Privacy|Terms|Google 应用|Google Apps|登录|Sign in|设置|工具|翻译此页|Translate this page)$/i.test(link.text || '')) return false;
      return true;
    })
    .slice(0, maxLinks)
    .map((link, index) => ({ ...link, index: index + 1 }));
}

function browserWorkflowLinksBlock(page = {}, maxLinks = 12) {
  const links = Array.isArray(page.links) ? page.links.slice(0, maxLinks) : [];
  if (!links.length) return '';
  return links.map((link) => `${link.index}. ${link.text} · ${link.href}`).join('\n');
}

function extractHtmlPage(html, maxChars, pageUrl = '') {
  const source = String(html || '');
  const title = decodeHtmlEntities(source.match(/<title[^>]*>([\s\S]*?)<\/title>/i)?.[1] || '').trim();
  const metaTag = source.match(/<meta[^>]+(?:name|property)\s*=\s*["'](?:description|og:description)["'][^>]*>/i)?.[0] || '';
  const metaDescription = htmlAttributeValue(metaTag, 'content');
  const headings = Array.from(source.matchAll(/<h[1-3][^>]*>([\s\S]*?)<\/h[1-3]>/gi))
    .map((match) => decodeHtmlEntities(match[1].replace(/<[^>]+>/g, ' ')).replace(/\s+/g, ' ').trim())
    .filter(Boolean)
    .slice(0, 40);
  const text = decodeHtmlEntities(
    source
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
      .replace(/<\/(p|div|section|article|li|h[1-6]|tr|br)>/gi, '\n')
      .replace(/<[^>]+>/g, ' '),
  )
    .replace(/[ \t\r]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  return {
    title,
    text: text.slice(0, maxChars),
    textLength: text.length,
    truncated: text.length > maxChars,
    headings,
    metaDescription,
    links: extractHtmlLinks(source, pageUrl),
  };
}

function browserPageFromFileUrl(browser, maxChars, previousError) {
  try {
    const url = new URL(browser.url);
    if (url.protocol !== 'file:') return null;
    const filePath = fileURLToPath(url);
    const html = readUtf8File(filePath, Math.max(maxChars * 4, 1000000));
    const extracted = extractHtmlPage(html, maxChars, browser.url);
    return {
      available: true,
      supported: true,
      app: browser.app,
      title: extracted.title || browser.title,
      url: browser.url,
      text: extracted.text,
      selectedText: '',
      textLength: extracted.textLength,
      truncated: extracted.truncated,
      headings: extracted.headings,
      metaDescription: extracted.metaDescription,
      links: extracted.links,
      fallback: 'file_url',
      error: previousError ? `${previousError}; used file_url fallback` : '',
    };
  } catch {
    return null;
  }
}

async function fetchTextWithLimit(url, maxBytes = 2000000, timeoutMs = 7000) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const response = await fetch(url, {
      signal: controller.signal,
      redirect: 'follow',
      headers: {
        Accept: 'text/html,application/xhtml+xml,text/plain;q=0.8,*/*;q=0.2',
        'User-Agent': `JAVIS/${packageInfo.version} read-only-page-fetch`,
      },
    });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);

    const contentLength = Number(response.headers.get('content-length') || 0);
    if (contentLength > maxBytes) throw new Error(`Response exceeds maxBytes (${contentLength} > ${maxBytes}).`);
    if (!response.body?.getReader) {
      const text = await response.text();
      return text.slice(0, maxBytes);
    }

    const reader = response.body.getReader();
    const chunks = [];
    let received = 0;
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      received += value.byteLength;
      if (received > maxBytes) {
        try {
          await reader.cancel();
        } catch {
          // The response may already be closed.
        }
        throw new Error(`Response exceeds maxBytes (${received} > ${maxBytes}).`);
      }
      chunks.push(Buffer.from(value));
    }
    return Buffer.concat(chunks).toString('utf8');
  } finally {
    clearTimeout(timer);
  }
}

async function browserPageFromHttpUrl(browser, maxChars, previousError) {
  try {
    const url = new URL(browser.url);
    if (url.protocol !== 'http:' && url.protocol !== 'https:') return null;
    const maxBytes = Math.min(2500000, Math.max(1000000, maxChars * 8));
    const html = await fetchTextWithLimit(url.toString(), maxBytes);
    const extracted = extractHtmlPage(html, maxChars, browser.url);
    const fallbackText = [extracted.metaDescription, ...(extracted.headings || [])].filter(Boolean).join('\n');
    const text = extracted.text || fallbackText.slice(0, maxChars);
    return {
      available: true,
      supported: true,
      app: browser.app,
      title: extracted.title || browser.title,
      url: browser.url,
      text,
      selectedText: '',
      textLength: extracted.textLength || text.length,
      truncated: extracted.truncated || fallbackText.length > maxChars,
      headings: extracted.headings,
      metaDescription: extracted.metaDescription,
      links: extracted.links,
      fallback: 'url_fetch',
      error: previousError ? `${previousError}; used url_fetch fallback` : '',
    };
  } catch {
    return null;
  }
}

function browserPageFromMetadata(browser, previousError) {
  const text = [`Title: ${browser.title || ''}`, `URL: ${browser.url || ''}`].join('\n').trim();
  return {
    available: true,
    supported: Boolean(browser.supported),
    app: browser.app || '',
    title: browser.title || '',
    url: browser.url || '',
    text,
    selectedText: '',
    textLength: text.length,
    truncated: false,
    headings: [],
    metaDescription: '',
    links: [],
    fallback: 'metadata_only',
    error: previousError ? 'browser_text_unavailable; using title and URL only' : '',
  };
}

async function browserPageSnapshot(options = {}) {
  const actionConfig = actionPolicy.allow?.read_browser_page;
  if (!actionConfig?.enabled) {
    return {
      available: false,
      supported: false,
      app: '',
      title: '',
      url: '',
      text: '',
      selectedText: '',
      textLength: 0,
      truncated: false,
      headings: [],
      metaDescription: '',
      links: [],
      error: 'read_browser_page_disabled_by_policy',
    };
  }

  const maxChars = normalizeBrowserMaxChars(options.maxChars);
  const browser = await browserContextSnapshot({ app: options.app });
  if (!browser.available || !browser.supported) {
    return {
      ...browser,
      text: '',
      selectedText: '',
      textLength: 0,
      truncated: false,
      headings: [],
      metaDescription: '',
      links: [],
    };
  }

  const js = `
(() => {
  const max = ${JSON.stringify(maxChars)};
  const maxLinks = ${JSON.stringify(MAX_BROWSER_PAGE_LINKS)};
  const clean = (value) => String(value || '').replace(/[\\t\\r ]+/g, ' ').replace(/\\n{3,}/g, '\\n\\n').trim();
  const visible = (node) => {
    try {
      const style = window.getComputedStyle(node);
      return style && style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0' && node.getClientRects().length > 0;
    } catch (_) {
      return false;
    }
  };
  const selectedText = clean(window.getSelection ? window.getSelection().toString() : '');
  const bodyText = clean(document.body ? document.body.innerText : '');
  const text = selectedText || bodyText;
  const meta = document.querySelector('meta[name="description"], meta[property="og:description"]');
  const headings = Array.from(document.querySelectorAll('h1,h2,h3'))
    .map((node) => clean(node.innerText))
    .filter(Boolean)
    .slice(0, 40);
  const links = Array.from(document.querySelectorAll('a[href]'))
    .filter(visible)
    .map((node) => ({
      text: clean(node.innerText || node.getAttribute('aria-label') || node.getAttribute('title') || ''),
      href: node.href || node.getAttribute('href') || '',
      title: clean(node.getAttribute('title') || ''),
      ariaLabel: clean(node.getAttribute('aria-label') || '')
    }))
    .filter((link) => link.href)
    .slice(0, maxLinks * 4);
  return JSON.stringify({
    title: document.title || '',
    url: location.href,
    selectedText: selectedText.slice(0, max),
    text: text.slice(0, max),
    textLength: text.length,
    truncated: text.length > max,
    headings,
    metaDescription: meta ? clean(meta.getAttribute('content') || '') : '',
    links
  });
})()
  `.trim();

  try {
    const page = await executeBrowserJavaScriptBridge(browser, js, { timeoutMs: 5000, maxBuffer: 1024 * 1024 * 4 });
    const parsed = JSON.parse(String(page.output || '').trim());
    const result = {
      available: true,
      supported: true,
      bridge: page.bridge,
      app: browser.app,
      title: parsed.title || browser.title,
      url: parsed.url || browser.url,
      text: String(parsed.text || ''),
      selectedText: String(parsed.selectedText || ''),
      textLength: Number(parsed.textLength || 0),
      truncated: Boolean(parsed.truncated),
      headings: Array.isArray(parsed.headings) ? parsed.headings.map(String) : [],
      metaDescription: String(parsed.metaDescription || ''),
      links: normalizeBrowserLinks(parsed.links, parsed.url || browser.url),
      error: '',
    };
    appendAudit('browser_page.read', {
      app: result.app,
      url: result.url,
      textLength: result.textLength,
      returnedLength: result.text.length,
      truncated: result.truncated,
      linkCount: result.links.length,
      bridge: result.bridge,
    });
    return result;
  } catch (error) {
    const message = compactBrowserJavaScriptError(error);
    const fileFallback = browserPageFromFileUrl(browser, maxChars, message);
    if (fileFallback) {
      appendAudit('browser_page.read', {
        app: fileFallback.app,
        url: fileFallback.url,
        textLength: fileFallback.textLength,
        returnedLength: fileFallback.text.length,
        truncated: fileFallback.truncated,
        linkCount: fileFallback.links?.length || 0,
        fallback: fileFallback.fallback,
      });
      return fileFallback;
    }
    const httpFallback = await browserPageFromHttpUrl(browser, maxChars, message);
    if (httpFallback) {
      appendAudit('browser_page.read', {
        app: httpFallback.app,
        url: httpFallback.url,
        textLength: httpFallback.textLength,
        returnedLength: httpFallback.text.length,
        truncated: httpFallback.truncated,
        linkCount: httpFallback.links?.length || 0,
        fallback: httpFallback.fallback,
      });
      return httpFallback;
    }
    const metadataFallback = browserPageFromMetadata(browser, message);
    appendAudit('browser_page.read', {
      app: metadataFallback.app,
      url: metadataFallback.url,
      textLength: metadataFallback.textLength,
      returnedLength: metadataFallback.text.length,
      truncated: metadataFallback.truncated,
      linkCount: 0,
      fallback: metadataFallback.fallback,
    });
    return metadataFallback;
  }
}

async function executeBrowserJavaScript(browser, js, options = {}) {
  const appName = browser?.app || String(options.app || '').trim();
  if (!appName) throw new Error('No supported browser is active.');
  const isSafari = appName === 'Safari' || appName === 'Safari Technology Preview';
  const quotedApp = appleScriptString(appName);
  const quotedJs = appleScriptString(js);
  const script = isSafari
    ? [
        `tell application ${quotedApp}`,
        '  if not (exists front document) then error "No front document"',
        `  set pageResult to do JavaScript ${quotedJs} in front document`,
        'end tell',
        'return pageResult',
      ].join('\n')
    : [
        `tell application ${quotedApp}`,
        '  if not (exists front window) then error "No front window"',
        `  set pageResult to execute active tab of front window javascript ${quotedJs}`,
        'end tell',
        'return pageResult',
      ].join('\n');
  const { stdout } = await execFileAsync('osascript', ['-e', script], {
    timeout: Math.max(1000, Math.min(15000, Number(options.timeoutMs || 6000))),
    maxBuffer: Math.max(1024 * 256, Math.min(1024 * 1024 * 8, Number(options.maxBuffer || 1024 * 1024 * 4))),
    env: guardedChildProcessEnv({ source: 'browser_javascript_bridge' }),
  });
  return String(stdout || '').trim();
}

function compactBrowserJavaScriptError(error) {
  const message = String(error?.stderr || (error instanceof Error ? error.message : error) || '');
  if (/AppleScript.*JavaScript|Apple Events|Apple 事件|执行 JavaScript 的功能已关闭|Allow JavaScript from Apple Events/i.test(message)) {
    return 'browser_javascript_from_apple_events_disabled';
  }
  if (/ECONNREFUSED|fetch failed|Failed to fetch/i.test(message)) {
    return 'browser_cdp_unavailable';
  }
  if (/WebSocket/i.test(message)) {
    return 'browser_cdp_websocket_error';
  }
  if (/cdp/i.test(message)) {
    return compactRecordText(message.split('\n')[0], 220) || 'browser_cdp_unavailable';
  }
  return message.split('\n')[0].slice(0, 500) || 'browser_javascript_unavailable';
}

function cdpBaseUrl() {
  return `http://127.0.0.1:${CHROME_DEBUG_PORT}`;
}

async function cdpFetchJson(pathname, options = {}) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), Math.max(500, Math.min(5000, Number(options.timeoutMs || 1200))));
  try {
    const response = await fetch(`${cdpBaseUrl()}${pathname}`, { signal: controller.signal });
    if (!response.ok) throw new Error(`cdp_http_${response.status}`);
    return await response.json();
  } finally {
    clearTimeout(timeout);
  }
}

async function cdpTargetsSnapshot() {
  const targets = await cdpFetchJson('/json/list');
  return Array.isArray(targets) ? targets : [];
}

function normalizeBrowserUrlForMatch(value) {
  try {
    const url = new URL(String(value || ''));
    url.hash = '';
    return url.toString();
  } catch {
    return String(value || '').trim();
  }
}

function isSafeBlankBrowserUrl(value = '') {
  const url = String(value || '').trim().toLowerCase();
  return url === 'about:blank' ||
    url === 'chrome://newtab/' ||
    url === 'chrome://new-tab-page/' ||
    url === 'edge://newtab/' ||
    url === 'brave://newtab/' ||
    url === 'vivaldi://newtab/' ||
    url === 'opera://startpage/' ||
    url === 'browser://newtab/';
}

function isSafeBlankCdpTarget(target = {}) {
  return target.type === 'page' &&
    Boolean(target.webSocketDebuggerUrl) &&
    isSafeBlankBrowserUrl(target.url || '');
}

function chooseCdpTarget(targets = [], browser = {}) {
  const pages = targets.filter((target) => target.type === 'page' && target.webSocketDebuggerUrl);
  const browserUrl = normalizeBrowserUrlForMatch(browser.url || '');
  if (browserUrl) {
    const exact = pages.find((target) => normalizeBrowserUrlForMatch(target.url || '') === browserUrl);
    if (exact) return exact;
  }
  const title = String(browser.title || '').trim();
  if (title) {
    const titleHit = pages.find((target) => String(target.title || '').trim() === title);
    if (titleHit) return titleHit;
  }
  if (isSafeBlankBrowserUrl(browserUrl) || isSafeBlankBrowserUrl(browser.url || '')) {
    const safeBlank = pages.find((target) => isSafeBlankCdpTarget(target));
    if (safeBlank) return safeBlank;
  }
  if (browserUrl || title) return null;
  return pages.find((target) => /^https?:|^file:/i.test(String(target.url || ''))) || pages[0] || null;
}

async function cdpStatusSnapshot(browser = {}) {
  if (!CHROME_DEBUG_PORT) {
    return { enabled: false, port: CHROME_DEBUG_PORT, targets: 0, selectedTarget: null, error: 'chrome_debug_port_disabled' };
  }
  if (typeof WebSocket !== 'function') {
    return { enabled: false, port: CHROME_DEBUG_PORT, targets: 0, selectedTarget: null, error: 'websocket_unavailable' };
  }
  try {
    await cdpFetchJson('/json/version');
    const targets = await cdpTargetsSnapshot();
    const selected = chooseCdpTarget(targets, browser);
    return {
      enabled: Boolean(selected),
      port: CHROME_DEBUG_PORT,
      targets: targets.length,
      selectedTarget: selected
        ? {
            id: selected.id || '',
            title: selected.title || '',
            url: selected.url || '',
          }
        : null,
      error: selected ? '' : 'no_cdp_page_target',
    };
  } catch (error) {
    return {
      enabled: false,
      port: CHROME_DEBUG_PORT,
      targets: 0,
      selectedTarget: null,
      error: compactBrowserJavaScriptError(error) || 'browser_cdp_unavailable',
    };
  }
}

function chromeExecutableForApp(appName = '') {
  const name = String(appName || '').trim();
  const candidates = name === 'Google Chrome Canary'
    ? ['/Applications/Google Chrome Canary.app/Contents/MacOS/Google Chrome Canary']
    : ['/Applications/Google Chrome.app/Contents/MacOS/Google Chrome'];
  return candidates.find((candidate) => fs.existsSync(candidate)) || '';
}

async function waitForCdpReady(browser = {}, timeoutMs = 5000) {
  const deadline = Date.now() + Math.max(1000, Math.min(15000, Number(timeoutMs || 5000)));
  let last = null;
  while (Date.now() < deadline) {
    last = await cdpStatusSnapshot(browser);
    if (last.enabled) return last;
    await waitMs(350);
  }
  return last || await cdpStatusSnapshot(browser);
}

async function launchChromeCdpFallback(browser = {}) {
  const appName = browser.app || 'Google Chrome';
  if (!CHROME_DEBUG_PORT || !['Google Chrome', 'Google Chrome Canary'].includes(appName)) {
    return { ok: false, launched: false, error: 'chrome_cdp_fallback_unsupported_app' };
  }
  const executable = chromeExecutableForApp(appName);
  if (!executable) return { ok: false, launched: false, error: 'chrome_executable_not_found' };
  fs.mkdirSync(CHROME_CDP_PROFILE_DIR, { recursive: true });
  const url = /^https?:|^file:/i.test(String(browser.url || '')) ? browser.url : 'about:blank';
  const child = spawn(executable, [
    `--remote-debugging-port=${CHROME_DEBUG_PORT}`,
    `--user-data-dir=${CHROME_CDP_PROFILE_DIR}`,
    '--no-first-run',
    '--no-default-browser-check',
    url,
  ], {
    detached: true,
    stdio: 'ignore',
    env: guardedChildProcessEnv({ source: 'chrome_cdp_fallback' }),
  });
  child.unref();
  appendAudit('browser_cdp.launch_requested', {
    app: appName,
    port: CHROME_DEBUG_PORT,
    profileDir: CHROME_CDP_PROFILE_DIR,
    url,
    pid: child.pid || null,
  });
  const status = await waitForCdpReady({ ...browser, url }, 7000);
  return {
    ok: Boolean(status.enabled),
    launched: true,
    status,
    error: status.enabled ? '' : status.error || 'browser_cdp_unavailable_after_launch',
  };
}

function cdpEvaluateExpression(webSocketUrl, expression, options = {}) {
  return new Promise((resolve, reject) => {
    const timeoutMs = Math.max(1000, Math.min(10000, Number(options.timeoutMs || 5000)));
    const ws = new WebSocket(webSocketUrl);
    const requestId = 1;
    const timer = setTimeout(() => {
      try {
        ws.close();
      } catch {
        // Ignore close failures.
      }
      reject(new Error('browser_cdp_evaluate_timeout'));
    }, timeoutMs);
    ws.addEventListener('open', () => {
      ws.send(JSON.stringify({
        id: requestId,
        method: 'Runtime.evaluate',
        params: {
          expression,
          awaitPromise: true,
          returnByValue: true,
          userGesture: true,
        },
      }));
    });
    ws.addEventListener('message', (event) => {
      let data = null;
      try {
        data = JSON.parse(String(event.data || ''));
      } catch {
        return;
      }
      if (data.id !== requestId) return;
      clearTimeout(timer);
      try {
        ws.close();
      } catch {
        // Ignore close failures.
      }
      if (data.error) {
        reject(new Error(data.error.message || 'browser_cdp_evaluate_failed'));
        return;
      }
      if (data.result?.exceptionDetails) {
        reject(new Error(data.result.exceptionDetails.text || 'browser_cdp_runtime_exception'));
        return;
      }
      resolve(data.result?.result?.value ?? '');
    });
    ws.addEventListener('error', () => {
      clearTimeout(timer);
      reject(new Error('browser_cdp_websocket_error'));
    });
  });
}

async function executeBrowserJavaScriptViaCdp(browser, js, options = {}) {
  const targets = await cdpTargetsSnapshot();
  const target = chooseCdpTarget(targets, browser);
  if (!target?.webSocketDebuggerUrl) throw new Error('browser_cdp_target_not_found');
  const output = await cdpEvaluateExpression(target.webSocketDebuggerUrl, js, options);
  return String(output || '');
}

async function executeBrowserJavaScriptBridge(browser, js, options = {}) {
  try {
    return {
      output: await executeBrowserJavaScript(browser, js, options),
      bridge: 'apple_events',
    };
  } catch (appleError) {
    const appleMessage = compactBrowserJavaScriptError(appleError);
    try {
      return {
        output: await executeBrowserJavaScriptViaCdp(browser, js, options),
        bridge: 'cdp',
        appleError: appleMessage,
      };
    } catch (cdpError) {
      const cdpMessage = compactBrowserJavaScriptError(cdpError);
      if (appleMessage === 'browser_javascript_from_apple_events_disabled' && ['browser_cdp_unavailable', 'browser_cdp_target_not_found'].includes(cdpMessage)) {
        const launched = await launchChromeCdpFallback(browser);
        if (launched.ok) {
          return {
            output: await executeBrowserJavaScriptViaCdp(browser, js, options),
            bridge: 'cdp',
            appleError: appleMessage,
            cdpLaunched: true,
          };
        }
      }
      const error = new Error(appleMessage || compactBrowserJavaScriptError(cdpError));
      error.appleError = appleMessage;
      error.cdpError = cdpMessage;
      throw error;
    }
  }
}

async function browserJavaScriptStatusSnapshot(options = {}) {
  const browser = await browserContextSnapshot({ app: options.app });
  if (!browser.supported || !browser.available) {
    return {
      available: false,
      supported: Boolean(browser.supported),
      enabled: false,
      app: browser.app || '',
      title: browser.title || '',
      url: browser.url || '',
      error: browser.error || 'no_supported_browser_page',
    };
  }
  const cdp = await cdpStatusSnapshot(browser);
  try {
    const result = await executeBrowserJavaScriptBridge(browser, 'JSON.stringify({ ok: true, title: document.title || "", url: location.href })', {
      timeoutMs: 3000,
      maxBuffer: 1024 * 256,
    });
    const raw = result.output;
    const parsed = JSON.parse(raw || '{}');
    return {
      available: true,
      supported: true,
      enabled: parsed.ok === true,
      bridge: result.bridge,
      appleEventsEnabled: result.bridge === 'apple_events',
      cdpEnabled: result.bridge === 'cdp',
      cdp,
      app: browser.app,
      title: parsed.title || browser.title,
      url: parsed.url || browser.url,
      error: '',
    };
  } catch (error) {
    return {
      available: true,
      supported: true,
      enabled: false,
      bridge: '',
      appleEventsEnabled: false,
      cdpEnabled: false,
      cdp,
      app: browser.app,
      title: browser.title,
      url: browser.url,
      error: compactBrowserJavaScriptError(error),
      appleError: error.appleError || '',
      cdpError: error.cdpError || '',
    };
  }
}

function browserReadinessStatus({ context = {}, cdp = {}, pagePolicy = {} } = {}) {
  if (process.platform !== 'darwin') return 'blocked';
  if (!pagePolicy.enabled) return 'blocked';
  if (!context.supported) return 'warning';
  if (!context.available) return 'warning';
  if (cdp.enabled) return 'ready';
  return 'limited';
}

function browserReadinessLabel(status) {
  if (status === 'ready') return 'Browser ready';
  if (status === 'limited') return 'Browser context ready, bridge unverified';
  if (status === 'blocked') return 'Browser blocked';
  return 'Browser needs attention';
}

function browserReadinessNextActions({ context = {}, cdp = {}, supportedRunning = [] } = {}) {
  const actions = [];
  if (process.platform !== 'darwin') {
    actions.push({
      id: 'use_macos',
      label: 'Run on macOS',
      summary: 'Browser context and UI automation currently use macOS browser automation bridges.',
    });
    return actions;
  }

  if (!context.available || !context.supported) {
    const appName = supportedRunning[0] || 'Google Chrome';
    actions.push({
      id: 'open_supported_browser',
      label: 'Open or focus a supported browser',
      summary: 'JAVIS defaults to the frontmost supported browser tab, then the first running supported browser tab. No window picker is required.',
      endpoint: '/api/browser/prepare',
      method: 'POST',
      prepareCommand: 'npm run browser:prepare',
      command: `open -a ${JSON.stringify(appName)}`,
    });
    actions.push({
      id: 'check_context',
      label: 'Check browser context',
      endpoint: '/api/browser/context',
      command: 'curl http://127.0.0.1:3417/api/browser/context',
    });
    return actions;
  }

  actions.push({
    id: 'read_current_page',
    label: 'Read current page',
    endpoint: '/api/browser/page',
    command: 'curl http://127.0.0.1:3417/api/browser/page',
  });

  if (cdp.enabled) {
    actions.push({
      id: 'read_dom_controls',
      label: 'Read DOM controls',
      endpoint: '/api/browser/dom?limit=20',
      command: 'curl "http://127.0.0.1:3417/api/browser/dom?limit=20"',
    });
    return actions;
  }

  actions.push({
    id: 'verify_javascript_bridge',
    label: 'Verify JavaScript bridge',
    summary: 'Runs the existing bridge check only when explicitly requested; the readiness packet itself does not execute page JavaScript.',
    endpoint: '/api/browser/javascript',
    command: 'curl http://127.0.0.1:3417/api/browser/javascript',
  });

  if (['Google Chrome', 'Google Chrome Canary'].includes(context.app)) {
    const executable = chromeExecutableForApp(context.app) || '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome';
    actions.push({
      id: 'start_chrome_devtools_bridge',
      label: 'Start Chrome DevTools bridge',
      summary: 'Use this only if Apple Events JavaScript is unavailable and DOM reads need CDP.',
      command: `${JSON.stringify(executable)} --remote-debugging-port=${CHROME_DEBUG_PORT} --user-data-dir=${JSON.stringify(CHROME_CDP_PROFILE_DIR)} --no-first-run --no-default-browser-check`,
    });
  }

  if (SAFARI_BROWSER_APPS.has(context.app)) {
    actions.push({
      id: 'enable_safari_javascript_events',
      label: 'Enable Safari JavaScript bridge',
      summary: 'Safari requires Develop > Allow JavaScript from Apple Events before DOM reads can execute page JavaScript.',
    });
  }

  return actions;
}

function rememberBrowserReadiness(snapshot = {}, options = {}) {
  const context = snapshot.context || {};
  const cdp = snapshot.bridges?.cdp || {};
  const page = snapshot.capabilities?.page || {};
  browserReadinessState = {
    lastCheckedAt: Date.now(),
    source: String(options.source || snapshot.source || 'browser_readiness').slice(0, 80),
    app: String(context.app || snapshot.defaultTarget?.app || '').slice(0, 120),
    title: compactRecordText(context.title || '', 180),
    url: compactRecordText(context.url || '', 500),
    readinessStatus: String(snapshot.status || ''),
    readinessSummary: compactRecordText(snapshot.summary || '', 260),
    contextAvailable: Boolean(context.available),
    contextSupported: Boolean(context.supported),
    cdpEnabled: Boolean(cdp.enabled),
    pageReady: page.status === 'ready',
  };
  return browserReadinessState;
}

async function browserReadinessSnapshot(options = {}) {
  const frontmost = await frontmostAppSnapshot();
  const runningNames = await runningApplicationNames();
  const requestedApp = String(options.app || '').trim();
  const context = await browserContextSnapshot({ app: requestedApp, frontmost });
  const cdp = await cdpStatusSnapshot(context.available && context.supported ? context : {});
  const supportedRunning = browserAppCandidates(runningNames, requestedApp || frontmost.app);
  const pagePolicy = actionPolicy.allow?.read_browser_page || {};
  const controlPolicy = actionPolicy.allow?.browser_control || {};
  const status = browserReadinessStatus({ context, cdp, pagePolicy });
  const nextActions = browserReadinessNextActions({ context, cdp, supportedRunning });
  const defaultTarget = {
    mode: requestedApp ? 'requested_app' : 'active_or_first_supported_browser',
    app: context.app || requestedApp || '',
    source: context.source || 'auto',
    asksWhichWindow: false,
    selector: requestedApp
      ? `requested app: ${requestedApp}`
      : 'frontmost supported browser tab, then first running supported browser tab',
    summary: requestedApp
      ? `Using requested browser app ${requestedApp}.`
      : 'Uses the current supported browser tab by default; if the frontmost app is not a browser, falls back to the first running supported browser.',
  };
  const pageReady = Boolean(pagePolicy.enabled && context.available && context.supported);
  const controlReady = Boolean(controlPolicy.enabled && context.supported && (context.available || context.app));
  const bridgeReady = Boolean(cdp.enabled);
  const snapshot = {
    version: 1,
    status,
    label: browserReadinessLabel(status),
    summary: status === 'ready'
      ? `Default browser target is ${context.app || 'browser'} · ${context.title || context.url || 'active tab'}.`
      : context.available
        ? `Browser context is available in ${context.app || 'browser'}, but DOM/JavaScript bridge should be verified before webpage actions.`
        : `No supported browser tab is currently available for the default target (${context.error || 'unknown'}).`,
    nextAction: nextActions[0] || null,
    defaultTarget,
    frontmost: {
      available: Boolean(frontmost.available),
      app: frontmost.app || '',
      windowTitle: frontmost.windowTitle || '',
      supportedBrowser: isSupportedBrowserApp(frontmost.app || ''),
      error: frontmost.error || '',
    },
    running: {
      supported: supportedRunning,
      count: supportedRunning.length,
    },
    context,
    bridges: {
      cdp: {
        ...cdp,
        baseUrl: CHROME_DEBUG_PORT ? cdpBaseUrl() : '',
        profileDir: CHROME_CDP_PROFILE_DIR,
      },
      javascript: {
        verified: false,
        status: bridgeReady ? 'ready_via_cdp' : context.available ? 'verify_on_demand' : 'unavailable',
        endpoint: '/api/browser/javascript',
        note: 'Readiness does not execute page JavaScript; call the endpoint explicitly when DOM reads or DOM actions are needed.',
      },
      appleEvents: {
        metadataReady: Boolean(context.available && context.supported),
        javascriptVerified: false,
        note: 'Context/title/URL are read through Apple Events metadata. JavaScript execution is checked separately.',
      },
    },
    capabilities: {
      context: {
        status: context.available ? 'ready' : context.supported ? 'limited' : 'warning',
        endpoint: '/api/browser/context',
      },
      page: {
        status: pageReady ? 'ready' : pagePolicy.enabled ? 'waiting_for_browser' : 'blocked_by_policy',
        endpoint: '/api/browser/page',
      },
      dom: {
        status: bridgeReady ? 'ready' : context.available ? 'verify_bridge' : 'waiting_for_browser',
        endpoint: '/api/browser/dom?limit=20',
      },
      control: {
        status: controlReady ? 'ready' : controlPolicy.enabled ? 'waiting_for_browser' : 'blocked_by_policy',
        endpoint: '/api/browser/control',
      },
    },
    endpoints: [
      '/api/browser/context',
      '/api/browser/prepare',
      '/api/browser/page',
      '/api/browser/javascript',
      '/api/browser/dom?limit=20',
      '/api/browser/control',
      '/api/browser/workflow',
      '/api/browser/benchmarks',
    ],
    commands: {
      readiness: 'npm run browser:ready',
      prepare: 'npm run browser:prepare',
      context: 'curl http://127.0.0.1:3417/api/browser/context',
      page: 'curl http://127.0.0.1:3417/api/browser/page',
      javascript: 'curl http://127.0.0.1:3417/api/browser/javascript',
      dom: 'curl "http://127.0.0.1:3417/api/browser/dom?limit=20"',
      benchmarks: 'npm run config -- --print-browser-benchmarks',
    },
    nextActions,
    safety: {
      readOnly: true,
      startsBrowser: false,
      executesBrowserActions: false,
      executesPageJavaScript: false,
      readsPageText: false,
      storesPageText: false,
      startsMicrophone: false,
      callsOpenAi: false,
      asksWhichWindow: false,
    },
  };
  rememberBrowserReadiness(snapshot, options);
  return snapshot;
}

function browserDomSnapshotScript(limit) {
  return `
(() => {
  const limit = ${JSON.stringify(limit)};
  const clean = (value, max = 180) => String(value || '')
    .replace(/[\\t\\r\\n ]+/g, ' ')
    .trim()
    .slice(0, max);
  const cssEscape = (value) => {
    if (window.CSS && typeof window.CSS.escape === 'function') return window.CSS.escape(String(value));
    return String(value).replace(/[^a-zA-Z0-9_-]/g, (char) => '\\\\' + char);
  };
  const attrEscape = (value) => String(value).replace(/\\\\/g, '\\\\\\\\').replace(/"/g, '\\\\"');
  const visible = (el) => {
    if (!el || !(el instanceof Element)) return false;
    const style = window.getComputedStyle(el);
    if (style.display === 'none' || style.visibility === 'hidden' || Number(style.opacity || 1) === 0) return false;
    const rect = el.getBoundingClientRect();
    return rect.width > 1 && rect.height > 1;
  };
  const selectorFor = (el) => {
    if (el.id) {
      const selector = '#' + cssEscape(el.id);
      if (document.querySelectorAll(selector).length === 1) return selector;
    }
    for (const attr of ['data-testid', 'data-test', 'aria-label', 'name', 'placeholder', 'title']) {
      const value = el.getAttribute(attr);
      if (!value) continue;
      const selector = el.tagName.toLowerCase() + '[' + attr + '="' + attrEscape(value) + '"]';
      try {
        if (document.querySelectorAll(selector).length === 1) return selector;
      } catch (_) {}
    }
    const parts = [];
    let node = el;
    while (node && node.nodeType === 1 && node !== document.documentElement && parts.length < 5) {
      const tag = node.tagName.toLowerCase();
      const parent = node.parentElement;
      if (!parent) break;
      const sameTag = Array.from(parent.children).filter((child) => child.tagName === node.tagName);
      const index = sameTag.indexOf(node) + 1;
      parts.unshift(tag + ':nth-of-type(' + index + ')');
      const selector = parts.join(' > ');
      try {
        if (document.querySelector(selector) === el) return selector;
      } catch (_) {}
      node = parent;
    }
    return parts.join(' > ');
  };
  const labelsFor = (el) => {
    const values = [
      el.getAttribute('aria-label'),
      el.getAttribute('title'),
      el.getAttribute('alt'),
      el.getAttribute('placeholder'),
      el.getAttribute('name'),
      el.innerText,
      el.textContent,
    ];
    if (el.id) {
      const label = document.querySelector('label[for="' + attrEscape(el.id) + '"]');
      if (label) values.unshift(label.innerText);
    }
    if (el.labels) {
      for (const label of Array.from(el.labels)) values.unshift(label.innerText);
    }
    if (['button', 'submit', 'reset'].includes(String(el.type || '').toLowerCase())) values.unshift(el.value);
    return values.map((value) => clean(value)).filter(Boolean);
  };
  const selector = [
    'a[href]',
    'button',
    'input',
    'textarea',
    'select',
    '[role="button"]',
    '[role="link"]',
    '[role="menuitem"]',
    '[role="checkbox"]',
    '[role="radio"]',
    '[role="tab"]',
    '[contenteditable="true"]',
    '[tabindex]:not([tabindex="-1"])'
  ].join(',');
  const elements = Array.from(document.querySelectorAll(selector))
    .filter(visible)
    .slice(0, limit)
    .map((el, index) => {
      const rect = el.getBoundingClientRect();
      const tag = el.tagName.toLowerCase();
      const type = clean(el.getAttribute('type') || el.getAttribute('role') || '', 40);
      const labels = labelsFor(el);
      const label = labels[0] || '';
      const disabled = Boolean(el.disabled || el.getAttribute('aria-disabled') === 'true');
      const valuePreview = tag === 'select'
        ? clean(el.options?.[el.selectedIndex]?.text || '', 80)
        : (['checkbox', 'radio'].includes(String(el.type || '').toLowerCase()) ? String(Boolean(el.checked)) : '');
      return {
        id: String(index + 1),
        selector: selectorFor(el),
        tag,
        type,
        role: clean(el.getAttribute('role') || '', 60),
        label,
        text: clean(el.innerText || el.textContent || '', 160),
        placeholder: clean(el.getAttribute('placeholder') || '', 100),
        name: clean(el.getAttribute('name') || '', 80),
        href: clean(el.getAttribute('href') || '', 220),
        valuePreview,
        disabled,
        rect: {
          x: Math.round(rect.x),
          y: Math.round(rect.y),
          width: Math.round(rect.width),
          height: Math.round(rect.height)
        }
      };
    });
  return JSON.stringify({
    available: true,
    title: document.title || '',
    url: location.href,
    count: elements.length,
    elements
  });
})()
  `.trim();
}

async function browserDomSnapshot(options = {}) {
  const actionConfig = actionPolicy.allow?.read_browser_page;
  if (!actionConfig?.enabled) {
    return {
      available: false,
      supported: false,
      app: '',
      title: '',
      url: '',
      count: 0,
      elements: [],
      error: 'read_browser_page_disabled_by_policy',
    };
  }
  const browser = await browserContextSnapshot({ app: options.app });
  if (!browser.available || !browser.supported) {
    return {
      ...browser,
      count: 0,
      elements: [],
    };
  }
  const limit = Math.max(1, Math.min(120, Number(options.limit || 60)));
  try {
    const snapshot = await executeBrowserJavaScriptBridge(browser, browserDomSnapshotScript(limit), { timeoutMs: 6000 });
    const parsed = JSON.parse(snapshot.output || '{}');
    const result = {
      available: true,
      supported: true,
      bridge: snapshot.bridge,
      app: browser.app,
      title: String(parsed.title || browser.title || ''),
      url: String(parsed.url || browser.url || ''),
      count: Number(parsed.count || 0),
      elements: Array.isArray(parsed.elements) ? parsed.elements.slice(0, limit) : [],
      error: '',
    };
    appendAudit('browser_dom.read', {
      app: result.app,
      url: result.url,
      count: result.count,
      returned: result.elements.length,
      bridge: result.bridge,
    });
    return result;
  } catch (error) {
    return {
      available: false,
      supported: true,
      app: browser.app,
      title: browser.title,
      url: browser.url,
      count: 0,
      elements: [],
      error: compactBrowserJavaScriptError(error),
      appleError: error.appleError || '',
      cdpError: error.cdpError || '',
    };
  }
}

const BROWSER_DOM_ACTIONS = new Set(['click', 'fill', 'select']);
const BROWSER_DOM_DANGEROUS_RE = /\b(submit|send|buy|purchase|pay|checkout|delete|remove|destroy|confirm|login|log in|sign in|sign up|register|subscribe|unsubscribe|post|publish|share|transfer|withdraw|deposit|trade)\b|提交|发送|购买|付款|支付|删除|移除|确认|登录|注册|发布|分享|转账|提现|充值|交易/i;

function explicitConfirmationFlag(value) {
  if (value === true) return true;
  if (value === 1) return true;
  const text = String(value || '').trim().toLowerCase();
  return ['true', '1', 'yes', 'y', 'confirm', 'confirmed', 'approve', 'approved'].includes(text);
}

function browserDomActionApproved(args = {}, options = {}) {
  return Boolean(
    options.approved ||
    explicitConfirmationFlag(args.confirm) ||
    explicitConfirmationFlag(args.approved),
  );
}

function normalizeBrowserDomAction(value) {
  const raw = String(value || '').trim().toLowerCase().replace(/[-\s]+/g, '_');
  const aliases = {
    press: 'click',
    tap: 'click',
    choose: 'select',
    set: 'fill',
    set_value: 'fill',
    type: 'fill',
    input: 'fill',
    点击: 'click',
    按: 'click',
    选择: 'select',
    填写: 'fill',
    输入: 'fill',
  };
  const normalized = aliases[raw] || raw;
  return BROWSER_DOM_ACTIONS.has(normalized) ? normalized : '';
}

function browserDomActionRisk(args = {}, domAction = '') {
  const text = [
    args.query,
    args.label,
    args.text,
    args.selector,
    args.expectedText,
    args.value,
  ].map((item) => String(item || '')).join(' ');
  if (BROWSER_DOM_DANGEROUS_RE.test(text)) return 4;
  if (domAction === 'click') return 3;
  if (domAction === 'fill' || domAction === 'select') return 3;
  return 2;
}

function buildBrowserDomActionPlan(args = {}) {
  const domAction = normalizeBrowserDomAction(args.domAction || args.browserAction || args.action);
  if (!domAction) throw new Error('Unsupported browser DOM action.');
  const browserAction = `dom_${domAction}`;
  const actionConfig = actionPolicy.allow?.browser_control || {};
  if (!valueMatchesAllowlist(browserAction, actionConfig.allowedActions || [])) {
    throw new Error(`Browser action ${browserAction} is not allowed by policy.`);
  }
  const selector = String(args.selector || '').trim().slice(0, 500);
  const query = String(args.query || args.label || args.text || '').trim().slice(0, 300);
  const value = String(args.value ?? args.content ?? '').slice(0, 4000);
  if (!selector && !query) throw new Error('Browser DOM action requires selector or query.');
  if ((domAction === 'fill' || domAction === 'select') && !value) throw new Error('Browser DOM fill/select requires value.');
  const target = selector || query;
  return {
    action: 'browser_control',
    riskLevel: browserDomActionRisk({ ...args, selector, query, value }, domAction),
    summary: domAction === 'click'
      ? `Click browser element ${compactRecordText(target, 120)}`
      : `${domAction === 'select' ? 'Select' : 'Fill'} browser element ${compactRecordText(target, 120)}`,
    target: browserAction,
    args: {
      action: 'browser_control',
      browserAction,
      domAction,
      app: String(args.app || '').trim(),
      selector,
      query,
      value,
    },
    metadata: {
      browserAction,
      domAction,
      reobserveBeforeExecute: true,
      noFormSubmitByDefault: true,
      submitLikeRiskLevel: 4,
    },
  };
}

function browserDomActionPreflightScript(plan) {
  const args = plan.args || {};
  return `
(() => {
  const domAction = ${JSON.stringify(args.domAction)};
  const selector = ${JSON.stringify(args.selector || '')};
  const query = ${JSON.stringify(args.query || '')}.toLowerCase();
  const clean = (input, max = 220) => String(input || '').replace(/[\\t\\r\\n ]+/g, ' ').trim().slice(0, max);
  const attrEscape = (input) => String(input).replace(/\\\\/g, '\\\\\\\\').replace(/"/g, '\\\\"');
  const visible = (el) => {
    if (!el || !(el instanceof Element)) return false;
    const style = window.getComputedStyle(el);
    if (style.display === 'none' || style.visibility === 'hidden' || Number(style.opacity || 1) === 0) return false;
    const rect = el.getBoundingClientRect();
    return rect.width > 1 && rect.height > 1;
  };
  const labelOf = (el) => {
    const values = [
      el.getAttribute('aria-label'),
      el.getAttribute('title'),
      el.getAttribute('alt'),
      el.getAttribute('placeholder'),
      el.getAttribute('name'),
      el.innerText,
      el.textContent,
    ];
    if (el.id) {
      const label = document.querySelector('label[for="' + attrEscape(el.id) + '"]');
      if (label) values.unshift(label.innerText);
    }
    if (el.labels) {
      for (const label of Array.from(el.labels)) values.unshift(label.innerText);
    }
    if (['button', 'submit', 'reset'].includes(String(el.type || '').toLowerCase())) values.unshift(el.value);
    return values.map((item) => clean(item)).filter(Boolean)[0] || '';
  };
  const selectorFor = (el) => {
    if (el.id) return '#' + (window.CSS?.escape ? CSS.escape(el.id) : String(el.id).replace(/[^a-zA-Z0-9_-]/g, (char) => '\\\\' + char));
    return el.tagName.toLowerCase();
  };
  const interactive = [
    'a[href]', 'button', 'input', 'textarea', 'select',
    '[role="button"]', '[role="link"]', '[role="menuitem"]',
    '[role="checkbox"]', '[role="radio"]', '[role="tab"]',
    '[contenteditable="true"]', '[tabindex]:not([tabindex="-1"])'
  ].join(',');
  let target = null;
  if (selector) {
    target = document.querySelector(selector);
  } else {
    target = Array.from(document.querySelectorAll(interactive))
      .filter(visible)
      .find((el) => labelOf(el).toLowerCase().includes(query) || clean(el.innerText || el.textContent).toLowerCase().includes(query));
  }
  if (!target) throw new Error('browser_dom_target_not_found');
  if (!visible(target)) throw new Error('browser_dom_target_not_visible');
  const tag = target.tagName.toLowerCase();
  const type = String(target.getAttribute('type') || '').toLowerCase();
  const role = clean(target.getAttribute('role') || '', 60);
  const label = labelOf(target);
  const text = clean(target.innerText || target.textContent || '', 180);
  const name = clean(target.getAttribute('name') || '', 80);
  const riskText = [type, role, label, text, name, selector, query].join(' ');
  const submitLike = domAction === 'click' && (
    type === 'submit' ||
    /\\b(submit|send|buy|purchase|pay|checkout|delete|remove|confirm|login|log in|sign in|sign up|register|subscribe|post|publish|share|transfer|withdraw|deposit|trade)\\b|提交|发送|购买|付款|支付|删除|移除|确认|登录|注册|发布|分享|转账|提现|充值|交易/i.test(riskText)
  );
  const rect = target.getBoundingClientRect();
  return JSON.stringify({
    ok: true,
    action: domAction,
    selector: selector || selectorFor(target),
    query,
    tag,
    type,
    role,
    label,
    text,
    name,
    submitLike,
    url: location.href,
    title: document.title || '',
    rect: {
      x: Math.round(rect.x),
      y: Math.round(rect.y),
      width: Math.round(rect.width),
      height: Math.round(rect.height)
    }
  });
})()
  `.trim();
}

function sanitizeBrowserDomPreflight(value = {}) {
  return {
    ok: Boolean(value.ok),
    action: compactRecordText(value.action || '', 40),
    selector: compactRecordText(value.selector || '', 220),
    tag: compactRecordText(value.tag || '', 40),
    type: compactRecordText(value.type || '', 40),
    role: compactRecordText(value.role || '', 60),
    label: compactRecordText(value.label || '', 120),
    submitLike: Boolean(value.submitLike),
    title: compactRecordText(value.title || '', 160),
    url: compactRecordText(value.url || '', 500),
    rect: value.rect || null,
  };
}

function browserDomActionSafetyContract(extra = {}) {
  return {
    preflightReobserve: true,
    reobserveTiming: 'before_execute',
    formSubmissionDefault: 'approval_required',
    submitLikeRiskLevel: 4,
    executesFormSubmitByDefault: false,
    ...extra,
  };
}

function browserDomActionFixtureLabel(element = {}) {
  return [
    element.label,
    element.text,
    element.placeholder,
    element.name,
    element.valuePreview,
    element.selector,
  ].map((item) => compactRecordText(item || '', 120)).find(Boolean) || '';
}

function findBrowserDomActionFixtureElement(plan, dom = {}) {
  const elements = Array.isArray(dom.elements) ? dom.elements : [];
  const selector = String(plan.args?.selector || '').trim();
  if (selector) {
    const selectorId = selector.startsWith('#') ? selector.slice(1) : '';
    const exact = elements.find((element) =>
      String(element.selector || '').trim() === selector ||
      (selectorId && String(element.id || '').trim() === selectorId));
    if (exact) return exact;
  }
  return findBrowserTaskElement(dom, plan.args?.query || selector, plan.args?.domAction || '');
}

function reobserveBrowserDomActionTargetFromFixture(plan, fixtureDom = {}) {
  const dom = normalizeBrowserFillDraftFixtureDom(fixtureDom);
  if (!dom) throw new Error('browser_dom_fixture_required');
  const target = findBrowserDomActionFixtureElement(plan, dom);
  if (!target) throw new Error('browser_dom_target_not_found_in_fixture');
  if (target.disabled || target.ariaDisabled === true || target['aria-disabled'] === true) {
    throw new Error('browser_dom_target_disabled_in_fixture');
  }
  const selector = String(target.selector || plan.args?.selector || '').trim();
  const query = String(plan.args?.query || '').trim().toLowerCase();
  const tag = compactRecordText(target.tag || '', 40).toLowerCase();
  const type = compactRecordText(target.type || '', 40).toLowerCase();
  const role = compactRecordText(target.role || '', 60);
  const label = browserDomActionFixtureLabel(target);
  const text = compactRecordText(target.text || '', 180);
  const name = compactRecordText(target.name || '', 80);
  const riskText = [type, role, label, text, name, selector, query].join(' ');
  const submitLike = plan.args?.domAction === 'click' && (
    type === 'submit' ||
    BROWSER_DOM_DANGEROUS_RE.test(riskText)
  );
  const preflight = sanitizeBrowserDomPreflight({
    ok: true,
    action: plan.args?.domAction || '',
    selector,
    tag,
    type,
    role,
    label,
    submitLike,
    title: dom.title,
    url: dom.url,
    rect: target.rect || null,
  });
  appendAudit('browser_dom.reobserved_fixture', {
    app: dom.app,
    action: plan.args?.domAction,
    selector: preflight.selector,
    label: compactRecordText(preflight.label, 120),
    url: preflight.url,
    submitLike: preflight.submitLike,
  });
  return { ...preflight, bridge: dom.bridge || 'fixture', fixture: true };
}

function promoteBrowserDomActionPlanAfterPreflight(plan, preflight = {}) {
  if (!preflight.submitLike) return plan;
  const riskLevel = Math.max(Number(plan.riskLevel || 0), 4);
  return {
    ...plan,
    riskLevel,
    summary: Number(plan.riskLevel || 0) >= 4
      ? plan.summary
      : `${plan.summary} (submit-like browser target requires explicit confirmation)`,
    metadata: {
      ...(plan.metadata || {}),
      submitLikePreflight: true,
      submitLikeRiskLevel: 4,
    },
  };
}

async function reobserveBrowserDomActionTarget(plan, browser) {
  const snapshot = await executeBrowserJavaScriptBridge(browser, browserDomActionPreflightScript(plan), { timeoutMs: 6000 });
  const preflight = sanitizeBrowserDomPreflight(JSON.parse(snapshot.output || '{}'));
  appendAudit('browser_dom.reobserved', {
    app: browser.app,
    action: plan.args?.domAction,
    selector: preflight.selector,
    label: compactRecordText(preflight.label, 120),
    url: preflight.url || browser.url,
    bridge: snapshot.bridge,
    submitLike: preflight.submitLike,
  });
  return { ...preflight, bridge: snapshot.bridge };
}

function browserDomActionScript(plan) {
  const args = plan.args || {};
  return `
(() => {
  const domAction = ${JSON.stringify(args.domAction)};
  const selector = ${JSON.stringify(args.selector || '')};
  const query = ${JSON.stringify(args.query || '')}.toLowerCase();
  const value = ${JSON.stringify(args.value || '')};
  const clean = (input, max = 220) => String(input || '').replace(/[\\t\\r\\n ]+/g, ' ').trim().slice(0, max);
  const attrEscape = (input) => String(input).replace(/\\\\/g, '\\\\\\\\').replace(/"/g, '\\\\"');
  const visible = (el) => {
    if (!el || !(el instanceof Element)) return false;
    const style = window.getComputedStyle(el);
    if (style.display === 'none' || style.visibility === 'hidden' || Number(style.opacity || 1) === 0) return false;
    const rect = el.getBoundingClientRect();
    return rect.width > 1 && rect.height > 1;
  };
  const labelOf = (el) => {
    const values = [
      el.getAttribute('aria-label'),
      el.getAttribute('title'),
      el.getAttribute('alt'),
      el.getAttribute('placeholder'),
      el.getAttribute('name'),
      el.innerText,
      el.textContent,
    ];
    if (el.id) {
      const label = document.querySelector('label[for="' + attrEscape(el.id) + '"]');
      if (label) values.unshift(label.innerText);
    }
    if (el.labels) {
      for (const label of Array.from(el.labels)) values.unshift(label.innerText);
    }
    if (['button', 'submit', 'reset'].includes(String(el.type || '').toLowerCase())) values.unshift(el.value);
    return values.map((item) => clean(item)).filter(Boolean)[0] || '';
  };
  const selectorFor = (el) => {
    if (el.id) return '#' + (window.CSS?.escape ? CSS.escape(el.id) : String(el.id).replace(/[^a-zA-Z0-9_-]/g, (char) => '\\\\' + char));
    return el.tagName.toLowerCase();
  };
  const interactive = [
    'a[href]', 'button', 'input', 'textarea', 'select',
    '[role="button"]', '[role="link"]', '[role="menuitem"]',
    '[role="checkbox"]', '[role="radio"]', '[role="tab"]',
    '[contenteditable="true"]', '[tabindex]:not([tabindex="-1"])'
  ].join(',');
  let target = null;
  if (selector) {
    target = document.querySelector(selector);
  } else {
    target = Array.from(document.querySelectorAll(interactive))
      .filter(visible)
      .find((el) => labelOf(el).toLowerCase().includes(query) || clean(el.innerText || el.textContent).toLowerCase().includes(query));
  }
  if (!target) throw new Error('browser_dom_target_not_found');
  if (!visible(target)) throw new Error('browser_dom_target_not_visible');
  const tag = target.tagName.toLowerCase();
  const type = String(target.getAttribute('type') || '').toLowerCase();
  const label = labelOf(target);
  if (target.disabled || target.getAttribute('aria-disabled') === 'true') throw new Error('browser_dom_target_disabled');
  if ((domAction === 'fill' || domAction === 'select') && type === 'password') throw new Error('browser_dom_password_field_blocked');
  target.scrollIntoView({ block: 'center', inline: 'center', behavior: 'instant' });
  if (typeof target.focus === 'function') target.focus();
  if (domAction === 'click') {
    target.click();
  } else if (domAction === 'select') {
    if (tag !== 'select') throw new Error('browser_dom_target_is_not_select');
    const option = Array.from(target.options).find((item) => item.value === value || clean(item.text).toLowerCase() === value.toLowerCase() || clean(item.text).toLowerCase().includes(value.toLowerCase()));
    if (!option) throw new Error('browser_dom_select_option_not_found');
    target.value = option.value;
    target.dispatchEvent(new Event('input', { bubbles: true }));
    target.dispatchEvent(new Event('change', { bubbles: true }));
  } else if (domAction === 'fill') {
    if (target.isContentEditable) {
      target.textContent = value;
    } else if (tag === 'input' || tag === 'textarea') {
      target.value = value;
    } else {
      throw new Error('browser_dom_target_not_fillable');
    }
    target.dispatchEvent(new Event('input', { bubbles: true }));
    target.dispatchEvent(new Event('change', { bubbles: true }));
  } else {
    throw new Error('unsupported_browser_dom_action:' + domAction);
  }
  const rect = target.getBoundingClientRect();
  return JSON.stringify({
    ok: true,
    action: domAction,
    selector: selector || selectorFor(target),
    tag,
    type,
    label,
    url: location.href,
    title: document.title || '',
    rect: {
      x: Math.round(rect.x),
      y: Math.round(rect.y),
      width: Math.round(rect.width),
      height: Math.round(rect.height)
    }
  });
})()
  `.trim();
}

async function runBrowserDomActionPlan(plan, evaluation, options = {}) {
  if (evaluation.dryRun) {
    appendAudit('browser_dom.dry_run', {
      action: plan.args.domAction,
      riskLevel: plan.riskLevel,
      summary: plan.summary,
    });
    return `[dry-run] ${plan.summary}`;
  }
  const browser = options.browser || await browserContextSnapshot({ app: plan.args.app });
  if (!browser.supported || !browser.available) throw new Error(browser.error || 'frontmost_app_is_not_supported_browser');
  const executed = await executeBrowserJavaScriptBridge(browser, browserDomActionScript(plan), { timeoutMs: 6000 });
  const result = JSON.parse(executed.output || '{}');
  appendAudit('browser_dom.executed', {
    app: browser.app,
    action: plan.args.domAction,
    selector: result.selector,
    label: compactRecordText(result.label, 120),
    url: result.url || browser.url,
    bridge: executed.bridge,
  });
  return `${result.action} executed on ${result.tag}${result.label ? ` "${result.label}"` : ''}.`;
}

async function executeBrowserDomAction(args = {}, options = {}) {
  let plan = buildBrowserDomActionPlan(args);
  const preview = args.execute === false || options.preview === true;
  const approved = browserDomActionApproved(args, options);
  appendAudit('browser_dom.requested', {
    action: plan.args.domAction,
    riskLevel: plan.riskLevel,
    summary: plan.summary,
    localExecutionEnabled: LOCAL_EXEC_ENABLED,
    preview,
    approved,
  });
  if (preview) {
    const evaluation = evaluateMacActionPlan(plan, { ...options, preview, approved });
    return {
      ok: !evaluation.blocked,
      executed: false,
      action: plan.args.domAction,
      output: `Prepared ${plan.summary}${evaluation.needsApproval ? ` (${evaluation.reason})` : ''}.`,
      plan,
      evaluation,
      safety: browserDomActionSafetyContract({ approvedRequested: approved }),
    };
  }
  const fixtureDom = normalizeBrowserFillDraftFixtureDom(args.dom || args.fixtureDom);
  if (fixtureDom) {
    const preflight = reobserveBrowserDomActionTargetFromFixture(plan, fixtureDom);
    plan = promoteBrowserDomActionPlanAfterPreflight(plan, preflight);
    const evaluation = evaluateMacActionPlan(plan, { ...options, preview: true, approved });
    const gateStatus = evaluation.blocked
      ? 'blocked'
      : evaluation.needsApproval ? 'approval_required' : 'fixture_preview_only';
    appendAudit('browser_dom.fixture_gate', {
      action: plan.args.domAction,
      riskLevel: plan.riskLevel,
      reobserved: true,
      submitLikePreflight: preflight.submitLike,
      gateStatus,
    });
    return {
      ok: !evaluation.blocked,
      executed: false,
      fixture: true,
      action: plan.args.domAction,
      output: evaluation.needsApproval
        ? `Approval required before ${plan.summary}. Fixture DOM was re-observed and no browser action ran.`
        : `Fixture DOM was re-observed for ${plan.summary}; no live browser action ran.`,
      plan,
      evaluation,
      preflight,
      confirmationRequired: Boolean(evaluation.needsApproval),
      gate: {
        status: gateStatus,
        reobserved: true,
        persistedApproval: false,
        approvedRequested: approved,
        reason: evaluation.reason || '',
        browserAction: false,
        formSubmitted: false,
      },
      safety: browserDomActionSafetyContract({
        fixtureExecutionBlocked: true,
        submitLikePreflight: preflight.submitLike,
        gateStatus,
        persistedApproval: false,
        approvedRequested: approved,
      }),
    };
  }
  const browser = await browserContextSnapshot({ app: plan.args.app });
  if (!browser.supported || !browser.available) throw new Error(browser.error || 'frontmost_app_is_not_supported_browser');
  const preflight = await reobserveBrowserDomActionTarget(plan, browser);
  plan = promoteBrowserDomActionPlanAfterPreflight(plan, preflight);
  const evaluation = evaluateMacActionPlan(plan, { ...options, preview, approved });
  const output = await runBrowserDomActionPlan(plan, evaluation, { browser, preflight });
  appendAudit('browser_dom.completed', {
    action: plan.args.domAction,
    riskLevel: plan.riskLevel,
    dryRun: evaluation.dryRun,
    reobserved: true,
    submitLikePreflight: preflight.submitLike,
  });
  return {
    ok: true,
    executed: !evaluation.dryRun,
    action: plan.args.domAction,
    output,
    plan,
    preflight,
    safety: browserDomActionSafetyContract({
      submitLikePreflight: preflight.submitLike,
      approvedRequested: approved,
    }),
  };
}

const BROWSER_CONTROL_ACTIONS = new Set([
  'back',
  'forward',
  'reload',
  'new_tab',
  'close_tab',
  'focus_address',
  'open_url',
  'search',
]);

function normalizeBrowserControlAction(value) {
  const raw = String(value || '').trim().toLowerCase().replace(/[-\s]+/g, '_');
  const aliases = {
    refresh: 'reload',
    reload_page: 'reload',
    newtab: 'new_tab',
    new: 'new_tab',
    close: 'close_tab',
    close_current_tab: 'close_tab',
    address: 'focus_address',
    focus_url: 'focus_address',
    open: 'open_url',
    navigate: 'open_url',
    google: 'search',
    web_search: 'search',
    后退: 'back',
    返回: 'back',
    前进: 'forward',
    刷新: 'reload',
    新标签: 'new_tab',
    新建标签: 'new_tab',
    关闭标签: 'close_tab',
    地址栏: 'focus_address',
    打开网址: 'open_url',
    搜索: 'search',
  };
  const normalized = aliases[raw] || raw;
  return BROWSER_CONTROL_ACTIONS.has(normalized) ? normalized : '';
}

function browserControlUrl(args = {}) {
  const action = normalizeBrowserControlAction(args.browserAction || args.action);
  if (action === 'search') {
    const query = String(args.query || args.value || args.text || '').trim();
    if (!query) throw new Error('Browser search requires query.');
    return `https://www.google.com/search?q=${encodeURIComponent(query)}`;
  }
  if (action === 'open_url') {
    const raw = String(args.url || args.value || '').trim();
    if (!/^https?:\/\//i.test(raw)) throw new Error('Browser open_url requires an http/https URL.');
    return new URL(raw).href;
  }
  return '';
}

function buildBrowserControlPlan(args = {}) {
  const browserAction = normalizeBrowserControlAction(args.browserAction || args.action);
  if (!browserAction) throw new Error('Unsupported browser control action.');
  const actionConfig = actionPolicy.allow?.browser_control || {};
  if (!valueMatchesAllowlist(browserAction, actionConfig.allowedActions || [])) {
    throw new Error(`Browser action ${browserAction} is not allowed by policy.`);
  }
  const url = browserControlUrl({ ...args, browserAction });
  if (url && !valueMatchesAllowlist(new URL(url).hostname, actionPolicy.allow?.open_url?.allowedHosts || [])) {
    throw new Error(`URL host ${new URL(url).hostname} is not allowed by policy.`);
  }
  const riskLevel = browserAction === 'close_tab' ? 3 : 2;
  const app = String(args.app || '').trim();
  const query = String(args.query || args.text || args.value || '').trim();
  return {
    action: 'browser_control',
    riskLevel,
    summary: browserAction === 'open_url'
      ? `Open browser URL ${url}`
      : browserAction === 'search'
        ? `Search the web for ${query}`
        : `Browser ${browserAction}`,
    target: browserAction,
    args: {
      action: 'browser_control',
      browserAction,
      app,
      url,
      query,
    },
    metadata: { browserAction },
  };
}

async function runBrowserControlPlan(plan, evaluation) {
  if (evaluation.dryRun) {
    appendAudit('browser_control.dry_run', {
      action: plan.args.browserAction,
      riskLevel: plan.riskLevel,
      summary: plan.summary,
    });
    return `[dry-run] ${plan.summary}`;
  }

  const browser = await browserContextSnapshot({ app: plan.args.app });
  if (!browser.supported) throw new Error(browser.error || 'frontmost_app_is_not_supported_browser');
  const appName = browser.app || plan.args.app;
  if (!appName) throw new Error('No supported browser is active.');
  const quotedApp = appleScriptString(appName);
  const browserAction = plan.args.browserAction;
  const keyMap = {
    back: '[',
    forward: ']',
    reload: 'r',
    new_tab: 't',
    close_tab: 'w',
    focus_address: 'l',
  };

  if (browserAction === 'open_url' || browserAction === 'search') {
    const url = plan.args.url;
    const isSafari = appName === 'Safari' || appName === 'Safari Technology Preview';
    const script = isSafari
      ? [
          `tell application ${quotedApp}`,
          '  activate',
          '  if not (exists front document) then make new document',
          `  set URL of front document to ${appleScriptString(url)}`,
          'end tell',
        ].join('\n')
      : [
          `tell application ${quotedApp}`,
          '  activate',
          '  if not (exists front window) then make new window',
          `  set URL of active tab of front window to ${appleScriptString(url)}`,
          'end tell',
        ].join('\n');
    await execFileAsync('osascript', ['-e', script], guardedChildProcessOptions(
      { timeout: 5000 },
      { source: 'browser_control' },
    ));
    appendAudit('browser_control.executed', { app: appName, action: browserAction, url });
    return browserAction === 'search'
      ? `Searched in ${appName}: ${plan.args.query}`
      : `Opened in ${appName}: ${url}`;
  }

  const key = keyMap[browserAction];
  if (!key) throw new Error(`Unsupported browser control action: ${browserAction}`);
  const script = [
    `tell application ${quotedApp} to activate`,
    `tell application "System Events" to keystroke ${appleScriptString(key)} using {command down}`,
  ].join('\n');
  await execFileAsync('osascript', ['-e', script], guardedChildProcessOptions(
    { timeout: 5000 },
    { source: 'browser_control' },
  ));
  appendAudit('browser_control.executed', { app: appName, action: browserAction });
  return `Browser ${browserAction} executed in ${appName}.`;
}

async function executeBrowserControl(args = {}, options = {}) {
  const plan = buildBrowserControlPlan(args);
  appendAudit('browser_control.requested', {
    action: plan.args.browserAction,
    riskLevel: plan.riskLevel,
    summary: plan.summary,
    localExecutionEnabled: LOCAL_EXEC_ENABLED,
    approved: Boolean(options.approved),
  });
  const evaluation = evaluateMacActionPlan(plan, options);
  const output = await runBrowserControlPlan(plan, evaluation);
  appendAudit('browser_control.completed', {
    action: plan.args.browserAction,
    riskLevel: plan.riskLevel,
    dryRun: evaluation.dryRun,
  });
  return {
    ok: true,
    executed: !evaluation.dryRun,
    action: plan.args.browserAction,
    output,
  };
}

function normalizeBrowserWorkflowIntent(value) {
  const raw = String(value || '').trim();
  const aliases = {
    fill_form: 'fill_draft',
    form_fill: 'fill_draft',
    form_draft: 'fill_draft',
    draft_fill: 'fill_draft',
  };
  const intent = aliases[raw] || raw;
  if (['summarize', 'extract_actions', 'draft', 'ask', 'act', 'fill_draft', 'search', 'compare', 'review_result', 'research'].includes(intent)) return intent;
  return 'summarize';
}

function normalizeBrowserWorkflowMode(value) {
  const mode = String(value || '').trim();
  if (['quick', 'background', 'codex', 'claude'].includes(mode)) return mode;
  return 'quick';
}

function normalizeBrowserWorkflowFixturePage(value, maxChars = 12000) {
  if (!value || typeof value !== 'object') return null;
  const rawText = String(value.text || value.body || '');
  const rawSelectedText = String(value.selectedText || '');
  const limit = normalizeBrowserMaxChars(maxChars);
  const text = rawText.slice(0, limit);
  const selectedText = rawSelectedText.slice(0, limit);
  const url = String(value.url || '');
  return {
    available: value.available !== false,
    supported: value.supported !== false,
    app: String(value.app || 'FixtureBrowser'),
    title: String(value.title || ''),
    url,
    selectedText,
    text,
    textLength: Number(value.textLength || rawText.length || selectedText.length),
    truncated: Boolean(value.truncated) || rawText.length > text.length || rawSelectedText.length > selectedText.length,
    headings: Array.isArray(value.headings) ? value.headings.map((item) => compactRecordText(item, 180)).filter(Boolean).slice(0, 40) : [],
    metaDescription: compactRecordText(value.metaDescription || value.description || '', 500),
    links: normalizeBrowserLinks(Array.isArray(value.links) ? value.links : [], url),
    fallback: String(value.fallback || 'fixture'),
    error: String(value.error || ''),
  };
}

function browserWorkflowPageSummary(page) {
  return {
    available: Boolean(page.available),
    supported: Boolean(page.supported),
    app: page.app || '',
    title: page.title || '',
    url: page.url || '',
    selectedTextLength: page.selectedText?.length || 0,
    returnedLength: page.text?.length || 0,
    textLength: page.textLength || 0,
    truncated: Boolean(page.truncated),
    fallback: page.fallback || '',
    error: page.error || '',
    headings: Array.isArray(page.headings) ? page.headings.slice(0, 10) : [],
    linkCount: Array.isArray(page.links) ? page.links.length : 0,
    links: Array.isArray(page.links) ? page.links.slice(0, 12) : [],
    searchResults: browserSearchResultLinks(page, 8),
  };
}

function browserWorkflowPrompt(page, intent, instruction) {
  const taskMap = {
    summarize: '总结当前网页，给出关键结论、重要细节、用户下一步可以做什么。',
    extract_actions: '从当前网页提取行动项、截止日期、待办、风险和需要用户确认的事项。',
    draft: '基于当前网页起草一段可直接使用的中文内容；如果用户给了具体要求，严格按要求写。',
    ask: '回答用户关于当前网页的问题；如果网页内容不足，说明缺口。',
    act: '规划并执行当前网页上的安全浏览器操作。',
    search: '搜索网页并总结结果页。',
    compare: '搜索多个查询并比较结果页。',
    review_result: '打开一个搜索结果或 URL，读取目标页面并总结可执行结论。',
    research: '搜索并读取多个结果页面，综合出结论和下一步。',
  };
  const pageText = page.selectedText || page.text || '';
  return [
    `Browser workflow: ${intent} · ${page.title || page.url || 'current page'}`,
    '',
    `User request: ${instruction || taskMap[intent]}`,
    '',
    'Page:',
    `Title: ${page.title || ''}`,
    `URL: ${page.url || ''}`,
    page.metaDescription ? `Description: ${page.metaDescription}` : '',
    page.headings?.length ? `Headings: ${page.headings.slice(0, 16).join(' / ')}` : '',
    browserWorkflowLinksBlock(page) ? `Links:\n${browserWorkflowLinksBlock(page)}` : '',
    '',
    'Page text:',
    pageText,
  ]
    .filter((line) => line !== '')
    .join('\n');
}

function normalizeBrowserSearchQueries(options = {}) {
  const rawList = Array.isArray(options.queries)
    ? options.queries
    : Array.isArray(options.query)
      ? options.query
      : [];
  const textQuery = String(options.query || options.instruction || '').trim();
  const splitTextQueries = textQuery
    ? textQuery.split(/\n|;|；|\s+\|\s+/).map((item) => item.trim()).filter(Boolean)
    : [];
  const queries = [...rawList, ...splitTextQueries]
    .map((item) => String(item || '').replace(/\s+/g, ' ').trim())
    .filter(Boolean);
  return Array.from(new Set(queries)).slice(0, MAX_BROWSER_SEARCH_QUERIES);
}

function browserSearchWorkflowPrompt(searches = [], intent = 'search', instruction = '') {
  const payload = searches.map((item, index) => ({
    index: index + 1,
    query: item.query,
    app: item.page?.app || '',
    title: item.page?.title || '',
    url: item.page?.url || '',
    headings: item.page?.headings?.slice(0, 12) || [],
    links: Array.isArray(item.page?.links) ? item.page.links.slice(0, 12) : [],
    candidateResultLinks: browserSearchResultLinks(item.page, 8),
    text: compactRecordText(item.page?.selectedText || item.page?.text || '', 5000),
    error: item.page?.error || '',
  }));
  return [
    `Browser ${intent} workflow.`,
    `User request: ${instruction || searches.map((item) => item.query).join(' ; ')}`,
    '',
    'Use only these browser search result page snapshots. Do not invent facts beyond them.',
    intent === 'compare'
      ? 'Compare the result pages, identify overlaps, conflicts, strongest next links/queries, and concrete next actions.'
      : 'Summarize the result page, identify likely useful next links/queries, and concrete next actions.',
    'Answer in concise Chinese.',
    '',
    JSON.stringify(payload, null, 2),
  ].join('\n');
}

function browserFailedPageSummary(error) {
  const message = error instanceof Error ? error.message : String(error || 'page unavailable');
  return {
    available: false,
    supported: false,
    app: '',
    title: '',
    url: '',
    selectedTextLength: 0,
    returnedLength: 0,
    textLength: 0,
    truncated: false,
    fallback: '',
    error: message,
    headings: [],
    linkCount: 0,
    links: [],
    searchResults: [],
  };
}

function browserReviewExplicitUrl(options = {}) {
  const direct = String(options.url || options.href || '').trim();
  const instruction = String(options.instruction || options.query || '').trim();
  const fromText = instruction.match(/https?:\/\/[^\s"'<>）)]+/i)?.[0] || '';
  return normalizeBrowserHref(direct || fromText);
}

function normalizeBrowserResultIndex(value) {
  const parsed = Number(value || 1);
  if (!Number.isFinite(parsed)) return 1;
  return Math.max(1, Math.min(MAX_BROWSER_PAGE_LINKS, Math.floor(parsed)));
}

function selectBrowserReviewLink(candidates = [], options = {}) {
  const links = Array.isArray(candidates) ? candidates : [];
  if (!links.length) return null;
  const preferredHost = String(options.host || options.domain || '').trim().replace(/^www\./i, '').toLowerCase();
  if (preferredHost) {
    const hostHit = links.find((link) => String(link.host || '').toLowerCase().includes(preferredHost));
    if (hostHit) return hostHit;
  }
  const preferredUrl = String(options.urlContains || options.hrefContains || '').trim().toLowerCase();
  if (preferredUrl) {
    const urlHit = links.find((link) => String(link.href || '').toLowerCase().includes(preferredUrl));
    if (urlHit) return urlHit;
  }
  const index = normalizeBrowserResultIndex(options.resultIndex || options.index || options.position);
  return links[index - 1] || links[0] || null;
}

function browserResultReviewPrompt({ request, query, searchPage, selectedLink, targetPage }) {
  const pageText = targetPage?.selectedText || targetPage?.text || '';
  return [
    'Browser result review workflow.',
    `User request: ${request}`,
    query ? `Search query: ${query}` : '',
    selectedLink ? `Selected link: ${selectedLink.text} · ${selectedLink.href}` : '',
    '',
    'Use only the provided target page snapshot. If the page content is insufficient, say what is missing.',
    'Answer in concise Chinese with concrete next actions and useful follow-up links from the page.',
    '',
    searchPage
      ? `Search page candidates:\n${JSON.stringify(browserSearchResultLinks(searchPage, 8), null, 2)}`
      : '',
    '',
    'Target page:',
    `Title: ${targetPage?.title || ''}`,
    `URL: ${targetPage?.url || ''}`,
    targetPage?.metaDescription ? `Description: ${targetPage.metaDescription}` : '',
    targetPage?.headings?.length ? `Headings: ${targetPage.headings.slice(0, 16).join(' / ')}` : '',
    browserWorkflowLinksBlock(targetPage) ? `Links:\n${browserWorkflowLinksBlock(targetPage)}` : '',
    '',
    'Target page text:',
    compactRecordText(pageText, 12000),
  ].filter((line) => line !== '').join('\n');
}

function normalizeBrowserResearchLimit(value) {
  const parsed = Number(value || 3);
  if (!Number.isFinite(parsed)) return 3;
  return Math.max(1, Math.min(5, Math.floor(parsed)));
}

function normalizeBrowserResearchUrls(options = {}, maxUrls = 5) {
  const rawList = [
    ...(Array.isArray(options.urls) ? options.urls : []),
    ...(Array.isArray(options.url) ? options.url : [options.url]),
  ];
  const text = String(options.instruction || options.query || '').trim();
  for (const match of text.matchAll(/https?:\/\/[^\s"'<>）)]+/gi)) {
    rawList.push(match[0]);
  }
  const seen = new Set();
  const urls = [];
  for (const raw of rawList) {
    const href = normalizeBrowserHref(raw);
    if (!href) continue;
    const key = href.replace(/#.*$/, '');
    if (seen.has(key)) continue;
    seen.add(key);
    urls.push(href);
    if (urls.length >= maxUrls) break;
  }
  return urls;
}

function browserResearchLinkFromUrl(href, index = 0) {
  const url = new URL(href);
  return {
    index: index + 1,
    text: href,
    href,
    host: url.hostname.replace(/^www\./i, ''),
    sameHost: false,
  };
}

function browserResearchWorkflowPrompt({ request, query, searchPage, selectedLinks, pages }) {
  const pagePayload = pages.map((item, index) => ({
    index: index + 1,
    selectedLink: item.selected,
    opened: item.openAction?.output || '',
    available: Boolean(item.page?.available),
    title: item.page?.title || '',
    url: item.page?.url || item.selected?.href || '',
    headings: item.page?.headings?.slice(0, 14) || [],
    links: Array.isArray(item.page?.links) ? item.page.links.slice(0, 10) : [],
    text: compactRecordText(item.page?.selectedText || item.page?.text || '', 5000),
    error: item.error || item.page?.error || '',
  }));
  return [
    'Browser multi-page research workflow.',
    `User request: ${request}`,
    query ? `Search query: ${query}` : '',
    '',
    'Use only the provided page snapshots. Compare sources, call out disagreements or missing evidence, and do not invent facts beyond the snapshots.',
    'Answer in concise Chinese. Include: conclusion, source-by-source evidence, concrete next actions, and which link JAVIS should open next if more work is needed.',
    '',
    searchPage
      ? `Search page candidates:\n${JSON.stringify(browserSearchResultLinks(searchPage, 12), null, 2)}`
      : '',
    selectedLinks?.length ? `Selected links:\n${JSON.stringify(selectedLinks, null, 2)}` : '',
    '',
    'Reviewed pages:',
    JSON.stringify(pagePayload, null, 2),
  ].filter((line) => line !== '').join('\n');
}

function browserResearchLinkKey(link = {}) {
  return String(link.href || '').replace(/#.*$/, '');
}

function browserResearchUniqueLinks(links = [], limit = 5) {
  const seen = new Set();
  const result = [];
  for (const link of Array.isArray(links) ? links : []) {
    const href = normalizeBrowserHref(link?.href || link?.url);
    if (!href) continue;
    const key = href.replace(/#.*$/, '');
    if (seen.has(key)) continue;
    seen.add(key);
    let host = '';
    try {
      host = new URL(href).hostname.replace(/^www\./i, '');
    } catch {
      continue;
    }
    result.push({
      index: result.length + 1,
      text: compactRecordText(link.text || link.title || link.label || href, 180) || href,
      href,
      host,
      sameHost: Boolean(link.sameHost),
    });
    if (result.length >= limit) break;
  }
  return result;
}

function browserResearchFollowUpLinks(pages = [], selectedLinks = [], limit = 8) {
  const selected = new Set(selectedLinks.map(browserResearchLinkKey).filter(Boolean));
  const candidates = [];
  for (const item of Array.isArray(pages) ? pages : []) {
    const pageLinks = Array.isArray(item.page?.links) ? item.page.links : [];
    for (const link of pageLinks) {
      const key = browserResearchLinkKey(link);
      if (!key || selected.has(key)) continue;
      if (/^(Privacy|Terms|Sign in|Login|Subscribe|登录|隐私|条款)$/i.test(String(link.text || ''))) continue;
      candidates.push({
        ...link,
        sourceTitle: item.page?.title || item.selected?.text || '',
        sourceUrl: item.page?.url || item.selected?.href || '',
      });
    }
  }
  return browserResearchUniqueLinks(candidates, limit);
}

function browserResearchContinuationPlan({
  request = '',
  query = '',
  mode = 'quick',
  maxPages = 3,
  selectedLinks = [],
  search = null,
  pages = [],
  executed = false,
} = {}) {
  const selected = browserResearchUniqueLinks(selectedLinks, Math.max(1, Math.min(12, Number(maxPages || selectedLinks.length || 3))));
  const selectedKeys = new Set(selected.map(browserResearchLinkKey).filter(Boolean));
  const availablePages = (Array.isArray(pages) ? pages : []).filter((item) => item.page?.available);
  const failedPages = (Array.isArray(pages) ? pages : []).filter((item) => !item.page?.available);
  const searchCandidates = browserResearchUniqueLinks(search?.candidates || browserSearchResultLinks(search?.page, 12), 12);
  const remainingSearchCandidates = browserResearchUniqueLinks(
    searchCandidates.filter((link) => !selectedKeys.has(browserResearchLinkKey(link))),
    Math.max(1, Math.min(5, Number(maxPages || 3))),
  );
  const failedLinks = browserResearchUniqueLinks(
    failedPages.map((item) => item.selected).filter(Boolean),
    Math.max(1, Math.min(5, Number(maxPages || 3))),
  );
  const followUpLinks = browserResearchFollowUpLinks(pages, selected, Math.max(1, Math.min(5, Number(maxPages || 3))));
  const nextActions = [];

  if (!executed && selected.length) {
    nextActions.push({
      type: 'research_selected_links',
      label: 'Run prepared browser research links',
      reason: `${selected.length} selected research link(s) are ready to open and review.`,
      arguments: {
        intent: 'research',
        mode,
        urls: selected.map((link) => link.href),
        maxPages: selected.length,
      },
    });
  }

  if (!executed && !selected.length && query) {
    nextActions.push({
      type: 'research_search_query',
      label: 'Run prepared browser research search',
      reason: 'A search query is ready to run for browser research.',
      arguments: {
        intent: 'research',
        mode,
        query,
        maxPages,
      },
    });
  }

  if (remainingSearchCandidates.length) {
    nextActions.push({
      type: 'research_more',
      label: 'Continue with unvisited search result links',
      reason: `${remainingSearchCandidates.length} search result candidate(s) were not reviewed yet.`,
      arguments: {
        intent: 'research',
        mode,
        urls: remainingSearchCandidates.map((link) => link.href),
        maxPages: remainingSearchCandidates.length,
      },
    });
  }

  if (failedLinks.length) {
    nextActions.push({
      type: 'retry_failed_pages',
      label: 'Retry failed research pages with a longer wait',
      reason: `${failedLinks.length} selected page(s) were not readable in this run.`,
      arguments: {
        intent: 'research',
        mode,
        urls: failedLinks.map((link) => link.href),
        maxPages: failedLinks.length,
        openWaitMs: 5000,
      },
    });
  }

  if (followUpLinks.length) {
    nextActions.push({
      type: 'research_follow_up_links',
      label: 'Open promising follow-up links from reviewed pages',
      reason: `${followUpLinks.length} follow-up link candidate(s) were found inside reviewed pages.`,
      arguments: {
        intent: 'research',
        mode,
        urls: followUpLinks.map((link) => link.href),
        maxPages: followUpLinks.length,
      },
    });
  }

  if (!availablePages.length && query) {
    const alternateQuery = compactRecordText(request || query, 180);
    nextActions.push({
      type: 'search_alternate_query',
      label: 'Try a narrower search query',
      reason: 'No selected research pages were readable.',
      arguments: {
        intent: 'research',
        mode,
        query: alternateQuery,
        maxPages,
      },
    });
  }

  const status = !executed
    ? 'preview'
    : availablePages.length
      ? nextActions.length ? 'ready_to_continue' : 'enough_context'
      : nextActions.length ? 'recovery_available' : 'blocked';
  return {
    status,
    reviewedCount: availablePages.length,
    failedCount: failedPages.length,
    selectedCount: selected.length,
    remainingCandidateCount: remainingSearchCandidates.length,
    followUpLinkCount: followUpLinks.length,
    summary: status === 'preview'
      ? `Prepared browser research plan for ${selected.length || maxPages} page(s).`
      : availablePages.length
        ? `Reviewed ${availablePages.length}/${selected.length || pages.length} page(s); ${nextActions.length} continuation action(s) available.`
        : `No research pages were readable; ${nextActions.length} recovery action(s) available.`,
    selectedLinks: selected,
    remainingSearchCandidates,
    failedLinks,
    followUpLinks,
    nextActions,
  };
}

function parseJsonFromModelText(text) {
  const raw = String(text || '').trim();
  if (!raw) throw new Error('empty_model_json');
  try {
    return JSON.parse(raw);
  } catch {}
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced?.[1]) {
    try {
      return JSON.parse(fenced[1].trim());
    } catch {}
  }
  const firstObject = raw.indexOf('{');
  const lastObject = raw.lastIndexOf('}');
  if (firstObject >= 0 && lastObject > firstObject) {
    try {
      return JSON.parse(raw.slice(firstObject, lastObject + 1));
    } catch {}
  }
  const firstArray = raw.indexOf('[');
  const lastArray = raw.lastIndexOf(']');
  if (firstArray >= 0 && lastArray > firstArray) {
    return JSON.parse(raw.slice(firstArray, lastArray + 1));
  }
  throw new Error('model_output_was_not_json');
}

function normalizeBrowserTaskAction(value) {
  const raw = String(value || '').trim().toLowerCase().replace(/[-\s]+/g, '_');
  const aliases = {
    press: 'click',
    tap: 'click',
    type: 'fill',
    input: 'fill',
    set: 'fill',
    choose: 'select',
    navigate: 'open_url',
    open: 'open_url',
    google: 'search',
    refresh: 'reload',
    pause: 'wait',
    sleep: 'wait',
  };
  return aliases[raw] || raw;
}

function normalizeBrowserTaskPlan(value = {}, maxSteps = 5) {
  const rawSteps = Array.isArray(value) ? value : Array.isArray(value.steps) ? value.steps : [];
  const steps = rawSteps
    .map((step, index) => {
      const action = normalizeBrowserTaskAction(step?.action || step?.type || step?.domAction || step?.browserAction);
      if (!['click', 'fill', 'select', 'wait', 'open_url', 'search', 'reload', 'back', 'forward'].includes(action)) return null;
      return {
        index,
        action,
        selector: String(step.selector || '').slice(0, 500),
        query: String(step.query || step.label || step.text || '').slice(0, 300),
        value: String(step.value ?? step.content ?? step.url ?? '').slice(0, 4000),
        url: String(step.url || '').slice(0, 2000),
        ms: Math.max(100, Math.min(5000, Number(step.ms || step.durationMs || step.waitMs || 600))),
        reason: compactRecordText(step.reason || step.summary || '', 220),
      };
    })
    .filter(Boolean)
    .slice(0, Math.max(1, Math.min(8, Number(maxSteps || 5))));
  return {
    summary: compactRecordText(value.summary || value.goal || 'Browser task plan', 500),
    successCheck: compactRecordText(value.successCheck || value.success || '', 500),
    steps,
  };
}

function browserTaskPrompt(page, dom, instruction, maxSteps) {
  const elements = (dom.elements || []).slice(0, 80).map((element) => ({
    id: element.id,
    selector: element.selector,
    tag: element.tag,
    type: element.type,
    role: element.role,
    label: element.label,
    text: element.text,
    placeholder: element.placeholder,
    name: element.name,
    valuePreview: element.valuePreview,
    disabled: element.disabled,
  }));
  return [
    'Return only compact JSON. No markdown.',
    `User browser task: ${instruction}`,
    `Max steps: ${maxSteps}`,
    '',
    'Allowed actions:',
    '- open_url: requires url',
    '- search: requires query',
    '- click: requires selector or query',
    '- fill: requires selector or query and value',
    '- select: requires selector or query and value',
    '- wait: requires ms',
    '- reload/back/forward: no target required',
    '',
    'Rules:',
    '- Do not submit forms, send messages, purchase, pay, delete, log in, sign up, publish, trade, or make account changes.',
    '- Prefer selector from DOM elements when available.',
    '- Use click/fill/select only for visible non-disabled controls listed in DOM.',
    '- If the page does not contain enough information to act safely, return steps: [] and explain in summary.',
    '',
    'Schema:',
    '{"summary":"what will be done","successCheck":"how to verify","steps":[{"action":"fill","selector":"...","query":"...","value":"...","reason":"..."}]}',
    '',
    'Current page:',
    JSON.stringify({
      app: page.app,
      title: page.title,
      url: page.url,
      headings: page.headings?.slice(0, 12) || [],
      textPreview: compactRecordText(page.selectedText || page.text || '', 4000),
      dom: {
        title: dom.title,
        url: dom.url,
        count: dom.count,
        elements,
      },
    }),
  ].join('\n');
}

function cleanBrowserTaskQuery(value) {
  return String(value || '')
    .replace(/[.,;:!?]+$/g, '')
    .replace(/\b(field|input|textbox|text box|textarea|area|button|link|tab)\b/gi, '')
    .replace(/\b(the|a|an)\b/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function browserTaskElementText(element = {}) {
  return [
    element.label,
    element.text,
    element.placeholder,
    element.name,
    element.type,
    element.role,
    element.selector,
  ].map((item) => String(item || '')).join(' ').toLowerCase();
}

function browserTaskElementKind(element = {}, kind = '') {
  const tag = String(element.tag || '').toLowerCase();
  const type = String(element.type || '').toLowerCase();
  const role = String(element.role || '').toLowerCase();
  if (element.disabled) return false;
  if (kind === 'fill') {
    if (type === 'password') return false;
    if (['button', 'submit', 'reset', 'checkbox', 'radio', 'file'].includes(type)) return false;
    return ['input', 'textarea'].includes(tag) || element.contentEditable === true;
  }
  if (kind === 'select') return tag === 'select';
  if (kind === 'click') {
    return tag === 'button'
      || tag === 'a'
      || ['button', 'link', 'menuitem', 'checkbox', 'radio', 'tab'].includes(role)
      || ['button', 'submit', 'reset'].includes(type);
  }
  return false;
}

function scoreBrowserTaskElement(element = {}, query = '', kind = '') {
  if (!browserTaskElementKind(element, kind)) return -1;
  const cleanedQuery = cleanBrowserTaskQuery(query).toLowerCase();
  if (!cleanedQuery) return 1;
  const haystack = browserTaskElementText(element);
  const label = String(element.label || '').toLowerCase();
  const placeholder = String(element.placeholder || '').toLowerCase();
  const name = String(element.name || '').toLowerCase();
  let score = 0;
  if (label === cleanedQuery) score += 100;
  if (placeholder === cleanedQuery) score += 80;
  if (name === cleanedQuery) score += 70;
  if (haystack.includes(cleanedQuery)) score += 50;
  const words = cleanedQuery.split(/\s+/).filter(Boolean);
  if (words.length && words.every((word) => haystack.includes(word))) score += 20 + words.length;
  if (kind === 'fill' && ['input', 'textarea'].includes(String(element.tag || '').toLowerCase())) score += 4;
  if (kind === 'click' && String(element.tag || '').toLowerCase() === 'button') score += 4;
  return score;
}

function findBrowserTaskElement(dom = {}, query = '', kind = '') {
  const elements = Array.isArray(dom.elements) ? dom.elements : [];
  let best = null;
  let bestScore = -1;
  for (const element of elements) {
    const score = scoreBrowserTaskElement(element, query, kind);
    if (score > bestScore) {
      best = element;
      bestScore = score;
    }
  }
  if (!best || bestScore < (query ? 20 : 1)) return null;
  return best;
}

function cleanBrowserTaskValue(value) {
  return String(value || '')
    .replace(/^["'`“”‘’]+|["'`“”‘’]+$/g, '')
    .replace(/[.,;，。；]+$/g, '')
    .trim();
}

function cleanBrowserTaskNavigationValue(value) {
  return cleanBrowserTaskValue(value)
    .replace(/^(?:url|网址|网站|网页)[:：]?\s*/i, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeBrowserTaskUrl(value) {
  const raw = cleanBrowserTaskNavigationValue(value);
  if (!raw || /\s/.test(raw)) return '';
  if (/^(?:javascript|mailto|tel|sms|data|blob|file):/i.test(raw)) return '';
  if (/^https?:\/\//i.test(raw)) return normalizeBrowserHref(raw);
  if (/^localhost(?::\d+)?(?:\/.*)?$/i.test(raw)) return normalizeBrowserHref(`http://${raw}`);
  if (/^(?:[a-z0-9-]+\.)+[a-z]{2,}(?::\d+)?(?:\/.*)?$/i.test(raw)) return normalizeBrowserHref(`https://${raw}`);
  return '';
}

function parseBrowserTaskFill(segment = '', fullInstruction = '') {
  const text = String(segment || '').trim();
  const patterns = [
    /\b(?:fill|enter|type|input)\s+(?:the\s+)?(.+?)\s+(?:with|as|to)\s+["'`“”‘’]?(.+?)["'`“”‘’]?$/i,
    /\b(?:type|enter|input)\s+["'`“”‘’]?(.+?)["'`“”‘’]?\s+(?:in|into|to)\s+(?:the\s+)?(.+?)$/i,
  ];
  for (const [index, pattern] of patterns.entries()) {
    const match = text.match(pattern);
    if (!match) continue;
    return index === 0
      ? { query: cleanBrowserTaskQuery(match[1]), value: cleanBrowserTaskValue(match[2]) }
      : { query: cleanBrowserTaskQuery(match[2]), value: cleanBrowserTaskValue(match[1]) };
  }
  const chinese = text.match(/(?:把|在)?(.+?)(?:字段|输入框|框|栏)?(?:填|输入|写入)(?:成|为|:|：)?(.+)$/i);
  if (chinese) return { query: cleanBrowserTaskQuery(chinese[1]), value: cleanBrowserTaskValue(chinese[2]) };
  const quoted = String(fullInstruction || text).match(/["'`“”‘’]([^"'`“”‘’]+)["'`“”‘’]/);
  const withValue = text.match(/\bwith\s+([^,.;]+)$/i);
  const value = cleanBrowserTaskValue(quoted?.[1] || withValue?.[1] || '');
  if (/\b(fill|enter|type|input)\b/i.test(text) && value) {
    return { query: cleanBrowserTaskQuery(text.replace(/\b(fill|enter|type|input|with)\b/gi, '').replace(value, '')), value };
  }
  return null;
}

function parseBrowserTaskOpenUrl(segment = '') {
  const text = String(segment || '').trim();
  const explicitUrl = text.match(/https?:\/\/[^\s"'<>）)]+/i)?.[0];
  if (explicitUrl) {
    const url = normalizeBrowserTaskUrl(explicitUrl);
    if (url) return { url };
  }
  const english = text.match(/^(?:please\s+)?(?:open|go to|navigate to|visit)\s+(?:the\s+)?(.+?)$/i);
  const chinese = text.match(/^(?:请\s*)?(?:帮我\s*)?(?:在(?:浏览器|网页|网站|google|Google|谷歌)(?:里|上)?\s*)?(?:打开|访问|进入|跳转到)\s*(?:网址|网站|网页)?[:：]?\s*(.+)$/i);
  const candidate = english?.[1] || chinese?.[1] || '';
  const url = normalizeBrowserTaskUrl(candidate);
  return url ? { url } : null;
}

function parseBrowserTaskSearch(segment = '') {
  const text = String(segment || '').trim();
  const english = text.match(/^(?:please\s+)?(?:search(?:\s+(?:the\s+)?(?:web|google))?(?:\s+for)?|google|look up(?:\s+online)?|web search)[:：]?\s+(.+)$/i);
  const chinese = text.match(/^(?:请\s*)?(?:帮我\s*)?(?:打开(?:浏览器|网页|google|Google|谷歌)\s*)?(?:在(?:浏览器|网页|网上|google|Google|谷歌)(?:里|上)?\s*)?(?:搜索(?:网页|一下)?|搜一下|查一下|查找|查询|查网页|网上搜|谷歌一下|google一下|Google一下|百度一下)[:：]?\s*(.+)$/i);
  const query = cleanBrowserTaskNavigationValue(english?.[1] || chinese?.[1] || '');
  if (!query) return null;
  return { query };
}

function parseBrowserTaskClick(segment = '') {
  const text = String(segment || '').trim();
  const english = text.match(/\b(?:click|press|tap)\s+(?:the\s+)?(.+?)$/i);
  if (english) return { query: cleanBrowserTaskQuery(english[1]) };
  const chinese = text.match(/(?:点击|按下|点一下)(.+?)(?:按钮|链接|标签)?$/i);
  if (chinese) return { query: cleanBrowserTaskQuery(chinese[1]) };
  return null;
}

function fallbackBrowserTaskPlan(instruction = '', dom = {}, maxSteps = 5, plannerError = '') {
  const text = String(instruction || '').trim();
  const lower = text.toLowerCase();
  const steps = [];
  const segments = text
    .split(/\bthen\b|\band then\b|\band\b|,|;|，|；|然后|再|并且|并/i)
    .map((segment) => segment.trim())
    .filter(Boolean);

  if (!text) {
    return { summary: 'No browser task instruction was provided.', successCheck: '', steps };
  }
  if (BROWSER_DOM_DANGEROUS_RE.test(text)) {
    return {
      summary: 'Local fallback refused to plan a risky browser action.',
      successCheck: '',
      steps,
    };
  }

  for (const segment of segments) {
    if (steps.length >= maxSteps) break;
    const open = parseBrowserTaskOpenUrl(segment);
    if (open?.url) {
      steps.push({
        action: 'open_url',
        url: open.url,
        reason: 'Local fallback recognized a safe browser URL navigation request.',
      });
      continue;
    }

    const search = parseBrowserTaskSearch(segment);
    if (search?.query) {
      steps.push({
        action: 'search',
        query: search.query,
        reason: 'Local fallback recognized a safe browser search request.',
      });
      continue;
    }

    const fill = parseBrowserTaskFill(segment, text);
    if (fill?.value) {
      const target = findBrowserTaskElement(dom, fill.query, 'fill');
      if (target?.selector) {
        steps.push({
          action: 'fill',
          selector: target.selector,
          query: fill.query,
          value: fill.value,
          reason: 'Local fallback matched a fillable DOM element.',
        });
        continue;
      }
    }

    const click = parseBrowserTaskClick(segment);
    if (click) {
      const target = findBrowserTaskElement(dom, click.query, 'click');
      if (target?.selector) {
        steps.push({
          action: 'click',
          selector: target.selector,
          query: click.query,
          value: '',
          reason: 'Local fallback matched a clickable DOM element.',
        });
      }
    }
  }

  if (!steps.length && /\b(fill|enter|type|input)\b/i.test(text)) {
    const fill = parseBrowserTaskFill(text, text);
    const target = findBrowserTaskElement(dom, fill?.query || '', 'fill');
    if (fill?.value && target?.selector) {
      steps.push({
        action: 'fill',
        selector: target.selector,
        query: fill.query,
        value: fill.value,
        reason: 'Local fallback used the best fillable DOM element.',
      });
    }
  }

  if (steps.length < maxSteps && /\b(click|press|tap)\b/i.test(lower)) {
    const click = parseBrowserTaskClick(text);
    const alreadyClicked = steps.some((step) => step.action === 'click');
    const target = !alreadyClicked ? findBrowserTaskElement(dom, click?.query || '', 'click') : null;
    if (target?.selector) {
      steps.push({
        action: 'click',
        selector: target.selector,
        query: click?.query || '',
        value: '',
        reason: 'Local fallback used the best clickable DOM element.',
      });
    }
  }

  return normalizeBrowserTaskPlan({
    summary: steps.length
      ? `Local fallback planned ${steps.length} browser step${steps.length === 1 ? '' : 's'}.${plannerError ? ` Model planner failed: ${compactRecordText(plannerError, 180)}` : ''}`
      : `No safe local browser steps could be inferred.${plannerError ? ` Model planner failed: ${compactRecordText(plannerError, 180)}` : ''}`,
    successCheck: 'Read the page after execution and confirm the requested visible state changed.',
    steps,
  }, maxSteps);
}

async function planBrowserTaskSteps(page, dom, instruction, maxSteps) {
  const localPlan = fallbackBrowserTaskPlan(instruction, dom, maxSteps);
  if (localPlan.steps.length) {
    return {
      ...localPlan,
      source: 'local_fallback',
      plannerError: '',
    };
  }
  if (openAiZeroSpendModeActive()) {
    return {
      ...localPlan,
      source: 'blocked',
      plannerError: 'OpenAI zero-spend mode is active and no safe local fallback steps were inferred.',
    };
  }
  if (!OPENAI_API_KEY) {
    return {
      ...fallbackBrowserTaskPlan(instruction, dom, maxSteps, 'OpenAI API key is not configured.'),
      source: 'local_fallback',
      plannerError: 'OpenAI API key is not configured.',
    };
  }

  let planText = '';
  try {
    planText = await callOpenAIResponses({
      model: models.fast,
      instructions: 'You are the browser task planner inside JAVIS. Return JSON only. Plan safe browser steps using the current page DOM. Never plan irreversible or account-changing actions.',
      input: browserTaskPrompt(page, dom, instruction, maxSteps),
      maxOutputTokens: 900,
      source: 'browser_task_planner',
    });
    return {
      ...normalizeBrowserTaskPlan(parseJsonFromModelText(planText), maxSteps),
      source: 'model',
      plannerOutput: compactRecordText(planText, 1200),
      plannerError: '',
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    const fallback = fallbackBrowserTaskPlan(instruction, dom, maxSteps, message);
    appendAudit('browser_task.plan_failed', {
      error: compactRecordText(message, 500),
      fallbackSteps: fallback.steps.length,
      model: models.fast,
      output: compactRecordText(planText, 1000),
    });
    return {
      ...fallback,
      source: fallback.steps.length ? 'local_fallback' : 'blocked',
      plannerOutput: compactRecordText(planText, 1200),
      plannerError: message,
    };
  }
}

function browserTaskStepLabel(step) {
  if (step.action === 'wait') return `Wait ${step.ms}ms`;
  if (step.action === 'open_url') return `Open ${step.url || step.value}`;
  if (step.action === 'search') return `Search ${step.query || step.value}`;
  if (['reload', 'back', 'forward'].includes(step.action)) return `Browser ${step.action}`;
  return `${step.action} ${step.selector || step.query}`;
}

async function runBrowserTaskStep(step, execute, options = {}) {
  if (step.action === 'wait') {
    if (execute) await waitMs(step.ms);
    return {
      status: execute ? 'executed' : 'previewed',
      action: step.action,
      label: browserTaskStepLabel(step),
      output: execute ? `Waited ${step.ms}ms.` : `Would wait ${step.ms}ms.`,
    };
  }

  if (['click', 'fill', 'select'].includes(step.action)) {
    let result;
    try {
      result = await executeBrowserDomAction({
        action: step.action,
        app: options.app,
        selector: step.selector,
        query: step.query,
        value: step.value,
        execute,
        source: 'browser_task',
      }, { preview: !execute, approvalContext: options.approvalContext });
    } catch (error) {
      if (error instanceof ActionApprovalRequired) {
        return {
          status: 'approval_required',
          action: step.action,
          label: browserTaskStepLabel(step),
          output: `Approval required before I can ${error.approval.summary}.`,
          approval: error.approval,
        };
      }
      throw error;
    }
    return {
      status: result.ok ? (result.executed ? 'executed' : 'previewed') : result.approval ? 'approval_required' : 'blocked',
      action: step.action,
      label: browserTaskStepLabel(step),
      output: result.output,
      approval: result.approval,
      plan: result.plan,
      evaluation: result.evaluation,
      preflight: result.preflight,
      safety: result.safety,
    };
  }

  const browserAction = step.action;
  const controlArgs = {
    action: 'browser_control',
    browserAction,
    app: options.app,
    url: step.url || step.value,
    query: step.query || step.value,
  };
  if (!execute) {
    const plan = buildBrowserControlPlan(controlArgs);
    const evaluation = evaluateMacActionPlan(plan, { preview: true });
    return {
      status: evaluation.blocked ? 'blocked' : 'previewed',
      action: step.action,
      label: browserTaskStepLabel(step),
      output: `Prepared ${plan.summary}${evaluation.needsApproval ? ` (${evaluation.reason})` : ''}.`,
      plan,
      evaluation,
    };
  }
  let result;
  try {
    result = await executeBrowserControl(controlArgs, { approvalContext: options.approvalContext });
  } catch (error) {
    if (error instanceof ActionApprovalRequired) {
      return {
        status: 'approval_required',
        action: step.action,
        label: browserTaskStepLabel(step),
        output: `Approval required before I can ${error.approval.summary}.`,
        approval: error.approval,
      };
    }
    throw error;
  }
  return {
    status: result.ok ? (result.executed ? 'executed' : 'previewed') : result.approval ? 'approval_required' : 'blocked',
    action: step.action,
    label: browserTaskStepLabel(step),
    output: result.output,
    approval: result.approval,
  };
}

function formatBrowserTaskResults(results) {
  return results
    .map((result, index) => `${index + 1}. ${result.status}: ${result.label} · ${compactRecordText(result.output, 220)}`)
    .join('\n');
}

function normalizeBrowserFillDraftFields(options = {}) {
  const raw = [];
  const objects = [options.fields, options.values, options.fieldValues]
    .filter((item) => item && typeof item === 'object' && !Array.isArray(item));
  for (const item of objects) {
    for (const [name, value] of Object.entries(item)) {
      raw.push({ name, value });
    }
  }
  const arrays = [options.items, options.entries, options.fieldEntries]
    .filter(Array.isArray);
  for (const list of arrays) {
    for (const item of list) {
      if (Array.isArray(item) && item.length >= 2) raw.push({ name: item[0], value: item[1] });
      else if (item && typeof item === 'object') raw.push({
        name: item.name || item.field || item.label || item.query,
        value: item.value ?? item.content ?? item.text,
      });
    }
  }
  const singleName = String(options.field || options.name || options.query || '').trim();
  if (singleName && options.value !== undefined) raw.push({ name: singleName, value: options.value });
  return raw
    .map((item) => ({
      name: compactRecordText(item.name, 120),
      value: String(item.value ?? '').slice(0, 4000),
    }))
    .filter((item) => item.name && item.value);
}

function normalizeBrowserFillDraftFixturePage(value) {
  if (!value || typeof value !== 'object') return null;
  return {
    available: value.available !== false,
    supported: value.supported !== false,
    app: String(value.app || 'Browser'),
    title: String(value.title || ''),
    url: String(value.url || ''),
    selectedText: String(value.selectedText || ''),
    text: String(value.text || ''),
    textLength: Number(value.textLength || String(value.text || '').length),
    returnedLength: Number(value.returnedLength || String(value.text || '').length),
    truncated: Boolean(value.truncated),
    headings: Array.isArray(value.headings) ? value.headings : [],
    links: Array.isArray(value.links) ? value.links : [],
    error: String(value.error || ''),
  };
}

function normalizeBrowserFillDraftFixtureDom(value) {
  if (!value || typeof value !== 'object') return null;
  const elements = Array.isArray(value.elements) ? value.elements : Array.isArray(value.controls) ? value.controls : [];
  return {
    available: value.available !== false,
    supported: value.supported !== false,
    bridge: String(value.bridge || 'fixture'),
    app: String(value.app || 'Browser'),
    title: String(value.title || ''),
    url: String(value.url || ''),
    count: Number(value.count || elements.length),
    elements,
    error: String(value.error || ''),
  };
}

function browserFillDraftSensitiveField(field = {}) {
  const text = `${field.name}\n${field.value}`.toLowerCase();
  return /\b(password|passcode|otp|2fa|security code|cvv|cvc|credit card|card number|ssn|sin)\b|密码|验证码|信用卡|银行卡|安全码|身份证/.test(text);
}

function browserFillDraftElementForField(field = {}, dom = {}) {
  const select = findBrowserTaskElement(dom, field.name, 'select');
  if (select) return { element: select, action: 'select' };
  const fill = findBrowserTaskElement(dom, field.name, 'fill');
  if (fill) return { element: fill, action: 'fill' };
  return { element: null, action: '' };
}

function buildBrowserFillDraftPlan(fields = [], dom = {}, maxFields = 8) {
  const steps = [];
  const blocked = [];
  for (const [index, field] of fields.slice(0, maxFields).entries()) {
    if (browserFillDraftSensitiveField(field)) {
      blocked.push({
        field: field.name,
        reason: 'sensitive_field_requires_explicit_manual_handling',
      });
      continue;
    }
    const { element, action } = browserFillDraftElementForField(field, dom);
    if (!element?.selector || !action) {
      blocked.push({
        field: field.name,
        reason: 'no_matching_fillable_control',
      });
      continue;
    }
    steps.push({
      index,
      action,
      selector: element.selector,
      query: field.name,
      value: field.value,
      reason: `Matched ${element.label || element.placeholder || element.name || element.selector}.`,
      field: field.name,
      valuePreview: compactRecordText(field.value, 100),
    });
  }
  return {
    summary: steps.length
      ? `Prepared ${steps.length} browser form field draft${steps.length === 1 ? '' : 's'}${blocked.length ? `; ${blocked.length} field(s) need review` : ''}.`
      : 'No safe browser form field drafts could be prepared.',
    successCheck: 'Read the page/DOM after execution and confirm each drafted field value is visible in the matching control.',
    source: 'deterministic_dom_match',
    steps,
    blocked,
  };
}

function redactedBrowserFillDraftPlan(plan = {}) {
  return {
    ...plan,
    steps: (plan.steps || []).map((step) => ({
      ...step,
      value: step.value ? `[redacted ${Buffer.byteLength(String(step.value), 'utf8')} bytes]` : '',
      valuePreview: compactRecordText(step.valuePreview || step.value, 80),
    })),
  };
}

function browserFillDraftTargetFromPlan({ plan = {}, verification = {}, recovery = {}, live = false, confirmed = false, confirmationRequired = false, fixtureExecutionBlocked = false } = {}) {
  const steps = (Array.isArray(plan.steps) ? plan.steps : []).map((step) => ({
    index: step.index,
    field: step.field || step.query || '',
    action: step.action || '',
    selector: step.selector || '',
    valueBytes: Buffer.byteLength(String(step.value || ''), 'utf8'),
    reason: step.reason || '',
  }));
  const blocked = (Array.isArray(plan.blocked) ? plan.blocked : []).map((item) => ({
    field: item.field || '',
    reason: item.reason || '',
    requiresUserPresence: true,
    requiresSensitiveValue: /sensitive|password|otp|cvv|card|密码|验证码|信用卡|银行卡/i.test(`${item.reason || ''} ${item.field || ''}`),
    storesValue: false,
  }));
  return normalizeBrowserFillDraftTarget({
    version: 1,
    source: 'browser_fill_draft',
    status: blocked.length ? 'needs_manual_review' : verification.status || recovery.status || 'prepared',
    summary: plan.summary || '',
    safeStepCount: steps.length,
    blockedFieldCount: blocked.length,
    verifiedFieldCount: verification.verifiedCount || 0,
    verificationStatus: verification.status || '',
    recoveryStatus: recovery.status || '',
    fixture: !live || fixtureExecutionBlocked,
    confirmed,
    confirmationRequired,
    steps,
    blocked,
  });
}

function redactedBrowserFillDraftResults(results = []) {
  return (Array.isArray(results) ? results : []).map((result) => {
    const next = { ...result };
    if (next.plan?.args && Object.prototype.hasOwnProperty.call(next.plan.args, 'value')) {
      next.plan = {
        ...next.plan,
        args: {
          ...next.plan.args,
          value: next.plan.args.value ? `[redacted ${Buffer.byteLength(String(next.plan.args.value), 'utf8')} bytes]` : '',
        },
      };
    }
    return next;
  });
}

function browserFillDraftVerificationPreview(plan = {}, status = 'preview_only') {
  const steps = Array.isArray(plan.steps) ? plan.steps : [];
  return {
    ok: false,
    status,
    plannedCount: steps.length,
    executedCount: 0,
    verifiedCount: 0,
    entries: steps.map((step) => ({
      index: step.index,
      field: step.field,
      action: step.action,
      selector: step.selector,
      found: false,
      matched: false,
      expectedBytes: Buffer.byteLength(String(step.value || ''), 'utf8'),
      actualBytes: 0,
      evidence: status,
    })),
    output: status === 'confirmation_required'
      ? 'Post-fill verification is waiting for confirm:true.'
      : status === 'fixture_blocked'
        ? 'Post-fill verification cannot run against fixture DOM.'
        : 'Post-fill verification will run after a confirmed live fill.',
  };
}

function browserFillDraftVerificationScript(steps = []) {
  const targets = steps.map((step) => ({
    index: step.index,
    field: step.field,
    action: step.action,
    selector: step.selector,
    expected: String(step.value || ''),
  }));
  return `
(() => {
  const targets = ${JSON.stringify(targets)};
  const clean = (input, max = 80) => String(input || '').replace(/[\\t\\r\\n ]+/g, ' ').trim().slice(0, max);
  const byteLength = (value) => new TextEncoder().encode(String(value || '')).length;
  const actualValue = (el) => {
    const tag = el.tagName.toLowerCase();
    if (tag === 'select') {
      const option = el.options?.[el.selectedIndex];
      return { value: String(el.value || ''), label: String(option?.text || '') };
    }
    if (el.isContentEditable) return { value: String(el.textContent || ''), label: '' };
    if (tag === 'input' || tag === 'textarea') return { value: String(el.value || ''), label: '' };
    return { value: String(el.textContent || ''), label: '' };
  };
  const entries = targets.map((target) => {
    let el = null;
    try {
      el = target.selector ? document.querySelector(target.selector) : null;
    } catch (_) {
      el = null;
    }
    if (!el) {
      return {
        index: target.index,
        field: target.field,
        action: target.action,
        selector: target.selector,
        found: false,
        matched: false,
        expectedBytes: byteLength(target.expected),
        actualBytes: 0,
        evidence: 'target_missing'
      };
    }
    const tag = el.tagName.toLowerCase();
    const type = clean(el.getAttribute('type') || '', 40);
    const actual = actualValue(el);
    const expectedLower = String(target.expected || '').toLowerCase();
    const actualLower = String(actual.value || '').toLowerCase();
    const labelLower = String(actual.label || '').toLowerCase();
    const matched = target.action === 'select'
      ? (actual.value === target.expected || actualLower === expectedLower || labelLower === expectedLower || Boolean(expectedLower && labelLower.includes(expectedLower)))
      : actual.value === target.expected;
    return {
      index: target.index,
      field: target.field,
      action: target.action,
      selector: target.selector,
      found: true,
      matched,
      expectedBytes: byteLength(target.expected),
      actualBytes: byteLength(actual.value),
      tag,
      type,
      evidence: matched ? 'value_matched_in_browser' : 'value_mismatch_in_browser'
    };
  });
  return JSON.stringify({
    ok: entries.length > 0 && entries.every((entry) => entry.matched),
    title: document.title || '',
    url: location.href,
    entries
  });
})()
  `.trim();
}

function normalizeBrowserFillDraftVerificationEntries(entries = []) {
  return (Array.isArray(entries) ? entries : []).map((entry) => ({
    index: Number(entry.index || 0),
    field: compactRecordText(entry.field || '', 120),
    action: compactRecordText(entry.action || '', 40),
    selector: compactRecordText(entry.selector || '', 220),
    found: Boolean(entry.found),
    matched: Boolean(entry.matched),
    expectedBytes: Math.max(0, Number(entry.expectedBytes || 0)),
    actualBytes: Math.max(0, Number(entry.actualBytes || 0)),
    tag: compactRecordText(entry.tag || '', 40),
    type: compactRecordText(entry.type || '', 40),
    evidence: compactRecordText(entry.evidence || '', 120),
  }));
}

function browserFillDraftRecoveryHints({ verification = {}, plan = {}, results = [], live = false, confirmationRequired = false, fixtureExecutionBlocked = false } = {}) {
  const entries = Array.isArray(verification.entries) ? verification.entries : [];
  const blockedResults = (Array.isArray(results) ? results : []).filter((result) => ['blocked', 'approval_required'].includes(result.status));
  const unmatched = entries.filter((entry) => !entry.matched);
  const missing = unmatched.filter((entry) => entry.evidence === 'target_missing' || entry.found === false);
  const mismatched = unmatched.filter((entry) => entry.found && !entry.matched);
  const plannedFields = (Array.isArray(plan.steps) ? plan.steps : []).map((step) => ({
    index: step.index,
    field: compactRecordText(step.field || step.query || '', 120),
    action: compactRecordText(step.action || '', 40),
    selector: compactRecordText(step.selector || '', 220),
  }));
  const safeUnmatched = unmatched.map((entry) => ({
    index: entry.index,
    field: entry.field,
    action: entry.action,
    selector: entry.selector,
    evidence: entry.evidence,
    found: entry.found,
    matched: entry.matched,
    expectedBytes: entry.expectedBytes,
    actualBytes: entry.actualBytes,
  }));

  const actions = [];
  let status = verification.status || 'unknown';
  let summary = 'No browser fill recovery is needed.';
  let nextAction = 'Continue with the completed browser form draft.';

  if (confirmationRequired) {
    status = 'waiting_for_confirmation';
    summary = 'Browser form fill is waiting for explicit confirmation before execution.';
    nextAction = 'Review the field draft, then rerun with execute:true and confirm:true if it is safe.';
    actions.push({ type: 'confirm_then_execute', riskLevel: 3, fields: plannedFields });
  } else if (fixtureExecutionBlocked) {
    status = 'fixture_preview_only';
    summary = 'Fixture DOM cannot prove live page state.';
    nextAction = 'Open the real browser page, then rerun the same fill draft with execute:true and confirm:true.';
    actions.push({ type: 'rerun_on_live_browser', riskLevel: 3, fields: plannedFields });
  } else if (!live && verification.status === 'preview_only') {
    status = 'preview_only';
    summary = 'Preview has no live browser state to recover.';
    nextAction = 'Use a live supported browser tab before asking JAVIS to execute and verify the fill.';
    actions.push({ type: 'open_live_browser_tab', riskLevel: 1, fields: plannedFields });
  } else if (verification.status === 'verified') {
    status = 'verified';
  } else if (verification.status === 'partial' || verification.status === 'unverified') {
    summary = `Browser post-fill verification did not match ${unmatched.length}/${entries.length} executed field(s).`;
    nextAction = missing.length
      ? 'Re-read the current DOM and rebuild the fill draft because at least one target selector disappeared.'
      : 'Retry only the unmatched fields after checking whether the page reformatted or rejected the values.';
    if (missing.length) {
      actions.push({
        type: 'refresh_dom_and_replan',
        riskLevel: 1,
        reason: 'One or more selectors were missing after execution.',
        fields: missing.map((entry) => ({ index: entry.index, field: entry.field, selector: entry.selector })),
      });
    }
    if (mismatched.length) {
      actions.push({
        type: 'retry_unmatched_fields',
        riskLevel: 3,
        reason: 'One or more fields were present but did not match the expected byte-length/value check.',
        fields: mismatched.map((entry) => ({ index: entry.index, field: entry.field, selector: entry.selector, actualBytes: entry.actualBytes, expectedBytes: entry.expectedBytes })),
      });
    }
    actions.push({
      type: 'read_browser_dom',
      riskLevel: 1,
      endpoint: '/api/browser/dom?limit=40',
      reason: 'Inspect visible controls before retrying.',
    });
  } else if (verification.status === 'browser_unavailable') {
    summary = 'JAVIS could not read the browser after attempting the fill.';
    nextAction = 'Bring a supported browser tab to the front and rerun verification or the fill draft.';
    actions.push({ type: 'focus_supported_browser', riskLevel: 1 });
    actions.push({ type: 'read_browser_dom', riskLevel: 1, endpoint: '/api/browser/dom?limit=40' });
  } else if (verification.status === 'verification_failed') {
    summary = 'Browser verification failed before it could compare field state.';
    nextAction = 'Check browser JavaScript bridge status, then re-read DOM before retrying.';
    actions.push({ type: 'check_browser_javascript_bridge', riskLevel: 1, endpoint: '/api/browser/javascript' });
    actions.push({ type: 'read_browser_dom', riskLevel: 1, endpoint: '/api/browser/dom?limit=40' });
  } else if (verification.status === 'no_executed_fields' && blockedResults.length) {
    summary = 'No fields executed because the fill draft was blocked or needed approval.';
    nextAction = 'Resolve the first blocked or approval-required field before retrying.';
    actions.push({
      type: 'resolve_blocked_result',
      riskLevel: 2,
      results: blockedResults.slice(0, 3).map((result) => ({
        index: result.index,
        field: compactRecordText(result.field || '', 120),
        status: result.status,
        action: result.action,
      })),
    });
  }

  return {
    needed: status !== 'verified' && status !== 'preview_only',
    status,
    summary,
    nextAction,
    unmatchedCount: unmatched.length,
    unmatched: safeUnmatched,
    actions,
  };
}

async function verifyBrowserFillDraftExecution(steps = [], options = {}) {
  const executableSteps = (Array.isArray(steps) ? steps : []).filter((step) => step?.selector && step?.value !== undefined);
  if (!executableSteps.length) {
    return {
      ok: false,
      status: 'no_executed_fields',
      plannedCount: 0,
      executedCount: 0,
      verifiedCount: 0,
      entries: [],
      output: 'Post-fill verification skipped: no executed fields.',
    };
  }
  try {
    const browser = await browserContextSnapshot({ app: options.app });
    if (!browser.supported || !browser.available) {
      return {
        ok: false,
        status: 'browser_unavailable',
        plannedCount: executableSteps.length,
        executedCount: executableSteps.length,
        verifiedCount: 0,
        entries: [],
        output: `Post-fill verification unavailable: ${browser.error || 'no supported browser is active'}.`,
      };
    }
    const snapshot = await executeBrowserJavaScriptBridge(browser, browserFillDraftVerificationScript(executableSteps), { timeoutMs: 6000 });
    const parsed = JSON.parse(snapshot.output || '{}');
    const entries = normalizeBrowserFillDraftVerificationEntries(parsed.entries);
    const verifiedCount = entries.filter((entry) => entry.matched).length;
    const status = entries.length && verifiedCount === entries.length
      ? 'verified'
      : verifiedCount > 0 ? 'partial' : 'unverified';
    appendAudit('browser_fill_draft.verified', {
      app: browser.app,
      url: parsed.url || browser.url,
      status,
      planned: executableSteps.length,
      verified: verifiedCount,
      bridge: snapshot.bridge,
    });
    return {
      ok: status === 'verified',
      status,
      plannedCount: executableSteps.length,
      executedCount: executableSteps.length,
      verifiedCount,
      entries,
      output: `Post-fill verification: ${verifiedCount}/${entries.length} executed field(s) matched in the live browser.`,
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    appendAudit('browser_fill_draft.verify_failed', {
      error: compactRecordText(message, 500),
      planned: executableSteps.length,
    });
    return {
      ok: false,
      status: 'verification_failed',
      plannedCount: executableSteps.length,
      executedCount: executableSteps.length,
      verifiedCount: 0,
      entries: [],
      output: `Post-fill verification failed: ${compactRecordText(message, 260)}`,
    };
  }
}

async function runBrowserFillDraftWorkflow(options = {}) {
  const instruction = String(options.instruction || options.goal || 'Draft browser form fills.').trim();
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  const confirmed = options.confirm === true || options.confirmed === true || String(options.confirm || options.confirmed || '').toLowerCase() === 'true';
  const maxFields = Math.max(1, Math.min(12, Number(options.maxFields || options.maxSteps || 8)));
  const fixturePage = normalizeBrowserFillDraftFixturePage(options.page);
  const fixtureDom = normalizeBrowserFillDraftFixtureDom(options.dom);
  const live = !fixturePage && !fixtureDom;
  const page = fixturePage || await browserPageSnapshot({ app: options.app, maxChars: normalizeBrowserMaxChars(options.maxChars || 10000) });
  const pageSummary = browserWorkflowPageSummary(page);
  const workflowTitle = `fill_draft · ${page.title || page.url || instruction}`.slice(0, 180);
  if (!page.available) {
    const workflow = createWorkflowRecord({
      kind: 'browser',
      source: 'browser_fill_draft',
      status: 'failed',
      title: workflowTitle,
      intent: 'fill_draft',
      mode: 'quick',
      request: instruction,
      target: pageSummary,
      result: page.error || 'No supported browser page is available.',
    });
    const routing = createRoutingRecordForWorkflow({
      task: instruction,
      workflow,
      mode: 'quick',
      source: options.source || 'browser_fill_draft',
      scope: options.scope || 'browser:fill_draft',
      parallelGroup: options.parallelGroup || options.group || 'browser:quick',
      resultSummary: workflow.result,
    });
    return { ok: false, executed: false, intent: 'fill_draft', workflow, routing, page: pageSummary, output: workflow.result };
  }
  const dom = fixtureDom || await browserDomSnapshot({ app: options.app, limit: options.domLimit || 100 });
  const fields = normalizeBrowserFillDraftFields(options);
  const workflow = createWorkflowRecord({
    kind: 'browser',
    source: 'browser_fill_draft',
    status: 'running',
    title: workflowTitle,
    intent: 'fill_draft',
    mode: 'quick',
    request: instruction,
    target: {
      ...pageSummary,
      resultCount: dom.elements?.length || 0,
    },
  });
  appendAudit('browser_fill_draft.requested', {
    app: page.app,
    title: page.title,
    url: page.url,
    fields: fields.length,
    execute,
    confirmed,
    live,
    domCount: dom.elements?.length || 0,
  });

  const plan = buildBrowserFillDraftPlan(fields, dom, maxFields);
  const confirmationRequired = execute && !confirmed;
  const fixtureExecutionBlocked = execute && !live;
  const results = [];
  let verification = browserFillDraftVerificationPreview(
    plan,
    confirmationRequired ? 'confirmation_required' : fixtureExecutionBlocked ? 'fixture_blocked' : 'preview_only',
  );
  if (execute && confirmed && !fixtureExecutionBlocked) {
    for (const step of plan.steps) {
      try {
        const result = await runBrowserTaskStep(step, true, {
          app: options.app,
          approvalContext: {
            type: 'browser_fill_draft',
            workflowId: workflow.id,
            title: workflowTitle,
            instruction,
            stepIndex: step.index,
          },
        });
        results.push({ index: step.index, field: step.field, ...result, reason: step.reason });
        if (['blocked', 'approval_required'].includes(result.status)) break;
        if (result.status === 'executed') await waitMs(300);
      } catch (error) {
        results.push({
          index: step.index,
          field: step.field,
          status: 'blocked',
          action: step.action,
          label: browserTaskStepLabel(step),
          output: error instanceof Error ? error.message : String(error),
          reason: step.reason,
        });
        break;
      }
    }
    const executedSteps = plan.steps.filter((step) => results.some((result) => result.index === step.index && result.status === 'executed'));
    verification = await verifyBrowserFillDraftExecution(executedSteps, { app: options.app });
  } else {
    for (const step of plan.steps) {
      results.push({
        index: step.index,
        field: step.field,
        status: confirmationRequired ? 'confirmation_required' : fixtureExecutionBlocked ? 'blocked' : 'previewed',
        action: step.action,
        label: browserTaskStepLabel(step),
        output: confirmationRequired
          ? 'Requires confirm:true before filling browser fields.'
          : fixtureExecutionBlocked
            ? 'Fixture DOM can only preview; execute against a live browser page.'
            : `Would ${step.action} ${step.field}.`,
        reason: step.reason,
      });
    }
  }
  const verificationBlocked = execute && confirmed && live && verification.status && !['verified', 'no_executed_fields'].includes(verification.status);
  const recovery = browserFillDraftRecoveryHints({
    verification,
    plan,
    results,
    live,
    confirmationRequired,
    fixtureExecutionBlocked,
  });
  const blocked = confirmationRequired || fixtureExecutionBlocked || verificationBlocked || plan.blocked.length > 0 || results.some((result) => ['blocked', 'approval_required'].includes(result.status));
  const output = [
    `Browser fill draft: ${instruction}`,
    `Plan: ${plan.summary}`,
    plan.blocked.length ? `Review needed: ${plan.blocked.map((item) => `${item.field} (${item.reason})`).join('; ')}` : '',
    results.length ? formatBrowserTaskResults(results) : 'No matching fillable fields were found.',
    verification.output,
    recovery.needed ? `Recovery: ${recovery.nextAction}` : '',
    confirmationRequired ? 'Execution paused: pass confirm:true after reviewing the field draft.' : '',
    fixtureExecutionBlocked ? 'Execution blocked: fixture DOM is preview-only.' : '',
  ].filter(Boolean).join('\n');
  const finalWorkflow = setWorkflow(workflow.id, {
    status: blocked ? 'blocked' : 'done',
    result: output,
    completedAt: Date.now(),
    target: {
      ...pageSummary,
      resultCount: results.length,
      plannedFieldCount: plan.steps.length,
      blockedFieldCount: plan.blocked.length,
      verifiedFieldCount: verification.verifiedCount,
      verificationStatus: verification.status,
      recoveryStatus: recovery.status,
      fixture: !live,
      confirmed,
      fillDraft: browserFillDraftTargetFromPlan({
        plan,
        verification,
        recovery,
        live,
        confirmed,
        confirmationRequired,
        fixtureExecutionBlocked,
      }),
    },
  });
  appendAudit('browser_fill_draft.completed', {
    workflowId: workflow.id,
    status: finalWorkflow?.status,
    planned: plan.steps.length,
    blocked: plan.blocked.length,
    results: results.length,
    verificationStatus: verification.status,
    verified: verification.verifiedCount,
    recoveryStatus: recovery.status,
    execute,
    confirmed,
    live,
  });
  const routing = createRoutingRecordForWorkflow({
    task: instruction,
    workflow: finalWorkflow,
    mode: 'quick',
    source: options.source || 'browser_fill_draft',
    scope: options.scope || 'browser:fill_draft',
    parallelGroup: options.parallelGroup || options.group || 'browser:quick',
    resultSummary: output,
  });
  return {
    ok: !blocked,
    executed: results.some((result) => result.status === 'executed'),
    confirmed,
    mode: 'quick',
    intent: 'fill_draft',
    workflow: finalWorkflow,
    routing,
    page: pageSummary,
    dom: { ...dom, elements: (dom.elements || []).slice(0, 40) },
    verification,
    recovery,
    fields: fields.map((field) => ({
      name: field.name,
      valuePreview: browserFillDraftSensitiveField(field) ? '[sensitive]' : compactRecordText(field.value, 80),
    })),
    plan: redactedBrowserFillDraftPlan(plan),
    results: redactedBrowserFillDraftResults(results),
    output,
  };
}

async function runBrowserTaskWorkflow(options = {}) {
  const instruction = String(options.instruction || '').trim();
  if (!instruction) throw new Error('Browser act workflow requires an instruction.');
  const fixturePage = normalizeBrowserFillDraftFixturePage(options.page || options.fixturePage);
  const fixtureDom = normalizeBrowserFillDraftFixtureDom(options.dom || options.fixtureDom);
  const fixture = Boolean(fixturePage || fixtureDom);
  const requestedExecute = options.execute !== false;
  const execute = requestedExecute && !fixture;
  const maxSteps = Math.max(1, Math.min(5, Number(options.maxSteps || 5)));
  const maxChars = normalizeBrowserMaxChars(options.maxChars || 12000);
  const page = fixturePage || await browserPageSnapshot({ app: options.app, maxChars });
  const planningPage = page.available
    ? page
    : {
        ...page,
        available: true,
        supported: page.supported !== false,
        app: page.app || options.app || 'Google Chrome',
        title: 'Browser navigation preview',
        url: '',
        selectedText: '',
        text: '',
        textLength: 0,
        returnedLength: 0,
        headings: [],
        links: [],
      };
  const pageSummary = browserWorkflowPageSummary(page);
  const workflowTitle = `act · ${page.title || page.url || instruction}`.slice(0, 180);
  const dom = page.available
    ? fixtureDom || await browserDomSnapshot({ app: options.app, limit: options.domLimit || 80 })
    : fixtureDom || {
        available: false,
        supported: false,
        app: planningPage.app,
        title: planningPage.title,
        url: planningPage.url,
        count: 0,
        elements: [],
        error: page.error || 'browser_page_unavailable',
      };
  const workflow = createWorkflowRecord({
    kind: 'browser',
    source: 'browser_task',
    status: 'running',
    title: workflowTitle,
    intent: 'act',
    mode: 'quick',
    request: instruction,
    target: {
      ...pageSummary,
      resultCount: dom.elements?.length || 0,
    },
  });

  appendAudit('browser_task.requested', {
    app: planningPage.app,
    title: planningPage.title,
    url: planningPage.url,
    execute,
    pageAvailable: Boolean(page.available),
    domCount: dom.elements?.length || 0,
    maxSteps,
  });

  const plan = await planBrowserTaskSteps(planningPage, dom, instruction, maxSteps);
  const results = [];
  for (const step of plan.steps) {
    try {
      const result = await runBrowserTaskStep(step, execute, {
        app: options.app,
        approvalContext: {
          type: 'browser_task',
          workflowId: workflow.id,
          title: workflowTitle,
          instruction,
          stepIndex: step.index,
        },
      });
      results.push({ index: step.index, ...result, reason: step.reason });
      if (['blocked', 'approval_required'].includes(result.status)) break;
      if (execute && result.status === 'executed' && step.action !== 'wait') await waitMs(450);
    } catch (error) {
      results.push({
        index: step.index,
        status: 'blocked',
        action: step.action,
        label: browserTaskStepLabel(step),
        output: error instanceof Error ? error.message : String(error),
        reason: step.reason,
      });
      break;
    }
  }

  const afterPage = !execute && !page.available
    ? page
    : fixturePage || await browserPageSnapshot({ app: options.app, maxChars: Math.min(6000, maxChars) }).catch((error) => ({
        available: false,
        error: error instanceof Error ? error.message : String(error),
      }));
  const afterDom = !execute && !page.available
    ? dom
    : fixtureDom || await browserDomSnapshot({ app: options.app, limit: 40 }).catch((error) => ({
        available: false,
        error: error instanceof Error ? error.message : String(error),
        elements: [],
      }));
  const noSafeSteps = plan.steps.length === 0;
  const blocked = noSafeSteps || results.some((result) => ['blocked', 'approval_required'].includes(result.status));
  const output = [
    `Browser task: ${instruction}`,
    `Plan: ${plan.summary}`,
    `Planner: ${plan.source}`,
    plan.plannerError ? `Planner note: ${compactRecordText(plan.plannerError, 260)}` : '',
    plan.successCheck ? `Check: ${plan.successCheck}` : '',
    results.length ? formatBrowserTaskResults(results) : 'No safe executable browser steps were planned.',
    afterPage?.available ? `After: ${afterPage.title || ''} ${afterPage.url || ''}` : `After: ${afterPage?.error || 'unavailable'}`,
  ].filter(Boolean).join('\n');
  const finalWorkflow = setWorkflow(workflow.id, {
    status: blocked ? 'blocked' : execute ? 'done' : 'done',
    result: output,
    completedAt: Date.now(),
    target: {
      ...pageSummary,
      returnedLength: afterPage?.text?.length || pageSummary.returnedLength,
      resultCount: afterDom?.elements?.length || 0,
    },
  });
  appendAudit('browser_task.completed', {
    workflowId: workflow.id,
    status: finalWorkflow?.status,
    steps: plan.steps.length,
    results: results.length,
    execute,
    blocked,
    noSafeSteps,
    planner: plan.source,
  });
  const routing = createRoutingRecordForWorkflow({
    task: instruction,
    workflow: finalWorkflow,
    mode: 'quick',
    source: options.source || 'browser_task',
    scope: options.scope || 'browser:act',
    parallelGroup: options.parallelGroup || options.group || 'browser:quick',
    resultSummary: output,
  });

  return {
    ok: !blocked,
    executed: results.some((result) => result.status === 'executed'),
    mode: 'quick',
    intent: 'act',
    queued: false,
    fixture,
    requestedExecute,
    workflow: finalWorkflow,
    routing,
    page: browserWorkflowPageSummary(afterPage?.available ? afterPage : page),
    beforePage: pageSummary,
    dom,
    afterDom,
    plan,
    results,
    output,
  };
}

async function runBrowserSearchWorkflow(options = {}) {
  const intent = normalizeBrowserWorkflowIntent(options.intent) === 'compare' ? 'compare' : 'search';
  const mode = normalizeBrowserWorkflowMode(options.mode);
  const instruction = String(options.instruction || '').trim();
  const queries = normalizeBrowserSearchQueries(options);
  if (!queries.length) throw new Error('Browser search workflow requires query or queries.');
  const execute = options.execute !== false;
  const maxChars = normalizeBrowserMaxChars(options.maxChars || (mode === 'quick' ? 12000 : 24000));
  const waitMsAfterSearch = Math.max(500, Math.min(6000, Number(options.waitMs || 1800)));
  const request = instruction || queries.join(' ; ');
  const workflowTitle = `${intent} · ${queries.join(' vs ')}`.slice(0, 180);

  if (!execute) {
    const workflow = createWorkflowRecord({
      kind: 'browser',
      source: 'browser_search_workflow',
      status: 'done',
      title: workflowTitle,
      intent,
      mode,
      request,
      target: {
        app: 'Browser',
        title: 'Search preview',
        url: '',
        fallback: '',
        textLength: 0,
        returnedLength: 0,
        resultCount: queries.length,
      },
      result: `Preview only. Would search: ${queries.join(' ; ')}`,
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow,
      mode,
      source: options.source || 'browser_search_workflow',
      scope: options.scope || `browser:${intent}`,
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary: workflow.result,
    });
    return {
      ok: true,
      executed: false,
      queued: false,
      mode,
      intent,
      queries,
      workflow,
      routing,
      searches: [],
      output: workflow.result,
    };
  }

  const workflow = createWorkflowRecord({
    kind: 'browser',
    source: 'browser_search_workflow',
    status: 'running',
    title: workflowTitle,
    intent,
    mode,
    request,
    target: {
      app: 'Browser',
      title: queries[0],
      url: '',
      fallback: '',
      textLength: 0,
      returnedLength: 0,
      resultCount: queries.length,
    },
  });

  const searches = [];
  for (const [index, query] of queries.entries()) {
    try {
      const action = await executeBrowserControl({
        action: 'search',
        query,
        app: options.app,
      }, {
        approvalContext: {
          type: 'browser_search_workflow',
          workflowId: workflow.id,
          title: workflowTitle,
          instruction: request,
          stepIndex: index,
        },
      });
      await waitMs(waitMsAfterSearch);
      const page = await browserPageSnapshot({ app: options.app, maxChars });
      searches.push({
        query,
        action,
        page,
        pageSummary: browserWorkflowPageSummary(page),
      });
    } catch (error) {
      searches.push({
        query,
        error: error instanceof Error ? error.message : String(error),
        page: null,
        pageSummary: { available: false, supported: false, app: '', title: '', url: '', selectedTextLength: 0, returnedLength: 0, textLength: 0, truncated: false, fallback: '', error: error instanceof Error ? error.message : String(error), headings: [] },
      });
      break;
    }
  }

  const failed = searches.some((item) => item.error || !item.page?.available);
  if (failed) {
    const output = [
      `Browser ${intent} blocked.`,
      searches.map((item, index) => `${index + 1}. ${item.query}: ${item.error || item.page?.error || 'page unavailable'}`).join('\n'),
    ].join('\n');
    const finalWorkflow = setWorkflow(workflow.id, {
      status: 'blocked',
      result: output,
      completedAt: Date.now(),
      target: {
        ...(workflow.target || {}),
        resultCount: searches.length,
      },
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow: finalWorkflow,
      mode,
      source: options.source || 'browser_search_workflow',
      scope: options.scope || `browser:${intent}`,
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary: output,
    });
    return {
      ok: false,
      executed: true,
      queued: false,
      mode,
      intent,
      queries,
      workflow: finalWorkflow,
      routing,
      searches,
      output,
    };
  }

  const prompt = browserSearchWorkflowPrompt(searches, intent, request);
  const latestPage = searches[searches.length - 1]?.pageSummary || {};
  if (mode !== 'quick') {
    const queuedWorkflow = setWorkflow(workflow.id, {
      status: 'queued',
      target: {
        ...(latestPage || {}),
        resultCount: searches.length,
        searchQueries: queries,
      },
    });
    const job = createJob(prompt, mode === 'background' ? 'background' : mode, 'browser_search_workflow', { workflowId: workflow.id });
    const finalWorkflow = setWorkflow(workflow.id, { jobId: job.id });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow: finalWorkflow,
      job,
      mode,
      source: options.source || 'browser_search_workflow',
      scope: options.scope || `browser:${intent}`,
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
    });
    return {
      ok: true,
      executed: true,
      queued: true,
      mode,
      intent,
      queries,
      workflow: finalWorkflow || queuedWorkflow,
      job,
      routing,
      searches: searches.map((item) => ({ query: item.query, page: item.pageSummary })),
      output: `Queued ${mode} browser ${intent} workflow for ${queries.join(' ; ')}.`,
    };
  }

  const output = await callOpenAIResponsesWithFallback({
    model: models.fast,
    instructions:
      'You are the browser search lane inside JAVIS. Use only the provided search result page snapshots. Answer in concise Chinese with concrete next actions and useful follow-up queries/links.',
    input: prompt,
    maxOutputTokens: intent === 'compare' ? 1200 : 850,
  }, {
    source: 'browser_search_workflow',
    timeoutMs: intent === 'compare' ? 90000 : 60000,
  });
  const finalWorkflow = setWorkflow(workflow.id, {
    status: quickLaneOutputOk(output) ? 'done' : 'blocked',
    result: output,
    completedAt: Date.now(),
    target: {
      ...(latestPage || {}),
      resultCount: searches.length,
      searchQueries: queries,
    },
  });
  const routing = createRoutingRecordForWorkflow({
    task: request,
    workflow: finalWorkflow,
    mode,
    source: options.source || 'browser_search_workflow',
    scope: options.scope || `browser:${intent}`,
    parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
    resultSummary: output,
  });
  return {
    ok: quickLaneOutputOk(output),
    executed: true,
    queued: false,
    mode,
    intent,
    queries,
    workflow: finalWorkflow,
    routing,
    searches: searches.map((item) => ({ query: item.query, page: item.pageSummary })),
    output,
  };
}

async function runBrowserResultReviewWorkflow(options = {}) {
  const mode = normalizeBrowserWorkflowMode(options.mode);
  const instruction = String(options.instruction || '').trim();
  const queries = normalizeBrowserSearchQueries(options);
  const explicitUrl = browserReviewExplicitUrl(options);
  const query = explicitUrl ? '' : queries[0];
  if (!explicitUrl && !query) throw new Error('Browser result review requires a URL or search query.');
  const execute = options.execute !== false;
  const maxChars = normalizeBrowserMaxChars(options.maxChars || (mode === 'quick' ? 14000 : 30000));
  const waitMsAfterSearch = Math.max(500, Math.min(6000, Number(options.waitMs || 1800)));
  const waitMsAfterOpen = Math.max(500, Math.min(8000, Number(options.openWaitMs || options.waitMsAfterOpen || 2200)));
  const request = instruction || explicitUrl || query;
  const workflowTitle = `review_result · ${explicitUrl || query}`.slice(0, 180);

  if (!execute) {
    const workflow = createWorkflowRecord({
      kind: 'browser',
      source: 'browser_result_review_workflow',
      status: 'done',
      title: workflowTitle,
      intent: 'review_result',
      mode,
      request,
      target: {
        app: 'Browser',
        title: explicitUrl ? 'URL preview' : 'Search result preview',
        url: explicitUrl,
        fallback: '',
        textLength: 0,
        returnedLength: 0,
        resultCount: explicitUrl ? 1 : 0,
      },
      result: explicitUrl
        ? `Preview only. Would open and review: ${explicitUrl}`
        : `Preview only. Would search "${query}" and review result #${normalizeBrowserResultIndex(options.resultIndex || options.index || options.position)}.`,
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow,
      mode,
      source: options.source || 'browser_result_review_workflow',
      scope: options.scope || 'browser:review_result',
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary: workflow.result,
    });
    return {
      ok: true,
      executed: false,
      queued: false,
      mode,
      intent: 'review_result',
      query,
      selected: explicitUrl ? { index: 1, text: explicitUrl, href: explicitUrl, host: new URL(explicitUrl).hostname.replace(/^www\./i, ''), sameHost: false } : null,
      workflow,
      routing,
      output: workflow.result,
    };
  }

  const workflow = createWorkflowRecord({
    kind: 'browser',
    source: 'browser_result_review_workflow',
    status: 'running',
    title: workflowTitle,
    intent: 'review_result',
    mode,
    request,
    target: {
      app: 'Browser',
      title: explicitUrl || query,
      url: explicitUrl,
      fallback: '',
      textLength: 0,
      returnedLength: 0,
      resultCount: 0,
    },
  });

  let search = null;
  let selected = explicitUrl
    ? { index: 1, text: explicitUrl, href: explicitUrl, host: new URL(explicitUrl).hostname.replace(/^www\./i, ''), sameHost: false }
    : null;

  try {
    if (!selected) {
      const action = await executeBrowserControl({
        action: 'search',
        query,
        app: options.app,
      }, {
        approvalContext: {
          type: 'browser_result_review_workflow',
          workflowId: workflow.id,
          title: workflowTitle,
          instruction: request,
          stepIndex: 0,
        },
      });
      await waitMs(waitMsAfterSearch);
      const page = await browserPageSnapshot({ app: options.app, maxChars });
      const candidates = browserSearchResultLinks(page, MAX_BROWSER_PAGE_LINKS);
      selected = selectBrowserReviewLink(candidates, options);
      search = {
        query,
        action,
        page,
        pageSummary: browserWorkflowPageSummary(page),
        candidates: candidates.slice(0, 12),
      };
      if (!page.available) throw new Error(page.error || 'Search result page is unavailable.');
      if (!selected) throw new Error('No reviewable search result link was found.');
    }

    const openAction = await executeBrowserControl({
      action: 'open_url',
      url: selected.href,
      app: options.app,
    }, {
      approvalContext: {
        type: 'browser_result_review_workflow',
        workflowId: workflow.id,
        title: workflowTitle,
        instruction: request,
        stepIndex: selected ? 1 : 0,
      },
    });
    await waitMs(waitMsAfterOpen);
    const targetPage = await browserPageSnapshot({ app: options.app, maxChars });
    const targetSummary = browserWorkflowPageSummary(targetPage);
    if (!targetPage.available) throw new Error(targetPage.error || 'Target page is unavailable.');

    const prompt = browserResultReviewPrompt({
      request,
      query,
      searchPage: search?.page,
      selectedLink: selected,
      targetPage,
    });

    if (mode !== 'quick') {
      const queuedWorkflow = setWorkflow(workflow.id, {
        status: 'queued',
        target: {
          ...targetSummary,
          selected,
          query,
          resultCount: search?.candidates?.length || 1,
        },
      });
      const job = createJob(prompt, mode === 'background' ? 'background' : mode, 'browser_result_review_workflow', { workflowId: workflow.id });
      const finalWorkflow = setWorkflow(workflow.id, { jobId: job.id });
      const routing = createRoutingRecordForWorkflow({
        task: request,
        workflow: finalWorkflow,
        job,
        mode,
        source: options.source || 'browser_result_review_workflow',
        scope: options.scope || 'browser:review_result',
        parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      });
      return {
        ok: true,
        executed: true,
        queued: true,
        mode,
        intent: 'review_result',
        query,
        selected,
        search: search ? { query: search.query, page: search.pageSummary, candidates: search.candidates } : null,
        openAction,
        page: targetSummary,
        workflow: finalWorkflow || queuedWorkflow,
        job,
        routing,
        output: `Queued ${mode} browser result review for ${selected.href}.`,
      };
    }

    const output = await callOpenAIResponsesWithFallback({
      model: models.fast,
      instructions:
        'You are the browser result review lane inside JAVIS. Use only the provided target page snapshot. Answer in concise Chinese with concrete conclusions, useful next links, and what JAVIS should do next.',
      input: prompt,
      maxOutputTokens: 1000,
    }, {
      source: 'browser_result_review_workflow',
      timeoutMs: 70000,
    });
    const finalWorkflow = setWorkflow(workflow.id, {
      status: quickLaneOutputOk(output) ? 'done' : 'blocked',
      result: output,
      completedAt: Date.now(),
      target: {
        ...targetSummary,
        selected,
        query,
        resultCount: search?.candidates?.length || 1,
      },
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow: finalWorkflow,
      mode,
      source: options.source || 'browser_result_review_workflow',
      scope: options.scope || 'browser:review_result',
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary: output,
    });
    return {
      ok: quickLaneOutputOk(output),
      executed: true,
      queued: false,
      mode,
      intent: 'review_result',
      query,
      selected,
      search: search ? { query: search.query, page: search.pageSummary, candidates: search.candidates } : null,
      openAction,
      page: targetSummary,
      workflow: finalWorkflow,
      routing,
      output,
    };
  } catch (error) {
    const output = `Browser review_result blocked: ${error instanceof Error ? error.message : String(error)}`;
    const finalWorkflow = setWorkflow(workflow.id, {
      status: 'blocked',
      result: output,
      completedAt: Date.now(),
      target: {
        ...(workflow.target || {}),
        selected,
        query,
        resultCount: search?.candidates?.length || 0,
      },
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow: finalWorkflow,
      mode,
      source: options.source || 'browser_result_review_workflow',
      scope: options.scope || 'browser:review_result',
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary: output,
    });
    return {
      ok: false,
      executed: true,
      queued: false,
      mode,
      intent: 'review_result',
      query,
      selected,
      search: search ? { query: search.query, page: search.pageSummary, candidates: search.candidates } : null,
      page: browserFailedPageSummary(error),
      workflow: finalWorkflow,
      routing,
      output,
    };
  }
}

async function runBrowserResearchWorkflow(options = {}) {
  const mode = normalizeBrowserWorkflowMode(options.mode);
  const instruction = String(options.instruction || '').trim();
  const maxPages = normalizeBrowserResearchLimit(options.maxPages || options.limit || options.resultCount);
  const urls = normalizeBrowserResearchUrls(options, maxPages);
  const queries = normalizeBrowserSearchQueries(options);
  const query = urls.length ? '' : queries[0];
  if (!urls.length && !query) throw new Error('Browser research requires a URL list or search query.');
  const execute = options.execute !== false;
  const maxChars = normalizeBrowserMaxChars(options.maxChars || (mode === 'quick' ? 8000 : 14000));
  const waitMsAfterSearch = Math.max(500, Math.min(6000, Number(options.waitMs || 1800)));
  const waitMsAfterOpen = Math.max(500, Math.min(8000, Number(options.openWaitMs || options.waitMsAfterOpen || 2200)));
  const request = instruction || query || urls.join(' ; ');
  const workflowTitle = `research · ${query || urls.join(' ; ')}`.slice(0, 180);

  if (!execute) {
    const selectedLinks = urls.map(browserResearchLinkFromUrl);
    const continuation = browserResearchContinuationPlan({
      request,
      query,
      mode,
      maxPages,
      selectedLinks,
      executed: false,
    });
    const workflow = createWorkflowRecord({
      kind: 'browser',
      source: 'browser_research_workflow',
      status: 'done',
      title: workflowTitle,
      intent: 'research',
      mode,
      request,
      parentWorkflowId: options.parentWorkflowId || '',
      target: {
        app: 'Browser',
        title: urls.length ? 'URL research preview' : 'Search research preview',
        url: urls[0] || '',
        fallback: '',
        textLength: 0,
        returnedLength: 0,
        resultCount: urls.length || maxPages,
      },
      result: urls.length
        ? `Preview only. Would open and review ${urls.length} URL(s).`
        : `Preview only. Would search "${query}" and review up to ${maxPages} result page(s).`,
      continuation,
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow,
      mode,
      source: options.source || 'browser_research_workflow',
      scope: options.scope || 'browser:research',
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary: workflow.result,
    });
    return {
      ok: true,
      executed: false,
      queued: false,
      mode,
      intent: 'research',
      query,
      selectedLinks,
      continuation,
      pages: [],
      workflow,
      routing,
      output: workflow.result,
    };
  }

  const workflow = createWorkflowRecord({
    kind: 'browser',
    source: 'browser_research_workflow',
    status: 'running',
    title: workflowTitle,
    intent: 'research',
    mode,
    request,
    parentWorkflowId: options.parentWorkflowId || '',
    target: {
      app: 'Browser',
      title: query || urls[0],
      url: urls[0] || '',
      fallback: '',
      textLength: 0,
      returnedLength: 0,
      resultCount: 0,
    },
  });

  let search = null;
  let selectedLinks = urls.map(browserResearchLinkFromUrl);
  const pages = [];

  try {
    if (!selectedLinks.length) {
      const action = await executeBrowserControl({
        action: 'search',
        query,
        app: options.app,
      }, {
        approvalContext: {
          type: 'browser_research_workflow',
          workflowId: workflow.id,
          title: workflowTitle,
          instruction: request,
          stepIndex: 0,
        },
      });
      await waitMs(waitMsAfterSearch);
      const page = await browserPageSnapshot({ app: options.app, maxChars });
      const candidates = browserSearchResultLinks(page, MAX_BROWSER_PAGE_LINKS);
      selectedLinks = candidates.slice(0, maxPages);
      search = {
        query,
        action,
        page,
        pageSummary: browserWorkflowPageSummary(page),
        candidates: candidates.slice(0, 12),
      };
      if (!page.available) throw new Error(page.error || 'Search result page is unavailable.');
      if (!selectedLinks.length) throw new Error('No reviewable search result links were found.');
    } else {
      selectedLinks = selectedLinks.slice(0, maxPages);
    }

    for (const [index, selected] of selectedLinks.entries()) {
      try {
        const openAction = await executeBrowserControl({
          action: 'open_url',
          url: selected.href,
          app: options.app,
        }, {
          approvalContext: {
            type: 'browser_research_workflow',
            workflowId: workflow.id,
            title: workflowTitle,
            instruction: request,
            stepIndex: index + (search ? 1 : 0),
          },
        });
        await waitMs(waitMsAfterOpen);
        const page = await browserPageSnapshot({ app: options.app, maxChars });
        pages.push({
          selected,
          openAction,
          page,
          pageSummary: browserWorkflowPageSummary(page),
          error: page.available ? '' : (page.error || 'Target page is unavailable.'),
        });
      } catch (error) {
        pages.push({
          selected,
          openAction: null,
          page: null,
          pageSummary: browserFailedPageSummary(error),
          error: error instanceof Error ? error.message : String(error),
        });
      }
    }

    const availablePages = pages.filter((item) => item.page?.available);
    if (!availablePages.length) throw new Error('No selected research pages could be read.');
    const continuation = browserResearchContinuationPlan({
      request,
      query,
      mode,
      maxPages,
      selectedLinks,
      search,
      pages,
      executed: true,
    });

    const prompt = browserResearchWorkflowPrompt({
      request,
      query,
      searchPage: search?.page,
      selectedLinks,
      pages,
    });
    const latestPage = availablePages[availablePages.length - 1]?.pageSummary || browserWorkflowPageSummary(availablePages[0].page);

    if (mode !== 'quick') {
      const queuedWorkflow = setWorkflow(workflow.id, {
        status: 'queued',
        target: {
          ...latestPage,
          query,
          selectedLinks,
          resultCount: selectedLinks.length,
          reviewedCount: availablePages.length,
          failedCount: pages.length - availablePages.length,
        },
        continuation,
      });
      const job = createJob(prompt, mode === 'background' ? 'background' : mode, 'browser_research_workflow', { workflowId: workflow.id });
      const finalWorkflow = setWorkflow(workflow.id, { jobId: job.id });
      const routing = createRoutingRecordForWorkflow({
        task: request,
        workflow: finalWorkflow,
        job,
        mode,
        source: options.source || 'browser_research_workflow',
        scope: options.scope || 'browser:research',
        parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      });
      return {
        ok: true,
        executed: true,
        queued: true,
        mode,
        intent: 'research',
        query,
        selectedLinks,
        search: search ? { query: search.query, page: search.pageSummary, candidates: search.candidates } : null,
        pages: pages.map((item) => ({ selected: item.selected, page: item.pageSummary, error: item.error })),
        continuation,
        workflow: finalWorkflow || queuedWorkflow,
        job,
        routing,
        output: `Queued ${mode} browser research over ${availablePages.length}/${selectedLinks.length} page(s).`,
      };
    }

    const output = await callOpenAIResponsesWithFallback({
      model: models.fast,
      instructions:
        'You are the browser research lane inside JAVIS. Use only the provided page snapshots. Synthesize across sources in concise Chinese, include concrete next actions, and note missing evidence.',
      input: prompt,
      maxOutputTokens: 1400,
    }, {
      source: 'browser_research_workflow',
      timeoutMs: 90000,
    });
    const resultSummary = [
      output,
      continuation.nextActions.length ? `Continuation: ${continuation.summary}` : '',
    ].filter(Boolean).join('\n');
    const finalWorkflow = setWorkflow(workflow.id, {
      status: quickLaneOutputOk(output) ? 'done' : 'blocked',
      result: resultSummary,
      completedAt: Date.now(),
      continuation,
      target: {
        ...latestPage,
        query,
        selectedLinks,
        resultCount: selectedLinks.length,
        reviewedCount: availablePages.length,
        failedCount: pages.length - availablePages.length,
      },
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow: finalWorkflow,
      mode,
      source: options.source || 'browser_research_workflow',
      scope: options.scope || 'browser:research',
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary,
    });
    return {
      ok: quickLaneOutputOk(output),
      executed: true,
      queued: false,
      mode,
      intent: 'research',
      query,
      selectedLinks,
      search: search ? { query: search.query, page: search.pageSummary, candidates: search.candidates } : null,
      pages: pages.map((item) => ({ selected: item.selected, page: item.pageSummary, error: item.error })),
      continuation,
      workflow: finalWorkflow,
      routing,
      output,
    };
  } catch (error) {
    const output = `Browser research blocked: ${error instanceof Error ? error.message : String(error)}`;
    const continuation = browserResearchContinuationPlan({
      request,
      query,
      mode,
      maxPages,
      selectedLinks,
      search,
      pages,
      executed: true,
    });
    const resultSummary = [
      output,
      continuation.nextActions.length ? `Recovery: ${continuation.summary}` : '',
    ].filter(Boolean).join('\n');
    const finalWorkflow = setWorkflow(workflow.id, {
      status: 'blocked',
      result: resultSummary,
      completedAt: Date.now(),
      continuation,
      target: {
        ...(workflow.target || {}),
        query,
        selectedLinks,
        resultCount: selectedLinks.length,
        reviewedCount: pages.filter((item) => item.page?.available).length,
        failedCount: pages.filter((item) => !item.page?.available).length,
      },
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow: finalWorkflow,
      mode,
      source: options.source || 'browser_research_workflow',
      scope: options.scope || 'browser:research',
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary,
    });
    return {
      ok: false,
      executed: true,
      queued: false,
      mode,
      intent: 'research',
      query,
      selectedLinks,
      search: search ? { query: search.query, page: search.pageSummary, candidates: search.candidates } : null,
      pages: pages.map((item) => ({ selected: item.selected, page: item.pageSummary, error: item.error })),
      continuation,
      page: browserFailedPageSummary(error),
      workflow: finalWorkflow,
      routing,
      output,
    };
  }
}

async function runBrowserWorkflow(options = {}) {
  const intent = normalizeBrowserWorkflowIntent(options.intent);
  if (intent === 'act') return runBrowserTaskWorkflow(options);
  if (intent === 'fill_draft') return runBrowserFillDraftWorkflow(options);
  if (intent === 'review_result') return runBrowserResultReviewWorkflow(options);
  if (intent === 'research') return runBrowserResearchWorkflow(options);
  if (intent === 'search' || intent === 'compare') return runBrowserSearchWorkflow({ ...options, intent });
  const mode = normalizeBrowserWorkflowMode(options.mode);
  const instruction = String(options.instruction || '').trim();
  const maxChars = normalizeBrowserMaxChars(options.maxChars || (mode === 'quick' ? 12000 : 30000));
  const fixturePage = normalizeBrowserWorkflowFixturePage(options.page, maxChars);
  const page = fixturePage || await browserPageSnapshot({ app: options.app, maxChars });
  const pageSummary = browserWorkflowPageSummary(page);
  const request = instruction || {
    summarize: 'Summarize current page.',
    extract_actions: 'Extract actions from current page.',
    draft: 'Draft from current page.',
    ask: 'Answer a question about current page.',
  }[intent];
  const workflowTitle = `${intent} · ${page.title || page.url || 'current page'}`.slice(0, 180);

  if (!page.available) {
    const workflow = createWorkflowRecord({
      kind: 'browser',
      source: 'browser_workflow',
      status: 'failed',
      title: workflowTitle,
      intent,
      mode,
      request,
      target: pageSummary,
      result: page.error || 'No supported browser page is available.',
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow,
      mode,
      source: options.source || 'browser_workflow',
      scope: options.scope || `browser:${intent}`,
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary: workflow.result,
    });
    return {
      ok: false,
      mode,
      intent,
      workflow,
      routing,
      page: pageSummary,
      output: page.error || 'No supported browser page is available.',
    };
  }

  const preview = options.execute === false || options.preview === true;
  if (preview) {
    const workflow = createWorkflowRecord({
      kind: 'browser',
      source: options.source || 'browser_workflow',
      status: 'done',
      title: workflowTitle,
      intent,
      mode,
      request,
      target: pageSummary,
      result: `Preview only. Would run ${mode} browser ${intent} workflow for ${page.title || page.url || 'current page'}.`,
    });
    appendAudit('browser_workflow.previewed', {
      intent,
      mode,
      app: page.app,
      title: page.title,
      url: page.url,
      textLength: page.textLength,
      truncated: page.truncated,
      fixture: Boolean(fixturePage),
    });
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow,
      mode,
      source: options.source || 'browser_workflow',
      scope: options.scope || `browser:${intent}`,
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
      resultSummary: workflow.result,
    });
    return {
      ok: true,
      mode,
      intent,
      preview: true,
      executed: false,
      queued: false,
      workflow,
      routing,
      page: pageSummary,
      output: workflow.result,
    };
  }

  const prompt = browserWorkflowPrompt(page, intent, instruction);
  appendAudit('browser_workflow.requested', {
    intent,
    mode,
    app: page.app,
    title: page.title,
    url: page.url,
    textLength: page.textLength,
    truncated: page.truncated,
  });

  if (mode !== 'quick') {
    const workflow = createWorkflowRecord({
      kind: 'browser',
      source: 'browser_workflow',
      status: 'queued',
      title: workflowTitle,
      intent,
      mode,
      request,
      target: pageSummary,
    });
    const job = createJob(prompt, mode === 'background' ? 'background' : mode, 'browser_workflow', { workflowId: workflow.id });
    setWorkflow(workflow.id, { jobId: job.id });
    const finalWorkflow = workflows.get(workflow.id);
    const routing = createRoutingRecordForWorkflow({
      task: request,
      workflow: finalWorkflow,
      job,
      mode,
      source: options.source || 'browser_workflow',
      scope: options.scope || `browser:${intent}`,
      parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
    });
    return {
      ok: true,
      mode,
      intent,
      queued: true,
      workflow: finalWorkflow,
      job,
      routing,
      page: pageSummary,
      output: `Queued ${mode} browser workflow for ${page.title || page.url}.`,
    };
  }

  const workflow = createWorkflowRecord({
    kind: 'browser',
    source: 'browser_workflow',
    status: 'running',
    title: workflowTitle,
    intent,
    mode,
    request,
    target: pageSummary,
  });
  const output = await callOpenAIResponsesWithFallback({
    model: models.fast,
    instructions:
      'You are the browser workflow lane inside JAVIS. Use only the provided page text and user request. Answer in concise Chinese with practical next steps.',
    input: prompt,
    maxOutputTokens: intent === 'draft' ? 1100 : 800,
  }, {
    source: 'browser_workflow',
    timeoutMs: intent === 'draft' ? 90000 : 60000,
  });

  const finalWorkflow = setWorkflow(workflow.id, {
    status: OPENAI_API_KEY ? 'done' : 'blocked',
    result: output,
    completedAt: Date.now(),
  });
  const routing = createRoutingRecordForWorkflow({
    task: request,
    workflow: finalWorkflow,
    mode,
    source: options.source || 'browser_workflow',
    scope: options.scope || `browser:${intent}`,
    parallelGroup: options.parallelGroup || options.group || `browser:${mode}`,
    resultSummary: output,
  });
  return {
    ok: Boolean(OPENAI_API_KEY),
    mode,
    intent,
    queued: false,
    workflow: finalWorkflow,
    routing,
    page: pageSummary,
    output,
  };
}

function browserBenchmarkSecretLeaked(value, secrets = []) {
  const text = JSON.stringify(value || {});
  return secrets.some((secret) => secret && text.includes(secret));
}

function browserBenchmarkCaseResult({ id, label, intent, ok, result, assertions = {}, secrets = [] }) {
  const leakedSecrets = browserBenchmarkSecretLeaked(result, secrets);
  const finalOk = Boolean(ok && !leakedSecrets);
  const workflow = result?.workflow || {};
  const routing = result?.routing || {};
  return {
    id,
    label,
    intent,
    ok: finalOk,
    status: finalOk ? 'pass' : 'fail',
    previewOnly: result?.executed === false || result?.preview === true,
    executed: Boolean(result?.executed),
    queued: Boolean(result?.queued),
    modelCall: false,
    browserAction: false,
    workflowId: workflow.id || '',
    workflowStatus: workflow.status || '',
    routingId: routing.id || '',
    routingStatus: routing.status || '',
    assertions: {
      ...assertions,
      leakedSecrets,
    },
    summary: compactRecordText(result?.output || workflow.result || '', 260),
  };
}

