const PET_TRAFFIC_LIGHT_LEGEND = [
  {
    color: 'green',
    label: 'Available',
    meaning: 'Passive and ready.',
    nextAction: 'Speak/click.',
  },
  {
    color: 'yellow',
    label: 'Active',
    meaning: 'Listening, working, fallback.',
    nextAction: 'Wait/click.',
  },
  {
    color: 'red',
    label: 'Attention',
    meaning: 'Needs setup/recovery.',
    nextAction: 'Open CUI.',
  },
];

function petTrafficLightSnapshot(options = {}) {
  const presence = options.presence || {};
  const mode = String(presence.mode || 'standby');
  const intervention = presence.intervention || {};
  const reason = compactRecordText(
    intervention.next || presence.summary || presence.label || 'Standing by until you ask for help.',
    100,
  );
  const base = {
    version: 1,
    sourceMode: mode,
    state: 'idle',
    color: 'green',
    activeLight: 'green',
    urgency: 'quiet',
    pulse: 'off',
    label: presence.label || 'Standby',
    reason,
    meaning: 'Passive and ready.',
    nextAction: reason,
    legend: PET_TRAFFIC_LIGHT_LEGEND,
    accessibleLabel: '',
    startsMicrophone: false,
    passiveByDefault: true,
  };

  if (mode === 'setup_blocked' || mode === 'voice_error') {
    Object.assign(base, {
      state: 'blocked',
      color: 'red',
      activeLight: 'red',
      urgency: 'interrupt',
      pulse: 'attention',
      label: presence.label || 'Setup blocked',
      meaning: 'Needs setup or recovery.',
      nextAction: reason,
    });
  } else if (mode === 'fallback_ready') {
    Object.assign(base, {
      state: 'fallback_ready',
      color: 'yellow',
      activeLight: 'yellow',
      urgency: 'ambient',
      pulse: 'off',
      label: presence.label || 'Local fallback ready',
      reason: 'Realtime voice is recovering; local no-mic input is ready.',
      meaning: 'Realtime is recovering; local input works.',
      nextAction: 'Click for local input, or probe from CUI.',
    });
  } else if (mode === 'needs_attention' || intervention.shouldNotify) {
    Object.assign(base, {
      state: 'attention',
      color: 'red',
      activeLight: 'red',
      urgency: 'interrupt',
      pulse: 'attention',
      label: presence.label || 'Needs attention',
      meaning: 'Waiting on approval, setup, or a blocker.',
      nextAction: reason,
    });
  } else if (mode === 'listening') {
    Object.assign(base, {
      state: 'listening',
      color: 'yellow',
      activeLight: 'yellow',
      urgency: 'active',
      pulse: 'live',
      label: presence.label || 'Listening',
      meaning: 'Live voice is active.',
      nextAction: 'Speak or click to stop.',
    });
  } else if (mode === 'connecting' || mode === 'waking') {
    Object.assign(base, {
      state: mode === 'waking' ? 'waking' : 'connecting',
      color: 'yellow',
      activeLight: 'yellow',
      urgency: 'active',
      pulse: 'slow',
      label: presence.label || (mode === 'waking' ? 'Wake pending' : 'Connecting'),
      meaning: 'Voice is starting.',
      nextAction: reason,
    });
  } else if (mode === 'working') {
    Object.assign(base, {
      state: 'working',
      color: 'yellow',
      activeLight: 'yellow',
      urgency: 'ambient',
      pulse: 'slow',
      label: presence.label || 'Working',
      meaning: 'Background work is active.',
      nextAction: reason,
    });
  } else if (mode === 'watching') {
    Object.assign(base, {
      state: 'watching',
      color: 'green',
      activeLight: 'green',
      urgency: 'quiet',
      pulse: 'off',
      label: presence.label || 'Watching',
      meaning: 'Passively watching; no intervention.',
      nextAction: 'Speak, press Alt+Space, or click.',
    });
  }

  base.meaning = compactRecordText(base.meaning || '', 120);
  base.nextAction = compactRecordText(base.nextAction || base.reason || '', 120);
  base.accessibleLabel = compactRecordText(`JAVIS ${base.label}: ${base.meaning} Next: ${base.nextAction}`, 180);
  return base;
}

function petReadinessSummary(readiness = petReadinessSnapshot()) {
  return {
    overall: readiness.overall,
    label: readiness.label,
    summary: compactRecordText(readiness.summary || '', 160),
    counts: readiness.counts,
    primaryIssue: readiness.primaryIssue
      ? {
          id: readiness.primaryIssue.id,
          label: readiness.primaryIssue.label,
          status: readiness.primaryIssue.status,
          summary: compactRecordText(readiness.primaryIssue.summary || '', 120),
          next: compactRecordText(readiness.primaryIssue.next || '', 120),
        }
      : null,
  };
}

function finalizePetPayloadContract(snapshot) {
  const contract = snapshot?.payloadContract;
  if (!contract || typeof contract !== 'object') return snapshot;
  for (let index = 0; index < 5; index += 1) {
    const bytes = Buffer.byteLength(JSON.stringify(snapshot), 'utf8');
    const headroom = Math.max(0, Number(contract.maxTargetBytes || 0) - bytes);
    if (contract.outputBytes === bytes && contract.headroomBytes === headroom) break;
    contract.outputBytes = bytes;
    contract.headroomBytes = headroom;
  }
  return snapshot;
}

function petStatusSnapshot() {
  const conversation = conversationStateSnapshot();
  const wake = wakeStatusSnapshot();
  const pendingApprovals = pendingApprovalSnapshot(5);
  const activeJobs = jobSnapshot(12).filter((job) => job.status === 'queued' || job.status === 'running');
  const readiness = petReadinessSnapshot();
  const rawPresence = petPresenceSnapshot({ conversation, wake, pendingApprovals, activeJobs, readiness });
  const presence = petPresenceStatusSnapshot(rawPresence);
  const trafficLight = petTrafficLightSnapshot({ presence });
  const screenFrame = latestScreenSnapshot();
  const rawVoiceHealth = realtimeVoiceHealthSnapshot({ conversation, includeRecentAudit: true });
  const maxTargetBytes = 12000;
  const minHeadroomBytes = 500;
  const allowedTopLevel = [
    'pet',
    'api',
    'runtime',
    'actionPolicy',
    'screenPrivacy',
    'presence',
    'conversation',
    'voiceHealth',
    'localVoice',
    'progressVersion',
    'wake',
    'speech',
    'window',
    'menuBar',
    'notifications',
    'approvals',
    'readiness',
    'activeJobs',
    'workflowCounts',
    'inbox',
    'sessions',
    'screen',
    'queue',
    'payloadContract',
  ];
  const forbiddenTopLevel = [
    'models',
    'routing',
    'collaboration',
    'memory',
    'memories',
    'learning',
    'learnedProfile',
    'shortcuts',
    'demonstrations',
    'workflows',
    'ambient',
    'laneContracts',
    'doctor',
    'config',
    'macContext',
    'audit',
  ];
  const snapshot = {
    pet: {
      version: 1,
      lightweight: true,
      surface: 'desktop_pet',
      detailEndpoint: '/api/status',
      excludes: [
        'screen.imageDataUrl',
        'runtime.dataDir',
        'model identifiers',
        'memory/learning profiles',
        'routing/workflow logs',
        'notification bodies',
      ],
      mode: presence.mode,
      label: presence.label,
      summary: compactRecordText(presence.summary || '', 90),
      next: compactRecordText(presence.intervention?.next || '', 80),
      color: trafficLight.color,
      trafficLight,
    },
    api: {
      baseUrl: API_BASE,
      hasOpenAiKey: Boolean(OPENAI_API_KEY),
      localExecutionEnabled: LOCAL_EXEC_ENABLED,
      trustedLocalMode: TRUSTED_LOCAL_MODE,
    },
    runtime: {
      version: packageInfo.version,
      uptimeSeconds: Math.round((Date.now() - startedAt) / 1000),
    },
    actionPolicy: {
      dryRun: actionPolicy.dryRun,
      maxAutoRiskLevel: actionPolicy.maxAutoRiskLevel,
      requireApprovalAtRiskLevel: actionPolicy.requireApprovalAtRiskLevel,
    },
    screenPrivacy: petScreenPrivacySnapshot(),
    presence,
    conversation: petConversationSnapshot(conversation),
    voiceHealth: (() => {
      const health = rawVoiceHealth;
      const fallback = health.fallback || {};
      return {
        ok: Boolean(health.ok),
        status: health.status || '',
        kind: health.kind || '',
        summary: compactRecordText(health.summary || health.message || '', 90),
        next: compactRecordText(health.next || '', 90),
        hasOpenAiKey: Boolean(health.hasOpenAiKey),
        lastStatusCode: boundedCount(health.lastNegotiation?.statusCode, 999),
        lastError: compactRecordText(health.error || health.lastError || '', 100),
        fallback: {
          available: Boolean(fallback.available),
          activeWhenRealtimeBlocked: Boolean(fallback.activeWhenRealtimeBlocked),
          lane: compactRecordText(fallback.lane || '', 60),
          endpoint: compactRecordText(fallback.endpoint || '', 80),
          dogfoodCommand: compactRecordText(fallback.dogfoodCommand || '', 80),
          summary: compactRecordText(fallback.summary || '', 90),
          next: compactRecordText(fallback.next || '', 90),
          blocker: fallback.blocker
            ? {
                active: Boolean(fallback.blocker.active),
                kind: compactRecordText(fallback.blocker.kind || '', 60),
                status: compactRecordText(fallback.blocker.status || '', 60),
                summary: compactRecordText(fallback.blocker.summary || '', 80),
                next: compactRecordText(fallback.blocker.next || '', 80),
              }
            : null,
          safety: {
            startsMicrophone: Boolean(fallback.safety?.startsMicrophone),
            usesRealtime: Boolean(fallback.safety?.usesRealtime),
            storesRawAudio: Boolean(fallback.safety?.storesRawAudio),
            speaksWithMacTts: Boolean(fallback.safety?.speaksWithMacTts),
            screenContextMetadataOnly: Boolean(fallback.safety?.screenContextMetadataOnly),
            accessibilityOutlineOnly: Boolean(fallback.safety?.accessibilityOutlineOnly),
          },
        },
      };
    })(),
    localVoice: localVoiceStatusSnapshot({ conversation, voiceHealth: rawVoiceHealth, historyLimit: 1, slim: true }),
    progressVersion: workProgressSnapshot(),
    wake: petWakeSnapshot(wake),
    speech: speechStateSnapshot(),
    window: petWindowStateSnapshot({ voiceHealth: rawVoiceHealth }),
    menuBar: menuBarSnapshot(),
    notifications: petNotificationSnapshot(),
    approvals: pendingApprovals.slice(0, 3).map((approval) => ({
      id: approval.id,
      action: approval.action,
      riskLevel: approval.riskLevel,
      summary: compactRecordText(approval.summary || '', 160),
      status: approval.status,
      createdAt: approval.createdAt,
      updatedAt: approval.updatedAt,
    })),
    readiness: petReadinessSummary(readiness),
    activeJobs: Array.from(activeJobRuns.keys()),
    workflowCounts: workflowCounts(),
    inbox: {
      counts: inboxCounts(),
      open: [],
    },
    sessions: {
      counts: sessionCounts(),
      active: null,
      recent: [],
    },
    screen: petScreenSnapshot(screenFrame),
    queue: activeJobs.slice(0, 6).map((job) => ({
      id: job.id,
      title: compactRecordText(job.title || '', 120),
      mode: job.mode,
      status: job.status,
      pid: job.pid || null,
      updatedAt: job.updatedAt,
    })),
    payloadContract: {
      version: 1,
      maxTargetBytes,
      minHeadroomBytes,
      headroomBytes: 0,
      allowedTopLevel,
      forbiddenTopLevel,
      screenImagesAllowed: false,
      rawLogsAllowed: false,
      rawRuntimePathsAllowed: false,
      diagnosticsEndpoint: '/api/status',
      outputBytes: 0,
    },
  };
  return finalizePetPayloadContract(snapshot);
}

function formatRealtimeContextAction(action, index) {
  return `${index + 1}. ${action.label}: ${compactRecordText(action.summary, 180)}`;
}

async function realtimePreflightContextSnapshot(options = {}) {
  const source = String(options.source || 'api').slice(0, 80);
  const presence = presenceStateSnapshot({ limit: 3 });
  const briefing = workflowBriefing({ workflowLimit: 3, jobLimit: 3 });
  const laneContracts = laneContractSnapshot();
  const mac = await macContextSnapshot({ includeClipboardText: false }).catch((error) => ({
    frontmost: { available: false, app: '', windowTitle: '', error: error instanceof Error ? error.message : String(error) },
    browser: { available: false, supported: false, app: '', title: '', url: '', source: '', error: '' },
    permissions: { accessibilityTrusted: null },
    clipboard: { hasText: false, length: 0, preview: '', truncated: false },
    activeJobs: [],
    pendingApprovals: [],
  }));
  const screenFrame = latestScreenSnapshot();
  const screenPrivacyPolicy = screenPrivacyContextPolicy(mac);
  const latest = presence.observing?.latest || {};
  const nextActions = (briefing.nextActions || []).slice(0, 3);
  const activeJobs = presence.work?.activeJobs || [];
  const activeRoutes = presence.work?.activeRoutes || [];
  const pendingApprovals = presence.work?.pendingApprovals || [];
  const learningSummary = presence.learning?.sourceEventCount ? presence.learning.summary : '';
  const browserActivity = presence.observing?.browserActivity || browserActivitySnapshot({ limit: 5 });
  const currentApp = mac.frontmost?.available
    ? [mac.frontmost.app, mac.frontmost.windowTitle].filter(Boolean).join(' · ')
    : [latest.app, latest.windowTitle].filter(Boolean).join(' · ');
  const currentBrowser = mac.browser?.available
    ? [mac.browser.app, mac.browser.title || mac.browser.url].filter(Boolean).join(' · ')
    : [latest.browser?.app, latest.browser?.title || latest.browser?.host].filter(Boolean).join(' · ');
  const lines = REALTIME_PREFLIGHT_CONTEXT_ENABLED
    ? [
        'Silent JAVIS preflight context for this voice session. Do not answer this message by itself.',
        `Presence: ${presence.label} (${presence.mode}). ${compactRecordText(presence.summary, 420)}`,
        `Conversation: ${presence.conversation.status}; mic ${presence.conversation.micMode}; screen context ${presence.conversation.screenLive ? 'on' : 'off'}.`,
        currentApp ? `Current app/window: ${compactRecordText(currentApp, 220)}` : '',
        currentBrowser ? `Current browser: ${compactRecordText(currentBrowser, 260)}` : '',
        browserActivity.current ? `Recent browser activity: ${compactRecordText(browserActivity.summary, 360)}` : '',
        screenFrame && screenPrivacyPolicy.allowed
          ? `Latest resident screen frame: ${screenFrame.width}x${screenFrame.height}, privacy ${screenFrame.privacy?.mode || 'unknown'}, age ${Math.round(latestScreenAgeMs() / 1000)}s. ${screenFrame.privacy?.rulesSummary || ''}`
          : screenFrame && screenPrivacyPolicy.blocked
            ? `Resident screen frame exists but is excluded from model context by screen privacy rule(s): ${screenPrivacyPolicy.matchingRules.map((rule) => rule.label || rule.id).join(', ')}.`
            : `No resident screen frame is cached yet. ${screenPrivacySnapshot().rulesSummary || ''}`,
        learningSummary ? `Local inferred profile: ${compactRecordText(learningSummary, 360)}` : '',
        activeJobs.length ? `Background work: ${activeJobs.map((job) => `${job.mode}/${job.status} ${compactRecordText(job.title, 80)}`).join('; ')}` : 'Background work: none active.',
        activeRoutes.length ? `Routed work: ${activeRoutes.map((route) => `${route.lane}/${route.status} ${route.owner} ${compactRecordText(route.taskTitle, 80)} next=${compactRecordText(route.nextAction || 'check progress', 80)}`).join('; ')}` : 'Routed work: none active.',
        `Lane contracts: quick/realtime keeps speech fluid; background handles durable work; Codex/Claude own scoped code; browser/file/app/local own their guarded tool surfaces. Use get_lane_contracts if routing boundaries are unclear.`,
        pendingApprovals.length ? `Approvals waiting: ${pendingApprovals.map((approval) => compactRecordText(approval.summary, 120)).join('; ')}` : 'Approvals waiting: none.',
        presence.work?.autopilot?.enabled ? `Autopilot: ${presence.work.autopilot.running ? 'running' : 'idle'}, executed ${presence.work.autopilot.executedCount || 0}, last ${compactRecordText(presence.work.autopilot.lastResult || 'none', 180)}.` : 'Autopilot: disabled.',
        nextActions.length ? `Likely next actions:\n${nextActions.map(formatRealtimeContextAction).join('\n')}` : '',
        `Guardrails: passive by default; act only after user intent. Local execution ${LOCAL_EXEC_ENABLED ? 'enabled' : 'disabled'}; auto risk level ${actionPolicy.maxAutoRiskLevel}; approval required at level ${actionPolicy.requireApprovalAtRiskLevel}.`,
      ].filter(Boolean)
    : [];
  const prompt = lines.join('\n');
  appendAudit('realtime.preflight_context', {
    source,
    enabled: REALTIME_PREFLIGHT_CONTEXT_ENABLED,
    presenceMode: presence.mode,
    promptLength: prompt.length,
    hasScreen: Boolean(screenFrame && screenPrivacyPolicy.allowed),
    screenPrivacyBlocked: Boolean(screenFrame && screenPrivacyPolicy.blocked),
    nextActions: nextActions.length,
  });
  return {
    enabled: REALTIME_PREFLIGHT_CONTEXT_ENABLED,
    generatedAt: new Date().toISOString(),
    prompt,
    presence: {
      mode: presence.mode,
      label: presence.label,
      summary: presence.summary,
      conversation: presence.conversation,
      intervention: presence.intervention,
    },
    mac,
    screen: screenFrame,
    screenPrivacyPolicy,
    browserActivity,
    briefing: {
      summary: briefing.summary,
      nextActions,
      routingLedger: briefing.routingLedger || [],
      laneContracts,
      counts: briefing.counts,
    },
  };
}

function startAmbientMonitor() {
  if (!AMBIENT_OBSERVE_ENABLED || ambientTimer) return;
  void sampleAmbientContext('ambient_startup');
  ambientTimer = setInterval(() => {
    void sampleAmbientContext('ambient_interval');
  }, AMBIENT_INTERVAL_MS);
  appendAudit('ambient.started', {
    intervalMs: AMBIENT_INTERVAL_MS,
    captureScreen: AMBIENT_CAPTURE_SCREEN,
  });
}

function stopAmbientMonitor() {
  if (!ambientTimer) return;
  clearInterval(ambientTimer);
  ambientTimer = null;
  appendAudit('ambient.stopped');
}

function startLearningMonitor() {
  if (!learningRuntimeEnabled() || learningTimer) return;
  distillAmbientLearning({ source: 'learning_startup' });
  learningTimer = setInterval(() => {
    distillAmbientLearning({ source: 'learning_interval' });
  }, AMBIENT_LEARNING_INTERVAL_MS);
  appendAudit('learning.started', {
    intervalMs: AMBIENT_LEARNING_INTERVAL_MS,
    sourceEventLimit: MAX_LEARNING_SOURCE_EVENTS,
  });
}

function stopLearningMonitor() {
  if (!learningTimer) return;
  clearInterval(learningTimer);
  learningTimer = null;
  appendAudit('learning.stopped');
}

function autopilotStateSnapshot() {
  return {
    ...autopilotState,
    enabled: AUTOPILOT_ENABLED,
    intervalMs: AUTOPILOT_INTERVAL_MS,
    busy: autopilotBusy,
    maintenance: maintenanceStateSnapshot(),
  };
}

function summarizeDogfoodActionPlanForAutopilot(plan = null) {
  if (!plan || typeof plan !== 'object') return null;
  const previewable = Array.isArray(plan.previewable) ? plan.previewable : [];
  const manual = Array.isArray(plan.manual) ? plan.manual : [];
  const primary = plan.primary || null;
  const preferredPreviewable =
    previewable.find((action) => action?.id === 'prepare_preflight_bundle') ||
    previewable.find((action) => action?.id === 'prepare_live_run') ||
    previewable[0] ||
    null;
  const preferredManual =
    manual.find((action) => action?.requiresLiveVoice || action?.requiresMicConfirmation || action?.startsMicrophone) ||
    manual.find((action) => action?.requiresUserPresence) ||
    manual[0] ||
    null;
  return {
    version: Number(plan.version || 0),
    scope: compactRecordText(plan.scope || '', 80),
    status: compactRecordText(plan.status || '', 80),
    accepted: Boolean(plan.accepted),
    primary: primary
      ? {
        id: compactRecordText(primary.id || '', 120),
        label: compactRecordText(primary.label || primary.id || '', 140),
        startsMicrophone: Boolean(primary.startsMicrophone),
        requiresMicConfirmation: Boolean(primary.requiresMicConfirmation),
        requiresLiveVoice: Boolean(primary.requiresLiveVoice),
        requiresUserPresence: Boolean(primary.requiresUserPresence),
      }
      : null,
    previewableCount: previewable.length,
    manualCount: manual.length,
    firstPreviewable: preferredPreviewable
      ? {
        id: compactRecordText(preferredPreviewable.id || '', 120),
        label: compactRecordText(preferredPreviewable.label || preferredPreviewable.id || '', 140),
        command: compactRecordText(preferredPreviewable.command || '', 180),
        endpoint: compactRecordText(preferredPreviewable.endpoint || '', 140),
        startsMicrophone: Boolean(preferredPreviewable.startsMicrophone),
      }
      : null,
    firstManual: preferredManual
      ? {
        id: compactRecordText(preferredManual.id || '', 120),
        label: compactRecordText(preferredManual.label || preferredManual.id || '', 140),
        startsMicrophone: Boolean(preferredManual.startsMicrophone),
        requiresMicConfirmation: Boolean(preferredManual.requiresMicConfirmation),
        requiresLiveVoice: Boolean(preferredManual.requiresLiveVoice),
      }
      : null,
    spokenSummary: compactRecordText(plan.spokenSummary || '', 260),
  };
}

function realtimePreflightFreshnessSourceAllowed(source = '') {
  const text = String(source || '').toLowerCase();
  return /preflight|work_next_realtime|realtime_prepare|dogfood_prepare|eval_autonomy_no_mic/.test(text);
}

function realtimePreflightFreshnessCandidateFromTime(input = {}) {
  const createdAt = Number(input.createdAt || 0);
  if (!createdAt) return null;
  return {
    createdAt,
    at: new Date(createdAt).toISOString(),
    source: compactRecordText(input.source || '', 80),
    eventType: compactRecordText(input.eventType || input.type || '', 100),
    id: compactRecordText(input.id || '', 120),
    file: compactRecordText(input.file || '', 300),
    phase: compactRecordText(input.phase || '', 80),
    status: compactRecordText(input.status || '', 80),
  };
}

function realtimeNoMicPreflightFreshness(options = {}) {
  const cooldownMs = Math.max(0, Number(options.cooldownMs || REALTIME_PREFLIGHT_FRESH_MS));
  if (!cooldownMs) {
    return {
      fresh: false,
      cooldownMs: 0,
      ageMs: null,
      waitMs: 0,
      ageLabel: '',
      waitLabel: '',
      latest: null,
    };
  }
  const candidates = [];
  const addCandidate = (candidate) => {
    if (!candidate) return;
    candidates.push(candidate);
  };

  try {
    const archives = realtimeDogfoodArchiveList({ limit: 20 }).items || [];
    for (const item of archives) {
      if (item.startsMicrophone === true) continue;
      if (!realtimePreflightFreshnessSourceAllowed(item.source)) continue;
      const createdAt = Date.parse(item.savedAt || item.generatedAt || '');
      addCandidate(realtimePreflightFreshnessCandidateFromTime({
        createdAt,
        source: item.source,
        eventType: 'archive',
        id: item.id,
        file: item.file,
        phase: item.phase,
        status: item.status,
      }));
    }
  } catch {}

  try {
    const events = readRecentAudit(200);
    for (let index = events.length - 1; index >= 0; index -= 1) {
      const event = events[index] || {};
      const data = event.data || {};
      const createdAt = Date.parse(event.ts || '') || Number(data.createdAt || 0);
      if (event.type === 'realtime.dogfood_preflight_bundle') {
        if (data.startsMicrophone === true) continue;
        addCandidate(realtimePreflightFreshnessCandidateFromTime({
          createdAt,
          source: data.source || 'audit',
          eventType: event.type,
          id: data.id,
          file: data.archiveFile,
          phase: data.nextGap ? 'preflight_bundle' : '',
          status: data.ok === false ? 'gap' : 'ready',
        }));
      } else if (event.type === 'realtime.dogfood_archive_saved') {
        if (data.startsMicrophone === true) continue;
        if (!realtimePreflightFreshnessSourceAllowed(data.source)) continue;
        addCandidate(realtimePreflightFreshnessCandidateFromTime({
          createdAt,
          source: data.source,
          eventType: event.type,
          id: data.id,
          file: data.file,
          phase: data.phase,
          status: data.status,
        }));
      }
    }
  } catch {}

  const latest = candidates
    .filter((candidate) => Number.isFinite(candidate.createdAt) && candidate.createdAt > 0)
    .sort((a, b) => b.createdAt - a.createdAt)[0] || null;
  if (!latest) {
    return {
      fresh: false,
      cooldownMs,
      ageMs: null,
      waitMs: 0,
      ageLabel: '',
      waitLabel: '',
      latest: null,
    };
  }
  const ageMs = Math.max(0, Date.now() - latest.createdAt);
  const waitMs = Math.max(0, cooldownMs - ageMs);
  return {
    fresh: waitMs > 0,
    cooldownMs,
    ageMs,
    waitMs,
    ageLabel: autopilotWaitDurationLabel(ageMs),
    waitLabel: autopilotWaitDurationLabel(waitMs),
    latest,
  };
}

function realtimeProviderProbeFreshness(options = {}) {
  const cooldownMs = Math.max(0, Number(options.cooldownMs || REALTIME_PROVIDER_PROBE_FRESH_MS));
  const active = Boolean(realtimeProviderProbeState.active);
  const activeStartedAt = Number(realtimeProviderProbeState.createdAt || realtimeProviderProbeState.updatedAt || 0);
  const result = latestRealtimeProviderProbeResultSnapshot({ includeRecentAudit: true });
  const createdAt = active
    ? activeStartedAt
    : Number(result?.createdAt || 0);
  const latest = createdAt
    ? {
      createdAt,
      at: new Date(createdAt).toISOString(),
      source: compactRecordText(active ? realtimeProviderProbeState.source || 'active_probe' : result?.source || '', 80),
      eventType: active ? 'realtime.provider_probe_running' : 'realtime.provider_probe',
      id: compactRecordText(active ? realtimeProviderProbeState.runId || '' : result?.runId || '', 120),
      phase: 'provider_probe',
      status: compactRecordText(active ? realtimeProviderProbeState.status || 'running' : result?.ok ? 'ready' : 'warning', 80),
    }
    : null;
  if (!cooldownMs || !latest) {
    return {
      fresh: active,
      running: active,
      cooldownMs,
      ageMs: null,
      waitMs: active ? cooldownMs : 0,
      ageLabel: '',
      waitLabel: active ? 'running' : '',
      latest,
    };
  }
  const ageMs = Math.max(0, Date.now() - latest.createdAt);
  const waitMs = active ? cooldownMs : Math.max(0, cooldownMs - ageMs);
  return {
    fresh: active || waitMs > 0,
    running: active,
    cooldownMs,
    ageMs,
    waitMs,
    ageLabel: autopilotWaitDurationLabel(ageMs),
    waitLabel: active ? 'running' : autopilotWaitDurationLabel(waitMs),
    latest,
  };
}

function compactRealtimePreflightFreshness(freshness = null) {
  if (!freshness || typeof freshness !== 'object') return null;
  return {
    fresh: Boolean(freshness.fresh),
    running: Boolean(freshness.running),
    cooldownMs: Math.max(0, Number(freshness.cooldownMs || 0)),
    ageMs: freshness.ageMs === null || freshness.ageMs === undefined ? null : Math.max(0, Number(freshness.ageMs || 0)),
    waitMs: Math.max(0, Number(freshness.waitMs || 0)),
    ageLabel: compactRecordText(freshness.ageLabel || '', 40),
    waitLabel: compactRecordText(freshness.waitLabel || '', 40),
    latest: freshness.latest
      ? {
        at: compactRecordText(freshness.latest.at || '', 80),
        source: compactRecordText(freshness.latest.source || '', 80),
        eventType: compactRecordText(freshness.latest.eventType || '', 100),
        id: compactRecordText(freshness.latest.id || '', 120),
        file: compactRecordText(freshness.latest.file || '', 220),
        phase: compactRecordText(freshness.latest.phase || '', 80),
        status: compactRecordText(freshness.latest.status || '', 80),
      }
      : null,
  };
}

function compactRealtimePreflightFreshnessForVoice(freshness = null) {
  if (!freshness || typeof freshness !== 'object') return null;
  return {
    fresh: Boolean(freshness.fresh),
    ageLabel: compactRecordText(freshness.ageLabel || '', 40),
    waitMs: boundedCount(freshness.waitMs, 24 * 60 * 60 * 1000),
    waitLabel: compactRecordText(freshness.waitLabel || '', 40),
  };
}

function browserRecoveryAutopilotFreshness(action = {}) {
  const cooldownMs = Math.max(0, Number(
    action.autopilotCooldownMs ||
    action.browserRecovery?.autopilotCooldownMs ||
    BROWSER_RECOVERY_AUTOPILOT_COOLDOWN_MS,
  ));
  const recovery = action.browserRecovery || {};
  const expectedActionId = String(action.id || 'browser_recovery:open_supported_browser');
  const expectedRouteId = String(recovery.firstRouteId || '').trim();
  const expectedApp = String(recovery.app || action.macAction?.value || '').trim();
  const candidates = [];
  const addCandidate = (candidate) => {
    if (!candidate?.createdAt) return;
    const actionId = String(candidate.actionId || '').trim();
    const routeId = String(candidate.routeId || '').trim();
    const app = String(candidate.app || '').trim();
    const sameAction = !expectedActionId || !actionId || actionId === expectedActionId;
    const sameRoute = !expectedRouteId || !routeId || routeId === expectedRouteId;
    const sameApp = !expectedApp || !app || app === expectedApp;
    if (sameAction && sameRoute && sameApp) candidates.push(candidate);
  };

  addCandidate({
    createdAt: Number(browserRecoveryAutopilotState.lastAttemptAt || 0),
    at: browserRecoveryAutopilotState.lastAttemptAt ? new Date(browserRecoveryAutopilotState.lastAttemptAt).toISOString() : '',
    source: 'memory',
    eventType: 'browser_recovery.autopilot_attempted',
    id: compactRecordText(browserRecoveryAutopilotState.lastActionId || expectedActionId, 120),
    app: compactRecordText(browserRecoveryAutopilotState.lastApp || expectedApp, 120),
    routeId: compactRecordText(browserRecoveryAutopilotState.lastRouteId || expectedRouteId, 120),
    phase: 'browser_recovery',
    status: compactRecordText(browserRecoveryAutopilotState.lastReadinessStatus || '', 80),
    runCount: Number(browserRecoveryAutopilotState.runCount || 0),
  });

  try {
    const events = readRecentAudit(300);
    for (let index = events.length - 1; index >= 0; index -= 1) {
      const event = events[index] || {};
      if (event.type !== 'browser_recovery.autopilot_attempted') continue;
      const data = event.data || {};
      const createdAt = Date.parse(event.ts || '') || Number(data.createdAt || 0);
      addCandidate({
        createdAt,
        at: createdAt ? new Date(createdAt).toISOString() : '',
        source: compactRecordText(data.source || 'audit', 80),
        eventType: event.type,
        id: compactRecordText(data.actionId || expectedActionId, 120),
        app: compactRecordText(data.app || expectedApp, 120),
        routeId: compactRecordText(data.routeId || expectedRouteId, 120),
        phase: 'browser_recovery',
        status: compactRecordText(data.readinessStatus || data.status || '', 80),
        runCount: Number(data.runCount || 0),
      });
    }
  } catch {}

  const latest = candidates
    .filter((candidate) => Number.isFinite(candidate.createdAt) && candidate.createdAt > 0)
    .sort((a, b) => b.createdAt - a.createdAt)[0] || null;
  if (!cooldownMs || !latest) {
    return {
      fresh: false,
      cooldownMs,
      ageMs: null,
      waitMs: 0,
      ageLabel: '',
      waitLabel: '',
      latest,
    };
  }
  const ageMs = Math.max(0, Date.now() - latest.createdAt);
  const waitMs = Math.max(0, cooldownMs - ageMs);
  return {
    fresh: waitMs > 0,
    cooldownMs,
    ageMs,
    waitMs,
    ageLabel: autopilotWaitDurationLabel(ageMs),
    waitLabel: autopilotWaitDurationLabel(waitMs),
    latest,
  };
}

function autopilotEligibilityDecision(action) {
  if (!action || typeof action !== 'object') {
    return {
      executable: false,
      reason: 'missing_action',
      detail: 'No action was available for autopilot.',
    };
  }
  if (action.manualOnly) {
    return {
      executable: false,
      reason: 'manual_only',
      detail: action.manualOnlyReason || 'This action requires explicit user presence.',
    };
  }
  if (action.autopilotEligible === false) {
    return {
      executable: false,
      reason: 'autopilot_disabled_for_action',
      detail: action.autopilotDisabledReason || 'This action is intentionally excluded from unattended autopilot.',
    };
  }
  if (action.source === 'maintenance') {
    const executable = Boolean(action.executable && action.autoEligible && Number(action.riskLevel || 0) <= 1);
    return {
      executable,
      reason: executable ? 'eligible_maintenance' : 'maintenance_not_low_risk',
      detail: executable
        ? 'Read-only maintenance snapshot is safe for unattended autopilot.'
        : 'Maintenance action is not marked as low-risk executable.',
    };
  }
  if (action.source === 'recovery') {
    if (action.trustedAutoEligible && Number(action.recoveryAttempts || 0) < Number(action.maxRecoveryAttempts || MAX_RECOVERY_JOB_ATTEMPTS)) {
      return {
        executable: true,
        reason: 'eligible_trusted_recovery',
        detail: 'Trusted local mode can queue this bounded recovery worker.',
      };
    }
    const executable = Boolean(action.autoEligible && Number(action.riskLevel || 0) <= 1);
    return {
      executable,
      reason: executable ? 'eligible_low_risk_recovery_review' : 'recovery_needs_user_or_trust',
      detail: executable
        ? 'Low-risk recovery review can run unattended.'
        : 'Recovery is not low-risk auto-eligible, or trusted local mode cannot queue it.',
    };
  }
  if (action.source === 'routing' && action.routeRecovery?.recommended?.type === 'job_recovery') {
    const candidate = action.routeRecovery.recommended;
    if (
      candidate.trustedAutoEligible &&
      Number(candidate.recoveryAttempts || 0) < Number(candidate.maxRecoveryAttempts || MAX_RECOVERY_JOB_ATTEMPTS)
    ) {
      return {
        executable: true,
        reason: 'eligible_trusted_routed_recovery',
        detail: 'Trusted local mode can queue this bounded routed worker recovery.',
      };
    }
    const executable = Boolean(candidate.autoEligible && Number(candidate.riskLevel || 0) <= 1);
    return {
      executable,
      reason: executable ? 'eligible_low_risk_routed_recovery_review' : 'routed_recovery_needs_user_or_trust',
      detail: executable
        ? 'Low-risk routed recovery review can run unattended.'
        : 'Routed recovery is not low-risk auto-eligible, or trusted local mode cannot queue it.',
    };
  }
  if (action.source === 'workflows' && action.workflowAction === 'retry_app_workflow') {
    const executable = Boolean(action.executable && LOCAL_EXEC_ENABLED && TRUSTED_LOCAL_MODE);
    return {
      executable,
      reason: executable ? 'eligible_trusted_workflow_retry' : 'workflow_retry_needs_trusted_local',
      detail: executable
        ? 'Trusted local mode can retry this blocked app workflow.'
        : 'Workflow retry needs local execution and trusted local mode.',
    };
  }
  if (action.source === 'browser_recovery') {
    const freshness = browserRecoveryAutopilotFreshness(action);
    const compactFreshness = compactRealtimePreflightFreshness(freshness);
    const macAction = action.macAction || { action: 'open_app', value: action.browserRecovery?.app || 'Google Chrome' };
    const safeShape = Boolean(
      action.executable &&
      action.autoEligible &&
      action.autopilotEligible !== false &&
      action.browserRecovery?.type === 'browser_window_unavailable' &&
      macAction.action === 'open_app' &&
      macAction.value &&
      action.requiresUserPresence === false &&
      action.startsMicrophone === false &&
      action.requiresMicConfirmation === false &&
      action.startsRecording === false &&
      action.startsWorkers === false &&
      action.opensSafeBlankTab === true &&
      action.executesBrowserActions === false &&
      action.readsPageText === false &&
      action.executesTask === false &&
      action.sendsMessages !== true &&
      action.mutatesUserFiles !== true &&
      action.mutatesUserRecords !== true
    );
    let policyEvaluation = null;
    let policyError = '';
    if (safeShape) {
      try {
        const plan = buildLocalActionPlan(macAction);
        policyEvaluation = evaluateMacActionPlan(plan, {
          preview: true,
          approvalContext: {
            source: 'autopilot_browser_recovery_preview',
            reason: action.summary,
          },
        });
      } catch (error) {
        policyError = error instanceof Error ? error.message : String(error);
      }
    }
    if (freshness?.fresh) {
      const agePhrase = freshness.ageLabel ? `${freshness.ageLabel} ago` : 'recently';
      return {
        executable: false,
        reason: 'browser_recovery_fresh',
        detail: `Browser recovery was attempted ${agePhrase}; wait ${freshness.waitLabel || 'for the cooldown'} before opening the browser again.`,
        freshness: compactFreshness,
      };
    }
    const blockedByPolicy = Boolean(policyEvaluation?.blocked || policyEvaluation?.needsApproval || policyError);
    const executable = Boolean(safeShape && !blockedByPolicy);
    return {
      executable,
      reason: executable
        ? 'eligible_browser_recovery'
        : blockedByPolicy
          ? 'browser_recovery_blocked_by_policy'
          : 'browser_recovery_not_safe_for_autopilot',
      detail: executable
        ? 'Autopilot may open or focus the supported browser once, ensure a safe blank tab is readable if needed, then recheck readiness; it will not click, fill, submit, read page text, or start microphone capture.'
        : blockedByPolicy
          ? (policyError || policyEvaluation?.reason || 'Current local action policy blocks this browser recovery.')
          : 'Browser recovery must be a bounded open-app plus safe blank-tab action with no microphone, recording, workers, task execution, page reading, messages, or file mutations.',
      freshness: compactFreshness,
      policy: policyEvaluation
        ? {
          dryRun: Boolean(policyEvaluation.dryRun),
          needsApproval: Boolean(policyEvaluation.needsApproval),
          blocked: Boolean(policyEvaluation.blocked),
          reason: compactRecordText(policyEvaluation.reason || '', 120),
        }
        : null,
    };
  }
  if (action.source === 'readiness' && action.providerProbe === true) {
    const freshness = realtimeProviderProbeFreshness();
    const compactFreshness = compactRealtimePreflightFreshness(freshness);
    if (freshness?.running) {
      return {
        executable: false,
        reason: 'realtime_provider_probe_running',
        detail: 'A no-mic Realtime provider probe is already running; wait for its result before retrying.',
        freshness: compactFreshness,
      };
    }
    if (freshness?.fresh) {
      const agePhrase = freshness.ageLabel ? `${freshness.ageLabel} ago` : 'recently';
      return {
        executable: false,
        reason: 'realtime_provider_probe_fresh',
        detail: `No-mic Realtime provider probe ran ${agePhrase}; wait ${freshness.waitLabel || 'for the cooldown'} before repeating it.`,
        freshness: compactFreshness,
      };
    }
    return {
      executable: false,
      reason: 'openai_spend_confirmation_required',
      detail: 'Realtime provider probing can consume OpenAI quota, so it remains manual-only, hard-spend-locked by default, and requires one-request phrase confirmation after the lock is disabled.',
      freshness: compactFreshness,
    };
  }
  if (action.source === 'realtime_voice' && action.realtimePreparation === 'preflight_bundle') {
    const executable = Boolean(
      action.executable &&
      action.autoEligible &&
      action.autopilotEligible !== false &&
      action.startsMicrophone === false &&
      action.requiresMicConfirmation === false &&
      action.requiresUserPresence === false &&
      Number(action.riskLevel || 0) <= 1,
    );
    const freshness = executable ? realtimeNoMicPreflightFreshness() : null;
    const compactFreshness = compactRealtimePreflightFreshness(freshness);
    if (freshness?.fresh) {
      const agePhrase = freshness.ageLabel ? `${freshness.ageLabel} ago` : 'recently';
      return {
        executable: false,
        reason: 'realtime_preflight_fresh',
        detail: `No-mic Realtime preflight was prepared ${agePhrase}; wait ${freshness.waitLabel || 'for the cooldown'} before repeating it.`,
        freshness: compactFreshness,
      };
    }
    return {
      executable,
      reason: executable ? 'eligible_realtime_no_mic_preflight' : 'realtime_preflight_not_safe_for_autopilot',
      detail: executable
        ? 'Autopilot may prepare the no-mic Realtime dogfood bundle; live microphone start still requires the user.'
        : 'Realtime preparation must prove it starts no microphone, needs no user presence, and stays low-risk before autopilot can run it.',
      freshness: compactFreshness,
    };
  }
  if (action.source === 'record_replay' && action.recordReplayPreparation === 'teaching_packet') {
    const executable = Boolean(
      action.executable &&
      action.autoEligible &&
      action.autopilotEligible !== false &&
      action.startsMicrophone === false &&
      action.startsRecording === false &&
      action.startsWorkers === false &&
      action.executesTask === false &&
      action.requiresUserPresence === false &&
      Number(action.riskLevel || 0) <= 1,
    );
    return {
      executable,
      reason: executable ? 'eligible_record_replay_teaching_packet' : 'record_replay_teaching_packet_not_safe_for_autopilot',
      detail: executable
        ? 'Autopilot may save the no-recording Record & Replay teaching packet; actual demonstration recording still requires the user.'
        : 'Record & Replay preparation must prove it does not start recording, microphone, workers, or UI actions before autopilot can run it.',
    };
  }
  if (action.source === 'productivity' && action.productivityPreparation === 'dogfood_archive') {
    const executable = Boolean(
      action.executable &&
      action.autoEligible &&
      action.autopilotEligible !== false &&
      action.startsMicrophone === false &&
      action.requiresMicConfirmation === false &&
      action.startsRecording === false &&
      action.startsWorkers === false &&
      action.startsApps === false &&
      action.executesTask === false &&
      action.executesProductivityActions === false &&
      action.sendsMessages === false &&
      action.mutatesUserFiles === false &&
      action.mutatesUserRecords === false &&
      action.requiresUserPresence === false &&
      Number(action.riskLevel || 0) <= 1
    );
    return {
      executable,
      reason: executable ? 'eligible_productivity_dogfood_archive' : 'productivity_dogfood_archive_not_safe_for_autopilot',
      detail: executable
        ? 'Autopilot may save a preview-only productivity dogfood archive; it starts no apps, sends no messages, and mutates no user data.'
        : 'Productivity dogfood archiving must prove it is preview-only and does not start apps, send messages, or mutate user data before autopilot can run it.',
    };
  }
  return {
    executable: false,
    reason: 'unsupported_action_source',
    detail: 'Autopilot only runs bounded maintenance, recovery, and trusted retry actions.',
  };
}

function isAutopilotExecutableAction(action) {
  return autopilotEligibilityDecision(action).executable;
}

function firstAutopilotExecutableAction(actions = []) {
  return (actions || []).find((action) => isAutopilotExecutableAction(action)) || null;
}

function autopilotActionDecision(action, index = 0) {
  if (!action) return null;
  const eligibility = autopilotEligibilityDecision(action);
  return {
    index,
    id: String(action.id || '').slice(0, 180),
    label: compactRecordText(action.label || action.title || action.id || 'Action', 140),
    source: compactRecordText(action.source || '', 80),
    priority: Number(action.priority ?? index),
    summary: compactRecordText(action.summary || action.manualOnlyReason || '', 240),
    executable: Boolean(action.executable),
    autoEligible: Boolean(action.autoEligible),
    autopilotEligible: action.autopilotEligible !== false,
    manualOnly: Boolean(action.manualOnly),
    requiresUserPresence: Boolean(action.requiresUserPresence),
    riskLevel: Math.max(0, Math.min(4, Number(action.riskLevel || 0))),
    startsMicrophone: Boolean(action.startsMicrophone),
    requiresMicConfirmation: Boolean(action.requiresMicConfirmation),
    startsRecording: Boolean(action.startsRecording),
    startsWorkers: Boolean(action.startsWorkers),
    startsApps: Boolean(action.startsApps),
    executesTask: Boolean(action.executesTask),
    executesProductivityActions: Boolean(action.executesProductivityActions),
    sendsMessages: Boolean(action.sendsMessages),
    mutatesUserFiles: Boolean(action.mutatesUserFiles),
    mutatesUserRecords: Boolean(action.mutatesUserRecords),
    recoveryType: compactRecordText(action.recoveryType || '', 80),
    trustedAutoEligible: Boolean(action.trustedAutoEligible),
    recoveryAttempts: Math.max(0, Number(action.recoveryAttempts || 0)),
    maxRecoveryAttempts: Math.max(0, Number(action.maxRecoveryAttempts || 0)),
    routeRecoveryType: compactRecordText(action.routeRecovery?.recommended?.type || '', 80),
    routeRecoveryLabel: compactRecordText(action.routeRecovery?.recommended?.label || '', 140),
    workflowAction: compactRecordText(action.workflowAction || '', 80),
    providerProbe: Boolean(action.providerProbe),
    realtimePreparation: compactRecordText(action.realtimePreparation || '', 80),
    recordReplayPreparation: compactRecordText(action.recordReplayPreparation || '', 80),
    productivityPreparation: compactRecordText(action.productivityPreparation || '', 80),
    phase: compactRecordText(action.phase || '', 80),
    freshness: compactRealtimePreflightFreshness(eligibility.freshness),
    dogfoodActionPlan: summarizeDogfoodActionPlanForAutopilot(action.dogfoodActionPlan),
    decision: eligibility,
  };
}

function autopilotNextWaitReason(reason, selectedAction = null, firstAction = null) {
  const action = selectedAction || firstAction;
  if (reason === 'autopilot_disabled') return 'Enable overnight autopilot before unattended work can run.';
  if (reason === 'preview_only') return 'Preview only; run a tick with execute=true to act.';
  if (reason === 'conversation_active') return 'Wait for the live voice conversation to finish before unattended work takes over.';
  if (reason === 'active_job_running') return 'Wait for the current worker job to finish or expose progress.';
  if (reason === 'manual_only_action') return action?.manualOnlyReason || 'Waiting for explicit user action.';
  if (reason === 'no_auto_executable_action') return 'Waiting for a low-risk recovery, maintenance, or trusted retry action.';
  if (reason === 'no_action') return 'No queued work is available; stand by for a user request or new evidence.';
  if (!reason && selectedAction) return `Run ${selectedAction.label || selectedAction.id || 'selected action'} now.`;
  return 'Review work-next for the safest next action.';
}

function autopilotWaitDurationLabel(ms) {
  const value = Math.max(0, Number(ms || 0));
  if (!value) return '';
  const seconds = Math.ceil(value / 1000);
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.ceil(seconds / 60);
  if (minutes < 60) return `${minutes}m`;
  const hours = Math.ceil(minutes / 60);
  if (hours < 24) return `${hours}h`;
  return `${Math.ceil(hours / 24)}d`;
}

function autopilotCandidateCounts(candidates = []) {
  const counts = {
    total: candidates.length,
    autoExecutable: 0,
    manualOnly: 0,
    requiresUserPresence: 0,
    trustedRecovery: 0,
    maintenance: 0,
    blocked: 0,
  };
  for (const candidate of candidates) {
    if (candidate.decision?.executable) counts.autoExecutable += 1;
    if (candidate.manualOnly) counts.manualOnly += 1;
    if (candidate.requiresUserPresence) counts.requiresUserPresence += 1;
    if (candidate.trustedAutoEligible || candidate.decision?.reason === 'eligible_trusted_routed_recovery') counts.trustedRecovery += 1;
    if (candidate.source === 'maintenance') counts.maintenance += 1;
  }
  counts.blocked = Math.max(0, counts.total - counts.autoExecutable);
  return counts;
}

function pushAutopilotWaitingCondition(list, item) {
  if (!item?.id || list.some((existing) => existing.id === item.id)) return;
  list.push({
    id: item.id,
    label: compactRecordText(item.label || item.id, 120),
    summary: compactRecordText(item.summary || '', 280),
    status: compactRecordText(item.status || 'waiting', 40),
    actionId: compactRecordText(item.actionId || '', 180),
    actionSource: compactRecordText(item.actionSource || '', 80),
    waitMs: Math.max(0, Number(item.waitMs || 0)),
    waitLabel: compactRecordText(item.waitLabel || '', 40),
  });
}

function autopilotWaitingConditions({ reason = '', candidates = [], selectedAction = null, firstAction = null, maintenance = null, recordReplayTeaching = null, productivityDogfood = null } = {}) {
  if (selectedAction?.decision?.executable && !reason) return [];
  const waiting = [];
  if (!AUTOPILOT_ENABLED) {
    pushAutopilotWaitingCondition(waiting, {
      id: 'enable_autopilot',
      label: 'Enable overnight autopilot',
      summary: 'JAVIS_AUTOPILOT_ENABLED is off, so unattended ticks only preview decisions.',
      status: 'blocked',
    });
  }
  if (reason === 'preview_only') {
    pushAutopilotWaitingCondition(waiting, {
      id: 'execute_tick',
      label: 'Run an executing tick',
      summary: 'This was only a preview; execute=true is required before autopilot can act.',
      status: 'waiting',
    });
  }
  if (reason === 'conversation_active') {
    pushAutopilotWaitingCondition(waiting, {
      id: 'voice_idle',
      label: 'Wait for voice to go idle',
      summary: 'A live voice session is active, so unattended work will not take over.',
      status: 'waiting',
    });
  }
  if (reason === 'active_job_running') {
    pushAutopilotWaitingCondition(waiting, {
      id: 'jobs_idle',
      label: 'Wait for active jobs',
      summary: `${activeJobRuns.size} background job(s) are still running or queued.`,
      status: 'waiting',
    });
  }

  const manual = candidates.find((candidate) => candidate.manualOnly || candidate.requiresUserPresence);
  if (manual) {
    pushAutopilotWaitingCondition(waiting, {
      id: 'manual_user_action',
      label: 'Needs user presence',
      summary: `${manual.label || manual.id} requires explicit user action and will be skipped by unattended autopilot.`,
      status: 'manual',
      actionId: manual.id,
      actionSource: manual.source,
    });
  }

  const freshRealtimePreflight = candidates.find((candidate) => (
    candidate.decision?.reason === 'realtime_preflight_fresh' &&
    candidate.decision?.freshness?.fresh === true
  ));
  if (freshRealtimePreflight) {
    const waitMs = Math.max(0, Number(freshRealtimePreflight.decision?.freshness?.waitMs || 0));
    const waitLabel = freshRealtimePreflight.decision?.freshness?.waitLabel || autopilotWaitDurationLabel(waitMs);
    pushAutopilotWaitingCondition(waiting, {
      id: 'realtime_preflight_fresh',
      label: 'Realtime preflight cooldown',
      summary: waitLabel
        ? `No-mic Realtime preflight is fresh; wait about ${waitLabel} before repeating it, or let maintenance run.`
        : 'No-mic Realtime preflight is fresh; skip repeating it for now.',
      status: 'cooldown',
      actionId: freshRealtimePreflight.id,
      actionSource: freshRealtimePreflight.source,
      waitMs,
      waitLabel,
    });
  }

  const providerProbeWaiting = candidates.find((candidate) => (
    candidate.decision?.reason === 'realtime_provider_probe_running' ||
    (
      candidate.decision?.reason === 'realtime_provider_probe_fresh' &&
      candidate.decision?.freshness?.fresh === true
    )
  ));
  if (providerProbeWaiting) {
    const running = providerProbeWaiting.decision?.reason === 'realtime_provider_probe_running' || providerProbeWaiting.decision?.freshness?.running === true;
    const waitMs = Math.max(0, Number(providerProbeWaiting.decision?.freshness?.waitMs || 0));
    const waitLabel = providerProbeWaiting.decision?.freshness?.waitLabel || autopilotWaitDurationLabel(waitMs);
    pushAutopilotWaitingCondition(waiting, {
      id: running ? 'realtime_provider_probe_running' : 'realtime_provider_probe_fresh',
      label: running ? 'Realtime provider probe running' : 'Realtime provider probe cooldown',
      summary: running
        ? 'A no-mic Realtime provider probe is already running; wait for the renderer result before retrying.'
        : waitLabel
          ? `No-mic Realtime provider probe is fresh; wait about ${waitLabel} before repeating it.`
          : 'No-mic Realtime provider probe is fresh; skip repeating it for now.',
      status: running ? 'running' : 'cooldown',
      actionId: providerProbeWaiting.id,
      actionSource: providerProbeWaiting.source,
      waitMs,
      waitLabel,
    });
  }

  const browserRecoveryFresh = candidates.find((candidate) => (
    candidate.decision?.reason === 'browser_recovery_fresh' &&
    candidate.decision?.freshness?.fresh === true
  ));
  if (browserRecoveryFresh) {
    const waitMs = Math.max(0, Number(browserRecoveryFresh.decision?.freshness?.waitMs || 0));
    const waitLabel = browserRecoveryFresh.decision?.freshness?.waitLabel || autopilotWaitDurationLabel(waitMs);
    pushAutopilotWaitingCondition(waiting, {
      id: 'browser_recovery_fresh',
      label: 'Browser recovery cooldown',
      summary: waitLabel
        ? `Browser recovery just tried opening the supported browser; wait about ${waitLabel} before repeating it.`
        : 'Browser recovery just tried opening the supported browser; skip repeating it for now.',
      status: 'cooldown',
      actionId: browserRecoveryFresh.id,
      actionSource: browserRecoveryFresh.source,
      waitMs,
      waitLabel,
    });
  }

  const dogfoodPrep = candidates.find((candidate) => (
    candidate.dogfoodActionPlan?.firstPreviewable &&
    candidate.decision?.reason !== 'realtime_preflight_fresh'
  ));
  if (dogfoodPrep?.dogfoodActionPlan?.firstPreviewable) {
    const prep = dogfoodPrep.dogfoodActionPlan.firstPreviewable;
    pushAutopilotWaitingCondition(waiting, {
      id: 'realtime_dogfood_prepare',
      label: 'Realtime dogfood can prepare',
      summary: `Without starting microphone capture, JAVIS can still prepare: ${prep.label || prep.id}.`,
      status: 'previewable',
      actionId: dogfoodPrep.id,
      actionSource: dogfoodPrep.source,
    });
  }

  const recordReplayTeachingFresh = recordReplayTeaching?.freshness?.fresh === true
    ? recordReplayTeaching.freshness
    : null;
  if (recordReplayTeachingFresh && !candidates.some((candidate) => candidate.id === 'record_replay:prepare_teaching_packet')) {
    const waitMs = Math.max(0, Number(recordReplayTeachingFresh.waitMs || 0));
    const waitLabel = recordReplayTeachingFresh.waitLabel || autopilotWaitDurationLabel(waitMs);
    pushAutopilotWaitingCondition(waiting, {
      id: 'record_replay_teaching_fresh',
      label: 'Teaching packet cooldown',
      summary: waitLabel
        ? `Record & Replay teaching packet is fresh; wait about ${waitLabel} before saving another no-recording packet.`
        : 'Record & Replay teaching packet is fresh; skip saving another packet for now.',
      status: 'cooldown',
      actionId: 'record_replay:prepare_teaching_packet',
      actionSource: 'record_replay',
      waitMs,
      waitLabel,
    });
  }

  const productivityDogfoodFresh = productivityDogfood?.freshness?.fresh === true
    ? productivityDogfood.freshness
    : null;
  if (productivityDogfoodFresh && !candidates.some((candidate) => candidate.id === 'productivity_dogfood:save_archive')) {
    const waitMs = Math.max(0, Number(productivityDogfoodFresh.waitMs || 0));
    const waitLabel = productivityDogfoodFresh.waitLabel || autopilotWaitDurationLabel(waitMs);
    pushAutopilotWaitingCondition(waiting, {
      id: 'productivity_dogfood_fresh',
      label: 'Productivity dogfood cooldown',
      summary: waitLabel
        ? `Productivity dogfood archive is fresh; wait about ${waitLabel} before saving another preview-only archive.`
        : 'Productivity dogfood archive is fresh; skip saving another preview-only archive for now.',
      status: 'cooldown',
      actionId: 'productivity_dogfood:save_archive',
      actionSource: 'productivity',
      waitMs,
      waitLabel,
    });
  }

  const noExecutableCandidate = candidates.length && !candidates.some((candidate) => candidate.decision?.executable);
  if (noExecutableCandidate) {
    pushAutopilotWaitingCondition(waiting, {
      id: 'eligible_safe_action',
      label: 'Wait for low-risk work',
      summary: 'No current work-next candidate is a bounded low-risk recovery, maintenance, or trusted retry action.',
      status: 'waiting',
    });
  }

  if (maintenance && maintenance.due === false) {
    const waitMs = Math.max(0, Number(maintenance.minIntervalMs || 0) - Number(maintenance.ageMs || 0));
    pushAutopilotWaitingCondition(waiting, {
      id: 'maintenance_cooldown',
      label: 'Maintenance cooldown',
      summary: waitMs
        ? `Read-only maintenance snapshot can run after the cooldown, in about ${autopilotWaitDurationLabel(waitMs)}.`
        : 'Read-only maintenance snapshot is still cooling down.',
      status: 'cooldown',
      waitMs,
      waitLabel: autopilotWaitDurationLabel(waitMs),
    });
  }

  if (!candidates.length) {
    pushAutopilotWaitingCondition(waiting, {
      id: 'new_evidence',
      label: 'Wait for new work',
      summary: 'No queued work is available; JAVIS is standing by for user intent or new local evidence.',
      status: 'waiting',
    });
  }

  if (!waiting.length && firstAction) {
    pushAutopilotWaitingCondition(waiting, {
      id: 'review_work_next',
      label: 'Review work-next',
      summary: `Current first action is not autopilot executable: ${firstAction.label || firstAction.id}.`,
      status: 'waiting',
      actionId: firstAction.id,
      actionSource: firstAction.source,
    });
  }

  return waiting;
}

function autopilotSkipSummary(reason = '', waitingFor = [], selectedAction = null) {
  if (!reason && selectedAction) {
    return `Ready to run ${selectedAction.label || selectedAction.id || 'the selected safe action'}.`;
  }
  if (waitingFor.length) {
    return waitingFor.slice(0, 3).map((item) => item.summary || item.label).filter(Boolean).join(' ');
  }
  return autopilotNextWaitReason(reason, selectedAction, null);
}

function autopilotSkipReason({ execute, selectedAction, firstAction, conversation } = {}) {
  const firstActionManualOnly = Boolean(firstAction?.manualOnly || firstAction?.autopilotEligible === false);
  if (!AUTOPILOT_ENABLED) return 'autopilot_disabled';
  if (!execute) return 'preview_only';
  if (conversation?.active) return 'conversation_active';
  if (activeJobRuns.size) return 'active_job_running';
  if (!selectedAction && firstActionManualOnly) return 'manual_only_action';
  if (!selectedAction) return firstAction ? 'no_auto_executable_action' : 'no_action';
  return '';
}

function autopilotDecisionSnapshot({ source = 'api', execute = true, briefing = null, selectedAction = null, firstAction = null, reason = '', outcome = 'preview', resultSummary = '' } = {}) {
  const actions = Array.isArray(briefing?.nextActions) ? briefing.nextActions : [];
  const candidates = actions.slice(0, 6).map(autopilotActionDecision).filter(Boolean);
  const selected = selectedAction ? autopilotActionDecision(selectedAction, actions.indexOf(selectedAction)) : null;
  const first = firstAction ? autopilotActionDecision(firstAction, actions.indexOf(firstAction)) : null;
  const maintenance = briefing?.maintenance || maintenanceStateSnapshot();
  const recordReplayTeaching = briefing?.recordReplayTeaching || null;
  const productivityDogfood = briefing?.productivityDogfood || null;
  const candidateCounts = autopilotCandidateCounts(candidates);
  const waitingFor = autopilotWaitingConditions({
    reason,
    candidates,
    selectedAction: selected,
    firstAction: first,
    maintenance,
    recordReplayTeaching,
    productivityDogfood,
  });
  const skipSummary = autopilotSkipSummary(reason, waitingFor, selected);
  return {
    generatedAt: new Date().toISOString(),
    source: String(source || 'api').slice(0, 80),
    execute: Boolean(execute),
    outcome,
    reason,
    resultSummary: compactRecordText(resultSummary || '', 500),
    enabled: AUTOPILOT_ENABLED,
    conversationActive: Boolean(conversationStateSnapshot().active),
    activeJobs: activeJobRuns.size,
    nextActionCount: actions.length,
    selectedAction: selected,
    firstAction: first,
    candidates,
    candidateCounts,
    waitingFor,
    skipSummary: compactRecordText(skipSummary || '', 500),
    maintenance,
    recordReplayTeaching,
    productivityDogfood,
    nextWait: autopilotNextWaitReason(reason, selectedAction, firstAction),
  };
}

function autopilotDecisionPreview(options = {}) {
  const briefing = options.briefing || workflowBriefing({
    workflowLimit: options.workflowLimit || 6,
    jobLimit: options.jobLimit || 6,
    includeMaintenance: true,
    forceMaintenance: options.forceMaintenance,
  });
  const firstAction = (briefing.nextActions || [])[0] || null;
  const selectedAction = firstAutopilotExecutableAction(briefing.nextActions || []);
  const conversation = conversationStateSnapshot();
  const execute = options.execute === true;
  const reason = autopilotSkipReason({ execute, selectedAction, firstAction, conversation });
  return autopilotDecisionSnapshot({
    source: options.source || 'status',
    execute,
    briefing,
    selectedAction,
    firstAction,
    reason,
    outcome: reason ? 'skipped' : 'ready',
  });
}

function autopilotTickSafetySnapshot({ execute = false, action = null } = {}) {
  const canExecute = execute === true;
  return {
    previewOnly: !canExecute,
    usesExistingActionPolicy: true,
    startsMicrophone: Boolean(canExecute && action?.startsMicrophone),
    usesRealtime: Boolean(canExecute && (action?.usesRealtime || action?.requiresLiveVoice)),
    opensTerminal: Boolean(canExecute && action?.opensTerminal),
    startsWorkers: Boolean(canExecute && action?.startsWorkers),
    startsApps: Boolean(canExecute && action?.startsApps),
    executesTask: Boolean(canExecute && action?.executesTask),
    executesProductivityActions: Boolean(canExecute && action?.executesProductivityActions),
    mutatesFiles: Boolean(canExecute && action?.mutatesUserFiles),
    mutatesRecords: Boolean(canExecute && action?.mutatesUserRecords),
    sendsMessages: Boolean(canExecute && action?.sendsMessages),
    storesRawAudio: false,
    bypassesApprovals: false,
    maxAutoRiskLevel: Number(actionPolicy?.maxAutoRiskLevel || 0),
    requireApprovalAtRiskLevel: Number(actionPolicy?.requireApprovalAtRiskLevel || 0),
    actionRiskLevel: Number(action?.riskLevel || 0),
  };
}

function autopilotVoiceStatusSnapshot(options = {}) {
  const preview = autopilotDecisionPreview({
    source: options.source || 'voice_tool',
    execute: true,
    workflowLimit: options.workflowLimit,
    jobLimit: options.jobLimit,
    forceMaintenance: options.forceMaintenance,
  });
  const state = autopilotStateSnapshot();
  const selected = preview.selectedAction || null;
  const first = preview.firstAction || null;
  const target = selected || first;
  const reason = preview.reason || selected?.decision?.reason || '';
  const canActNow = Boolean(preview.outcome === 'ready' && selected?.decision?.executable);
  const spokenSummary = canActNow
    ? `Autopilot 可以自己执行下一步: ${compactRecordText(selected.label || selected.id, 90)}。`
    : reason
      ? `Autopilot 当前没有自动执行: ${compactRecordText(preview.skipSummary || preview.nextWait || reason, 220)}`
      : 'Autopilot 当前没有需要自动执行的动作。';
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    enabled: state.enabled,
    running: state.running,
    busy: state.busy,
    tickCount: state.tickCount,
    executedCount: state.executedCount,
    skippedCount: state.skippedCount,
    lastTickAt: state.lastTickAt,
    lastExecutedAt: state.lastExecutedAt,
    lastResult: compactRecordText(state.lastResult || '', 500),
    lastError: compactRecordText(state.lastError || '', 500),
    maintenance: state.maintenance,
    recordReplayTeaching: preview.recordReplayTeaching || null,
    productivityDogfood: preview.productivityDogfood || null,
    canActNow,
    reason,
    nextWait: preview.nextWait,
    spokenSummary,
    skipSummary: preview.skipSummary,
    candidateCounts: preview.candidateCounts,
    waitingFor: preview.waitingFor,
    selectedAction: selected,
    firstAction: first,
    candidates: preview.candidates,
    lastDecision: state.lastDecision,
    decisionPreview: preview,
    nextAction: canActNow
      ? `Ask me to run the autopilot tick or run_work_next if you want to execute ${target?.label || 'the selected action'}.`
      : preview.nextWait || 'Keep using work-next; autopilot will act when a low-risk eligible action appears.',
  };
}

function compactAutopilotActionForVoice(action = null) {
  if (!action || typeof action !== 'object') return null;
  const dogfoodActionPlan = action.dogfoodActionPlan?.firstPreviewable ||
    action.dogfoodActionPlan?.firstManual ||
    action.dogfoodActionPlan?.previewableCount !== undefined ||
    action.dogfoodActionPlan?.manualCount !== undefined
    ? {
      version: Number(action.dogfoodActionPlan.version || 0),
      scope: compactRecordText(action.dogfoodActionPlan.scope || '', 80),
      status: compactRecordText(action.dogfoodActionPlan.status || '', 80),
      accepted: Boolean(action.dogfoodActionPlan.accepted),
      primary: action.dogfoodActionPlan.primary
        ? {
          id: compactRecordText(action.dogfoodActionPlan.primary.id || '', 120),
          label: compactRecordText(action.dogfoodActionPlan.primary.label || action.dogfoodActionPlan.primary.id || '', 120),
          startsMicrophone: Boolean(action.dogfoodActionPlan.primary.startsMicrophone),
          requiresMicConfirmation: Boolean(action.dogfoodActionPlan.primary.requiresMicConfirmation),
          requiresLiveVoice: Boolean(action.dogfoodActionPlan.primary.requiresLiveVoice),
          requiresUserPresence: Boolean(action.dogfoodActionPlan.primary.requiresUserPresence),
        }
        : null,
      previewableCount: boundedCount(action.dogfoodActionPlan.previewableCount, 100),
      manualCount: boundedCount(action.dogfoodActionPlan.manualCount, 100),
      firstPreviewable: action.dogfoodActionPlan.firstPreviewable
        ? {
          id: compactRecordText(action.dogfoodActionPlan.firstPreviewable.id || '', 120),
          label: compactRecordText(action.dogfoodActionPlan.firstPreviewable.label || action.dogfoodActionPlan.firstPreviewable.id || '', 120),
          command: compactRecordText(action.dogfoodActionPlan.firstPreviewable.command || '', 140),
          endpoint: compactRecordText(action.dogfoodActionPlan.firstPreviewable.endpoint || '', 100),
          startsMicrophone: Boolean(action.dogfoodActionPlan.firstPreviewable.startsMicrophone),
        }
        : null,
      firstManual: action.dogfoodActionPlan.firstManual
        ? {
          id: compactRecordText(action.dogfoodActionPlan.firstManual.id || '', 120),
          label: compactRecordText(action.dogfoodActionPlan.firstManual.label || action.dogfoodActionPlan.firstManual.id || '', 120),
          startsMicrophone: Boolean(action.dogfoodActionPlan.firstManual.startsMicrophone),
          requiresMicConfirmation: Boolean(action.dogfoodActionPlan.firstManual.requiresMicConfirmation),
          requiresLiveVoice: Boolean(action.dogfoodActionPlan.firstManual.requiresLiveVoice),
        }
        : null,
      spokenSummary: compactRecordText(action.dogfoodActionPlan.spokenSummary || '', 180),
    }
    : summarizeDogfoodActionPlanForAutopilot(action.dogfoodActionPlan);
  return {
    index: boundedCount(action.index, 1000),
    id: compactRecordText(action.id || '', 160),
    label: compactRecordText(action.label || action.id || '', 140),
    source: compactRecordText(action.source || '', 80),
    priority: boundedCount(action.priority, 1000),
    summary: compactRecordText(action.summary || '', 180),
    executable: Boolean(action.executable),
    autoEligible: Boolean(action.autoEligible),
    autopilotEligible: action.autopilotEligible !== false,
    manualOnly: Boolean(action.manualOnly),
    requiresUserPresence: Boolean(action.requiresUserPresence),
    startsMicrophone: Boolean(action.startsMicrophone),
    requiresMicConfirmation: Boolean(action.requiresMicConfirmation),
    startsRecording: Boolean(action.startsRecording),
    startsWorkers: Boolean(action.startsWorkers),
    startsApps: Boolean(action.startsApps),
    executesTask: Boolean(action.executesTask),
    executesProductivityActions: Boolean(action.executesProductivityActions),
    sendsMessages: Boolean(action.sendsMessages),
    mutatesUserFiles: Boolean(action.mutatesUserFiles),
    mutatesUserRecords: Boolean(action.mutatesUserRecords),
    riskLevel: boundedCount(action.riskLevel, 4),
    recoveryType: compactRecordText(action.recoveryType || '', 80),
    trustedAutoEligible: Boolean(action.trustedAutoEligible),
    recoveryAttempts: boundedCount(action.recoveryAttempts, 1000),
    maxRecoveryAttempts: boundedCount(action.maxRecoveryAttempts, 1000),
    routeRecoveryType: compactRecordText(action.routeRecoveryType || '', 80),
    routeRecoveryLabel: compactRecordText(action.routeRecoveryLabel || '', 140),
    workflowAction: compactRecordText(action.workflowAction || '', 80),
    realtimePreparation: compactRecordText(action.realtimePreparation || '', 80),
    recordReplayPreparation: compactRecordText(action.recordReplayPreparation || '', 80),
    productivityPreparation: compactRecordText(action.productivityPreparation || '', 80),
    phase: compactRecordText(action.phase || '', 80),
    dogfoodActionPlan,
    decision: action.decision
      ? {
        executable: Boolean(action.decision.executable),
        reason: compactRecordText(action.decision.reason || '', 120),
        detail: compactRecordText(action.decision.detail || '', 160),
        freshness: compactRealtimePreflightFreshnessForVoice(action.decision.freshness),
      }
      : null,
  };
}

function compactAutopilotWaitingForVoice(item = null) {
  if (!item || typeof item !== 'object') return null;
  return {
    id: compactRecordText(item.id || '', 120),
    label: compactRecordText(item.label || item.id || '', 140),
    summary: compactRecordText(item.summary || '', 240),
    status: compactRecordText(item.status || '', 60),
    actionId: compactRecordText(item.actionId || '', 160),
    actionSource: compactRecordText(item.actionSource || '', 80),
    waitMs: boundedCount(item.waitMs, 12 * 60 * 60 * 1000),
    waitLabel: compactRecordText(item.waitLabel || '', 40),
  };
}

function compactAutopilotMaintenanceForVoice(maintenance = null) {
  if (!maintenance || typeof maintenance !== 'object') return null;
  return {
    lastSnapshotAt: boundedCount(maintenance.lastSnapshotAt, 4102444800000),
    runCount: boundedCount(maintenance.runCount, 1000000),
    lastWorkflowId: compactRecordText(maintenance.lastWorkflowId || '', 120),
    lastSummary: compactRecordText(maintenance.lastSummary || '', 260),
    minIntervalMs: boundedCount(maintenance.minIntervalMs, 24 * 60 * 60 * 1000),
    ageMs: boundedCount(maintenance.ageMs, 24 * 60 * 60 * 1000),
    due: Boolean(maintenance.due),
  };
}

function compactAutopilotRecordReplayTeachingForVoice(state = null) {
  if (!state || typeof state !== 'object') return null;
  const freshness = state.freshness || {};
  return {
    actionAvailable: Boolean(state.actionAvailable),
    fresh: Boolean(freshness.fresh),
    waitMs: boundedCount(freshness.waitMs, 7 * 24 * 60 * 60 * 1000),
    waitLabel: compactRecordText(freshness.waitLabel || '', 40),
    ageLabel: compactRecordText(freshness.ageLabel || '', 40),
    latestCandidate: compactRecordText(freshness.latest?.candidate?.label || '', 140),
  };
}

function compactAutopilotProductivityDogfoodForVoice(state = null) {
  if (!state || typeof state !== 'object') return null;
  const freshness = state.freshness || {};
  return {
    actionAvailable: Boolean(state.actionAvailable),
    fresh: Boolean(freshness.fresh),
    waitMs: boundedCount(freshness.waitMs, 7 * 24 * 60 * 60 * 1000),
    waitLabel: compactRecordText(freshness.waitLabel || '', 40),
    ageLabel: compactRecordText(freshness.ageLabel || '', 40),
    latestSummary: compactRecordText(freshness.latest?.summary || '', 180),
    latestFile: compactRecordText(freshness.latest?.file || '', 220),
    pass: boundedCount(freshness.latest?.pass, 100),
    total: boundedCount(freshness.latest?.total, 100),
    previewOnly: freshness.latest?.previewOnly === true,
  };
}

function autopilotStatusVoicePayload(status = {}, options = {}) {
  const candidates = Array.isArray(status.candidates) ? status.candidates : [];
  const waitingFor = Array.isArray(status.waitingFor) ? status.waitingFor : [];
  const preview = status.decisionPreview || {};
  const payload = {
    ok: status.ok !== false,
    generatedAt: status.generatedAt || new Date().toISOString(),
    source: compactRecordText(options.source || preview.source || 'voice', 80),
    enabled: Boolean(status.enabled),
    running: Boolean(status.running),
    busy: Boolean(status.busy),
    tickCount: boundedCount(status.tickCount, 1000000),
    executedCount: boundedCount(status.executedCount, 1000000),
    skippedCount: boundedCount(status.skippedCount, 1000000),
    lastTickAt: boundedCount(status.lastTickAt, 4102444800000),
    lastExecutedAt: boundedCount(status.lastExecutedAt, 4102444800000),
    lastResult: compactRecordText(status.lastResult || '', 200),
    lastError: compactRecordText(status.lastError || '', 200),
    maintenance: compactAutopilotMaintenanceForVoice(status.maintenance),
    recordReplayTeaching: compactAutopilotRecordReplayTeachingForVoice(status.recordReplayTeaching || preview.recordReplayTeaching),
    productivityDogfood: compactAutopilotProductivityDogfoodForVoice(status.productivityDogfood || preview.productivityDogfood),
    canActNow: Boolean(status.canActNow),
    reason: compactRecordText(status.reason || '', 120),
    nextWait: compactRecordText(status.nextWait || '', 260),
    spokenSummary: compactRecordText(status.spokenSummary || '', 320),
    skipSummary: compactRecordText(status.skipSummary || '', 320),
    candidateCounts: status.candidateCounts || null,
    waitingFor: waitingFor.slice(0, 4).map(compactAutopilotWaitingForVoice).filter(Boolean),
    selectedAction: compactAutopilotActionForVoice(status.selectedAction),
    firstAction: compactAutopilotActionForVoice(status.firstAction),
    candidates: candidates.slice(0, 2).map(compactAutopilotActionForVoice).filter(Boolean),
    lastDecision: status.lastDecision
      ? {
        generatedAt: compactRecordText(status.lastDecision.generatedAt || '', 80),
        source: compactRecordText(status.lastDecision.source || '', 80),
        outcome: compactRecordText(status.lastDecision.outcome || '', 80),
        reason: compactRecordText(status.lastDecision.reason || '', 120),
        nextWait: compactRecordText(status.lastDecision.nextWait || '', 260),
        skipSummary: compactRecordText(status.lastDecision.skipSummary || '', 320),
        candidateCounts: status.lastDecision.candidateCounts || null,
      }
      : null,
    decisionPreview: {
      generatedAt: compactRecordText(preview.generatedAt || '', 80),
      source: compactRecordText(preview.source || '', 80),
      execute: Boolean(preview.execute),
      outcome: compactRecordText(preview.outcome || '', 80),
      reason: compactRecordText(preview.reason || '', 120),
      resultSummary: compactRecordText(preview.resultSummary || '', 260),
      enabled: Boolean(preview.enabled),
      conversationActive: Boolean(preview.conversationActive),
      activeJobs: boundedCount(preview.activeJobs, 100000),
      nextActionCount: boundedCount(preview.nextActionCount, 1000),
      selectedAction: preview.selectedAction
        ? {
          id: compactRecordText(preview.selectedAction.id || '', 120),
          label: compactRecordText(preview.selectedAction.label || preview.selectedAction.id || '', 120),
          executable: Boolean(preview.selectedAction.decision?.executable || preview.selectedAction.executable),
          reason: compactRecordText(preview.selectedAction.decision?.reason || '', 100),
        }
        : null,
      firstAction: preview.firstAction
        ? {
          id: compactRecordText(preview.firstAction.id || '', 120),
          label: compactRecordText(preview.firstAction.label || preview.firstAction.id || '', 120),
          executable: Boolean(preview.firstAction.decision?.executable || preview.firstAction.executable),
          reason: compactRecordText(preview.firstAction.decision?.reason || '', 100),
        }
        : null,
      candidateCounts: preview.candidateCounts || null,
      waitingFor: Array.isArray(preview.waitingFor)
        ? preview.waitingFor.slice(0, 4).map((item) => ({
          id: compactRecordText(item.id || '', 120),
          status: compactRecordText(item.status || '', 60),
          waitLabel: compactRecordText(item.waitLabel || '', 40),
        })).filter((item) => item.id)
        : [],
      skipSummary: compactRecordText(preview.skipSummary || '', 240),
      maintenance: compactAutopilotMaintenanceForVoice(preview.maintenance),
      recordReplayTeaching: compactAutopilotRecordReplayTeachingForVoice(preview.recordReplayTeaching),
      productivityDogfood: compactAutopilotProductivityDogfoodForVoice(preview.productivityDogfood),
      nextWait: compactRecordText(preview.nextWait || '', 220),
    },
    nextAction: compactRecordText(status.nextAction || '', 260),
    responseBudget: {
      compact: true,
      maxTargetBytes: 20000,
      omitted: [
        'decisionPreview.candidates.full',
        'lastDecision.candidates.full',
        'candidate.decision.full',
        'maintenance.full_history',
        'raw workflow/job records',
      ],
    },
  };
  const bytes = Buffer.byteLength(JSON.stringify(payload), 'utf8');
  return {
    ...payload,
    responseBudget: {
      ...payload.responseBudget,
      outputBytes: bytes,
    },
  };
}

async function autopilotTick(options = {}) {
  const source = String(options.source || 'api').slice(0, 80);
  const execute = options.execute !== false;
  let decision = null;
  if (!execute) {
    const briefing = workflowBriefing({
      workflowLimit: options.workflowLimit || 6,
      jobLimit: options.jobLimit || 6,
      includeMaintenance: true,
      forceMaintenance: options.forceMaintenance,
    });
    const firstAction = (briefing.nextActions || [])[0] || null;
    const action = firstAutopilotExecutableAction(briefing.nextActions);
    const conversation = conversationStateSnapshot();
    const reason = autopilotSkipReason({ execute, selectedAction: action, firstAction, conversation });
    decision = autopilotDecisionSnapshot({
      source,
      execute,
      briefing,
      selectedAction: action,
      firstAction,
      reason,
      outcome: 'preview',
      resultSummary: 'Previewed one autopilot tick without updating tick counters or executing work-next.',
    });
    return {
      ok: true,
      executed: false,
      skipped: false,
      previewOnly: true,
      reason,
      action: action || firstAction,
      selectedAction: action,
      briefing,
      decision,
      safety: autopilotTickSafetySnapshot({ execute, action }),
      autopilot: autopilotStateSnapshot(),
    };
  }
  if (autopilotBusy) {
    return {
      ok: true,
      executed: false,
      skipped: true,
      reason: 'autopilot_busy',
      safety: autopilotTickSafetySnapshot({ execute }),
      autopilot: autopilotStateSnapshot(),
    };
  }
  autopilotBusy = true;
  autopilotState = {
    ...autopilotState,
    running: true,
    tickCount: Number(autopilotState.tickCount || 0) + 1,
    lastTickAt: Date.now(),
    lastError: '',
  };
  try {
    const briefing = workflowBriefing({
      workflowLimit: options.workflowLimit || 6,
      jobLimit: options.jobLimit || 6,
      includeMaintenance: true,
      forceMaintenance: options.forceMaintenance,
    });
    const firstAction = (briefing.nextActions || [])[0] || null;
    const action = firstAutopilotExecutableAction(briefing.nextActions);
    const conversation = conversationStateSnapshot();
    const reason = autopilotSkipReason({ execute, selectedAction: action, firstAction, conversation });
    decision = autopilotDecisionSnapshot({
      source,
      execute,
      briefing,
      selectedAction: action,
      firstAction,
      reason,
      outcome: reason ? 'skipped' : 'ready',
    });

    if (reason) {
      autopilotState = {
        ...autopilotState,
        skippedCount: Number(autopilotState.skippedCount || 0) + 1,
        lastAction: action || firstAction,
        lastDecision: decision,
        lastResult: reason,
      };
      appendAudit('autopilot.skipped', {
        source,
        reason,
        action: action?.id || firstAction?.id || '',
        actionSource: action?.source || firstAction?.source || '',
        nextWait: decision.nextWait,
        nextActions: (briefing.nextActions || []).length,
        candidates: decision.candidates.map((candidate) => ({
          id: candidate.id,
          source: candidate.source,
          decision: candidate.decision.reason,
        })),
      });
      return {
        ok: true,
        executed: false,
        skipped: true,
        reason,
        action: action || firstAction,
        selectedAction: action,
        briefing,
        decision,
        safety: autopilotTickSafetySnapshot({ execute, action }),
        autopilot: autopilotStateSnapshot(),
      };
    }

    const result = await workNextAction({
      execute: true,
      actionId: action.id,
      autopilot: true,
      source: `autopilot:${source}`,
      workflowLimit: options.workflowLimit || 6,
      jobLimit: options.jobLimit || 6,
    });
    autopilotState = {
      ...autopilotState,
      executedCount: Number(autopilotState.executedCount || 0) + 1,
      lastExecutedAt: Date.now(),
      lastAction: action,
      lastDecision: {
        ...decision,
        outcome: 'executed',
        resultSummary: compactRecordText(result.output || '', 500),
      },
      lastResult: compactRecordText(result.output || '', 1000),
    };
    appendAudit('autopilot.executed', {
      source,
      action: action.id,
      actionSource: action.source,
      outputLength: result.output ? String(result.output).length : 0,
    });
    return {
      ok: true,
      executed: true,
      skipped: false,
      action,
      result,
      briefing,
      decision: autopilotState.lastDecision,
      safety: autopilotTickSafetySnapshot({ execute, action }),
      autopilot: autopilotStateSnapshot(),
    };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    autopilotState = {
      ...autopilotState,
      lastError: errorMessage,
      lastDecision: decision
        ? { ...decision, outcome: 'failed', resultSummary: errorMessage }
        : autopilotState.lastDecision,
    };
    appendAudit('autopilot.failed', { source, error: autopilotState.lastError });
    return {
      ok: false,
      executed: false,
      skipped: false,
      error: autopilotState.lastError,
      safety: autopilotTickSafetySnapshot({ execute }),
      autopilot: autopilotStateSnapshot(),
    };
  } finally {
    autopilotBusy = false;
    autopilotState = {
      ...autopilotState,
      running: false,
    };
  }
}

function startAutopilotMonitor() {
  if (!AUTOPILOT_ENABLED || autopilotTimer) return;
  autopilotTimer = setInterval(() => {
    void autopilotTick({ source: 'interval' });
  }, AUTOPILOT_INTERVAL_MS);
  appendAudit('autopilot.started', {
    intervalMs: AUTOPILOT_INTERVAL_MS,
    localExecutionEnabled: LOCAL_EXEC_ENABLED,
    trustedLocalMode: TRUSTED_LOCAL_MODE,
  });
  void autopilotTick({ source: 'startup' });
}

function stopAutopilotMonitor() {
  if (!autopilotTimer) return;
  clearInterval(autopilotTimer);
  autopilotTimer = null;
  appendAudit('autopilot.stopped');
}

function wakeStatusSnapshot(options = {}) {
  const since = Number(options.since || 0);
  const ageMs = wakeState.lastTriggerAt ? Date.now() - wakeState.lastTriggerAt : Infinity;
  const conversation = conversationStateSnapshot();
  const voiceHealth = realtimeVoiceHealthSnapshot({ conversation, includeRecentAudit: true });
  const localVoice = localVoiceStatusSnapshot({ conversation, voiceHealth });
  return {
    words: WAKE_WORDS,
    softWakeOnly: !WAKE_ENGINE_CMD,
    triggerTtlMs: WAKE_TRIGGER_TTL_MS,
    pending: Boolean(wakeState.lastTriggerAt && wakeState.lastTriggerAt > since && ageMs <= WAKE_TRIGGER_TTL_MS),
    ageMs: Number.isFinite(ageMs) ? ageMs : null,
    lastTriggerAt: wakeState.lastTriggerAt,
    lastSource: wakeState.lastSource,
    lastPhrase: wakeState.lastPhrase,
    triggerCount: wakeState.triggerCount,
    engine: {
      configured: Boolean(WAKE_ENGINE_CMD),
      command: WAKE_ENGINE_CMD ? redactCommandForLog(WAKE_ENGINE_CMD) : '',
      running: wakeState.engineRunning,
      pid: wakeState.enginePid,
      startedAt: wakeState.engineStartedAt,
      lastLine: wakeState.engineLastLine,
      lastError: wakeState.engineLastError,
    },
    handoff: wakeHandoffSnapshot({ conversation, voiceHealth, localVoice }),
  };
}

function triggerWake(options = {}) {
  const phrase = String(options.phrase || options.word || '').trim().slice(0, 120);
  const source = String(options.source || 'api').trim().slice(0, 80) || 'api';
  wakeState = {
    ...wakeState,
    lastTriggerAt: Date.now(),
    lastSource: source,
    lastPhrase: phrase,
    triggerCount: wakeState.triggerCount + 1,
  };
  appendAudit('wake.triggered', {
    source,
    phrase,
    triggerCount: wakeState.triggerCount,
  });
  return wakeStatusSnapshot();
}

function normalizeConversationStatus(value) {
  const status = String(value || '').trim().toLowerCase();
  return ['idle', 'connecting', 'live', 'error'].includes(status) ? status : '';
}

function normalizeConversationMicMode(value) {
  return String(value || '').trim().toLowerCase() === 'push' ? 'push' : 'open';
}

function conversationMicrophoneSnapshot(conversation = conversationState) {
  const status = normalizeConversationStatus(conversation.status) || 'idle';
  const active = status === 'connecting' || status === 'live';
  const requestedMode = normalizeConversationMicMode(conversation.micMode);
  const state = active
    ? requestedMode === 'push'
      ? 'armed'
      : 'open'
    : 'off';
  return {
    active,
    state,
    label: state === 'off' ? 'Mic off' : state === 'armed' ? 'Push-to-talk armed' : 'Mic open',
    requestedMode,
    realtimeStatus: status,
    realtimePathActive: active,
    startsMicrophone: active,
    usesRealtime: active,
    summary: active
      ? requestedMode === 'push'
        ? 'Realtime voice path is active with push-to-talk armed.'
        : 'Realtime voice path is active with open microphone mode.'
      : 'No Realtime voice session is active; the resident is not using the microphone.',
  };
}

function normalizeRealtimeSessionNegotiation(options = {}) {
  return {
    source: compactRecordText(options.source || 'api', 80),
    sessionId: String(options.sessionId || conversationState.sessionId || '').slice(0, 120),
    micMode: normalizeConversationMicMode(options.micMode),
    model: compactRecordText(options.model || models.realtime, 80),
    voice: compactRecordText(options.voice || models.realtimeVoice, 80),
    offerBytes: boundedCount(options.offerBytes, 10_000_000),
    answerBytes: boundedCount(options.answerBytes, 10_000_000),
    statusCode: boundedCount(options.statusCode, 999),
    ok: Boolean(options.ok),
    durationMs: boundedCount(options.durationMs, 600000),
    error: compactRecordText(options.error || '', 300),
    createdAt: Date.now(),
  };
}

function normalizeRealtimeProviderProbe(options = {}) {
  return {
    kind: 'provider_probe',
    source: compactRecordText(options.source || 'api', 80),
    runId: String(options.runId || realtimeProviderProbeState.runId || '').slice(0, 120),
    sessionId: String(options.sessionId || '').slice(0, 120),
    micMode: normalizeConversationMicMode(options.micMode || 'open'),
    model: compactRecordText(options.model || models.realtime, 80),
    voice: compactRecordText(options.voice || models.realtimeVoice, 80),
    offerBytes: boundedCount(options.offerBytes, 10_000_000),
    answerBytes: boundedCount(options.answerBytes, 10_000_000),
    statusCode: boundedCount(options.statusCode, 999),
    ok: Boolean(options.ok),
    durationMs: boundedCount(options.durationMs, 600000),
    startsMicrophone: false,
    requiresMicConfirmation: false,
    error: compactRecordText(options.error || '', 300),
    createdAt: Date.now(),
  };
}

function parseRealtimeErrorPayload(value) {
  if (!value) return '';
  if (typeof value === 'string') {
    const text = value.trim();
    if (!text) return '';
    if ((text.startsWith('{') && text.endsWith('}')) || (text.startsWith('[') && text.endsWith(']'))) {
      try {
        const parsed = JSON.parse(text);
        const parsedText = parseRealtimeErrorPayload(parsed);
        return parsedText || text;
      } catch {
        return text;
      }
    }
    return text;
  }
  if (Array.isArray(value)) {
    return value.map(parseRealtimeErrorPayload).filter(Boolean).join(' ');
  }
  if (typeof value === 'object') {
    return [
      value.message,
      value.code,
      value.type,
      value.error,
      value.error?.message,
      value.error?.code,
      value.error?.type,
      value.details,
    ].map(parseRealtimeErrorPayload).filter(Boolean).join(' ');
  }
  return String(value);
}

function realtimeNegotiationFromAuditEvent(event = {}) {
  if (event.type !== 'realtime.session_negotiation') return null;
  const data = event.data || {};
  const createdAt = Date.parse(event.ts || '') || 0;
  if (!createdAt || Date.now() - createdAt > REALTIME_PROVIDER_WARNING_MAX_AGE_MS) return null;
  return {
    source: compactRecordText(data.source || 'audit', 80),
    sessionId: String(data.sessionId || '').slice(0, 120),
    micMode: normalizeConversationMicMode(data.micMode),
    model: compactRecordText(data.model || models.realtime, 80),
    voice: compactRecordText(data.voice || models.realtimeVoice, 80),
    offerBytes: boundedCount(data.offerBytes, 10_000_000),
    answerBytes: boundedCount(data.answerBytes, 10_000_000),
    statusCode: boundedCount(data.statusCode, 999),
    ok: Boolean(data.ok),
    durationMs: boundedCount(data.durationMs, 600000),
    error: compactRecordText(data.error || '', 300),
    createdAt,
    auditTs: event.ts || '',
    fromAudit: true,
  };
}

function latestRealtimeNegotiationAuditSnapshot(limit = 80) {
  const events = readRecentAudit(limit);
  for (let index = events.length - 1; index >= 0; index -= 1) {
    const negotiation = realtimeNegotiationFromAuditEvent(events[index]);
    if (negotiation) return negotiation;
  }
  return null;
}

function latestRealtimeNegotiationSnapshot(conversation, options = {}) {
  const current = recentRealtimeProviderCheckSnapshot(conversation?.lastRealtimeSessionNegotiation || null);
  const audit = options.includeRecentAudit ? latestRealtimeNegotiationAuditSnapshot() : null;
  if (!current) return audit;
  if (!audit) return current;
  return Number(audit.createdAt || 0) > Number(current.createdAt || 0) ? audit : current;
}

function realtimeProviderProbeFromAuditEvent(event = {}) {
  if (event.type !== 'realtime.provider_probe') return null;
  const data = event.data || {};
  const createdAt = Date.parse(event.ts || '') || 0;
  if (!createdAt || Date.now() - createdAt > REALTIME_PROVIDER_WARNING_MAX_AGE_MS) return null;
  return {
    kind: 'provider_probe',
    source: compactRecordText(data.source || 'audit', 80),
    runId: String(data.runId || '').slice(0, 120),
    sessionId: String(data.sessionId || '').slice(0, 120),
    micMode: normalizeConversationMicMode(data.micMode || 'open'),
    model: compactRecordText(data.model || models.realtime, 80),
    voice: compactRecordText(data.voice || models.realtimeVoice, 80),
    offerBytes: boundedCount(data.offerBytes, 10_000_000),
    answerBytes: boundedCount(data.answerBytes, 10_000_000),
    statusCode: boundedCount(data.statusCode, 999),
    ok: Boolean(data.ok),
    durationMs: boundedCount(data.durationMs, 600000),
    startsMicrophone: false,
    requiresMicConfirmation: false,
    error: compactRecordText(data.error || '', 300),
    createdAt,
    auditTs: event.ts || '',
    fromAudit: true,
  };
}

function latestRealtimeProviderProbeAuditSnapshot(limit = 300) {
  const events = readRecentAudit(limit);
  for (let index = events.length - 1; index >= 0; index -= 1) {
    const probe = realtimeProviderProbeFromAuditEvent(events[index]);
    if (probe) return probe;
  }
  return null;
}

function latestRealtimeProviderProbeResultSnapshot(options = {}) {
  const current = recentRealtimeProviderCheckSnapshot(realtimeProviderProbeState.result || null);
  const audit = options.includeRecentAudit ? latestRealtimeProviderProbeAuditSnapshot() : null;
  if (!current) return audit;
  if (!audit) return current;
  return Number(audit.createdAt || 0) > Number(current.createdAt || 0) ? audit : current;
}

function recentRealtimeProviderCheckSnapshot(check = null) {
  if (!check || typeof check !== 'object') return null;
  const createdAt = Number(check.createdAt || 0);
  if (!createdAt || Date.now() - createdAt > REALTIME_PROVIDER_WARNING_MAX_AGE_MS) return null;
  return check;
}

function classifyRealtimeProviderIssue(details = {}) {
  const statusCode = Number(details.statusCode || 0);
  const rawError = parseRealtimeErrorPayload(details.error || '');
  const text = `${statusCode || ''} ${rawError}`.toLowerCase();
  if (!rawError && !statusCode && details.ok !== false) return null;
  if (statusCode === 429 || /insufficient[_ -]?quota|quota|billing|rate[_ -]?limit|too many requests|exceeded your current quota/i.test(text)) {
    return {
      kind: 'quota_or_rate_limit',
      status: 'warning',
      summary: statusCode === 429
        ? 'Realtime voice last hit an OpenAI quota/rate-limit error (HTTP 429).'
        : 'Realtime voice last hit an OpenAI quota or billing error.',
      next: OPENAI_API_KEY
        ? 'OPENAI_API_KEY is loaded, but the OpenAI API project is out of usable quota or rate-limited. ChatGPT app subscriptions do not cover API/Realtime usage; add API Platform billing/credits, raise project limits, or replace OPENAI_API_KEY with a project key that has Realtime quota, then restart JAVIS.'
        : 'Add OPENAI_API_KEY to .env, confirm the project has Realtime quota, then restart JAVIS.',
    };
  }
  if ([401, 403].includes(statusCode) || /invalid[_ -]?api[_ -]?key|incorrect api key|unauthorized|forbidden|permission denied|not allowed/i.test(text)) {
    return {
      kind: 'auth_or_permission',
      status: 'blocked',
      summary: `Realtime voice provider rejected auth or permissions${statusCode ? ` (HTTP ${statusCode})` : ''}.`,
      next: 'Update OPENAI_API_KEY, confirm the project has Realtime access, then restart JAVIS.',
    };
  }
  if (statusCode >= 400 || details.ok === false) {
    return {
      kind: 'provider_error',
      status: 'warning',
      summary: `Realtime voice last provider call failed${statusCode ? ` (HTTP ${statusCode})` : ''}.`,
      next: 'Open the terminal CUI Realtime evidence monitor or retry a live voice session after checking provider status.',
    };
  }
  if (/fetch failed|network|timeout|timed out|econn|enotfound|socket/i.test(text)) {
    return {
      kind: 'network',
      status: 'warning',
      summary: 'Realtime voice last failed before reaching the provider.',
      next: 'Check network connectivity and retry a live voice session.',
    };
  }
  return null;
}

function realtimeProviderProbeSpendGuardDecision(source = 'realtime_provider_probe_status') {
  return evaluateOpenAiSpendGuard({
    kind: 'realtime_provider_probe',
    source,
    model: models.realtime,
    isProviderProbe: true,
    reserve: false,
    recordBlocked: false,
  });
}

function compactOpenAiSpendGuardDecision(decision = {}) {
  const state = decision.state || openAiSpendGuardSnapshot();
  return {
    allowed: Boolean(decision.allowed),
    reasons: Array.isArray(decision.reasons)
      ? decision.reasons.map((reason) => compactRecordText(reason, 120)).filter(Boolean).slice(0, 12)
      : [],
    summary: compactRecordText(decision.summary || '', 260),
    mode: compactRecordText(state.mode || decision.mode || OPENAI_CLOUD_MODE, 40),
    hardSpendLock: Boolean(state.hardSpendLock ?? decision.hardSpendLock ?? OPENAI_HARD_SPEND_LOCK),
    dailyRequestLimit: Number(state.dailyRequestLimit ?? OPENAI_DAILY_REQUEST_LIMIT),
    unattendedDailyRequestLimit: Number(state.unattendedDailyRequestLimit ?? OPENAI_UNATTENDED_DAILY_REQUEST_LIMIT),
    remaining: {
      total: Math.max(0, Number(state.remaining?.total ?? 0)),
      unattended: Math.max(0, Number(state.remaining?.unattended ?? 0)),
    },
    requireSpendConfirmationPhrase: Boolean(state.requireSpendConfirmationPhrase ?? OPENAI_REQUIRE_SPEND_CONFIRMATION_PHRASE),
    requireSpendLease: Boolean(state.requireSpendLease ?? OPENAI_REQUIRE_SPEND_LEASE),
    activeSpendLeases: Math.max(0, Number(state.spendLease?.activeCount ?? 0)),
    zeroSpendMode: openAiZeroSpendModeActive(),
  };
}

function openAiSpendGuardBlocksRealtimeProviderProbe(decision = null) {
  const guard = decision || realtimeProviderProbeSpendGuardDecision();
  return Boolean(OPENAI_API_KEY && guard.allowed === false && Array.isArray(guard.reasons) && guard.reasons.length);
}

function realtimeProviderRetryPolicySnapshot(issue = null, options = {}) {
  const active = Boolean(issue && issue.status !== 'ready');
  const freshness = options.freshness || realtimeProviderProbeFreshness();
  const spendLocked = issue?.kind === 'spend_locked';
  const state = !active
    ? 'ready'
    : spendLocked
      ? 'spend_locked'
      : freshness.running
      ? 'probe_running'
      : freshness.fresh
        ? 'cooldown'
        : 'probe_due';
  const spendGuard = spendLocked
    ? compactOpenAiSpendGuardDecision(issue.spendGuardDecision || realtimeProviderProbeSpendGuardDecision('realtime_provider_retry_policy'))
    : null;
  return {
    version: 1,
    active,
    state,
    canProbeNow: Boolean(OPENAI_API_KEY && active && !spendLocked && !freshness.running && !freshness.fresh),
    shouldUseLocalFallback: active,
    requiresOpenAiSpendUnlock: spendLocked,
    spendGuard,
    cooldownMs: Math.max(0, Number(freshness.cooldownMs || REALTIME_PROVIDER_PROBE_FRESH_MS)),
    waitMs: Math.max(0, Number(freshness.waitMs || 0)),
    waitLabel: compactRecordText(freshness.waitLabel || '', 40),
    lastCheck: freshness.latest
      ? {
        at: compactRecordText(freshness.latest.at || '', 80),
        status: compactRecordText(freshness.latest.status || '', 80),
        source: compactRecordText(freshness.latest.source || '', 80),
      }
      : null,
    nextCommand: 'npm run dogfood:realtime-provider-probe',
    runCommand: 'npm run dogfood:realtime-provider-probe:run',
    safety: {
      startsMicrophone: false,
      requiresMicConfirmation: false,
      storesRawAudio: false,
    },
  };
}

function realtimeProviderRecoverySnapshot(issue = null, options = {}) {
  const kind = compactRecordText(issue?.kind || '', 80);
  const status = compactRecordText(issue?.status || 'ready', 80);
  const quotaLike = kind === 'quota_or_rate_limit';
  const spendLocked = kind === 'spend_locked';
  const active = Boolean(issue && status !== 'ready');
  const billingUrl = 'https://platform.openai.com/settings/organization/billing/overview';
  const limitsUrl = 'https://platform.openai.com/settings/organization/limits';
  const keysUrl = 'https://platform.openai.com/api-keys';
  const steps = [];

  if (!OPENAI_API_KEY || kind === 'missing_key') {
    steps.push({
      id: 'add_api_key',
      label: 'Add an OpenAI API key',
      detail: 'Add OPENAI_API_KEY to the local .env file for an API project that has Realtime access.',
      command: 'npm run config',
      action: 'prepare_env_file',
    });
  }

  if (spendLocked) {
    steps.push(
      {
        id: 'review_openai_spend_guard',
        label: 'Review OpenAI spend guard',
        detail: 'Confirm the local guard is intentionally in zero-spend mode before enabling any provider check.',
        command: 'npm run openai:spend',
      },
      {
        id: 'unlock_one_provider_probe',
        label: 'Unlock one provider check',
        detail: 'Only when you are present, disable the hard lock, set a positive daily limit, restart JAVIS, create a one-request spend lease with the exact phrase, then run the probe.',
        command: 'npm run config -- --print-openai-spend-guard',
      },
      {
        id: 'run_provider_probe_after_unlock',
        label: 'Run no-mic provider probe after unlock',
        detail: 'This command can spend one OpenAI API request only after the guard and one-request lease allow it.',
        command: 'npm run dogfood:realtime-provider-probe:run',
      },
    );
  } else if (quotaLike) {
    steps.push(
      {
        id: 'open_api_billing',
        label: 'Open API billing',
        detail: 'OpenAI API usage is billed separately from ChatGPT subscriptions; add billing/credits to the API organization that owns this key.',
        url: billingUrl,
        action: 'open_openai_platform_billing',
      },
      {
        id: 'check_api_limits',
        label: 'Check API limits',
        detail: 'Confirm the project has enough budget/rate-limit headroom for Realtime calls.',
        url: limitsUrl,
        action: 'open_openai_platform_limits',
      },
      {
        id: 'replace_project_key',
        label: 'Replace project key if needed',
        detail: 'If the current project has no quota, create or paste a key from a project with Realtime quota.',
        url: keysUrl,
        command: 'npm run config',
      },
    );
  } else if (kind === 'auth_or_permission') {
    steps.push({
      id: 'replace_api_key',
      label: 'Replace API key',
      detail: 'Update OPENAI_API_KEY and confirm the API project has permission to call Realtime.',
      url: keysUrl,
      command: 'npm run config',
      action: 'prepare_env_file',
    });
  } else if (kind === 'provider_unverified') {
    steps.push({
      id: 'run_provider_probe',
      label: 'Run no-mic provider probe',
      detail: 'Verify the key/project/model/voice path before opening the microphone.',
      command: 'npm run dogfood:realtime-provider-probe:run',
    });
  } else if (kind === 'network' || kind === 'provider_error') {
    steps.push({
      id: 'retry_provider_probe',
      label: 'Retry provider probe',
      detail: 'Retry the no-mic provider probe after checking network/provider status.',
      command: 'npm run dogfood:realtime-provider-probe:run',
    });
  }

  if (active && !spendLocked) {
    steps.push({
      id: 'restart_and_probe',
      label: 'Restart and probe again',
      detail: 'After billing/key/limit changes, restart JAVIS and rerun the no-mic provider probe before live voice.',
      command: 'npm run resident:restart && npm run dogfood:realtime-provider-probe:run',
    });
  }

  const providerProbeFreshness = realtimeProviderProbeFreshness();
  const retryPolicy = realtimeProviderRetryPolicySnapshot(issue, { freshness: providerProbeFreshness });

  return {
    version: 1,
    active,
    kind,
    status,
    summary: spendLocked
      ? 'OpenAI zero-spend guard is intentionally blocking the paid no-mic Realtime provider probe; local voice fallback remains available.'
      : quotaLike
      ? 'OpenAI Realtime reached the API, but the API project has no usable quota/billing/rate-limit headroom.'
      : compactRecordText(issue?.summary || 'Realtime provider is ready or has no current recovery issue.', 260),
    next: compactRecordText(issue?.next || (steps[0]?.detail || ''), 320),
    chatGptSubscriptionCoversApi: false,
    subscriptionBoundary: 'ChatGPT app subscriptions and OpenAI API Platform billing are separate; API/Realtime usage needs API billing or credits on the project/org that owns OPENAI_API_KEY.',
    billingLikely: quotaLike,
    spendLocked,
    spendGuard: spendLocked
      ? compactOpenAiSpendGuardDecision(issue.spendGuardDecision || realtimeProviderProbeSpendGuardDecision('realtime_provider_recovery'))
      : null,
    retryPolicy,
    links: {
      billing: billingUrl,
      limits: limitsUrl,
      apiKeys: keysUrl,
      help: 'https://help.openai.com/en/articles/9039756-managing-billing-settings-on-chatgpt-web-and-platform',
    },
    steps,
    autoProbe: {
      actionId: 'readiness:realtime_voice_provider',
      available: Boolean(OPENAI_API_KEY && !spendLocked),
      autopilotEligible: false,
      manualOnlyReason: spendLocked
        ? 'OpenAI zero-spend guard is active; provider probes stay disabled until the user intentionally unlocks one request.'
        : 'Provider probes can consume OpenAI API quota and require explicit user action.',
      cooldownMs: REALTIME_PROVIDER_PROBE_FRESH_MS,
      due: Boolean(OPENAI_API_KEY && active && !spendLocked && !providerProbeFreshness.fresh),
      running: Boolean(providerProbeFreshness.running),
      freshness: compactRealtimePreflightFreshness(providerProbeFreshness),
      safety: {
        startsMicrophone: false,
        requiresMicConfirmation: false,
        usesRealtime: true,
        storesRawAudio: false,
      },
    },
    localFallback: {
      available: true,
      command: 'npm run voice:chat',
      oneShotCommand: 'npm run voice -- "..."',
      endpoint: '/api/voice/command',
      summary: 'Use local voice-command fallback for typed or future local-STT transcripts while live Realtime voice is unavailable.',
    },
    safety: {
      startsMicrophone: false,
      usesRealtime: false,
      storesRawAudio: false,
      opensBrowserOnlyOnUserAction: true,
    },
    source: compactRecordText(options.source || 'realtime_voice_health', 80),
  };
}

function realtimeProviderUnverifiedIssue() {
  return {
    kind: 'provider_unverified',
    status: 'warning',
    summary: 'Realtime voice provider has not been verified by a recent no-mic probe or live WebRTC negotiation.',
    next: 'Preview with npm run dogfood:realtime-provider-probe, then explicitly run npm run dogfood:realtime-provider-probe:run to verify OpenAI Realtime without starting the microphone.',
  };
}

function realtimeProviderSpendLockedIssue(decision = null) {
  const spendGuardDecision = decision || realtimeProviderProbeSpendGuardDecision('realtime_provider_spend_locked_issue');
  const spendGuard = compactOpenAiSpendGuardDecision(spendGuardDecision);
  return {
    kind: 'spend_locked',
    status: 'warning',
    summary: 'Realtime provider probe is waiting behind the OpenAI zero-spend guard; no provider request will run until the user explicitly unlocks one check.',
    next: 'Use local voice fallback now. To verify Realtime later, review npm run openai:spend, disable the hard lock/set a positive daily limit, create a one-request spend lease with the exact phrase, then run npm run dogfood:realtime-provider-probe:run.',
    spendGuard,
    spendGuardDecision,
  };
}

function realtimeLocalVoiceFallbackSnapshot(issue = null) {
  const blockedByQuota = issue?.kind === 'quota_or_rate_limit';
  const spendLocked = issue?.kind === 'spend_locked';
  const providerBlocked = Boolean(issue && ['missing_key', 'spend_locked', 'provider_unverified', 'quota_or_rate_limit', 'auth_or_permission', 'provider_error', 'network'].includes(issue.kind));
  const blocker = {
    active: Boolean(issue),
    kind: compactRecordText(issue?.kind || '', 80),
    status: compactRecordText(issue?.status || '', 80),
    summary: compactRecordText(issue?.summary || '', 220),
    next: compactRecordText(issue?.next || '', 260),
  };
  return {
    available: true,
    activeWhenRealtimeBlocked: providerBlocked,
    lane: 'local_voice_command',
    endpoint: '/api/voice/command',
    dogfoodCommand: 'npm run dogfood:voice-command -- --include-screen --include-accessibility',
    summary: blockedByQuota
      ? 'Realtime quota is blocked, but local voice-command fallback can still route typed or tap transcripts with Mac context and local speech.'
      : spendLocked
        ? 'OpenAI zero-spend guard is active, so local voice-command fallback is the default no-cost lane.'
      : 'Local voice-command fallback can route typed or tap transcripts without starting Realtime.',
    next: blockedByQuota
      ? 'Use the local voice-command fallback for task routing now; add API quota later to restore live WebRTC voice.'
      : spendLocked
        ? 'Keep using local no-mic intake; unlock exactly one provider check only when you are present and want to spend one API request.'
      : 'Use this fallback when live Realtime is unavailable or when a no-mic preview is safer.',
    blocker,
    safety: {
      startsMicrophone: false,
      usesRealtime: false,
      storesRawAudio: false,
      speaksWithMacTts: true,
      screenContextMetadataOnly: true,
      accessibilityOutlineOnly: true,
    },
  };
}

function realtimeVoiceHealthSnapshot(options = {}) {
  const conversation = options.conversation || conversationStateSnapshot();
  const negotiation = latestRealtimeNegotiationSnapshot(conversation, {
    includeRecentAudit: options.includeRecentAudit === true,
  });
  const providerProbe = latestRealtimeProviderProbeResultSnapshot({
    includeRecentAudit: options.includeRecentAudit === true,
  });
  const providerCheck = !negotiation
    ? providerProbe
    : !providerProbe
      ? negotiation
      : Number(providerProbe.createdAt || 0) > Number(negotiation.createdAt || 0)
        ? providerProbe
        : negotiation;
  const errorText = parseRealtimeErrorPayload(providerCheck?.error || conversation?.error || '');
  const statusCode = Number(providerCheck?.statusCode || 0);
  const lastSuccess = Boolean(providerCheck?.ok && (!statusCode || (statusCode >= 200 && statusCode < 300)));
  const spendGuardDecision = OPENAI_API_KEY
    ? realtimeProviderProbeSpendGuardDecision('realtime_voice_health')
    : null;
  const issue = OPENAI_API_KEY
    ? classifyRealtimeProviderIssue({
      ok: providerCheck?.ok,
      statusCode,
      error: errorText,
    }) || (lastSuccess ? null : (openAiSpendGuardBlocksRealtimeProviderProbe(spendGuardDecision)
      ? realtimeProviderSpendLockedIssue(spendGuardDecision)
      : realtimeProviderUnverifiedIssue()))
    : {
      kind: 'missing_key',
      status: 'blocked',
      summary: 'Realtime voice cannot start because OPENAI_API_KEY is missing.',
      next: 'Add OPENAI_API_KEY to .env and restart JAVIS.',
    };
  const status = issue?.status || 'ready';
  const summary = issue?.summary
    || (lastSuccess
      ? providerCheck.kind === 'provider_probe'
        ? `Last no-mic Realtime provider probe succeeded${providerCheck.statusCode ? ` (HTTP ${providerCheck.statusCode})` : ''}.`
        : `Last Realtime WebRTC negotiation succeeded${providerCheck.statusCode ? ` (HTTP ${providerCheck.statusCode})` : ''}.`
      : realtimeProviderUnverifiedIssue().summary);
  const recovery = realtimeProviderRecoverySnapshot(issue, { source: 'voice_health' });
  return {
    ok: status !== 'blocked',
    status,
    kind: issue?.kind || (lastSuccess ? (providerCheck.kind === 'provider_probe' ? 'provider_probe_success' : 'last_success') : 'no_provider_error'),
    summary,
    next: issue?.next || '',
    hasOpenAiKey: Boolean(OPENAI_API_KEY),
    maxAuditAgeMs: REALTIME_PROVIDER_WARNING_MAX_AGE_MS,
    recovery,
    retryPolicy: recovery.retryPolicy || null,
    fallback: realtimeLocalVoiceFallbackSnapshot(issue),
    lastNegotiation: negotiation,
    lastProviderProbe: providerProbe,
    lastProviderCheck: providerCheck,
    error: compactRecordText(errorText, 300),
  };
}

function recordRealtimeSessionNegotiation(options = {}) {
  const negotiation = normalizeRealtimeSessionNegotiation(options);
  if (options.dryRun === true) {
    return { ok: true, dryRun: true, negotiation, conversation: conversationStateSnapshot() };
  }
  conversationState = {
    ...conversationState,
    realtimeSessionNegotiationCount: Number(conversationState.realtimeSessionNegotiationCount || 0) + 1,
    lastRealtimeSessionNegotiation: negotiation,
    updatedAt: Date.now(),
  };
  appendAudit('realtime.session_negotiation', {
    sessionId: negotiation.sessionId,
    source: negotiation.source,
    micMode: negotiation.micMode,
    model: negotiation.model,
    voice: negotiation.voice,
    offerBytes: negotiation.offerBytes,
    answerBytes: negotiation.answerBytes,
    statusCode: negotiation.statusCode,
    ok: negotiation.ok,
    durationMs: negotiation.durationMs,
    error: negotiation.error,
  });
  return { ok: true, negotiation, conversation: conversationStateSnapshot() };
}

function recordRealtimeProviderProbe(options = {}) {
  const probe = normalizeRealtimeProviderProbe(options);
  if (options.dryRun === true) {
    return { ok: true, dryRun: true, probe: realtimeProviderProbeSnapshot({ result: probe }) };
  }
  const now = Date.now();
  realtimeProviderProbeState = {
    ...realtimeProviderProbeState,
    active: false,
    runId: probe.runId || realtimeProviderProbeState.runId,
    status: probe.ok ? 'ok' : 'error',
    source: probe.source,
    startsMicrophone: false,
    requiresMicConfirmation: false,
    updatedAt: now,
    completedAt: now,
    result: probe,
    error: probe.error,
  };
  appendAudit('realtime.provider_probe', {
    runId: probe.runId,
    sessionId: probe.sessionId,
    source: probe.source,
    micMode: probe.micMode,
    model: probe.model,
    voice: probe.voice,
    offerBytes: probe.offerBytes,
    answerBytes: probe.answerBytes,
    statusCode: probe.statusCode,
    ok: probe.ok,
    durationMs: probe.durationMs,
    startsMicrophone: false,
    requiresMicConfirmation: false,
    error: probe.error,
  });
  return { ok: true, probe: realtimeProviderProbeSnapshot() };
}

function normalizeRealtimeLatencyTimestamp(value) {
  const number = Number(value || 0);
  if (!Number.isFinite(number) || number <= 0) return 0;
  return Math.max(0, Math.min(4102444800000, number));
}

function realtimeLatencyDelta(start, end, max = 600000) {
  const left = normalizeRealtimeLatencyTimestamp(start);
  const right = normalizeRealtimeLatencyTimestamp(end);
  if (!left || !right || right < left) return 0;
  return Math.max(0, Math.min(max, right - left));
}

function realtimeLatencyQuality(latency = {}) {
  const startToLiveMs = Number(latency.startToLiveMs || 0);
  if (!startToLiveMs) return latency.ok === false ? 'failed_before_live' : 'pending_live';
  if (startToLiveMs <= 4000) return 'fast';
  if (startToLiveMs <= 8000) return 'usable';
  return 'slow';
}

function normalizeRealtimeLatencyReceipt(options = {}) {
  const startedAt = normalizeRealtimeLatencyTimestamp(options.startedAt || options.startAt);
  const micReadyAt = normalizeRealtimeLatencyTimestamp(options.micReadyAt);
  const offerCreatedAt = normalizeRealtimeLatencyTimestamp(options.offerCreatedAt);
  const negotiationStartedAt = normalizeRealtimeLatencyTimestamp(options.negotiationStartedAt);
  const answerReceivedAt = normalizeRealtimeLatencyTimestamp(options.answerReceivedAt);
  const remoteDescriptionAt = normalizeRealtimeLatencyTimestamp(options.remoteDescriptionAt);
  const dataChannelOpenAt = normalizeRealtimeLatencyTimestamp(options.dataChannelOpenAt || options.liveAt);
  const firstProgressInjectionAt = normalizeRealtimeLatencyTimestamp(options.firstProgressInjectionAt);
  const endedAt = normalizeRealtimeLatencyTimestamp(options.endedAt);
  const errorAt = normalizeRealtimeLatencyTimestamp(options.errorAt);
  const liveAt = dataChannelOpenAt;
  const receipt = {
    source: compactRecordText(options.source || 'renderer', 80),
    sessionId: String(options.sessionId || conversationState.sessionId || '').slice(0, 120),
    micMode: normalizeConversationMicMode(options.micMode),
    screenLive: Boolean(options.screenLive),
    ok: options.ok !== false,
    status: compactRecordText(options.status || (errorAt ? 'error' : endedAt ? 'ended' : liveAt ? 'live' : 'starting'), 40),
    stage: compactRecordText(options.stage || (errorAt ? 'error' : endedAt ? 'ended' : firstProgressInjectionAt ? 'progress_injected' : liveAt ? 'live' : answerReceivedAt ? 'answer_received' : negotiationStartedAt ? 'negotiating' : micReadyAt ? 'mic_ready' : 'starting'), 80),
    model: compactRecordText(options.model || models.realtime, 80),
    voice: compactRecordText(options.voice || models.realtimeVoice, 80),
    startedAt,
    micReadyAt,
    offerCreatedAt,
    negotiationStartedAt,
    answerReceivedAt,
    remoteDescriptionAt,
    dataChannelOpenAt,
    firstProgressInjectionAt,
    endedAt,
    errorAt,
    micReadyMs: realtimeLatencyDelta(startedAt, micReadyAt),
    offerReadyMs: realtimeLatencyDelta(startedAt, offerCreatedAt),
    negotiationMs: realtimeLatencyDelta(negotiationStartedAt, answerReceivedAt),
    answerToRemoteDescriptionMs: realtimeLatencyDelta(answerReceivedAt, remoteDescriptionAt),
    remoteDescriptionToLiveMs: realtimeLatencyDelta(remoteDescriptionAt, liveAt),
    startToLiveMs: realtimeLatencyDelta(startedAt, liveAt),
    liveToFirstProgressMs: realtimeLatencyDelta(liveAt, firstProgressInjectionAt),
    totalSessionMs: realtimeLatencyDelta(startedAt, endedAt || errorAt || 0, 12 * 60 * 60 * 1000),
    error: compactRecordText(options.error || '', 300),
    createdAt: Date.now(),
  };
  receipt.quality = realtimeLatencyQuality(receipt);
  return receipt;
}

function recordRealtimeLatencyReceipt(options = {}) {
  const latency = normalizeRealtimeLatencyReceipt(options);
  if (options.dryRun === true) {
    return { ok: true, dryRun: true, latency, conversation: conversationStateSnapshot() };
  }
  conversationState = {
    ...conversationState,
    realtimeLatencyReceiptCount: Number(conversationState.realtimeLatencyReceiptCount || 0) + 1,
    lastRealtimeLatencyReceipt: latency,
    updatedAt: Date.now(),
  };
  appendAudit('realtime.latency', {
    sessionId: latency.sessionId,
    source: latency.source,
    stage: latency.stage,
    status: latency.status,
    quality: latency.quality,
    ok: latency.ok,
    micReadyMs: latency.micReadyMs,
    negotiationMs: latency.negotiationMs,
    startToLiveMs: latency.startToLiveMs,
    liveToFirstProgressMs: latency.liveToFirstProgressMs,
    totalSessionMs: latency.totalSessionMs,
    error: latency.error,
  });
  return { ok: true, latency, conversation: conversationStateSnapshot() };
}

function boundedCount(value, max = 100000) {
  return Math.max(0, Math.min(max, Number(value || 0)));
}

function normalizeRealtimeProgressInjectionGroup(group = {}) {
  return {
    owner: compactRecordText(group.owner || '', 50),
    lane: compactRecordText(group.lane || '', 40),
    parallelGroup: compactRecordText(group.parallelGroup || '', 70),
    active: boundedCount(group.active, 1000),
    done: boundedCount(group.done, 1000),
    failed: boundedCount(group.failed, 1000),
  };
}

function normalizeRealtimeProgressInjection(options = {}) {
  const groups = Array.isArray(options.groups)
    ? options.groups.slice(0, 5).map(normalizeRealtimeProgressInjectionGroup)
    : [];
  return {
    source: compactRecordText(options.source || 'renderer', 80),
    sessionId: String(options.sessionId || conversationState.sessionId || '').slice(0, 120),
    status: conversationStateSnapshot().status,
    transport: compactRecordText(options.transport || (options.source === 'renderer' ? 'webrtc-datachannel' : 'api'), 80),
    dataChannelReadyState: compactRecordText(options.dataChannelReadyState || '', 40),
    eventType: compactRecordText(options.eventType || '', 80),
    eventRole: compactRecordText(options.eventRole || '', 40),
    contentType: compactRecordText(options.contentType || '', 40),
    forcedResponse: Boolean(options.forcedResponse),
    responseActive: Boolean(options.responseActive),
    progressSequence: boundedCount(options.progressSequence, 1000000000),
    progressUpdatedAt: boundedCount(options.progressUpdatedAt, 4102444800000),
    progressSource: compactRecordText(options.progressSource || '', 80),
    voiceStatus: compactRecordText(options.voiceStatus || '', 40),
    micMode: normalizeConversationMicMode(options.micMode),
    screenLive: Boolean(options.screenLive),
    contextLength: boundedCount(options.contextLength, 200000),
    contextPreview: compactRecordText(options.contextPreview || '', 300),
    workerSummary: compactRecordText(options.workerSummary || '', 300),
    workerGroups: boundedCount(options.workerGroups ?? groups.length, 1000),
    activeWorkerGroups: boundedCount(options.activeWorkerGroups, 1000),
    activeWorkers: boundedCount(options.activeWorkers, 1000),
    doneWorkers: boundedCount(options.doneWorkers, 100000),
    failedWorkers: boundedCount(options.failedWorkers, 100000),
    activeJobs: boundedCount(options.activeJobs, 100000),
    activeWorkflows: boundedCount(options.activeWorkflows, 100000),
    blockedWorkflows: boundedCount(options.blockedWorkflows, 100000),
    activeRoutes: boundedCount(options.activeRoutes, 100000),
    groups,
    createdAt: Date.now(),
  };
}

function recordRealtimeProgressInjection(options = {}) {
  const snapshot = conversationStateSnapshot();
  const injection = normalizeRealtimeProgressInjection(options);
  if (options.dryRun === true) {
    return { ok: true, dryRun: true, injection, conversation: snapshot };
  }
  if (snapshot.status !== 'live') {
    appendAudit('realtime.progress_injection_ignored', {
      reason: 'conversation_not_live',
      status: snapshot.status,
      source: injection.source,
      workerSummary: injection.workerSummary,
    });
    return { ok: false, ignored: true, reason: 'conversation_not_live', injection, conversation: snapshot };
  }
  if (snapshot.sessionId && injection.sessionId && snapshot.sessionId !== injection.sessionId) {
    appendAudit('realtime.progress_injection_ignored', {
      reason: 'session_mismatch',
      currentSessionId: snapshot.sessionId,
      incomingSessionId: injection.sessionId,
      source: injection.source,
    });
    return { ok: false, ignored: true, reason: 'session_mismatch', injection, conversation: snapshot };
  }

  const now = Date.now();
  conversationState = {
    ...conversationState,
    sessionId: conversationState.sessionId || injection.sessionId,
    updatedAt: now,
    lastHeartbeatAt: conversationState.status === 'live' ? now : conversationState.lastHeartbeatAt,
    realtimeProgressInjectionCount: Number(conversationState.realtimeProgressInjectionCount || 0) + 1,
    lastRealtimeProgressInjection: injection,
  };
  appendAudit('realtime.progress_injection', {
    sessionId: injection.sessionId,
    source: injection.source,
    transport: injection.transport,
    dataChannelReadyState: injection.dataChannelReadyState,
    eventType: injection.eventType,
    forcedResponse: injection.forcedResponse,
    progressSequence: injection.progressSequence,
    progressSource: injection.progressSource,
    voiceStatus: injection.voiceStatus,
    contextLength: injection.contextLength,
    workerSummary: injection.workerSummary,
    workerGroups: injection.workerGroups,
    activeWorkerGroups: injection.activeWorkerGroups,
    activeWorkers: injection.activeWorkers,
    doneWorkers: injection.doneWorkers,
    failedWorkers: injection.failedWorkers,
  });
  return { ok: true, injection, conversation: conversationStateSnapshot() };
}

