function realtimeShortcutRecallEvidence(limit = 5) {
  const recent = routingSnapshot(100)
    .filter((record) => !isInternalRoutingRecord(record))
    .map((record) => ({ record, plan: normalizeSkillRecallPlan(record.skillRecallPlan) }))
    .filter(({ plan }) => plan.applied && plan.decisionEffect === 'shortcut_phrase_matched')
    .slice(0, Math.max(1, Math.min(20, Number(limit || 5))))
    .map(({ record, plan }) => ({
      id: record.id,
      taskTitle: compactRecordText(record.taskTitle, 160),
      lane: record.lane,
      owner: record.owner,
      status: record.status,
      resultLink: record.resultLink,
      primarySkill: plan.primarySkill.name,
      summary: compactRecordText(plan.summary, 220),
      updatedAt: record.updatedAt,
    }));
  return {
    ok: recent.length > 0,
    count: recent.length,
    recent,
    nextAction: recent.length
      ? 'Ask the live voice session to repeat the saved phrase and confirm the route mentions the recalled skill plan.'
      : 'After saving a shortcut phrase, ask the live voice session to use that phrase so routing records shortcut recall evidence.',
  };
}

function realtimeDogfoodShortcutRecallPlan(options = {}) {
  const phrase = compactRecordText(options.phrase || 'javis realtime shortcut recall dogfood', 120);
  const skillName = compactRecordText(options.skillName || 'javis-realtime-shortcut-recall-dogfood', 120);
  return normalizeSkillRecallPlan(options.skillRecallPlan || {
    applied: true,
    matched: 1,
    decisionEffect: 'realtime_dogfood_shortcut_recall',
    summary: 'Realtime dogfood shortcut recall plan. It verifies saved phrases can change routing without executing a skill.',
    primarySkill: {
      name: skillName,
      kind: 'learning',
      summary: 'Dogfood-only shortcut recall proof for local learning and routing.',
    },
    skills: [{
      name: skillName,
      kind: 'learning',
      summary: 'Dogfood-only shortcut recall proof for local learning and routing.',
    }],
    recommendedTools: ['route_task', 'search_local_skills'],
    planSteps: [
      'Match the saved shortcut phrase.',
      'Attach the recalled skill plan to the route preview.',
      'Stop before execution or any local action.',
    ],
    confirmationRequired: true,
    confirmationGates: ['action_policy', 'control_mode', 'explicit_confirmation_for_replay_or_mutation'],
    shortcutCandidate: {
      eligible: true,
      reason: 'Dogfood verifies a saved local shortcut can be routed back into a skillRecallPlan.',
      nextAction: `Use the phrase "${phrase}" in a route preview.`,
    },
  });
}

async function prepareRealtimeDogfoodShortcutRecall(options = {}) {
  const phrase = compactRecordText(options.phrase || 'javis realtime shortcut recall dogfood', 120);
  const task = compactRecordText(options.task || `${phrase} preview the recalled local workflow without executing it`, 420);
  const source = compactRecordText(options.source || 'realtime_dogfood_shortcut_recall', 80);
  const confirm = options.confirm === true || String(options.confirm || '').toLowerCase() === 'true';
  const skillRecallPlan = realtimeDogfoodShortcutRecallPlan({ ...options, phrase });
  const preview = {
    ok: false,
    status: 409,
    requiresConfirmation: true,
    confirmed: false,
    phrase,
    task,
    skillRecallPlan,
    output: `Confirm before saving dogfood shortcut phrase "${phrase}" and routing it as a preview.`,
    safety: {
      localOnly: true,
      startsMicrophone: false,
      startsWorkers: false,
      executesTask: false,
      routePreviewOnly: true,
      writesLocalJson: true,
      confirmationRequired: true,
    },
  };
  if (!confirm) return preview;

  const saved = upsertShortcutFromPromotion({
    phrase,
    title: options.title || 'Realtime dogfood shortcut recall',
    source,
    confirm: true,
    skillRecallPlan,
  });
  const routed = await routeTask({
    message: task,
    execute: false,
    includeScreen: false,
    useMemory: false,
    useShortcuts: true,
    preferShortcuts: true,
    source,
    owner: 'Realtime dogfood',
    scope: 'realtime shortcut recall dogfood',
  });
  const routePlan = normalizeSkillRecallPlan(routed.skillRecallPlan || routed.routing?.skillRecallPlan);
  const recalled = Boolean(routePlan.applied && routePlan.decisionEffect === 'shortcut_phrase_matched');
  const recallEvidence = realtimeShortcutRecallEvidence(5);
  const payload = {
    ok: recalled,
    status: recalled ? 'ready' : 'not_recalled',
    requiresConfirmation: false,
    confirmed: true,
    phrase,
    task,
    shortcut: saved.shortcut
      ? {
        id: saved.shortcut.id,
        phrase: saved.shortcut.phrase,
        primarySkill: saved.shortcut.skillRecallPlan?.primarySkill?.name || '',
        usedCount: Number(saved.shortcut.usedCount || 0),
      }
      : null,
    route: routed.routing
      ? {
        id: routed.routing.id,
        lane: routed.routing.lane,
        owner: routed.routing.owner,
        status: routed.routing.status,
        source: routed.routing.source,
        resultSummary: compactRecordText(routed.routing.resultSummary || routed.output || '', 260),
      }
      : null,
    recalled,
    routeSkillRecall: {
      applied: routePlan.applied,
      decisionEffect: routePlan.decisionEffect,
      primarySkill: routePlan.primarySkill.name,
      summary: routePlan.summary,
    },
    recallEvidence,
    output: recalled
      ? `Shortcut recall ready: "${phrase}" routed to ${routePlan.primarySkill.name} as a preview.`
      : `Shortcut was saved, but route preview did not recall "${phrase}".`,
    safety: {
      localOnly: true,
      startsMicrophone: false,
      startsWorkers: false,
      executesTask: false,
      routePreviewOnly: true,
      writesLocalJson: true,
      confirmationRequired: true,
    },
  };
  appendAudit('realtime_dogfood.shortcut_recall_prepared', {
    source,
    phrase,
    routeId: payload.route?.id || '',
    shortcutId: payload.shortcut?.id || '',
    recalled,
  });
  return payload;
}

function realtimeEvidenceStep({ id, label, ok, blocked = false, detail = '', nextAction = '', evidence = {} }) {
  const status = ok ? 'ready' : blocked ? 'blocked' : 'pending';
  return {
    id,
    label,
    status,
    ok: Boolean(ok),
    detail: compactRecordText(detail, 240),
    nextAction: compactRecordText(nextAction, 240),
    evidence,
  };
}

function realtimeEvidencePhase(checks = {}, voiceHealth = {}) {
  if (!checks.providerReady) {
    return voiceHealth.status === 'blocked' ? 'provider_blocked' : 'provider_attention';
  }
  if (!checks.sessionNegotiated) return 'needs_live_session';
  if (!checks.voiceSessionLive) return 'needs_live_voice';
  if (!checks.progressInjectedFromRenderer) return 'needs_worker_progress_injection';
  if (!checks.progressVersionSynced) return 'needs_fresh_worker_progress';
  if (!checks.passiveContextOnly) return 'needs_passive_injection';
  if (!checks.spokenSummaryReady) return 'needs_spoken_summary';
  return 'ready';
}

function realtimeProgressSyncEvidence({ currentVersion = null, injection = null } = {}) {
  const version = currentVersion || workProgressSnapshot();
  const currentSequence = boundedCount(version?.sequence, 1000000000);
  const currentUpdatedAt = boundedCount(version?.updatedAt, 4102444800000);
  const currentSource = compactRecordText(version?.source || 'startup', 80);
  const injectedSequence = boundedCount(injection?.progressSequence, 1000000000);
  const injectedUpdatedAt = boundedCount(injection?.progressUpdatedAt, 4102444800000);
  const injectedSource = compactRecordText(injection?.progressSource || '', 80);
  const hasInjection = Boolean(injection);
  const hasVersionedInjection = hasInjection && Boolean(injectedSequence || injectedUpdatedAt || injectedSource);
  const behindBy = hasInjection ? Math.max(0, currentSequence - injectedSequence) : currentSequence;
  const status = !hasInjection
    ? 'pending'
    : !hasVersionedInjection
      ? 'unversioned'
      : behindBy > 0
        ? 'stale'
        : 'synced';
  const ok = status === 'synced';
  const detail = ok
    ? `Progress sequence ${injectedSequence} has reached Realtime.`
    : status === 'stale'
      ? `Realtime is ${behindBy} progress sequence(s) behind current work.`
      : status === 'unversioned'
        ? 'Last Realtime progress receipt did not include a work progress version.'
        : 'No Realtime progress receipt has been recorded yet.';
  return {
    ok,
    status,
    detail,
    currentSequence,
    injectedSequence,
    behindBy,
    current: {
      sequence: currentSequence,
      updatedAt: currentUpdatedAt,
      source: currentSource,
    },
    injected: hasInjection
      ? {
        sequence: injectedSequence,
        updatedAt: injectedUpdatedAt,
        source: injectedSource,
        receiptSource: injection.source || '',
        transport: injection.transport || '',
        createdAt: injection.createdAt || 0,
      }
      : null,
    nextAction: ok
      ? 'Ask in the live voice session: 后台现在怎么样'
      : 'Keep voice live while background work changes so the renderer can send the latest progress sequence.',
  };
}

function realtimeEvidenceChecklist({ checks = {}, voiceHealth = {}, conversation = null, negotiation = null, injection = null, progress = null, progressSync = null, includeSpokenSummary = true } = {}) {
  const checklist = [
    realtimeEvidenceStep({
      id: 'provider_ready',
      label: 'Realtime provider ready',
      ok: checks.providerReady,
      blocked: voiceHealth.status === 'blocked',
      detail: voiceHealth.summary,
      nextAction: voiceHealth.next,
      evidence: { status: voiceHealth.status, kind: voiceHealth.kind, hasOpenAiKey: voiceHealth.hasOpenAiKey },
    }),
    realtimeEvidenceStep({
      id: 'session_negotiated',
      label: 'Renderer WebRTC session negotiated',
      ok: checks.sessionNegotiated,
      detail: checks.sessionNegotiated
        ? `session ${negotiation?.sessionId || '-'} · status ${negotiation?.statusCode || '-'}`
        : 'No successful renderer WebRTC offer/answer receipt has been recorded.',
      nextAction: 'Start a real renderer/WebRTC voice session from the desktop pet or summon hotkey.',
      evidence: {
        sessionId: negotiation?.sessionId || '',
        statusCode: negotiation?.statusCode || 0,
        offerBytes: negotiation?.offerBytes || 0,
        answerBytes: negotiation?.answerBytes || 0,
      },
    }),
    realtimeEvidenceStep({
      id: 'voice_session_live',
      label: 'Renderer voice session reached live state',
      ok: checks.voiceSessionLive,
      detail: checks.voiceSessionLive
        ? `voice ${conversation?.status || 'live'} · session ${conversation?.sessionId || negotiation?.sessionId || '-'}`
        : 'No renderer live/data-channel-open heartbeat has been recorded after SDP negotiation.',
      nextAction: 'Keep the renderer voice session open after starting it from the desktop pet or summon hotkey.',
      evidence: {
        conversationStatus: conversation?.status || '',
        active: Boolean(conversation?.active),
        liveAt: conversation?.liveAt || 0,
        lastHeartbeatAt: conversation?.lastHeartbeatAt || 0,
      },
    }),
    realtimeEvidenceStep({
      id: 'worker_progress_injected',
      label: 'Worker progress injected through renderer',
      ok: checks.progressInjectedFromRenderer,
      detail: checks.progressInjectedFromRenderer
        ? `${injection?.workerSummary || 'progress injected'} via ${injection?.transport || '-'}`
        : 'No open WebRTC data-channel progress injection has been recorded from the renderer.',
      nextAction: 'Keep voice live while background worker progress changes.',
      evidence: {
        transport: injection?.transport || '',
        dataChannelReadyState: injection?.dataChannelReadyState || '',
        workerSummary: injection?.workerSummary || '',
        progressSequence: injection?.progressSequence || 0,
      },
    }),
    realtimeEvidenceStep({
      id: 'progress_version_synced',
      label: 'Latest work progress sequence reached voice',
      ok: checks.progressVersionSynced,
      detail: progressSync?.detail || 'No progress sync evidence has been recorded yet.',
      nextAction: progressSync?.nextAction || 'Keep voice live while background work changes.',
      evidence: {
        status: progressSync?.status || 'pending',
        currentSequence: progressSync?.currentSequence || 0,
        injectedSequence: progressSync?.injectedSequence || 0,
        behindBy: progressSync?.behindBy || 0,
      },
    }),
    realtimeEvidenceStep({
      id: 'passive_context_only',
      label: 'Progress update stayed passive',
      ok: checks.passiveContextOnly,
      detail: checks.passiveContextOnly
        ? 'Progress was sent as passive context without forcing a response.'
        : 'Progress injection has not yet proven conversation.item.create with forcedResponse=false.',
      nextAction: 'Let the live voice session receive progress without forcing a model response.',
      evidence: {
        eventType: injection?.eventType || '',
        forcedResponse: Boolean(injection?.forcedResponse),
      },
    }),
  ];
  if (includeSpokenSummary) {
    checklist.push(realtimeEvidenceStep({
      id: 'spoken_summary_ready',
      label: 'Short spoken progress summary ready',
      ok: checks.spokenSummaryReady,
      detail: progress?.spokenSummary || 'No short spokenSummary available from /api/work/progress.',
      nextAction: 'Refresh /api/work/progress until it returns a short spokenSummary.',
      evidence: { length: String(progress?.spokenSummary || '').length },
    }));
  }
  return checklist;
}

function realtimeVoiceWorkbenchSnapshot() {
  const conversation = conversationStateSnapshot();
  const negotiation = conversation.lastRealtimeSessionNegotiation || null;
  const injection = conversation.lastRealtimeProgressInjection || null;
  const latency = conversation.lastRealtimeLatencyReceipt || null;
  const voiceHealth = realtimeVoiceHealthSnapshot({ conversation, includeRecentAudit: true });
  const progressSync = realtimeProgressSyncEvidence({ injection });
  const liveAt = Number(conversation.liveAt || 0);
  const negotiationAt = Number(negotiation?.createdAt || 0);
  const checks = {
    providerReady: voiceHealth.status === 'ready',
    sessionNegotiated: Boolean(negotiation?.ok && negotiation.offerBytes > 0 && negotiation.answerBytes > 0),
    voiceSessionLive: Boolean(conversation.status === 'live' && liveAt && (!negotiationAt || liveAt >= negotiationAt - 5000)),
    progressInjectedFromRenderer: Boolean(injection?.transport === 'webrtc-datachannel' && injection.dataChannelReadyState === 'open'),
    progressVersionSynced: progressSync.ok,
    passiveContextOnly: Boolean(injection && injection.eventType === 'conversation.item.create' && injection.forcedResponse === false),
    spokenSummaryReady: true,
  };
  const checklist = realtimeEvidenceChecklist({ checks, voiceHealth, conversation, negotiation, injection, progressSync, includeSpokenSummary: false });
  const phase = realtimeEvidencePhase(checks, voiceHealth);
  const status = phase === 'ready'
    ? 'ready'
    : phase === 'provider_blocked'
      ? 'blocked'
      : 'pending';
  const blockerStep = checklist.find((step) => !step.ok) || null;
  const snapshot = {
    ok: true,
    status,
    phase,
    ready: status === 'ready',
    checks,
    checklist,
    blocker: blockerStep
      ? {
        id: blockerStep.id,
        label: blockerStep.label,
        status: blockerStep.status,
        summary: blockerStep.detail,
        nextAction: blockerStep.nextAction,
      }
      : null,
    nextAction: blockerStep?.nextAction || 'Ask in the live voice session: 后台现在怎么样',
    conversation: {
      status: conversation.status,
      active: conversation.active,
      sessionId: conversation.sessionId,
      micMode: conversation.micMode,
    },
    voiceHealth,
  };
  snapshot.dogfoodGuide = realtimeDogfoodGuideFromEvidence(snapshot);
  snapshot.actionPlan = realtimeDogfoodWorkbenchActionPlan(snapshot);
  return snapshot;
}

function realtimeDogfoodWorkbenchGateFromStep(step = {}) {
  const idMap = {
    provider_ready: 'provider_ready',
    session_negotiated: 'start_live_voice',
    voice_session_live: 'start_live_voice',
    worker_progress_injected: 'inject_worker_progress',
    progress_version_synced: 'sync_latest_progress',
    passive_context_only: 'sync_latest_progress',
    spoken_summary_ready: 'ask_progress',
  };
  const groupMap = {
    provider_ready: 'live_voice',
    session_negotiated: 'live_voice',
    voice_session_live: 'live_voice',
    worker_progress_injected: 'live_voice',
    progress_version_synced: 'live_voice',
    passive_context_only: 'live_voice',
    spoken_summary_ready: 'spoken_answer',
  };
  const mappedId = idMap[step.id] || step.id || 'realtime_dogfood_step';
  return realtimeDogfoodAcceptanceGate({
    id: mappedId,
    group: groupMap[step.id] || 'live_voice',
    label: step.label || mappedId,
    ok: Boolean(step.ok),
    detail: step.detail || '',
    nextAction: step.nextAction || '',
    evidence: {
      sourceStepId: step.id || '',
      stepStatus: step.status || (step.ok ? 'ready' : 'pending'),
      prompt: step.evidence?.prompt || step.evidence?.tool || '',
    },
  });
}

function realtimeDogfoodWorkbenchActionPlan(evidence = {}) {
  const checklist = Array.isArray(evidence.checklist) ? evidence.checklist : [];
  const gates = checklist.map(realtimeDogfoodWorkbenchGateFromStep);
  const gaps = gates.filter((gate) => !gate.ok);
  const accepted = Boolean(evidence.ready || evidence.readyForVoiceProgressQuestion || gaps.length === 0);
  return {
    ...realtimeDogfoodAcceptanceActionPlan({
      accepted,
      nextGap: gaps[0] || null,
      gaps,
      gates,
    }),
    scope: 'workbench',
  };
}

