      hasCapabilityMap: Boolean(capabilityTools.hasCapabilityMap),
      hasRecommendedTools: Boolean(capabilityTools.hasRecommendedTools),
      hasLocalExecutionState: Boolean(capabilityTools.hasLocalExecutionState),
