  api.post('/api/realtime/session', express.text({ type: ['application/sdp', 'text/plain'], limit: '4mb' }), async (req, res) => {
    const isProviderProbe = req.query.probe === 'true' || String(req.query.micMode || '').toLowerCase() === 'probe';
    const runId = String(req.query.runId || '').slice(0, 120);
    const source = isProviderProbe
      ? String(req.query.source || 'renderer_provider_probe').slice(0, 80)
      : String(req.query.source || 'renderer').slice(0, 80);
    const confirmOpenAiSpend = truthyRequestValue(req.query.confirmOpenAiSpend || req.query.confirmCloud);
    const confirmOpenAiSpendPhrase = String(
      req.query.confirmOpenAiSpendPhrase ||
        req.query.openAiSpendPhrase ||
        req.query.spendConfirmationPhrase ||
        req.query.confirmationPhrase ||
        '',
    ).slice(0, 160);
    const openAiSpendLeaseId = String(
      req.query.openAiSpendLeaseId ||
        req.query.spendLeaseId ||
        req.query.leaseId ||
        req.query.openAiLeaseId ||
        '',
    ).slice(0, 160);
    const sessionId = isProviderProbe ? runId : conversationState.sessionId;
    const offerBytes = Buffer.byteLength(String(req.body || ''), 'utf8');
    const recordProviderAttempt = (payload = {}) => {
      if (isProviderProbe) {
        return recordRealtimeProviderProbe({
          source,
          runId,
          sessionId,
          micMode: 'open',
          offerBytes,
          ...payload,
        });
      }
      return recordRealtimeSessionNegotiation({
        source,
        sessionId,
        micMode: req.query.micMode,
        offerBytes,
        ...payload,
      });
    };
    if (!OPENAI_API_KEY) {
      recordProviderAttempt({
        answerBytes: 0,
        statusCode: 400,
        ok: false,
        durationMs: 0,
        error: 'missing_openai_api_key',
      });
      jsonError(res, 400, 'Missing OPENAI_API_KEY');
      return;
    }

    const startedAt = Date.now();
    const micMode = isProviderProbe ? 'open' : normalizeConversationMicMode(req.query.micMode);
    const spendConfirmation = openAiSpendConfirmationSnapshot({
      kind: isProviderProbe ? 'realtime_provider_probe' : 'realtime_session',
      source,
      confirmOpenAiSpend,
      confirmOpenAiSpendPhrase,
      openAiSpendLeaseId,
      required: isProviderProbe,
    });
    if (spendConfirmation.required && !spendConfirmation.confirmed) {
      recordProviderAttempt({
        micMode,
        answerBytes: 0,
        statusCode: 428,
        ok: false,
        durationMs: Date.now() - startedAt,
        error: 'openai_spend_confirmation_required',
      });
      res.status(428).send(spendConfirmation.prompt);
      return;
    }
    let spendDecision = null;
    try {
      spendDecision = assertOpenAiSpendAllowed({
        kind: isProviderProbe ? 'realtime_provider_probe' : 'realtime_session',
        source,
        model: models.realtime,
        isProviderProbe,
        confirmOpenAiSpend,
        confirmOpenAiSpendPhrase,
        openAiSpendLeaseId,
        confirmCloud: confirmOpenAiSpend,
      });
    } catch (error) {
      if (error instanceof OpenAiSpendGuardBlocked) {
        recordProviderAttempt({
          micMode,
          answerBytes: 0,
          statusCode: 403,
          ok: false,
          durationMs: Date.now() - startedAt,
          error: error.message,
        });
        res.status(403).send(error.message);
        return;
      }
      throw error;
    }
    const fd = new FormData();
    fd.set('sdp', req.body);
    fd.set('session', JSON.stringify(createRealtimeSessionConfig({ micMode })));

    try {
      const response = await withOpenAiEgressAllowed(spendDecision, () => fetch('https://api.openai.com/v1/realtime/calls', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${OPENAI_API_KEY}`,
          'OpenAI-Safety-Identifier': hashSafetyIdentifier(),
        },
        body: fd,
      }));
      const sdp = await response.text();
      recordProviderAttempt({
        micMode,
        answerBytes: Buffer.byteLength(sdp, 'utf8'),
        statusCode: response.status,
        ok: response.ok,
        durationMs: Date.now() - startedAt,
        error: response.ok ? '' : compactRecordText(sdp, 240),
      });
      appendAudit('openai.realtime.completed', {
        spendEventId: spendDecision?.id || '',
        source,
        runId,
        providerProbe: isProviderProbe,
        status: response.status,
        ok: response.ok,
        answerBytes: Buffer.byteLength(sdp, 'utf8'),
      });
      if (!response.ok) {
        res.status(response.status).send(sdp);
        return;
      }
      res.type('application/sdp').send(sdp);
    } catch (error) {
      recordProviderAttempt({
        micMode,
        answerBytes: 0,
        statusCode: 500,
        ok: false,
        durationMs: Date.now() - startedAt,
        error: error instanceof Error ? error.message : String(error),
      });
      jsonError(res, 500, 'Failed to create realtime session', String(error));
    }
  });

